const COMPTIME_TEST_TIMEOUT_NS: u64 = 30_000_000_000;
const INTEGRATION_TEST_TIMEOUT_NS: u64 = 30_000_000_000;
const GENERATED_BOOT_TIMEOUT_NS: u64 = 30_000_000_000;
const GENERATED_SHUTDOWN_TIMEOUT_NS: u64 = 5_000_000_000;
const GENERATED_MAXIMUM_OUTPUT_BYTES: u64 = 1024 * 1024;
const GENERATED_GROUP_NAME: &str = "wrela-generated-integration-tests";
const GENERATED_HARNESS_NAME: &str = "__wrela_test_harness";
const MAX_TEST_FILTER_BYTES: usize = 4096;
const MAX_RUNTIME_ASSERTION_EXPRESSION_BYTES: usize = 4096;
const BUILTIN_ATTRIBUTE_DIAGNOSTIC_CODE: &str = "semantic-builtin-attribute-not-implemented";

/// Production semantic analyzer for the minimum closed image surface and its
/// real compiler-evaluated/generated-image test forms. Unsupported source
/// operations remain explicit diagnostics; no test result or image fact is
/// synthesized in place of source semantics.
#[derive(Debug, Clone, Copy, Default)]
pub struct CanonicalSemanticAnalyzer;

impl CanonicalSemanticAnalyzer {
    #[must_use]
    pub const fn new() -> Self {
        Self
    }

    /// Derive the exact declaration ChangeSet from a sealed prior product.
    /// This is the production entry for stateful compiler consumers: callers
    /// provide no declaration identities and therefore cannot underreport a
    /// dependency edge.
    pub fn derive_change_set(
        &self,
        current_hir: &ValidatedProgram,
        current_source_graph: Sha256Digest,
        previous: PreviousAnalysisProduct<'_>,
        reuse_limits: AnalysisReuseLimits,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<DerivedAnalysisChangeSet, AnalysisFailure> {
        reuse_limits.validate()?;
        if previous.contract_version != ANALYSIS_CHANGE_SET_REUSE_VERSION {
            return Err(AnalysisFailure::UnsupportedReuseVersion {
                observed: previous.contract_version,
            });
        }
        check_cancelled(is_cancelled)?;
        let previous = previous
            .output
            .successful()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let previous_source_graph = previous.facts().build.source_graph;
        if previous_source_graph == current_source_graph
            || !compatible_hir_graphs(previous.hir(), current_hir)
        {
            return Err(AnalysisFailure::RequestMismatch);
        }
        let mut meter = AnalysisReuseMeter::new(reuse_limits, is_cancelled);
        let changed_declarations = affected_declarations(previous.hir(), current_hir, &mut meter)?;
        Ok(DerivedAnalysisChangeSet {
            changes: AnalysisChangeSet {
                previous_source_graph: Some(previous_source_graph),
                changed_declarations,
            },
            comparisons: meter.used,
        })
    }

    /// Analyze with explicit sealed-product reuse and independently bounded
    /// comparison work. A cold tracked run cannot smuggle incremental flags;
    /// an incremental run rejects any omitted direct or dependent declaration.
    pub fn analyze_tracked(
        &self,
        request: AnalysisRequest<'_>,
        previous: Option<PreviousAnalysisProduct<'_>>,
        reuse_limits: AnalysisReuseLimits,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<TrackedAnalysisOutput, AnalysisFailure> {
        reuse_limits.validate()?;
        let Some(previous) = previous else {
            if request.changes.previous_source_graph.is_some()
                || !request.changes.changed_declarations.is_empty()
            {
                return Err(AnalysisFailure::RequestMismatch);
            }
            let output = self.analyze(request, is_cancelled)?;
            let executed = output.partial().functions.len() as u64;
            return Ok(TrackedAnalysisOutput {
                output,
                reuse: AnalysisReuseReport::cold(executed),
            });
        };
        if previous.contract_version != ANALYSIS_CHANGE_SET_REUSE_VERSION {
            return Err(AnalysisFailure::UnsupportedReuseVersion {
                observed: previous.contract_version,
            });
        }
        let previous_image = validate_previous_analysis(&request, previous.output, is_cancelled)?;
        let mut meter = AnalysisReuseMeter::new(reuse_limits, is_cancelled);
        let recomputed =
            affected_declarations(previous_image.hir(), request.hir.as_ref(), &mut meter)?;
        if request.changes.changed_declarations.as_slice() != recomputed.as_slice() {
            return Err(AnalysisFailure::RequestMismatch);
        }

        let affected = recomputed
            .iter()
            .copied()
            .collect::<std::collections::BTreeSet<_>>();
        let mut semantic_declarations = std::collections::BTreeSet::new();
        match &previous_image.facts().root {
            AnalysisRoot::DeclaredImage { declaration, .. } => {
                semantic_declarations.insert(*declaration);
            }
            AnalysisRoot::GeneratedTestHarness { .. } => {}
        }
        for function in &previous_image.facts().functions {
            meter.poll()?;
            if let Some(declaration) =
                function_origin_declaration(&function.origin, previous_image.hir().as_program())
            {
                semantic_declarations.insert(declaration);
            }
        }
        let semantic_affected = semantic_declarations
            .iter()
            .any(|declaration| affected.contains(declaration));
        let (output, reused_declarations, reused_functions, producer_functions_executed) =
            if semantic_affected {
                // This is the honest fallback boundary for revision 0.1:
                // affected semantic roots are recomputed cold rather than
                // represented as unsupported partial reuse.
                let output = self.analyze(request.clone(), is_cancelled)?;
                let executed = output.partial().functions.len() as u64;
                (output, Vec::new(), Vec::new(), executed)
            } else {
                if !matches!(request.mode, AnalysisMode::Image { .. })
                    || previous_image.facts().test_plan.is_some()
                    || previous_image.facts().compiled_test_group.is_some()
                    || !previous_image.facts().comptime_test_results.is_empty()
                    || previous_image.facts().functions.len() != 1
                    || !matches!(
                        previous_image.facts().functions[0].origin,
                        FunctionOrigin::GeneratedImageEntry { .. }
                    )
                    || previous_image.facts().graph.as_ref().is_none_or(|graph| {
                        !graph.actors.is_empty()
                            || !graph.tasks.is_empty()
                            || !graph.devices.is_empty()
                            || !graph.pools.is_empty()
                            || !graph.regions.is_empty()
                            || !graph.brands.is_empty()
                    })
                {
                    return Err(AnalysisFailure::UnsupportedReuseShape(
                        "whole-product semantic reuse currently supports the minimum ordinary image",
                    ));
                }
                let expected_root = analysis_root(&request, is_cancelled)?;
                meter.equal(&expected_root, &previous_image.facts().root)?;
                let mut facts = previous_image.facts().clone();
                facts.hir = HirSummary::from_validated(request.hir.as_ref())?;
                facts.build = request.build.identity.clone();
                facts.target_digest = request.target.content_digest();
                facts.root = expected_root;
                // Generated-entry keys are request identities rather than
                // semantic facts. Rebinding this fixed-width identity is the
                // only current-build work on the whole-product reuse path.
                facts.functions[0].key = FunctionKey(request.build.identity.request);
                let output = finish_analysis(
                    &request,
                    facts,
                    previous.output.diagnostics().to_vec(),
                    is_cancelled,
                )?;
                let reused_functions = previous_image
                    .facts()
                    .functions
                    .iter()
                    .map(|function| function.id)
                    .collect();
                (
                    output,
                    semantic_declarations.into_iter().collect(),
                    reused_functions,
                    0,
                )
            };
        meter.poll()?;
        Ok(TrackedAnalysisOutput {
            output,
            reuse: AnalysisReuseReport {
                reused_declarations,
                reused_functions,
                recomputed_declarations: recomputed,
                producer_functions_executed,
                comparisons: meter.used,
            },
        })
    }
}

struct AnalysisReuseMeter<'a> {
    used: u64,
    limits: AnalysisReuseLimits,
    is_cancelled: &'a dyn Fn() -> bool,
}

impl<'a> AnalysisReuseMeter<'a> {
    fn new(limits: AnalysisReuseLimits, is_cancelled: &'a dyn Fn() -> bool) -> Self {
        Self {
            used: 0,
            limits,
            is_cancelled,
        }
    }

    fn poll(&mut self) -> Result<(), AnalysisFailure> {
        check_cancelled(self.is_cancelled)?;
        self.used = self
            .used
            .checked_add(1)
            .ok_or(AnalysisFailure::ResourceLimit {
                resource: "semantic reuse comparisons",
                limit: self.limits.comparisons,
            })?;
        if self.used > self.limits.comparisons {
            return Err(AnalysisFailure::ResourceLimit {
                resource: "semantic reuse comparisons",
                limit: self.limits.comparisons,
            });
        }
        Ok(())
    }

    fn equal<T: PartialEq>(&mut self, left: &T, right: &T) -> Result<(), AnalysisFailure> {
        self.poll()?;
        if left == right {
            Ok(())
        } else {
            Err(AnalysisFailure::RequestMismatch)
        }
    }
}

fn validate_previous_analysis<'a>(
    request: &AnalysisRequest<'_>,
    previous: &'a AnalysisOutput,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<&'a AnalyzedImage, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let previous = previous
        .successful()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let old = &previous.facts().build;
    let new = &request.build.identity;
    if request.changes.previous_source_graph != Some(old.source_graph)
        || old.source_graph == new.source_graph
        || old.compiler != new.compiler
        || old.language != new.language
        || old.target != new.target
        || old.target_package != new.target_package
        || old.standard_library != new.standard_library
        || old.profile != new.profile
        || previous.facts().target_digest != request.target.content_digest()
        || previous.facts().target_digest != new.target_package
        || request.target.identity() != &new.target
        || !compatible_hir_graphs(previous.hir(), request.hir.as_ref())
    {
        return Err(AnalysisFailure::RequestMismatch);
    }
    Ok(previous)
}

fn compatible_hir_graphs(previous: &ValidatedProgram, current: &ValidatedProgram) -> bool {
    let previous = previous.as_program();
    let current = current.as_program();
    previous.modules.len() == current.modules.len()
        && previous.declarations.len() == current.declarations.len()
        && previous.bodies.len() == current.bodies.len()
        && previous.parameters.len() == current.parameters.len()
        && previous.locals.len() == current.locals.len()
        && previous.statements.len() == current.statements.len()
        && previous.expressions.len() == current.expressions.len()
        && previous.patterns.len() == current.patterns.len()
        && previous.regions.len() == current.regions.len()
        && previous.packages.root() == current.packages.root()
        && previous.packages.modules() == current.packages.modules()
        && previous
            .packages
            .packages()
            .iter()
            .zip(current.packages.packages())
            .all(|(left, right)| {
                left.id == right.id
                    && left.identity.name == right.identity.name
                    && left.identity.version == right.identity.version
                    && left.dependencies == right.dependencies
            })
}

fn affected_declarations(
    previous: &ValidatedProgram,
    current: &ValidatedProgram,
    meter: &mut AnalysisReuseMeter<'_>,
) -> Result<Vec<DeclarationId>, AnalysisFailure> {
    if !compatible_hir_graphs(previous, current) {
        return Err(AnalysisFailure::RequestMismatch);
    }
    let previous = previous.as_program();
    let current = current.as_program();
    let mut affected = std::collections::BTreeSet::new();
    let mut requires_conservative_reanalysis = false;
    for index in 0..current.declarations.len() {
        meter.poll()?;
        let id =
            DeclarationId(
                u32::try_from(index).map_err(|_| AnalysisFailure::ResourceLimit {
                    resource: "semantic reuse declaration identities",
                    limit: meter.limits.comparisons,
                })?,
            );
        if !declaration_semantically_equal(previous, current, id, meter)? {
            affected.insert(id);
            if !declaration_change_is_literal_only(previous, current, id, meter)? {
                requires_conservative_reanalysis = true;
            }
        }
    }
    // The revision-0.1 semantic product does not yet expose a complete
    // declaration dependency graph for types, attributes, generics, roles,
    // effects, resources, or name-resolution edges. Until it does, only a
    // literal payload edit inside a private, attribute-free, non-generic sync
    // runtime helper is narrow enough to prove local. Every other HIR mutation
    // conservatively invalidates the complete declaration product.
    if requires_conservative_reanalysis {
        let mut all = Vec::with_capacity(current.declarations.len());
        for index in 0..current.declarations.len() {
            meter.poll()?;
            all.push(DeclarationId(u32::try_from(index).map_err(|_| {
                AnalysisFailure::ResourceLimit {
                    resource: "semantic reuse declaration identities",
                    limit: meter.limits.comparisons,
                }
            })?));
        }
        return Ok(all);
    }
    loop {
        let before = affected.len();
        for program in [previous, current] {
            for expression in &program.expressions {
                meter.poll()?;
                let ExpressionKind::Reference(Definition::Declaration(target)) = &expression.kind
                else {
                    continue;
                };
                let Some(owner) = expression_owner_declaration(program, expression.owner) else {
                    continue;
                };
                if affected.contains(&target.declaration) {
                    affected.insert(owner);
                }
            }
        }
        if affected.len() == before {
            break;
        }
    }
    Ok(affected.into_iter().collect())
}

fn declaration_change_is_literal_only(
    previous: &wrela_hir::Program,
    current: &wrela_hir::Program,
    declaration: DeclarationId,
    meter: &mut AnalysisReuseMeter<'_>,
) -> Result<bool, AnalysisFailure> {
    let index = declaration.0 as usize;
    meter.poll()?;
    let (Some(previous_declaration), Some(current_declaration)) = (
        previous.declarations.get(index),
        current.declarations.get(index),
    ) else {
        return Ok(false);
    };
    if previous_declaration != current_declaration
        || !narrow_runtime_literal_owner(previous, previous_declaration)
        || !narrow_runtime_literal_owner(current, current_declaration)
    {
        return Ok(false);
    }
    macro_rules! require_equal_owned {
        ($arena:ident, $owner:expr) => {{
            let left = previous
                .$arena
                .iter()
                .filter(|value| $owner(previous, value, declaration))
                .collect::<Vec<_>>();
            let right = current
                .$arena
                .iter()
                .filter(|value| $owner(current, value, declaration))
                .collect::<Vec<_>>();
            meter.poll()?;
            if left != right {
                return Ok(false);
            }
        }};
    }
    require_equal_owned!(generic_parameters, generic_owned_by);
    require_equal_owned!(parameters, parameter_owned_by);
    require_equal_owned!(bodies, body_owned_by);
    require_equal_owned!(scopes, scope_owned_by);
    require_equal_owned!(locals, local_owned_by);
    require_equal_owned!(statements, statement_owned_by);
    require_equal_owned!(patterns, pattern_owned_by);
    require_equal_owned!(regions, region_owned_by);

    let left = previous
        .expressions
        .iter()
        .filter(|value| expression_owned_by(previous, value, declaration))
        .collect::<Vec<_>>();
    let right = current
        .expressions
        .iter()
        .filter(|value| expression_owned_by(current, value, declaration))
        .collect::<Vec<_>>();
    meter.poll()?;
    if left.len() != right.len() {
        return Ok(false);
    }
    let mut changed_literal = false;
    for (left, right) in left.into_iter().zip(right) {
        meter.poll()?;
        if left == right {
            continue;
        }
        if left.id != right.id
            || left.owner != right.owner
            || left.scope != right.scope
            || left.source != right.source
            || !matches!(
                (&left.kind, &right.kind),
                (ExpressionKind::Literal(_), ExpressionKind::Literal(_))
            )
        {
            return Ok(false);
        }
        changed_literal = true;
    }
    Ok(changed_literal)
}

fn narrow_runtime_literal_owner(
    program: &wrela_hir::Program,
    declaration: &wrela_hir::Declaration,
) -> bool {
    let DeclarationKind::Function(function) = &declaration.kind else {
        return false;
    };
    declaration.owner == wrela_hir::DeclarationOwner::Module(declaration.module)
        && declaration.visibility == wrela_hir::Visibility::Private
        && declaration.attributes.is_empty()
        && function.color == FunctionColor::Sync
        && function.generics.is_empty()
        && function.parameters.is_empty()
        && function.body.is_some()
        && !program.image_candidates.contains(&declaration.id)
        && !program.test_candidates.contains(&declaration.id)
}

fn declaration_semantically_equal(
    previous: &wrela_hir::Program,
    current: &wrela_hir::Program,
    declaration: DeclarationId,
    meter: &mut AnalysisReuseMeter<'_>,
) -> Result<bool, AnalysisFailure> {
    let index = declaration.0 as usize;
    meter.poll()?;
    if previous.declarations.get(index) != current.declarations.get(index) {
        return Ok(false);
    }
    macro_rules! equal_owned {
        ($arena:ident, $owner:expr) => {{
            let left = previous
                .$arena
                .iter()
                .filter(|value| $owner(previous, value, declaration))
                .collect::<Vec<_>>();
            let right = current
                .$arena
                .iter()
                .filter(|value| $owner(current, value, declaration))
                .collect::<Vec<_>>();
            meter.poll()?;
            if left != right {
                return Ok(false);
            }
        }};
    }
    equal_owned!(generic_parameters, generic_owned_by);
    equal_owned!(parameters, parameter_owned_by);
    equal_owned!(bodies, body_owned_by);
    equal_owned!(scopes, scope_owned_by);
    equal_owned!(locals, local_owned_by);
    equal_owned!(statements, statement_owned_by);
    equal_owned!(expressions, expression_owned_by);
    equal_owned!(patterns, pattern_owned_by);
    equal_owned!(regions, region_owned_by);
    Ok(true)
}

fn generic_owned_by(
    _: &wrela_hir::Program,
    value: &wrela_hir::GenericParameter,
    declaration: DeclarationId,
) -> bool {
    value.owner == declaration
}

fn parameter_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::Parameter,
    declaration: DeclarationId,
) -> bool {
    match value.owner {
        wrela_hir::CallableOwner::Declaration(owner) => owner == declaration,
        wrela_hir::CallableOwner::Closure(expression) => {
            expression_owner_declaration(program, wrela_hir::ExpressionOwner::Closure(expression))
                == Some(declaration)
        }
    }
}

fn body_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::Body,
    declaration: DeclarationId,
) -> bool {
    body_owner_declaration(program, value.id) == Some(declaration)
}

fn scope_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::LexicalScope,
    declaration: DeclarationId,
) -> bool {
    body_owner_declaration(program, value.body) == Some(declaration)
}

fn local_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::Local,
    declaration: DeclarationId,
) -> bool {
    body_owner_declaration(program, value.body) == Some(declaration)
}

fn statement_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::Statement,
    declaration: DeclarationId,
) -> bool {
    body_owner_declaration(program, value.body) == Some(declaration)
}

fn expression_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::Expression,
    declaration: DeclarationId,
) -> bool {
    expression_owner_declaration(program, value.owner) == Some(declaration)
}

fn pattern_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::Pattern,
    declaration: DeclarationId,
) -> bool {
    expression_owner_declaration(program, value.owner) == Some(declaration)
}

fn region_owned_by(
    program: &wrela_hir::Program,
    value: &wrela_hir::RegionBinding,
    declaration: DeclarationId,
) -> bool {
    body_owner_declaration(program, value.body) == Some(declaration)
}

fn body_owner_declaration(program: &wrela_hir::Program, body: BodyId) -> Option<DeclarationId> {
    match program.bodies.get(body.0 as usize)?.owner {
        wrela_hir::BodyOwner::Declaration(declaration) => Some(declaration),
        wrela_hir::BodyOwner::Closure(expression) => {
            expression_owner_declaration(program, wrela_hir::ExpressionOwner::Closure(expression))
        }
    }
}

fn expression_owner_declaration(
    program: &wrela_hir::Program,
    owner: wrela_hir::ExpressionOwner,
) -> Option<DeclarationId> {
    match owner {
        wrela_hir::ExpressionOwner::Declaration(declaration) => Some(declaration),
        wrela_hir::ExpressionOwner::Body(body) => body_owner_declaration(program, body),
        wrela_hir::ExpressionOwner::Closure(expression) => {
            let expression = program.expressions.get(expression.0 as usize)?;
            expression_owner_declaration(program, expression.owner)
        }
    }
}

fn function_origin_declaration(
    origin: &FunctionOrigin,
    hir: &wrela_hir::Program,
) -> Option<DeclarationId> {
    match origin {
        FunctionOrigin::Source { declaration, .. }
        | FunctionOrigin::GeneratedImageEntry {
            constructor: declaration,
        } => Some(*declaration),
        FunctionOrigin::SourceClosure { expression } => {
            let expression = hir.expressions.get(expression.0 as usize)?;
            expression_owner_declaration(hir, expression.owner)
        }
        FunctionOrigin::GeneratedTestHarness { .. } => None,
    }
}

#[derive(Debug)]
struct BuiltinAttributeCensus {
    diagnostics: Vec<Diagnostic>,
    work_units: u64,
    diagnostic_bytes: u64,
}

impl BuiltinAttributeCensus {
    fn new() -> Self {
        Self {
            diagnostics: Vec::new(),
            work_units: 0,
            diagnostic_bytes: 0,
        }
    }

    fn visit_owner(
        &mut self,
        limits: AnalysisLimits,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<(), AnalysisFailure> {
        check_cancelled(is_cancelled)?;
        self.work_units = self
            .work_units
            .checked_add(1)
            .ok_or(AnalysisFailure::ResourceLimit {
                resource: "semantic built-in attribute census work",
                limit: limits.fact_edges,
            })?;
        if self.work_units > limits.fact_edges {
            return Err(AnalysisFailure::ResourceLimit {
                resource: "semantic built-in attribute census work",
                limit: limits.fact_edges,
            });
        }
        Ok(())
    }

    fn visit_attribute(
        &mut self,
        attribute: &wrela_hir::Attribute,
        limits: AnalysisLimits,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<(), AnalysisFailure> {
        self.visit_owner(limits, is_cancelled)?;
        let wrela_hir::AttributeIdentity::Builtin(builtin) = attribute.identity else {
            return Ok(());
        };
        if builtin_attribute_has_semantic_consumer(builtin) {
            return Ok(());
        }
        let next_count =
            self.diagnostics
                .len()
                .checked_add(1)
                .ok_or(AnalysisFailure::ResourceLimit {
                    resource: "semantic diagnostics",
                    limit: u64::from(limits.diagnostic_count),
                })?;
        if next_count > limits.diagnostic_count as usize {
            return Err(AnalysisFailure::ResourceLimit {
                resource: "semantic diagnostics",
                limit: u64::from(limits.diagnostic_count),
            });
        }
        let message = unimplemented_builtin_attribute_message(builtin);
        let bytes = u64::try_from(BUILTIN_ATTRIBUTE_DIAGNOSTIC_CODE.len())
            .ok()
            .and_then(|code| {
                u64::try_from(message.len())
                    .ok()
                    .and_then(|message| code.checked_add(message))
            })
            .and_then(|bytes| self.diagnostic_bytes.checked_add(bytes))
            .ok_or(AnalysisFailure::ResourceLimit {
                resource: "diagnostic bytes",
                limit: limits.diagnostic_bytes,
            })?;
        if bytes > limits.diagnostic_bytes {
            return Err(AnalysisFailure::ResourceLimit {
                resource: "diagnostic bytes",
                limit: limits.diagnostic_bytes,
            });
        }
        self.diagnostics
            .try_reserve_exact(1)
            .map_err(|_| AnalysisFailure::ResourceLimit {
                resource: "semantic diagnostics",
                limit: u64::from(limits.diagnostic_count),
            })?;
        let code = copy_builtin_attribute_diagnostic_text(
            BUILTIN_ATTRIBUTE_DIAGNOSTIC_CODE,
            limits.diagnostic_bytes,
        )?;
        let message = copy_builtin_attribute_diagnostic_text(message, limits.diagnostic_bytes)?;
        self.diagnostics.push(Diagnostic {
            category: unimplemented_builtin_attribute_category(builtin),
            code: Some(code),
            severity: Severity::Error,
            primary: attribute.source,
            message,
            labels: Vec::new(),
            notes: Vec::new(),
            help: Vec::new(),
            related: Vec::new(),
            repairs: Vec::new(),
        });
        self.diagnostic_bytes = bytes;
        Ok(())
    }

    fn visit_attributes(
        &mut self,
        attributes: &[wrela_hir::Attribute],
        limits: AnalysisLimits,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<(), AnalysisFailure> {
        for attribute in attributes {
            self.visit_attribute(attribute, limits, is_cancelled)?;
        }
        Ok(())
    }
}

fn census_builtin_attributes(
    program: &wrela_hir::Program,
    limits: AnalysisLimits,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<BuiltinAttributeCensus, AnalysisFailure> {
    let mut census = BuiltinAttributeCensus::new();
    for declaration in &program.declarations {
        census.visit_owner(limits, is_cancelled)?;
        census.visit_attributes(&declaration.attributes, limits, is_cancelled)?;
        if let DeclarationKind::Structure(aggregate) = &declaration.kind {
            for field in &aggregate.fields {
                census.visit_owner(limits, is_cancelled)?;
                census.visit_attributes(&field.attributes, limits, is_cancelled)?;
            }
        }
    }
    for statement in &program.statements {
        census.visit_owner(limits, is_cancelled)?;
        census.visit_attributes(&statement.attributes, limits, is_cancelled)?;
    }
    Ok(census)
}

const fn builtin_attribute_has_semantic_consumer(builtin: wrela_hir::BuiltinAttribute) -> bool {
    matches!(
        builtin,
        wrela_hir::BuiltinAttribute::Image
            | wrela_hir::BuiltinAttribute::App
            | wrela_hir::BuiltinAttribute::Service
            | wrela_hir::BuiltinAttribute::Driver
            | wrela_hir::BuiltinAttribute::Task
            | wrela_hir::BuiltinAttribute::Test
            | wrela_hir::BuiltinAttribute::NoPromote
    )
}

const fn unimplemented_builtin_attribute_category(
    builtin: wrela_hir::BuiltinAttribute,
) -> Category {
    match builtin {
        wrela_hir::BuiltinAttribute::ReceiptHandoff => Category::ACTOR,
        wrela_hir::BuiltinAttribute::Dma => Category::DMA,
        wrela_hir::BuiltinAttribute::IsrSafe
        | wrela_hir::BuiltinAttribute::Wire
        | wrela_hir::BuiltinAttribute::Mmio
        | wrela_hir::BuiltinAttribute::Offset
        | wrela_hir::BuiltinAttribute::LayoutAssert => Category::HARDWARE,
        wrela_hir::BuiltinAttribute::SuspendSafe => Category::ASYNC,
        wrela_hir::BuiltinAttribute::NoPromote => Category::OWNERSHIP,
        wrela_hir::BuiltinAttribute::Budget | wrela_hir::BuiltinAttribute::Uninterrupted => {
            Category::CAPACITY
        }
        wrela_hir::BuiltinAttribute::Image
        | wrela_hir::BuiltinAttribute::App
        | wrela_hir::BuiltinAttribute::Service
        | wrela_hir::BuiltinAttribute::Driver
        | wrela_hir::BuiltinAttribute::Task
        | wrela_hir::BuiltinAttribute::Test => Category::TYPE,
    }
}

const fn unimplemented_builtin_attribute_message(
    builtin: wrela_hir::BuiltinAttribute,
) -> &'static str {
    match builtin {
        wrela_hir::BuiltinAttribute::IsrSafe => {
            "built-in attribute `@isr_safe` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::ReceiptHandoff => {
            "built-in attribute `@receipt_handoff` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::Dma => {
            "built-in attribute `@dma` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::Wire => {
            "built-in attribute `@wire` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::Mmio => {
            "built-in attribute `@mmio` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::Offset => {
            "built-in attribute `@offset` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::LayoutAssert => {
            "built-in attribute `@layout_assert` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::SuspendSafe => {
            "built-in attribute `@suspend_safe` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::NoPromote => {
            "implemented built-in attribute cannot produce an unimplemented diagnostic"
        }
        wrela_hir::BuiltinAttribute::Budget => {
            "built-in attribute `@budget` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::Uninterrupted => {
            "built-in attribute `@uninterrupted` is recognized but its semantic contract is not implemented"
        }
        wrela_hir::BuiltinAttribute::Image
        | wrela_hir::BuiltinAttribute::App
        | wrela_hir::BuiltinAttribute::Service
        | wrela_hir::BuiltinAttribute::Driver
        | wrela_hir::BuiltinAttribute::Task
        | wrela_hir::BuiltinAttribute::Test => {
            "implemented built-in attribute cannot produce an unimplemented diagnostic"
        }
    }
}

fn copy_builtin_attribute_diagnostic_text(
    value: &str,
    limit: u64,
) -> Result<String, AnalysisFailure> {
    if u64::try_from(value.len()).unwrap_or(u64::MAX) > limit {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "diagnostic bytes",
            limit,
        });
    }
    let mut output = String::new();
    output
        .try_reserve_exact(value.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "diagnostic bytes",
            limit,
        })?;
    output.push_str(value);
    Ok(output)
}

impl SemanticAnalyzer for CanonicalSemanticAnalyzer {
    fn analyze(
        &self,
        request: AnalysisRequest<'_>,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<AnalysisOutput, AnalysisFailure> {
        check_cancelled(is_cancelled)?;
        request.limits.validate()?;
        request
            .build
            .validate()
            .map_err(|error| AnalysisFailure::InvalidBuild(error.to_string()))?;

        let root = analysis_root(&request, is_cancelled)?;
        let mut partial = empty_partial(&request, root)?;
        let census =
            census_builtin_attributes(request.hir.as_program(), request.limits, is_cancelled)?;
        let mut diagnostics = census.diagnostics;
        diagnose_deriving_clauses(&request, &mut diagnostics, is_cancelled)?;
        diagnose_unsupported_initializers(&request, &mut diagnostics, is_cancelled)?;
        diagnose_driver_handler_waits(&request, &mut diagnostics, is_cancelled)?;
        let (_, interface_diagnostics) = crate::interfaces::collect_interface_model(
            request.hir.as_program(),
            request.standard_library_package,
            is_cancelled,
        )?;
        for diagnostic in interface_diagnostics {
            push_diagnostic(&mut diagnostics, diagnostic, request.limits)?;
        }
        if !diagnostics.is_empty() {
            check_cancelled(is_cancelled)?;
            return finish_analysis(&request, partial, diagnostics, is_cancelled);
        }
        diagnostics
            .try_reserve_exact(1)
            .map_err(|_| AnalysisFailure::ResourceLimit {
                resource: "semantic diagnostics",
                limit: u64::from(request.limits.diagnostic_count),
            })?;

        match &request.mode {
            AnalysisMode::Image { name, entry } => {
                let result = ImageEvaluator::new(&request, is_cancelled)?.evaluate(*entry);
                match result {
                    Ok(image) if image.name() == Some(*name) => {
                        if let Some(diagnostic) = populate_evaluated_image(
                            &request,
                            &mut partial,
                            *entry,
                            image,
                            is_cancelled,
                        )? {
                            push_diagnostic(&mut diagnostics, diagnostic, request.limits)?;
                        }
                    }
                    Ok(image) => {
                        let mut diagnostic = Diagnostic::error(
                            Category::IMAGE,
                            image.name_source,
                            "runtime Image name differs from the selected manifest image",
                        );
                        diagnostic.code = Some("semantic-image-name-mismatch".to_owned());
                        diagnostic.help.push(format!(
                            "use the selected manifest image name `{name}` in this Image constructor"
                        ));
                        diagnostics.push(diagnostic);
                    }
                    Err(EvaluationFailure::Diagnostic(diagnostic)) => {
                        diagnostics.push(*diagnostic);
                    }
                    Err(EvaluationFailure::Analysis(error)) => return Err(error),
                }
            }
            AnalysisMode::DiscoverTests {
                image_entry,
                image_name,
                declared_image_tests,
                source_selection,
            } => {
                if evaluate_and_populate_declared_image(
                    &request,
                    &mut partial,
                    *image_entry,
                    image_name,
                    &mut diagnostics,
                    is_cancelled,
                )? {
                    discover_tests(
                        &request,
                        &mut partial,
                        declared_image_tests,
                        *source_selection,
                        &mut diagnostics,
                        is_cancelled,
                    )?;
                }
            }
            AnalysisMode::CompileTestGroup {
                plan,
                group,
                declared_entry,
            } => {
                let record = plan.group(*group).ok_or(AnalysisFailure::RequestMismatch)?;
                partial.compiled_test_group = Some(record.clone());
                match (&record.root, declared_entry) {
                    (ImageRoot::GeneratedHarness { .. }, None) => compile_generated_test_group(
                        &request,
                        &mut partial,
                        plan,
                        *group,
                        &mut diagnostics,
                        is_cancelled,
                    )?,
                    (ImageRoot::Declared { image_name, .. }, Some(entry)) => {
                        let _ = evaluate_and_populate_declared_image(
                            &request,
                            &mut partial,
                            *entry,
                            image_name,
                            &mut diagnostics,
                            is_cancelled,
                        )?;
                    }
                    _ => return Err(AnalysisFailure::RequestMismatch),
                }
            }
        }

        // Image and generated-entry construction still owns the initial dense
        // semantic IDs. Projection declaration facts are image-independent, so
        // append them only after the selected mode has populated its root. A
        // later projection-call increment may also intern one lazily while
        // analyzing a caller; this complete scan remains idempotent.
        diagnose_projection_protocols(&request, &mut partial, &mut diagnostics, is_cancelled)?;

        cancellable_stable_sort_owned_by(
            &mut partial.expressions,
            u64::from(request.limits.expression_facts),
            "expression fact sort scratch",
            is_cancelled,
            &|left, right| {
                Ok((left.function, left.expression).cmp(&(right.function, right.expression)))
            },
        )?;
        cancellable_stable_sort_owned_by(
            &mut partial.statements,
            u64::from(request.limits.statement_facts),
            "statement fact sort scratch",
            is_cancelled,
            &|left, right| {
                Ok((left.function, left.statement).cmp(&(right.function, right.statement)))
            },
        )?;
        finish_analysis(&request, partial, diagnostics, is_cancelled)
    }
}

fn analysis_root(
    request: &AnalysisRequest<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<AnalysisRoot, AnalysisFailure> {
    match &request.mode {
        AnalysisMode::Image { name, entry } => Ok(AnalysisRoot::DeclaredImage {
            image_name: copy_analysis_text(name, request.limits.fact_bytes, is_cancelled)?,
            declaration: *entry,
            test_group: None,
        }),
        AnalysisMode::DiscoverTests {
            image_name,
            image_entry,
            ..
        } => Ok(AnalysisRoot::DeclaredImage {
            image_name: copy_analysis_text(image_name, request.limits.fact_bytes, is_cancelled)?,
            declaration: *image_entry,
            test_group: None,
        }),
        AnalysisMode::CompileTestGroup {
            plan,
            group,
            declared_entry,
        } => {
            let record = plan.group(*group).ok_or(AnalysisFailure::RequestMismatch)?;
            match (&record.root, declared_entry) {
                (TestImageRoot::GeneratedHarness { harness_name }, None) => {
                    Ok(AnalysisRoot::GeneratedTestHarness {
                        group: *group,
                        harness_name: copy_analysis_text(
                            harness_name,
                            request.limits.fact_bytes,
                            is_cancelled,
                        )?,
                    })
                }
                (TestImageRoot::Declared { image_name, .. }, Some(declaration)) => {
                    Ok(AnalysisRoot::DeclaredImage {
                        image_name: copy_analysis_text(
                            image_name,
                            request.limits.fact_bytes,
                            is_cancelled,
                        )?,
                        declaration: *declaration,
                        test_group: Some(*group),
                    })
                }
                _ => Err(AnalysisFailure::RequestMismatch),
            }
        }
    }
}

fn copy_static_analysis_text(value: &str, limit: u64) -> Result<String, AnalysisFailure> {
    if u64::try_from(value.len()).unwrap_or(u64::MAX) > limit {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit,
        });
    }
    let mut output = String::new();
    output
        .try_reserve_exact(value.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit,
        })?;
    output.push_str(value);
    Ok(output)
}

fn copy_analysis_text(
    value: &str,
    limit: u64,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<String, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    if u64::try_from(value.len()).unwrap_or(u64::MAX) > limit {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit,
        });
    }
    let mut output = String::new();
    output
        .try_reserve_exact(value.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit,
        })?;
    append_polled_test_text(&mut output, value, is_cancelled)?;
    Ok(output)
}

fn empty_partial(
    request: &AnalysisRequest<'_>,
    root: AnalysisRoot,
) -> Result<PartialAnalysis, AnalysisFailure> {
    Ok(PartialAnalysis {
        hir: HirSummary::from_validated(request.hir.as_ref())?,
        build: request.build.identity.clone(),
        target_digest: request.target.content_digest(),
        root,
        types: Vec::new(),
        functions: Vec::new(),
        values: Vec::new(),
        expressions: Vec::new(),
        statements: Vec::new(),
        actor_state_accesses: Vec::new(),
        region_assignments: Vec::new(),
        promotions: Vec::new(),
        projection_protocols: Vec::new(),
        lexical_views: Vec::new(),
        scope_protocols: Vec::new(),
        scope_activations: Vec::new(),
        graph: None,
        proofs: Vec::new(),
        baked_artifacts: Vec::new(),
        test_plan: None,
        comptime_test_results: Vec::new(),
        compiled_test_group: None,
    })
}

fn evaluate_and_populate_declared_image(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    entry: DeclarationId,
    expected_name: &str,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<bool, AnalysisFailure> {
    let result = ImageEvaluator::new(request, is_cancelled)?.evaluate(entry);
    match result {
        Ok(image) if image.name() == Some(expected_name) => {
            if let Some(diagnostic) =
                populate_evaluated_image(request, partial, entry, image, is_cancelled)?
            {
                push_diagnostic(diagnostics, diagnostic, request.limits)?;
                Ok(false)
            } else {
                Ok(true)
            }
        }
        Ok(image) => {
            let mut diagnostic = Diagnostic::error(
                Category::IMAGE,
                image.name_source,
                "runtime Image name differs from the selected manifest image",
            );
            diagnostic.code = Some("semantic-image-name-mismatch".to_owned());
            diagnostic.help.push(format!(
                "use the selected manifest image name `{expected_name}` in this Image constructor"
            ));
            push_diagnostic(diagnostics, diagnostic, request.limits)?;
            Ok(false)
        }
        Err(EvaluationFailure::Diagnostic(diagnostic)) => {
            push_diagnostic(diagnostics, *diagnostic, request.limits)?;
            Ok(false)
        }
        Err(EvaluationFailure::Analysis(error)) => Err(error),
    }
}

fn push_diagnostic(
    diagnostics: &mut Vec<Diagnostic>,
    diagnostic: Diagnostic,
    limits: AnalysisLimits,
) -> Result<(), AnalysisFailure> {
    if diagnostics.len() >= limits.diagnostic_count as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic diagnostics",
            limit: u64::from(limits.diagnostic_count),
        });
    }
    diagnostics
        .try_reserve(1)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic diagnostics",
            limit: u64::from(limits.diagnostic_count),
        })?;
    diagnostics.push(diagnostic);
    Ok(())
}

fn diagnose_deriving_clauses(
    request: &AnalysisRequest<'_>,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    for declaration in &request.hir.as_program().declarations {
        check_cancelled(is_cancelled)?;
        let deriving = match &declaration.kind {
            DeclarationKind::Structure(aggregate) => aggregate.deriving.as_slice(),
            DeclarationKind::Enumeration(enumeration) => enumeration.deriving.as_slice(),
            _ => continue,
        };
        if deriving.is_empty() {
            continue;
        }
        let valid_from_shape = match &declaration.kind {
            DeclarationKind::Structure(aggregate) => aggregate.fields.len() == 1,
            DeclarationKind::Enumeration(enumeration) => {
                let mut payloads = enumeration
                    .variants
                    .iter()
                    .filter(|variant| !variant.fields.is_empty());
                payloads
                    .next()
                    .is_some_and(|variant| variant.fields.len() == 1)
                    && payloads.next().is_none()
            }
            _ => false,
        };
        for name in deriving {
            match name.as_str() {
                "Eq" | "Format" => {}
                "From" => {
                    if !valid_from_shape {
                        let mut diagnostic = Diagnostic::error(
                            Category::TYPE,
                            declaration.source,
                            "`deriving(From)` requires exactly one payload-carrying field or variant",
                        );
                        diagnostic.code = Some("semantic-deriving-from-shape".to_owned());
                        diagnostic.help.push(
                            "use `deriving(From)` only on a single-field struct or a single-payload enum"
                                .to_owned(),
                        );
                        push_diagnostic(diagnostics, diagnostic, request.limits)?;
                    }
                }
                _ => {
                    let mut diagnostic = Diagnostic::error(
                        Category::TYPE,
                        declaration.source,
                        format!(
                            "`deriving({})` is not in the closed compiler-known list `Eq`, `Format`, `From`",
                            name.as_str()
                        ),
                    );
                    diagnostic.code = Some("semantic-deriving-unknown".to_owned());
                    diagnostic.help.push(
                        "spell one of `Eq`, `Format`, or `From`, or remove the deriving clause"
                            .to_owned(),
                    );
                    push_diagnostic(diagnostics, diagnostic, request.limits)?;
                }
            }
        }
    }
    Ok(())
}

fn initializer_diagnostic(source: Span, code: &str, message: &str) -> Diagnostic {
    let mut diagnostic = Diagnostic::error(Category::TYPE, source, message);
    diagnostic.code = Some(code.to_owned());
    diagnostic.notes.push(
        "the admitted init slice is an exact infallible call-site desugar, not a partially initialized runtime place"
            .to_owned(),
    );
    diagnostic.help.push(
        "use `init(mut self, field: Scalar, ...)` with one direct `self.field = field` assignment per public field"
            .to_owned(),
    );
    diagnostic
}

fn exact_initializer_builtin_type(
    left: &wrela_hir::TypeExpression,
    right: &wrela_hir::TypeExpression,
) -> bool {
    matches!(
        (&left.kind, &right.kind),
        (
            wrela_hir::TypeExpressionKind::Named {
                definition: Definition::Builtin(left),
                arguments: left_arguments,
            },
            wrela_hir::TypeExpressionKind::Named {
                definition: Definition::Builtin(right),
                arguments: right_arguments,
            },
        ) if left == right
            && left_arguments.is_empty()
            && right_arguments.is_empty()
            && matches!(
                left,
                wrela_hir::Builtin::Bool
                    | wrela_hir::Builtin::U8
                    | wrela_hir::Builtin::U16
                    | wrela_hir::Builtin::U32
                    | wrela_hir::Builtin::U64
                    | wrela_hir::Builtin::U128
                    | wrela_hir::Builtin::Usize
                    | wrela_hir::Builtin::I8
                    | wrela_hir::Builtin::I16
                    | wrela_hir::Builtin::I32
                    | wrela_hir::Builtin::I64
                    | wrela_hir::Builtin::I128
                    | wrela_hir::Builtin::Isize
                    | wrela_hir::Builtin::F32
                    | wrela_hir::Builtin::F64
            )
    )
}

fn structural_initializer_diagnostic(
    program: &wrela_hir::Program,
    record: &wrela_hir::Declaration,
    initializer: &wrela_hir::InitializerDeclaration,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Option<Diagnostic>, AnalysisFailure> {
    let wrela_hir::DeclarationOwner::Declaration(owner) = record.owner else {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-owner",
            "initializer is not owned by one structure declaration",
        )));
    };
    let Some(owner_record) = program.declaration(owner) else {
        return Err(AnalysisFailure::RequestMismatch);
    };
    let DeclarationKind::Structure(structure) = &owner_record.kind else {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-owner",
            "initializer is not owned by one structure declaration",
        )));
    };
    if initializer.result.is_some() {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-fallible-rollback-pending",
            "fallible initializer rollback is not yet executable",
        )));
    }
    if !structure.generics.is_empty() {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-generic-pending",
            "generic structure initializers are not in the admitted constructor slice",
        )));
    }
    if structure.linear || structure.copy {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-linearity-pending",
            "linear and copy-annotated initializer protocols are not yet executable",
        )));
    }
    if structure.fields.is_empty() {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-zero-sized-pending",
            "zero-sized initializer protocols are not yet executable",
        )));
    }
    if structure.fields.iter().any(|field| {
        field.visibility != wrela_hir::Visibility::Public
            || !field.attributes.is_empty()
            || field.default.is_some()
    }) {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-field-contract-pending",
            "initializer fields must be public, attribute-free, and have no defaults in this slice",
        )));
    }
    if initializer.parameters.len() != structure.fields.len().saturating_add(1) {
        return Ok(Some(initializer_diagnostic(
            record.source,
            "semantic-init-parameter-shape",
            "initializer must declare one value parameter for every structure field",
        )));
    }
    let Some(receiver) = initializer
        .parameters
        .first()
        .and_then(|parameter| program.parameters.get(parameter.0 as usize))
    else {
        return Err(AnalysisFailure::RequestMismatch);
    };
    if !receiver.receiver
        || receiver.access != wrela_hir::AccessMode::Mutate
        || receiver.name.is_some()
        || receiver.ty.is_some()
    {
        return Ok(Some(initializer_diagnostic(
            receiver.source,
            "semantic-init-receiver-shape",
            "initializer must begin with the exact `mut self` receiver",
        )));
    }
    for (field, parameter_id) in structure
        .fields
        .iter()
        .zip(initializer.parameters.iter().skip(1))
    {
        check_cancelled(is_cancelled)?;
        let Some(parameter) = program
            .parameters
            .get(parameter_id.0 as usize)
            .filter(|parameter| parameter.id == *parameter_id)
        else {
            return Err(AnalysisFailure::RequestMismatch);
        };
        if parameter.receiver
            || parameter.access != wrela_hir::AccessMode::Value
            || parameter.positional_only
            || parameter.name.as_ref() != Some(&field.name)
            || parameter
                .ty
                .as_ref()
                .is_none_or(|parameter_ty| !exact_initializer_builtin_type(parameter_ty, &field.ty))
        {
            return Ok(Some(initializer_diagnostic(
                parameter.source,
                "semantic-init-parameter-shape",
                "initializer parameters must exactly mirror primitive-scalar structure fields",
            )));
        }
    }
    let Some(body) = program.body(initializer.body) else {
        return Err(AnalysisFailure::RequestMismatch);
    };
    let mut initialized = Vec::new();
    initialized
        .try_reserve_exact(structure.fields.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "initializer census fields",
            limit: structure.fields.len() as u64,
        })?;
    initialized.resize(structure.fields.len(), false);
    for statement_id in &body.statements {
        check_cancelled(is_cancelled)?;
        let Some(statement) = program.statement(*statement_id) else {
            return Err(AnalysisFailure::RequestMismatch);
        };
        let StatementKind::Assign {
            targets,
            operator: wrela_hir::AssignmentOperator::Assign,
            value,
        } = &statement.kind
        else {
            return Ok(Some(initializer_diagnostic(
                statement.source,
                "semantic-init-control-flow-pending",
                "initializer body contains control flow or an operation beyond direct field initialization",
            )));
        };
        let [target] = targets.as_slice() else {
            return Ok(Some(initializer_diagnostic(
                statement.source,
                "semantic-init-assignment-shape",
                "initializer assignment must target exactly one direct self field",
            )));
        };
        let [wrela_hir::PlaceProjection::Field(name)] = target.projections.as_slice() else {
            return Ok(Some(initializer_diagnostic(
                target.source,
                "semantic-init-assignment-shape",
                "initializer assignment must target exactly one direct self field",
            )));
        };
        let Some(field_index) = structure
            .fields
            .iter()
            .position(|field| field.name == *name)
        else {
            return Ok(Some(initializer_diagnostic(
                target.source,
                "semantic-init-assignment-shape",
                "initializer assignment names no declared field",
            )));
        };
        let rhs_matches = program.expression(*value).is_some_and(|expression| {
            matches!(expression.kind,
                ExpressionKind::Reference(Definition::Parameter(parameter))
                    if initializer.parameters.get(field_index.saturating_add(1)) == Some(&parameter))
        });
        if !matches!(target.root, Definition::Parameter(parameter) if parameter == receiver.id)
            || !rhs_matches
            || std::mem::replace(&mut initialized[field_index], true)
        {
            return Ok(Some(initializer_diagnostic(
                statement.source,
                "semantic-init-assignment-shape",
                "initializer must assign each self field exactly once from its matching parameter",
            )));
        }
    }
    if initialized.iter().any(|field| !field) {
        return Ok(Some(initializer_diagnostic(
            body.source,
            "semantic-init-partial",
            "initializer success path leaves a field uninitialized",
        )));
    }
    Ok(None)
}

fn diagnose_unsupported_initializers(
    request: &AnalysisRequest<'_>,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    for record in &request.hir.as_program().declarations {
        check_cancelled(is_cancelled)?;
        let DeclarationKind::Initializer(initializer) = &record.kind else {
            continue;
        };
        if let Some(diagnostic) = structural_initializer_diagnostic(
            request.hir.as_program(),
            record,
            initializer,
            is_cancelled,
        )? {
            push_diagnostic(diagnostics, diagnostic, request.limits)?;
        }
    }
    Ok(())
}

/// A public handler declared on a `@driver` struct, retained so the wait-for
/// graph can reject any that self-wait.
struct DriverHandler {
    declaration: DeclarationId,
    /// Qualified `Struct.method` name for the named rejection.
    qualified_name: String,
    /// Where the handler is declared, labelled on the rejection.
    declaration_source: Span,
}

/// Reject any public `@driver` handler that self-waits.
///
/// The unified wait-for graph (design ch04 §3.1) requires that a public
/// `@driver` handler is synchronous in revision 0.1: it validates, reserves or
/// rejects, publishes, and returns without awaiting, so a driver never waits
/// for work whose producer needs the same driver. This is a declaration-level
/// property of the handler body: it holds whether or not the driver is ever
/// installed into an image, so it is decided here, before image evaluation and
/// independent of the (separate) driver-installation fail-closed. Any `await`
/// reachable inside a public driver handler is a named rejection that points at
/// the suspension point and names the offending handler.
fn diagnose_driver_handler_waits(
    request: &AnalysisRequest<'_>,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    let program = request.hir.as_program();
    let mut handlers: Vec<DriverHandler> = Vec::new();
    for declaration in &program.declarations {
        check_cancelled(is_cancelled)?;
        let DeclarationKind::Structure(aggregate) = &declaration.kind else {
            continue;
        };
        let is_driver = declaration.attributes.iter().any(|attribute| {
            attribute.identity
                == wrela_hir::AttributeIdentity::Builtin(wrela_hir::BuiltinAttribute::Driver)
        });
        if !is_driver {
            continue;
        }
        let struct_name = declaration
            .name
            .as_ref()
            .map(wrela_hir::Name::as_str)
            .unwrap_or("<driver>");
        for member_id in &aggregate.members {
            check_cancelled(is_cancelled)?;
            let Some(member) = program.declaration(*member_id) else {
                continue;
            };
            if member.visibility != wrela_hir::Visibility::Public {
                continue;
            }
            let DeclarationKind::Function(_) = &member.kind else {
                continue;
            };
            let method_name = member
                .name
                .as_ref()
                .map(wrela_hir::Name::as_str)
                .unwrap_or("<handler>");
            let qualified_name = format!("{struct_name}.{method_name}");
            if u64::try_from(qualified_name.len()).unwrap_or(u64::MAX) > request.limits.fact_bytes {
                return Err(AnalysisFailure::ResourceLimit {
                    resource: "driver handler name bytes",
                    limit: request.limits.fact_bytes,
                });
            }
            handlers
                .try_reserve(1)
                .map_err(|_| AnalysisFailure::ResourceLimit {
                    resource: "driver handlers",
                    limit: u64::from(request.limits.image_nodes),
                })?;
            handlers.push(DriverHandler {
                declaration: *member_id,
                qualified_name,
                declaration_source: member.source,
            });
        }
    }
    if handlers.is_empty() {
        return Ok(());
    }
    // Attribute the first `await` of each handler to it in one ordered pass over
    // the expression arena, so the rejection span is deterministic.
    let mut first_wait: Vec<Option<Span>> = Vec::new();
    first_wait
        .try_reserve_exact(handlers.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "driver handlers",
            limit: u64::from(request.limits.image_nodes),
        })?;
    first_wait.resize(handlers.len(), None);
    for expression in &program.expressions {
        check_cancelled(is_cancelled)?;
        if !matches!(
            expression.kind,
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::Await,
                ..
            }
        ) {
            continue;
        }
        let Some(owner) = expression_owner_declaration(program, expression.owner) else {
            continue;
        };
        if let Some(index) = handlers
            .iter()
            .position(|handler| handler.declaration == owner)
            && first_wait[index].is_none()
        {
            first_wait[index] = Some(expression.source);
        }
    }
    for (handler, source) in handlers.iter().zip(first_wait.iter()) {
        check_cancelled(is_cancelled)?;
        let Some(source) = *source else {
            continue;
        };
        let mut diagnostic = Diagnostic::error(
            Category::ASYNC,
            source,
            format!(
                "public @driver handler `{}` self-waits at `await`; revision 0.1 driver handlers are synchronous and never self-wait",
                handler.qualified_name
            ),
        );
        diagnostic.code = Some("semantic-driver-handler-waits".to_owned());
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: handler.declaration_source,
            message: format!(
                "driver handler `{}` is declared here",
                handler.qualified_name
            ),
        });
        diagnostic.notes.push(
            "a driver owns hardware authority; if a handler suspended it could wait on work whose producer needs the same driver, closing a wait-for cycle"
                .to_owned(),
        );
        diagnostic.help.push(
            "make the driver handler synchronous — validate, reserve or reject, publish, and return a receipt without awaiting"
                .to_owned(),
        );
        push_diagnostic(diagnostics, diagnostic, request.limits)?;
    }
    Ok(())
}

#[derive(Debug, Clone)]
struct ProjectionYieldSummary {
    minimum: u32,
    maximum: u32,
    yields: Vec<ExpressionId>,
}

fn diagnose_projection_protocols(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    let mut aggregate_work = RuntimeAggregateWork::default();
    for declaration in &request.hir.as_program().declarations {
        check_cancelled(is_cancelled)?;
        if !matches!(declaration.kind, DeclarationKind::Projection(_)) {
            continue;
        }
        let checkpoint = RuntimeCheckpoint::new(partial);
        match ensure_projection_protocol(
            request,
            partial,
            declaration.id,
            &mut aggregate_work,
            is_cancelled,
        ) {
            Ok(_) => {}
            Err(RuntimeFailure::Diagnostic(diagnostic)) => {
                checkpoint.rollback(partial);
                push_diagnostic(diagnostics, *diagnostic, request.limits)?;
            }
            Err(RuntimeFailure::Analysis(error)) => {
                checkpoint.rollback(partial);
                return Err(error);
            }
        }
    }
    Ok(())
}

fn ensure_projection_protocol(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<ProjectionProtocolId> {
    if let Some(existing) = partial
        .projection_protocols
        .iter()
        .find(|protocol| protocol.declaration == declaration)
    {
        return Ok(existing.id);
    }
    let program = request.hir.as_program();
    let declaration_record = program
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Projection(projection) = &declaration_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if !projection.generics.is_empty() {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            "semantic-projection-generic-pending",
            "generic projection protocols are not yet supported",
            "the analysis-tier projection contract currently seals nongeneric declarations",
            "use a nongeneric free projection until generic specialization lands",
        ));
    }
    let wrela_hir::ProjectionCarrierKind::View { mutable, ty } = &projection.carrier.kind else {
        return Err(runtime_type_diagnostic(
            request,
            projection.carrier.source,
            "semantic-projection-wrapped-carrier-pending",
            "wrapped projection carriers are not yet supported",
            "this increment seals one bare view leaf; Option/Result carrier consumption follows",
            "return a bare view from the projection for now",
        ));
    };
    let body = projection.body.ok_or_else(|| {
        runtime_type_diagnostic(
            request,
            declaration_record.source,
            "semantic-projection-body-required",
            "projection declaration requires a body",
            "a projection protocol must prove one yielded view on every successful path",
            "add a projection body with exactly one yield",
        )
    })?;

    let mut parameters = Vec::new();
    parameters
        .try_reserve_exact(projection.parameters.len())
        .map_err(|_| fact_resource(request, "projection protocol parameters"))?;
    for parameter_id in &projection.parameters {
        check_cancelled(is_cancelled)?;
        let parameter = program
            .parameters
            .get(parameter_id.0 as usize)
            .filter(|parameter| parameter.id == *parameter_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if parameter.receiver {
            return Err(runtime_type_diagnostic(
                request,
                parameter.source,
                "semantic-projection-receiver-call-pending",
                "receiver projection protocols are not yet supported",
                "method-call resolution is required to bind a projection receiver exactly",
                "use a module-level free projection until method resolution lands",
            ));
        }
        if parameter.access == wrela_hir::AccessMode::Take {
            return Err(runtime_type_diagnostic(
                request,
                parameter.source,
                "semantic-projection-source-taken",
                "projection source parameters cannot transfer ownership",
                "a yielded view must retain its backing source through the caller's lexical loan",
                "use read or mut access for a projection source",
            ));
        }
        let parameter_ty = semantic_type_from_source(
            request,
            partial,
            parameter
                .ty
                .as_ref()
                .ok_or(AnalysisFailure::RequestMismatch)?,
            aggregate_work,
            is_cancelled,
        )?;
        parameters.push(ProjectionParameter {
            parameter: *parameter_id,
            access: lower_access(parameter.access),
            ty: parameter_ty,
        });
    }
    if projection.provenance.as_slice() != projection.parameters.as_slice()
        || !projection
            .provenance
            .windows(2)
            .all(|pair| pair[0] < pair[1])
    {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let target = semantic_type_from_source(request, partial, ty, aggregate_work, is_cancelled)?;
    if scope_phase_contains_await(program, body, is_cancelled)? {
        return Err(runtime_type_diagnostic(
            request,
            program
                .body(body)
                .map_or(declaration_record.source, |body| body.source),
            "semantic-projection-await",
            "projection body may not suspend",
            "projection setup, yield, and teardown are one synchronous lexical activation",
            "remove await from the projection body",
        ));
    }
    let summary = projection_yield_summary(request, body, is_cancelled)?;
    if summary.maximum > 1 {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            "semantic-projection-multiple-yields",
            "projection may expose more than one active yielded view",
            "every successful projection path must execute exactly one yield",
            "remove the additional yield or make the paths mutually exclusive",
        ));
    }
    if summary.minimum != 1 || summary.maximum != 1 {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            "semantic-projection-yield-required",
            "bare-view projection does not yield exactly once on every path",
            "a bare view has no unsuccessful carrier path, so every path must execute one yield",
            "add one yield to every path",
        ));
    }
    for expression in summary.yields {
        let (yield_ty, source_parameter) = projection_yield_expression_type(
            request,
            partial,
            expression,
            &parameters,
            is_cancelled,
        )?;
        if yield_ty != target {
            return Err(runtime_type_diagnostic(
                request,
                program
                    .expression(expression)
                    .map_or(declaration_record.source, |expression| expression.source),
                "semantic-projection-yield-type",
                "yielded projection leaf has the wrong type",
                "the yielded place must have exactly the carrier's declared view target type",
                "yield a place with the declared target type",
            ));
        }
        let source = parameters
            .iter()
            .find(|parameter| parameter.parameter == source_parameter)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if *mutable && source.access != AccessMode::Mutate {
            return Err(runtime_type_diagnostic(
                request,
                program
                    .expression(expression)
                    .map_or(declaration_record.source, |expression| expression.source),
                "semantic-projection-mutable-source",
                "mutable view requires a mutable projection source",
                "read-only provenance cannot authorize an exclusive yielded view",
                "declare the backing projection parameter with mut access",
            ));
        }
    }
    if partial.projection_protocols.len() >= request.limits.projection_protocols as usize
        || partial.proofs.len() >= request.limits.proofs as usize
    {
        return Err(fact_resource(request, "projection protocols").into());
    }
    let id = ProjectionProtocolId(
        u32::try_from(partial.projection_protocols.len())
            .map_err(|_| fact_resource(request, "projection protocols"))?,
    );
    let proof = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "projection protocol proofs"))?,
    );
    let name = declaration_record
        .name
        .as_ref()
        .map(wrela_hir::Name::as_str)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    partial.proofs.push(Proof {
        id: proof,
        kind: ProofKind::ViewDoesNotEscape,
        subject: bounded_test_fact(request, "projection protocol: ", name, is_cancelled)?,
        sources: vec![declaration_record.source],
        depends_on: Vec::new(),
        bound: Some(1),
        explanation: vec![
            "every source path of this bare-view projection has exactly one active yield; provenance conservatively includes every declared parameter"
                .to_owned(),
        ],
    });
    partial.projection_protocols.push(ProjectionProtocol {
        id,
        declaration,
        name: copy_analysis_text(name, request.limits.fact_bytes, is_cancelled)?,
        parameters,
        mutable: *mutable,
        target,
        provenance: projection.provenance.clone(),
        body,
        proof,
    });
    Ok(id)
}

fn projection_yield_summary(
    request: &AnalysisRequest<'_>,
    root: BodyId,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<ProjectionYieldSummary> {
    let program = request.hir.as_program();
    let mut summaries: Vec<Option<ProjectionYieldSummary>> = Vec::new();
    summaries
        .try_reserve_exact(program.bodies.len())
        .map_err(|_| fact_resource(request, "projection body summaries"))?;
    summaries.resize(program.bodies.len(), None);
    let mut colors = Vec::new();
    colors
        .try_reserve_exact(program.bodies.len())
        .map_err(|_| fact_resource(request, "projection body colors"))?;
    colors.resize(program.bodies.len(), 0_u8);
    let mut stack = vec![(root, false)];
    while let Some((body_id, exiting)) = stack.pop() {
        check_cancelled(is_cancelled)?;
        let index = body_id.0 as usize;
        let body = program
            .bodies
            .get(index)
            .filter(|body| body.id == body_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if !exiting {
            match colors[index] {
                2 => continue,
                1 => return Err(AnalysisFailure::RequestMismatch.into()),
                _ => colors[index] = 1,
            }
            stack.push((body_id, true));
            for statement_id in body.statements.iter().rev() {
                let statement = program
                    .statement(*statement_id)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                match &statement.kind {
                    StatementKind::If {
                        branches,
                        else_body,
                    } => {
                        for (condition, _) in branches {
                            if !matches!(
                                program
                                    .expression(*condition)
                                    .map(|expression| &expression.kind),
                                Some(ExpressionKind::Literal(wrela_hir::Literal::Boolean(_)))
                            ) {
                                return Err(runtime_type_diagnostic(
                                    request,
                                    program
                                        .expression(*condition)
                                        .map_or(statement.source, |expression| expression.source),
                                    "semantic-projection-condition-pending",
                                    "projection condition is outside the proven path subset",
                                    "this increment proves boolean-literal branches without executing or fabricating expression facts",
                                    "use a boolean literal condition until projection expression analysis lands",
                                ));
                            }
                        }
                        if let Some(child) = else_body {
                            stack.push((*child, false));
                        }
                        for (_, child) in branches.iter().rev() {
                            stack.push((*child, false));
                        }
                    }
                    StatementKind::Pass | StatementKind::Yield(_) => {}
                    _ => {
                        return Err(runtime_type_diagnostic(
                            request,
                            statement.source,
                            "semantic-projection-body-form-pending",
                            "projection body statement is outside the current analysis subset",
                            "this increment proves pass, yield, and conditional single-yield control flow",
                            "use pass/yield/if until projection teardown operations are modeled",
                        ));
                    }
                }
            }
            continue;
        }
        let mut summary = ProjectionYieldSummary {
            minimum: 0,
            maximum: 0,
            yields: Vec::new(),
        };
        for statement_id in &body.statements {
            check_cancelled(is_cancelled)?;
            let statement = program
                .statement(*statement_id)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            match &statement.kind {
                StatementKind::Pass => {}
                StatementKind::Yield(expression) => {
                    summary.minimum = summary
                        .minimum
                        .checked_add(1)
                        .ok_or_else(|| fact_resource(request, "projection yield paths"))?;
                    summary.maximum = summary
                        .maximum
                        .checked_add(1)
                        .ok_or_else(|| fact_resource(request, "projection yield paths"))?;
                    summary
                        .yields
                        .try_reserve(1)
                        .map_err(|_| fact_resource(request, "projection yields"))?;
                    summary.yields.push(*expression);
                }
                StatementKind::If {
                    branches,
                    else_body,
                } => {
                    let mut branch_minimum = u32::MAX;
                    let mut branch_maximum = 0_u32;
                    for (_, child) in branches {
                        let child = summaries
                            .get(child.0 as usize)
                            .and_then(Option::as_ref)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        branch_minimum = branch_minimum.min(child.minimum);
                        branch_maximum = branch_maximum.max(child.maximum);
                        summary
                            .yields
                            .try_reserve(child.yields.len())
                            .map_err(|_| fact_resource(request, "projection yields"))?;
                        summary.yields.extend_from_slice(&child.yields);
                    }
                    if let Some(child) = else_body {
                        let child = summaries
                            .get(child.0 as usize)
                            .and_then(Option::as_ref)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        branch_minimum = branch_minimum.min(child.minimum);
                        branch_maximum = branch_maximum.max(child.maximum);
                        summary
                            .yields
                            .try_reserve(child.yields.len())
                            .map_err(|_| fact_resource(request, "projection yields"))?;
                        summary.yields.extend_from_slice(&child.yields);
                    } else {
                        branch_minimum = 0;
                    }
                    if branch_minimum == u32::MAX {
                        return Err(AnalysisFailure::RequestMismatch.into());
                    }
                    summary.minimum = summary
                        .minimum
                        .checked_add(branch_minimum)
                        .ok_or_else(|| fact_resource(request, "projection yield paths"))?;
                    summary.maximum = summary
                        .maximum
                        .checked_add(branch_maximum)
                        .ok_or_else(|| fact_resource(request, "projection yield paths"))?;
                }
                _ => return Err(AnalysisFailure::RequestMismatch.into()),
            }
        }
        colors[index] = 2;
        summaries[index] = Some(summary);
    }
    summaries
        .get_mut(root.0 as usize)
        .and_then(Option::take)
        .ok_or(AnalysisFailure::RequestMismatch.into())
}

fn projection_yield_expression_type(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    expression: ExpressionId,
    parameters: &[ProjectionParameter],
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<(SemanticTypeId, wrela_hir::ParameterId)> {
    let program = request.hir.as_program();
    let mut fields = Vec::new();
    let mut current = expression;
    let source_parameter = loop {
        check_cancelled(is_cancelled)?;
        let record = program
            .expression(current)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        match &record.kind {
            ExpressionKind::Field { base, name } => {
                fields
                    .try_reserve(1)
                    .map_err(|_| fact_resource(request, "projection yield fields"))?;
                fields.push(name);
                current = *base;
            }
            ExpressionKind::Reference(Definition::Parameter(parameter)) => break *parameter,
            _ => {
                return Err(runtime_type_diagnostic(
                    request,
                    record.source,
                    "semantic-projection-yield-source",
                    "projection yield is not rooted in a declared source parameter",
                    "locals, temporaries, and globals cannot back a caller-visible lexical view",
                    "yield a place rooted in one of the projection parameters",
                ));
            }
        }
    };
    let mut ty = parameters
        .iter()
        .find(|parameter| parameter.parameter == source_parameter)
        .map(|parameter| parameter.ty)
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                program
                    .expression(current)
                    .map_or(fallback_span(program), |record| record.source),
                "semantic-projection-yield-source",
                "projection yield source is outside the declared provenance set",
                "only declared projection parameters may back the yielded view",
                "yield a place rooted in a projection parameter",
            )
        })?;
    for field_name in fields.into_iter().rev() {
        check_cancelled(is_cancelled)?;
        let field = partial
            .types
            .get(ty.0 as usize)
            .and_then(|record| match &record.kind {
                SemanticTypeKind::Structure { fields, .. } => fields
                    .iter()
                    .find(|field| field.name == field_name.as_str()),
                _ => None,
            })
            .ok_or_else(|| {
                runtime_type_diagnostic(
                    request,
                    program
                        .expression(expression)
                        .map_or(fallback_span(program), |record| record.source),
                    "semantic-projection-yield-field",
                    "projection yield selects an unknown or unsupported field",
                    "the analysis-tier projection subset follows fields of flat runtime structures",
                    "yield a declared field of a flat structure parameter",
                )
            })?;
        ty = field.ty;
    }
    Ok((ty, source_parameter))
}

fn test_plan_limits(limits: AnalysisLimits) -> TestPlanLimits {
    TestPlanLimits {
        tests: limits.tests,
        groups: limits.test_groups,
        scenarios: limits.test_scenarios,
        scenario_steps: limits.test_scenario_steps,
        payload_bytes: limits.test_bytes,
        report_bytes: limits.test_report_bytes,
        events_per_group: limits.test_events_per_group,
        output_bytes_per_group: limits.test_output_bytes_per_group,
        execution_timeout_ns_per_group: limits.test_timeout_ns_per_group,
    }
}

fn source_test_key(request: &AnalysisRequest<'_>, declaration: DeclarationId) -> FunctionKey {
    let mut bytes = *request.build.identity.request.as_bytes();
    // The request digest already binds the complete source graph, build
    // profile, test selection, and order. This fixed-width domain tweak is
    // injective for declaration IDs within that cryptographic identity and is
    // stable across discovery and per-group compilation.
    bytes[0] ^= 0x53;
    for (destination, source) in bytes[24..28].iter_mut().zip(declaration.0.to_be_bytes()) {
        *destination ^= source;
    }
    if bytes.iter().all(|byte| *byte == 0) {
        bytes[0] = 0x53;
    }
    FunctionKey(wrela_build_model::Sha256Digest::from_bytes(bytes))
}

fn generated_harness_key(request: &AnalysisRequest<'_>, group: ImageGroupId) -> FunctionKey {
    let mut bytes = *request.build.identity.request.as_bytes();
    bytes[0] ^= 0x48;
    for (destination, source) in bytes[24..28].iter_mut().zip(group.0.to_be_bytes()) {
        *destination ^= source;
    }
    if bytes.iter().all(|byte| *byte == 0) {
        bytes[0] = 0x48;
    }
    FunctionKey(wrela_build_model::Sha256Digest::from_bytes(bytes))
}

fn copy_test_name(
    request: &AnalysisRequest<'_>,
    declaration: DeclarationId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<String, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let declaration = program
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let module = program
        .modules
        .get(declaration.module.0 as usize)
        .filter(|module| module.id == declaration.module)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let package = program
        .packages
        .package(module.package)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let local_name = declaration
        .name
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?
        .as_str();
    let mut module_bytes = 0usize;
    for (index, segment) in module.path.segments().iter().enumerate() {
        check_cancelled(is_cancelled)?;
        module_bytes = module_bytes
            .checked_add(usize::from(index != 0))
            .and_then(|bytes| bytes.checked_add(segment.len()))
            .ok_or_else(|| test_resource_failure(request))?;
    }
    let length = package
        .identity
        .name
        .as_str()
        .len()
        .checked_add(package.identity.version.as_str().len())
        .and_then(|total| total.checked_add(module_bytes))
        .and_then(|total| total.checked_add(local_name.len()))
        .and_then(|total| total.checked_add(5))
        .ok_or(AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit: request.limits.test_bytes,
        })?;
    if u64::try_from(length).unwrap_or(u64::MAX) > request.limits.test_bytes {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit: request.limits.test_bytes,
        });
    }
    let mut output = String::new();
    output
        .try_reserve_exact(length)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit: request.limits.test_bytes,
        })?;
    append_polled_test_text(&mut output, package.identity.name.as_str(), is_cancelled)?;
    output.push('@');
    append_polled_test_text(&mut output, package.identity.version.as_str(), is_cancelled)?;
    output.push_str("::");
    for (index, segment) in module.path.segments().iter().enumerate() {
        check_cancelled(is_cancelled)?;
        if index != 0 {
            output.push('.');
        }
        append_polled_test_text(&mut output, segment, is_cancelled)?;
    }
    output.push_str("::");
    append_polled_test_text(&mut output, local_name, is_cancelled)?;
    if output.len() != length {
        return Err(AnalysisFailure::RequestMismatch);
    }
    Ok(output)
}

fn append_polled_test_text(
    output: &mut String,
    value: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    let mut start = 0;
    while start < value.len() {
        check_cancelled(is_cancelled)?;
        let mut end = start
            .checked_add(COMPTIME_SOURCE_COPY_CHUNK_BYTES)
            .unwrap_or(value.len())
            .min(value.len());
        while end > start && !value.is_char_boundary(end) {
            end -= 1;
        }
        if end == start {
            return Err(AnalysisFailure::RequestMismatch);
        }
        output.push_str(&value[start..end]);
        start = end;
    }
    Ok(())
}

#[derive(Debug)]
struct SupportedSourceTest {
    declaration: DeclarationId,
    body: BodyId,
    color: FunctionColor,
    key: FunctionKey,
    name: String,
    source: Span,
    checked_comptime: Option<CheckedComptimeClosure>,
    // Set when this test's transitive closure failed the comptime-legality
    // check but it was still accepted as a valid runtime/image test. An
    // explicit `--comptime` selection that ends up excluding every
    // candidate uses this to explain *why*, instead of silently sealing an
    // empty comptime test group.
    comptime_gate_diagnostic: Option<Diagnostic>,
    runtime_statements: Vec<StatementId>,
    assertions: Vec<PlannedAssertionDescriptor>,
    work_bound: u64,
}

#[derive(Debug)]
struct PendingImageTest {
    name: String,
    kind: TestKind,
    source: Option<Span>,
    timeout_ns: u64,
    invocation: ImageTestInvocation,
    assertions: Vec<PlannedAssertionDescriptor>,
}

#[derive(Debug)]
struct PendingImageGroup {
    name: String,
    root: ImageRoot,
    tests: Vec<PendingImageTest>,
    deterministic_seed: Option<u64>,
    boot_timeout_ns: u64,
    shutdown_timeout_ns: u64,
    maximum_events: u32,
    maximum_output_bytes: u64,
}

fn discover_tests(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declared_image_tests: &[DeclaredImageTest],
    source_selection: TestDiscoverySelection<'_>,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let source_count = program.test_candidates.len();
    let total_count = source_count.checked_add(declared_image_tests.len()).ok_or(
        AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit: request.limits.test_bytes,
        },
    )?;
    if total_count > request.limits.tests as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit: request.limits.test_bytes,
        });
    }

    let mut unit_tests = Vec::new();
    let mut comptime_results = Vec::new();
    let mut runtime_tests = Vec::new();
    unit_tests
        .try_reserve_exact(source_count)
        .map_err(|_| test_resource_failure(request))?;
    comptime_results
        .try_reserve_exact(source_count)
        .map_err(|_| test_resource_failure(request))?;
    runtime_tests
        .try_reserve_exact(source_count)
        .map_err(|_| test_resource_failure(request))?;

    let initial_diagnostic_count = diagnostics.len();
    let mut runtime_aggregate_work = RuntimeAggregateWork::default();
    // An explicit `--comptime` selection that ends up excluding every
    // candidate (each one only qualified for a different tier) has
    // discovered zero tests for no visible reason; remember the first
    // exclusion's own comptime-legality diagnostic so that scenario can
    // fail closed with a real explanation instead of silently sealing an
    // empty test group. A selection that keeps at least one comptime test
    // alongside other, differently-tiered candidates is a normal, healthy
    // scan, so this is never consulted when `unit_tests` ends up nonempty.
    let mut comptime_selection_exclusion: Option<Diagnostic> = None;
    for candidate in &program.test_candidates {
        check_cancelled(is_cancelled)?;
        if !source_test_selected(request, *candidate, source_selection, is_cancelled)? {
            continue;
        }
        let supported =
            match inspect_source_test(request, *candidate, source_selection, is_cancelled)? {
                Ok(test) => test,
                Err(diagnostic) => {
                    push_diagnostic(diagnostics, diagnostic, request.limits)?;
                    continue;
                }
            };
        // A plain `fn` test's tier is decided by whether its transitive call
        // closure is comptime-legal (or by an explicit `@test(runtime)` force),
        // not by its declared color, so the requested `--comptime`/
        // `--integration` selection can only be enforced once that has
        // actually been checked.
        let is_comptime_tier = supported.checked_comptime.is_some();
        let tier_selected = match source_selection {
            TestDiscoverySelection::Comptime => is_comptime_tier,
            TestDiscoverySelection::Integration => !is_comptime_tier,
            TestDiscoverySelection::All
            | TestDiscoverySelection::None
            | TestDiscoverySelection::NameContains(_) => true,
        };
        if !tier_selected {
            if matches!(source_selection, TestDiscoverySelection::Comptime)
                && comptime_selection_exclusion.is_none()
            {
                comptime_selection_exclusion = supported.comptime_gate_diagnostic;
            }
            continue;
        }
        match append_source_test_function(
            request,
            partial,
            &supported,
            &mut runtime_aggregate_work,
            is_cancelled,
        )? {
            Ok(_) => {}
            Err(diagnostic) => {
                push_diagnostic(diagnostics, diagnostic, request.limits)?;
                continue;
            }
        }
        let descriptor = TestDescriptor {
            id: TestId(
                u32::try_from(unit_tests.len()).map_err(|_| test_resource_failure(request))?,
            ),
            name: copy_bounded_test_text(request, &supported.name, is_cancelled)?,
            kind: TestKind::ComptimeUnit,
            source: Some(supported.source),
            timeout_ns: COMPTIME_TEST_TIMEOUT_NS,
        };
        if is_comptime_tier {
            let result_descriptor = TestDescriptor {
                id: TestId(descriptor.id.0),
                name: copy_bounded_test_text(request, &descriptor.name, is_cancelled)?,
                kind: TestKind::ComptimeUnit,
                source: descriptor.source,
                timeout_ns: descriptor.timeout_ns,
            };
            match evaluate_comptime_test(request, &supported, result_descriptor, is_cancelled)? {
                ComptimeCase::Result(result) => {
                    unit_tests.push(ComptimeTest {
                        descriptor,
                        function_key: supported.key,
                    });
                    comptime_results.push(result);
                }
                ComptimeCase::Unsupported(diagnostic) => {
                    push_diagnostic(diagnostics, diagnostic, request.limits)?;
                }
            }
        } else {
            runtime_tests.push(PendingImageTest {
                name: supported.name,
                kind: TestKind::IntegrationImage,
                source: Some(supported.source),
                timeout_ns: INTEGRATION_TEST_TIMEOUT_NS,
                invocation: ImageTestInvocation::GeneratedFunction {
                    function_key: supported.key,
                },
                assertions: supported.assertions,
            });
        }
    }

    if unit_tests.is_empty()
        && diagnostics.len() == initial_diagnostic_count
        && let Some(diagnostic) = comptime_selection_exclusion
    {
        push_diagnostic(diagnostics, diagnostic, request.limits)?;
    }

    if diagnostics.len() != initial_diagnostic_count {
        return Ok(());
    }
    if runtime_tests.len() != 1
        && let Some(asserting) = runtime_tests
            .iter()
            .find(|test| !test.assertions.is_empty())
    {
        let mut diagnostic = Diagnostic::error(
            Category::COMPTIME,
            asserting.source.unwrap_or_else(|| fallback_span(program)),
            "runtime assertions require exactly one selected generated source test",
        );
        diagnostic.code = Some("semantic-runtime-assertion-selection".to_owned());
        diagnostic.help.push(
            "select the asserting test alone so assertion failure can terminate with a complete canonical report"
                .to_owned(),
        );
        push_diagnostic(diagnostics, diagnostic, request.limits)?;
        return Ok(());
    }

    let mut scenarios = canonical_declared_scenarios(request, declared_image_tests, is_cancelled)?;
    let mut groups = Vec::new();
    let group_capacity = declared_image_tests
        .len()
        .checked_add(usize::from(!runtime_tests.is_empty()))
        .ok_or_else(|| test_resource_failure(request))?;
    if group_capacity > request.limits.test_groups as usize {
        return Err(test_resource_failure(request));
    }
    groups
        .try_reserve_exact(group_capacity)
        .map_err(|_| test_resource_failure(request))?;
    if !runtime_tests.is_empty() {
        if declared_image_tests
            .iter()
            .any(|test| test.name == GENERATED_GROUP_NAME)
        {
            let mut diagnostic = Diagnostic::error(
                Category::COMPTIME,
                fallback_span(program),
                "manifest image-test name collides with the compiler-generated integration group",
            );
            diagnostic.code = Some("semantic-test-group-name-reserved".to_owned());
            diagnostic.help.push(format!(
                "rename the manifest image test `{GENERATED_GROUP_NAME}`"
            ));
            push_diagnostic(diagnostics, diagnostic, request.limits)?;
            return Ok(());
        }
        let generated_events = u32::try_from(runtime_tests.len())
            .ok()
            .and_then(|count| count.checked_mul(2))
            .and_then(|count| count.checked_add(3))
            .ok_or_else(|| test_resource_failure(request))?;
        let generated_timeout = GENERATED_BOOT_TIMEOUT_NS
            .checked_add(GENERATED_SHUTDOWN_TIMEOUT_NS)
            .and_then(|value| {
                value.checked_add(
                    INTEGRATION_TEST_TIMEOUT_NS
                        .checked_mul(u64::try_from(runtime_tests.len()).ok()?)?,
                )
            })
            .ok_or_else(|| test_resource_failure(request))?;
        if generated_timeout > request.limits.test_timeout_ns_per_group
            || generated_events > request.limits.test_events_per_group
            || GENERATED_MAXIMUM_OUTPUT_BYTES > request.limits.test_output_bytes_per_group
        {
            return Err(test_resource_failure(request));
        }
        groups.push(PendingImageGroup {
            name: copy_bounded_test_text(request, GENERATED_GROUP_NAME, is_cancelled)?,
            root: ImageRoot::GeneratedHarness {
                harness_name: copy_bounded_test_text(
                    request,
                    GENERATED_HARNESS_NAME,
                    is_cancelled,
                )?,
            },
            tests: runtime_tests,
            deterministic_seed: None,
            boot_timeout_ns: GENERATED_BOOT_TIMEOUT_NS,
            shutdown_timeout_ns: GENERATED_SHUTDOWN_TIMEOUT_NS,
            maximum_events: generated_events,
            maximum_output_bytes: GENERATED_MAXIMUM_OUTPUT_BYTES,
        });
    }
    for declared in declared_image_tests {
        check_cancelled(is_cancelled)?;
        let scenario = scenarios
            .get(declared.scenario.id.0 as usize)
            .filter(|scenario| **scenario == declared.scenario)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let timeout_ns = declared
            .boot_timeout_ns
            .checked_add(declared.shutdown_timeout_ns)
            .and_then(|value| value.checked_add(scenario.wait_budget_ns()?))
            .ok_or_else(|| test_resource_failure(request))?;
        if timeout_ns > request.limits.test_timeout_ns_per_group
            || declared.maximum_events > request.limits.test_events_per_group
            || declared.maximum_output_bytes > request.limits.test_output_bytes_per_group
        {
            return Err(test_resource_failure(request));
        }
        groups.push(PendingImageGroup {
            name: copy_bounded_test_text(request, &declared.name, is_cancelled)?,
            root: ImageRoot::Declared {
                image_name: copy_bounded_test_text(request, &declared.image_name, is_cancelled)?,
                scenario: declared.scenario.id,
            },
            tests: vec![PendingImageTest {
                name: copy_bounded_test_text(request, &declared.name, is_cancelled)?,
                kind: TestKind::DeclaredImage,
                source: None,
                timeout_ns,
                invocation: ImageTestInvocation::DeclaredScenario,
                assertions: Vec::new(),
            }],
            deterministic_seed: declared.deterministic_seed,
            boot_timeout_ns: declared.boot_timeout_ns,
            shutdown_timeout_ns: declared.shutdown_timeout_ns,
            maximum_events: declared.maximum_events,
            maximum_output_bytes: declared.maximum_output_bytes,
        });
    }
    cancellable_stable_sort_owned_by(
        &mut groups,
        u64::from(request.limits.test_groups),
        "test group sort scratch",
        is_cancelled,
        &|left, right| cancellable_str_cmp(&left.name, &right.name, is_cancelled),
    )?;
    for pair in groups.windows(2) {
        if cancellable_str_cmp(&pair[0].name, &pair[1].name, is_cancelled)?
            == std::cmp::Ordering::Equal
        {
            return Err(AnalysisFailure::RequestMismatch);
        }
    }

    let mut next_test =
        u32::try_from(unit_tests.len()).map_err(|_| test_resource_failure(request))?;
    let mut image_groups = Vec::new();
    image_groups
        .try_reserve_exact(groups.len())
        .map_err(|_| test_resource_failure(request))?;
    for (group_index, pending) in groups.into_iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let mut tests = Vec::new();
        tests
            .try_reserve_exact(pending.tests.len())
            .map_err(|_| test_resource_failure(request))?;
        for test in pending.tests {
            let id = TestId(next_test);
            next_test = next_test
                .checked_add(1)
                .ok_or_else(|| test_resource_failure(request))?;
            tests.push(ImageTest {
                descriptor: TestDescriptor {
                    id,
                    name: test.name,
                    kind: test.kind,
                    source: test.source,
                    timeout_ns: test.timeout_ns,
                },
                invocation: test.invocation,
                assertions: test.assertions,
            });
        }
        image_groups.push(FullImageTestGroup {
            id: ImageGroupId(
                u32::try_from(group_index).map_err(|_| test_resource_failure(request))?,
            ),
            name: pending.name,
            root: pending.root,
            tests,
            deterministic_seed: pending.deterministic_seed,
            boot_timeout_ns: pending.boot_timeout_ns,
            shutdown_timeout_ns: pending.shutdown_timeout_ns,
            maximum_events: pending.maximum_events,
            maximum_output_bytes: pending.maximum_output_bytes,
        });
    }
    let plan = TestPlan {
        schema: TEST_PLAN_SCHEMA,
        build: request.build.identity.clone(),
        target: request.target.identity().clone(),
        scenarios: std::mem::take(&mut scenarios),
        unit_tests,
        image_groups,
    }
    .seal_with_limits_and_cancellation(test_plan_limits(request.limits), is_cancelled)
    .map_err(|error| match error {
        wrela_test_model::TestModelError::ResourceLimit { .. }
        | wrela_test_model::TestModelError::TooManyTests(_) => test_resource_failure(request),
        wrela_test_model::TestModelError::Cancelled => AnalysisFailure::Cancelled,
        error => AnalysisFailure::InternalInvariant(format!(
            "canonical test discovery produced an invalid plan: {error}"
        )),
    })?;
    partial.test_plan = Some(plan);
    partial.comptime_test_results = comptime_results;
    Ok(())
}

fn declaration_forces_runtime_tier(declaration: &wrela_hir::Declaration) -> bool {
    // Lowering admits only bare `@test` or `@test(runtime)`, so a retained
    // argument on the test attribute is exactly the runtime-tier force.
    declaration.attributes.iter().any(|attribute| {
        attribute.identity
            == wrela_hir::AttributeIdentity::Builtin(wrela_hir::BuiltinAttribute::Test)
            && !attribute.arguments.is_empty()
    })
}

fn source_test_selected(
    request: &AnalysisRequest<'_>,
    declaration: DeclarationId,
    selection: TestDiscoverySelection<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<bool, AnalysisFailure> {
    let program = request.hir.as_program();
    let declaration_record = program
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let module = program
        .modules
        .get(declaration_record.module.0 as usize)
        .filter(|module| module.id == declaration_record.module)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if module.package != program.packages.root() {
        return Ok(false);
    }
    let function = match &declaration_record.kind {
        DeclarationKind::Function(function) => Some(function),
        _ => None,
    }
    .ok_or(AnalysisFailure::RequestMismatch)?;
    Ok(match selection {
        TestDiscoverySelection::All => true,
        // Only a plain `fn` can ever be comptime-legal; an `async fn` test
        // can never run in the comptime tier (section 2 forbids async
        // operations at comptime), so this remains a coarse pre-filter and
        // the exact tier is decided once the closure is actually checked.
        TestDiscoverySelection::Comptime => function.color == FunctionColor::Sync,
        TestDiscoverySelection::Integration => {
            matches!(function.color, FunctionColor::Sync | FunctionColor::Async)
        }
        TestDiscoverySelection::None => false,
        TestDiscoverySelection::NameContains(filter) => bounded_name_contains(
            &copy_test_name(request, declaration, is_cancelled)?,
            filter,
            is_cancelled,
        )?,
    })
}

fn bounded_name_contains(
    value: &str,
    filter: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<bool, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    if filter.is_empty() || filter.len() > MAX_TEST_FILTER_BYTES {
        return Err(AnalysisFailure::RequestMismatch);
    }
    if filter.len() > value.len() {
        return Ok(false);
    }

    // Knuth-Morris-Pratt keeps the public substring selection linear even for
    // adversarial repeated prefixes. The only scratch is one bounded entry per
    // filter byte, and every construction/search transition polls cancellation.
    let needle = filter.as_bytes();
    let mut prefix = Vec::new();
    prefix
        .try_reserve_exact(needle.len())
        .map_err(|_| test_resource_failure_for_limit(MAX_TEST_FILTER_BYTES as u64))?;
    prefix.push(0usize);
    let mut matched = 0usize;
    for index in 1..needle.len() {
        check_cancelled(is_cancelled)?;
        while matched != 0 && needle[index] != needle[matched] {
            check_cancelled(is_cancelled)?;
            matched = prefix[matched - 1];
        }
        if needle[index] == needle[matched] {
            matched += 1;
        }
        prefix.push(matched);
    }

    matched = 0;
    for byte in value.bytes() {
        check_cancelled(is_cancelled)?;
        while matched != 0 && byte != needle[matched] {
            check_cancelled(is_cancelled)?;
            matched = prefix[matched - 1];
        }
        if byte == needle[matched] {
            matched += 1;
            if matched == needle.len() {
                return Ok(true);
            }
        }
    }
    Ok(false)
}

fn test_resource_failure_for_limit(limit: u64) -> AnalysisFailure {
    AnalysisFailure::ResourceLimit {
        resource: "test name filter",
        limit,
    }
}

fn test_resource_failure(request: &AnalysisRequest<'_>) -> AnalysisFailure {
    AnalysisFailure::ResourceLimit {
        resource: "test plan or results",
        limit: request.limits.test_bytes,
    }
}

fn copy_bounded_test_text(
    request: &AnalysisRequest<'_>,
    value: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<String, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    if u64::try_from(value.len()).unwrap_or(u64::MAX) > request.limits.test_bytes {
        return Err(test_resource_failure(request));
    }
    let mut output = String::new();
    output
        .try_reserve_exact(value.len())
        .map_err(|_| test_resource_failure(request))?;
    append_polled_test_text(&mut output, value, is_cancelled)?;
    Ok(output)
}

fn canonical_declared_scenarios(
    request: &AnalysisRequest<'_>,
    declared: &[DeclaredImageTest],
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Vec<ImageScenario>, AnalysisFailure> {
    let mut unique = std::collections::HashMap::new();
    unique
        .try_reserve(declared.len())
        .map_err(|_| test_resource_failure(request))?;
    let mut scenarios = Vec::new();
    scenarios
        .try_reserve_exact(declared.len())
        .map_err(|_| test_resource_failure(request))?;
    let mut steps = 0usize;
    let mut payload = 0u64;
    for test in declared {
        let scenario = &test.scenario;
        steps = steps
            .checked_add(scenario.steps.len())
            .ok_or_else(|| test_resource_failure(request))?;
        for length in [
            test.name.len(),
            test.image_name.len(),
            scenario.name.len(),
            scenario.source_path.len(),
        ] {
            payload = payload
                .checked_add(u64::try_from(length).map_err(|_| test_resource_failure(request))?)
                .ok_or_else(|| test_resource_failure(request))?;
        }
        for step in &scenario.steps {
            let length = match step {
                wrela_test_model::ImageScenarioStep::SendSerial { bytes }
                | wrela_test_model::ImageScenarioStep::ExpectSerial { bytes, .. } => bytes.len(),
                wrela_test_model::ImageScenarioStep::ExpectTestEvent {
                    message_contains, ..
                } => message_contains.as_ref().map_or(0, String::len),
                wrela_test_model::ImageScenarioStep::ExpectExit { .. }
                | wrela_test_model::ImageScenarioStep::RequestShutdown { .. } => 0,
            };
            payload = payload
                .checked_add(u64::try_from(length).map_err(|_| test_resource_failure(request))?)
                .ok_or_else(|| test_resource_failure(request))?;
        }
        if steps > request.limits.test_scenario_steps as usize
            || payload > request.limits.test_bytes
        {
            return Err(test_resource_failure(request));
        }
        match unique.get(&scenario.id.0).copied() {
            Some(index) => {
                if scenarios.get(index) != Some(scenario) {
                    return Err(AnalysisFailure::RequestMismatch);
                }
            }
            None => {
                unique.insert(scenario.id.0, scenarios.len());
                scenarios.push(scenario.clone());
            }
        }
    }
    cancellable_stable_sort_owned_by(
        &mut scenarios,
        u64::from(request.limits.test_scenarios),
        "test scenario sort scratch",
        is_cancelled,
        &|left, right| Ok(left.id.cmp(&right.id)),
    )?;
    if scenarios.len() > request.limits.test_scenarios as usize {
        return Err(AnalysisFailure::RequestMismatch);
    }
    for (expected, scenario) in scenarios.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        if scenario.id.0 as usize != expected {
            return Err(AnalysisFailure::RequestMismatch);
        }
    }
    for pair in scenarios.windows(2) {
        if cancellable_str_cmp(&pair[0].name, &pair[1].name, is_cancelled)?
            != std::cmp::Ordering::Less
        {
            return Err(AnalysisFailure::RequestMismatch);
        }
    }
    Ok(scenarios)
}

fn inspect_source_test(
    request: &AnalysisRequest<'_>,
    id: DeclarationId,
    source_selection: TestDiscoverySelection<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Result<SupportedSourceTest, Diagnostic>, AnalysisFailure> {
    let program = request.hir.as_program();
    let declaration = program
        .declaration(id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Function(function) = &declaration.kind else {
        return Err(AnalysisFailure::RequestMismatch);
    };
    if !function.generics.is_empty() || !function.parameters.is_empty() {
        return Err(AnalysisFailure::RequestMismatch);
    }
    if !test_result_is_unit(function.result.as_ref()) {
        return Ok(Err(test_source_diagnostic(
            declaration.source,
            "semantic-test-result-not-supported",
            "revision 0.1 tests in the production semantic subset must return unit",
        )));
    }
    let Some(body_id) = function.body else {
        return Ok(Err(test_source_diagnostic(
            declaration.source,
            "semantic-test-body-missing",
            "a test function must have a body",
        )));
    };
    let _body = program
        .body(body_id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    // Revision 0.1 has no comptime function color: a plain `fn` test is
    // comptime-tier when its transitive call closure happens to be
    // comptime-legal, and a runtime/image test otherwise (an `async fn`
    // test can never be comptime-legal, since comptime forbids async
    // operations). `@test(runtime)` forces the runtime tier even when the
    // closure would otherwise be comptime-legal. Try the comptime tier
    // first; a closure-legality failure here is not itself a hard error on
    // its own -- this test may still be a perfectly good runtime/image
    // test, so fall through to the runtime shape check below. An explicit
    // `--comptime` selection, though, is a request to run *this* test at
    // the comptime tier specifically: if the runtime shape check *also*
    // rejects the closure, the comptime checker's own diagnostic is the
    // more specific and correct one to report (it names the real reason,
    // e.g. a moved-value read or an unsupported aggregate shape, rather
    // than the runtime checker's generic "not supported"), so prefer it
    // over the runtime shape failure below. For every other selection, the
    // runtime shape checker's own diagnostic remains authoritative -- it
    // is, after all, testing the runtime tier specifically.
    let prefer_comptime_diagnostic = matches!(source_selection, TestDiscoverySelection::Comptime);
    let force_runtime = declaration_forces_runtime_tier(declaration);
    let mut comptime_failure = None;
    let checked_comptime = if force_runtime {
        comptime_failure = Some(test_source_diagnostic(
            declaration
                .attributes
                .iter()
                .find(|attribute| {
                    attribute.identity
                        == wrela_hir::AttributeIdentity::Builtin(wrela_hir::BuiltinAttribute::Test)
                        && !attribute.arguments.is_empty()
                })
                .map_or(declaration.source, |attribute| attribute.source),
            "semantic-test-runtime-forced",
            "@test(runtime) forces the runtime/image tier",
        ));
        None
    } else if function.color == FunctionColor::Sync {
        match check_source_comptime_unit_test(
            request.hir.as_ref(),
            request.standard_library_package,
            request.target.pointer_width(),
            id,
            ComptimeCheckLimits {
                work_units: request.limits.fact_edges,
                storage_entries: request.limits.fact_edges,
                syntax_depth: request.limits.constant_depth.min(COMPTIME_SYNTAX_DEPTH),
                diagnostic_bytes: request.limits.diagnostic_bytes,
                test_bytes: request.limits.test_bytes,
            },
            is_cancelled,
        )? {
            Ok(checked) => Some(checked),
            Err(diagnostic) => {
                comptime_failure = Some(diagnostic);
                None
            }
        }
    } else {
        None
    };
    let mut runtime_statements = Vec::new();
    let mut runtime_callees = Vec::new();
    if checked_comptime.is_none() {
        match inspect_runtime_body_shape(
            request,
            body_id,
            function.color,
            true,
            &mut runtime_statements,
            &mut runtime_callees,
            is_cancelled,
        ) {
            Ok(()) => {}
            Err(RuntimeShapeFailure::Unsupported(source)) => {
                let runtime_diagnostic = test_source_diagnostic(
                    source,
                    "semantic-runtime-test-body-not-supported",
                    "runtime bodies support scalar initialization and assignment, direct calls, return, and scalar `if` joins",
                );
                return Ok(Err(if prefer_comptime_diagnostic {
                    comptime_failure.unwrap_or(runtime_diagnostic)
                } else {
                    runtime_diagnostic
                }));
            }
            Err(RuntimeShapeFailure::UnsupportedAssertion(source)) => {
                let runtime_diagnostic = test_source_diagnostic(
                    source,
                    "semantic-runtime-assertion-not-supported",
                    "runtime assertions are supported only in selected generated tests",
                );
                return Ok(Err(if prefer_comptime_diagnostic {
                    comptime_failure.unwrap_or(runtime_diagnostic)
                } else {
                    runtime_diagnostic
                }));
            }
            Err(RuntimeShapeFailure::Failure(error)) => return Err(error),
        }
        let mut seen_declarations = vec![false; program.declarations.len()];
        if let Some(slot) = seen_declarations.get_mut(id.0 as usize) {
            *slot = true;
        }
        while let Some(callee) = runtime_callees.pop() {
            check_cancelled(is_cancelled)?;
            let Some(seen) = seen_declarations.get_mut(callee.0 as usize) else {
                return Err(AnalysisFailure::RequestMismatch);
            };
            if *seen {
                continue;
            }
            *seen = true;
            let declaration = program
                .declaration(callee)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let DeclarationKind::Function(helper) = &declaration.kind else {
                continue;
            };
            let Some(helper_body) = helper.body else {
                continue;
            };
            // A plain `fn` test's transitive call closure can now genuinely
            // reach a helper whose own body is unsupported by the runtime
            // shape checker (revision 0.1 has no comptime function color, so
            // any helper can be called from a test whose own shape happens
            // to look supported at the call site); report the same clean
            // diagnostics the top-level body check above would, rather than
            // treating an unsupported helper shape as an internal
            // request/facts mismatch.
            match inspect_runtime_body_shape(
                request,
                helper_body,
                helper.color,
                true,
                &mut runtime_statements,
                &mut runtime_callees,
                is_cancelled,
            ) {
                Ok(()) => {}
                Err(RuntimeShapeFailure::Unsupported(source)) => {
                    let runtime_diagnostic = test_source_diagnostic(
                        source,
                        "semantic-runtime-test-body-not-supported",
                        "runtime bodies support scalar initialization and assignment, direct calls, return, and scalar `if` joins",
                    );
                    return Ok(Err(if prefer_comptime_diagnostic {
                        comptime_failure.unwrap_or(runtime_diagnostic)
                    } else {
                        runtime_diagnostic
                    }));
                }
                Err(RuntimeShapeFailure::UnsupportedAssertion(source)) => {
                    let runtime_diagnostic = test_source_diagnostic(
                        source,
                        "semantic-runtime-assertion-not-supported",
                        "runtime assertions are supported only in selected generated tests",
                    );
                    return Ok(Err(if prefer_comptime_diagnostic {
                        comptime_failure.unwrap_or(runtime_diagnostic)
                    } else {
                        runtime_diagnostic
                    }));
                }
                Err(RuntimeShapeFailure::Failure(error)) => return Err(error),
            }
        }
    }
    let work_bound = runtime_body_work_bound(program, body_id)
        .and_then(|count| count.checked_add(1))
        .ok_or_else(|| test_resource_failure(request))?;
    let mut assertions = Vec::new();
    for statement in &runtime_statements {
        check_cancelled(is_cancelled)?;
        if let Some(wrela_hir::Statement {
            kind:
                StatementKind::Assert {
                    expression,
                    witness,
                    message,
                    comptime: false,
                    ..
                },
            ..
        }) = program.statement(*statement)
        {
            if expression.len() > MAX_RUNTIME_ASSERTION_EXPRESSION_BYTES
                || expression.chars().all(char::is_whitespace)
            {
                return Ok(Err(test_source_diagnostic(
                    witness.source,
                    "semantic-runtime-assertion-expression-limit",
                    "runtime assertion condition source exceeds its bounded report payload",
                )));
            }
            if message.as_ref().is_some_and(|message| {
                message.len() > MAX_RUNTIME_ASSERTION_EXPRESSION_BYTES
                    || message.chars().all(char::is_whitespace)
            }) {
                return Ok(Err(test_source_diagnostic(
                    witness.source,
                    "semantic-runtime-assertion-message-limit",
                    "runtime assertion message is empty or exceeds its bounded report payload",
                )));
            }
            assertions.push(PlannedAssertionDescriptor {
                source: witness.source,
                expression: copy_bounded_test_text(request, expression, is_cancelled)?,
                message: match message {
                    Some(message) => Some(copy_bounded_test_text(request, message, is_cancelled)?),
                    None => None,
                },
            });
        }
    }
    cancellable_stable_sort_owned_by(
        &mut assertions,
        u64::from(request.limits.statement_facts),
        "runtime assertion descriptor sort scratch",
        is_cancelled,
        &|left, right| {
            check_cancelled(is_cancelled)?;
            let ordering = (
                left.source.file.0,
                left.source.range.start,
                left.source.range.end,
            )
                .cmp(&(
                    right.source.file.0,
                    right.source.range.start,
                    right.source.range.end,
                ))
                .then_with(|| left.expression.cmp(&right.expression));
            check_cancelled(is_cancelled)?;
            Ok(ordering.then_with(|| left.message.cmp(&right.message)))
        },
    )?;
    if assertions.windows(2).any(|pair| pair[0] == pair[1]) {
        return Err(AnalysisFailure::RequestMismatch);
    }
    Ok(Ok(SupportedSourceTest {
        declaration: id,
        body: body_id,
        color: function.color,
        key: source_test_key(request, id),
        name: copy_test_name(request, id, is_cancelled)?,
        source: declaration.source,
        checked_comptime,
        comptime_gate_diagnostic: comptime_failure,
        runtime_statements,
        assertions,
        work_bound,
    }))
}

enum RuntimeShapeFailure {
    Unsupported(Span),
    UnsupportedAssertion(Span),
    Failure(AnalysisFailure),
}

fn body_assigns_local(
    program: &wrela_hir::Program,
    body: BodyId,
    local: wrela_hir::LocalId,
) -> Option<bool> {
    let body = program.body(body)?;
    for statement in &body.statements {
        match &program.statement(*statement)?.kind {
            StatementKind::Assign { targets, .. }
                if targets.iter().any(|target| {
                    target.projections.is_empty() && target.root == Definition::Local(local)
                }) =>
            {
                return Some(true);
            }
            StatementKind::If {
                branches,
                else_body,
            } => {
                for (_, body) in branches {
                    if body_assigns_local(program, *body, local)? {
                        return Some(true);
                    }
                }
                if else_body
                    .is_some_and(|body| body_assigns_local(program, body, local).unwrap_or(true))
                {
                    return Some(true);
                }
            }
            StatementKind::While { body, .. } if body_assigns_local(program, *body, local)? => {
                return Some(true);
            }
            StatementKind::Match { arms, .. } => {
                for arm in arms {
                    if body_assigns_local(program, arm.body, local)? {
                        return Some(true);
                    }
                }
            }
            _ => {}
        }
    }
    Some(false)
}

fn bounded_while_shape(
    program: &wrela_hir::Program,
    condition: ExpressionId,
    body: BodyId,
) -> Option<u64> {
    let expression = program.expression(condition)?;
    let ExpressionKind::Compare {
        left,
        operator: wrela_hir::ComparisonOperator::Less,
        right,
    } = expression.kind
    else {
        return None;
    };
    let ExpressionKind::Reference(Definition::Local(induction)) = program.expression(left)?.kind
    else {
        return None;
    };
    let ExpressionKind::Literal(Literal::Integer(ref spelling)) = program.expression(right)?.kind
    else {
        return None;
    };
    let bound = spelling.replace('_', "").parse::<u64>().ok()?;
    let local = program.locals.get(induction.0 as usize)?;
    if !matches!(
        local.ty.as_ref()?.kind,
        wrela_hir::TypeExpressionKind::Named {
            definition: Definition::Builtin(
                wrela_hir::Builtin::U8
                    | wrela_hir::Builtin::U16
                    | wrela_hir::Builtin::U32
                    | wrela_hir::Builtin::U64
                    | wrela_hir::Builtin::U128
                    | wrela_hir::Builtin::Usize
            ),
            ref arguments,
        } if arguments.is_empty()
    ) {
        return None;
    }
    let body = program.body(body)?;
    let first = program.statement(*body.statements.first()?)?;
    let StatementKind::Assign {
        targets,
        operator: AssignmentOperator::Add,
        value,
    } = &first.kind
    else {
        return None;
    };
    let [target] = targets.as_slice() else {
        return None;
    };
    if target.root != Definition::Local(induction) || !target.projections.is_empty() {
        return None;
    }
    if !matches!(
        &program.expression(*value)?.kind,
        ExpressionKind::Literal(Literal::Integer(one))
            if one.replace('_', "").parse::<u64>().ok() == Some(1)
    ) {
        return None;
    }
    for statement in body.statements.iter().skip(1) {
        match &program.statement(*statement)?.kind {
            StatementKind::Assign { targets, .. }
                if targets.iter().any(|target| {
                    target.projections.is_empty() && target.root == Definition::Local(induction)
                }) =>
            {
                return None;
            }
            StatementKind::If {
                branches,
                else_body,
            } => {
                for (_, body) in branches {
                    if body_assigns_local(program, *body, induction)? {
                        return None;
                    }
                }
                if let Some(body) = else_body {
                    if body_assigns_local(program, *body, induction)? {
                        return None;
                    }
                }
            }
            StatementKind::While { body, .. } if body_assigns_local(program, *body, induction)? => {
                return None;
            }
            StatementKind::Match { arms, .. } => {
                for arm in arms {
                    if body_assigns_local(program, arm.body, induction)? {
                        return None;
                    }
                }
            }
            _ => {}
        }
    }
    Some(bound)
}

fn closed_literal_range_shape(
    program: &wrela_hir::Program,
    iterable: ExpressionId,
) -> Option<(ExpressionId, ExpressionId, u64, u64)> {
    let expression = program.expression(iterable)?;
    let ExpressionKind::Range {
        start,
        end,
        inclusive: false,
    } = expression.kind
    else {
        return None;
    };
    let parse = |id| match &program.expression(id)?.kind {
        ExpressionKind::Literal(Literal::Integer(spelling)) => {
            u64::try_from(parse_integer_spelling(spelling)?).ok()
        }
        _ => None,
    };
    Some((start, end, parse(start)?, parse(end)?))
}

fn runtime_body_work_bound(program: &wrela_hir::Program, body: BodyId) -> Option<u64> {
    let body = program.body(body)?;
    body.statements.iter().try_fold(0u64, |total, id| {
        let statement = program.statement(*id)?;
        let work = match &statement.kind {
            StatementKind::If {
                branches,
                else_body,
            } => {
                let branches = branches.iter().try_fold(0u64, |sum, (_, body)| {
                    sum.checked_add(runtime_body_work_bound(program, *body)?)
                })?;
                branches
                    .checked_add(
                        else_body
                            .and_then(|body| runtime_body_work_bound(program, body))
                            .unwrap_or(0),
                    )?
                    .checked_add(1)?
            }
            StatementKind::While { condition, body } => {
                bounded_while_shape(program, *condition, *body)?
                    .checked_mul(runtime_body_work_bound(program, *body)?.checked_add(1)?)?
                    .checked_add(1)?
            }
            StatementKind::For { iterable, body, .. } => {
                let body_work = runtime_body_work_bound(program, *body)?.checked_add(1)?;
                if let Some((_, _, start, end)) = closed_literal_range_shape(program, *iterable) {
                    half_open_trip_count(start, end)
                        .checked_mul(body_work)?
                        .checked_add(1)?
                } else {
                    // Unsupported forms still need enough provisional shape
                    // to reach their stable diagnostic. No successful fact
                    // product can retain this fallback bound.
                    body_work.checked_add(1)?
                }
            }
            StatementKind::With { body, .. } => {
                runtime_body_work_bound(program, *body)?.checked_add(1)?
            }
            _ => 1,
        };
        total.checked_add(work)
    })
}

fn inspect_runtime_body_shape(
    request: &AnalysisRequest<'_>,
    root: BodyId,
    color: FunctionColor,
    allow_assertions: bool,
    statements: &mut Vec<StatementId>,
    callees: &mut Vec<DeclarationId>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), RuntimeShapeFailure> {
    let program = request.hir.as_program();
    let mut bodies = Vec::new();
    reserve_runtime_shape(
        &mut bodies,
        1,
        request.limits.fact_edges,
        "runtime body scratch",
    )?;
    bodies.push(root);
    let mut visited_bodies = 0u64;
    while let Some(body_id) = bodies.pop() {
        check_cancelled(is_cancelled).map_err(RuntimeShapeFailure::Failure)?;
        visited_bodies = visited_bodies.checked_add(1).ok_or({
            RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit {
                resource: "runtime body traversal",
                limit: request.limits.fact_edges,
            })
        })?;
        if visited_bodies > request.limits.fact_edges
            || usize::try_from(visited_bodies).map_or(true, |count| count > program.bodies.len())
        {
            return Err(RuntimeShapeFailure::Failure(
                AnalysisFailure::ResourceLimit {
                    resource: "runtime body traversal",
                    limit: request.limits.fact_edges,
                },
            ));
        }
        let body = program
            .body(body_id)
            .ok_or_else(|| RuntimeShapeFailure::Unsupported(fallback_span(program)))?;
        reserve_runtime_shape(
            statements,
            body.statements.len(),
            u64::from(request.limits.statement_facts),
            "statement facts",
        )?;
        let mut returned = false;
        for statement_id in &body.statements {
            check_cancelled(is_cancelled).map_err(RuntimeShapeFailure::Failure)?;
            let statement = program
                .statement(*statement_id)
                .ok_or(RuntimeShapeFailure::Unsupported(body.source))?;
            if !statement.attributes.is_empty() || returned {
                return Err(RuntimeShapeFailure::Unsupported(statement.source));
            }
            match &statement.kind {
                StatementKind::Pass => {}
                StatementKind::Return(value) => {
                    if let Some(expression) = value {
                        inspect_runtime_expression_shape(
                            request,
                            *expression,
                            color,
                            callees,
                            is_cancelled,
                        )?;
                    }
                    returned = true;
                }
                StatementKind::Initialize { value, .. }
                | StatementKind::Assign { value, .. }
                | StatementKind::Expression(value)
                | StatementKind::Send(value) => {
                    inspect_runtime_expression_shape(
                        request,
                        *value,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                }
                StatementKind::If {
                    branches,
                    else_body,
                } => {
                    let [(condition, then_body)] = branches.as_slice() else {
                        return Err(RuntimeShapeFailure::Unsupported(statement.source));
                    };
                    inspect_runtime_expression_shape(
                        request,
                        *condition,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                    let reserve = usize::from(else_body.is_some()).checked_add(1).ok_or({
                        RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit {
                            resource: "runtime body scratch",
                            limit: request.limits.fact_edges,
                        })
                    })?;
                    reserve_runtime_shape(
                        &mut bodies,
                        reserve,
                        request.limits.fact_edges,
                        "runtime body scratch",
                    )?;
                    if let Some(otherwise) = else_body {
                        bodies.push(*otherwise);
                    }
                    bodies.push(*then_body);
                }
                StatementKind::Match { scrutinee, arms } => {
                    inspect_runtime_expression_shape(
                        request,
                        *scrutinee,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                    reserve_runtime_shape(
                        &mut bodies,
                        arms.len(),
                        request.limits.fact_edges,
                        "runtime match body scratch",
                    )?;
                    for arm in arms.iter().rev() {
                        if let Some(guard) = arm.guard {
                            inspect_runtime_expression_shape(
                                request,
                                guard,
                                color,
                                callees,
                                is_cancelled,
                            )?;
                        }
                        bodies.push(arm.body);
                    }
                }
                StatementKind::Assert {
                    condition,
                    comptime: false,
                    ..
                } if allow_assertions => {
                    inspect_runtime_expression_shape(
                        request,
                        *condition,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                }
                StatementKind::Assert { .. } => {
                    return Err(RuntimeShapeFailure::UnsupportedAssertion(statement.source));
                }
                StatementKind::While { condition, body } => {
                    let bound = bounded_while_shape(program, *condition, *body)
                        .ok_or(RuntimeShapeFailure::Unsupported(statement.source))?;
                    if bound == 0 {
                        return Err(RuntimeShapeFailure::Unsupported(statement.source));
                    }
                    inspect_runtime_expression_shape(
                        request,
                        *condition,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                    reserve_runtime_shape(
                        &mut bodies,
                        1,
                        request.limits.fact_edges,
                        "runtime body scratch",
                    )?;
                    bodies.push(*body);
                }
                StatementKind::For { iterable, body, .. } => {
                    inspect_runtime_expression_shape(
                        request,
                        *iterable,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                    reserve_runtime_shape(
                        &mut bodies,
                        1,
                        request.limits.fact_edges,
                        "runtime body scratch",
                    )?;
                    bodies.push(*body);
                }
                StatementKind::Break | StatementKind::Continue => {}
                StatementKind::Yield(_)
                | StatementKind::Loop { .. }
                | StatementKind::ComptimeIf { .. }
                | StatementKind::Error => {
                    return Err(RuntimeShapeFailure::Unsupported(statement.source));
                }
                StatementKind::With {
                    value,
                    body,
                    region,
                    ..
                } => {
                    if region.is_some() {
                        return Err(RuntimeShapeFailure::Unsupported(statement.source));
                    }
                    inspect_runtime_expression_shape(
                        request,
                        *value,
                        color,
                        callees,
                        is_cancelled,
                    )?;
                    reserve_runtime_shape(
                        &mut bodies,
                        1,
                        request.limits.fact_edges,
                        "runtime with body scratch",
                    )?;
                    bodies.push(*body);
                }
            }
            statements.push(*statement_id);
        }
    }
    cancellable_stable_sort_by(
        statements,
        u64::from(request.limits.statement_facts),
        "runtime statement sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )
    .map_err(RuntimeShapeFailure::Failure)?;
    for pair in statements.windows(2) {
        check_cancelled(is_cancelled).map_err(RuntimeShapeFailure::Failure)?;
        if pair[0] == pair[1] {
            return Err(RuntimeShapeFailure::Unsupported(
                program
                    .body(root)
                    .map_or_else(|| fallback_span(program), |body| body.source),
            ));
        }
    }
    Ok(())
}

fn inspect_runtime_expression_shape(
    request: &AnalysisRequest<'_>,
    root: ExpressionId,
    color: FunctionColor,
    callees: &mut Vec<DeclarationId>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), RuntimeShapeFailure> {
    let program = request.hir.as_program();
    let mut pending = Vec::new();
    let limit = u64::from(request.limits.expression_facts);
    reserve_runtime_shape(&mut pending, 1, limit, "runtime expression scratch")?;
    pending.push(root);
    let mut visited = 0u64;
    while let Some(id) = pending.pop() {
        check_cancelled(is_cancelled).map_err(RuntimeShapeFailure::Failure)?;
        visited = visited.checked_add(1).ok_or({
            RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit {
                resource: "runtime expression traversal",
                limit,
            })
        })?;
        if visited > limit {
            return Err(RuntimeShapeFailure::Failure(
                AnalysisFailure::ResourceLimit {
                    resource: "runtime expression traversal",
                    limit,
                },
            ));
        }
        let expression = program
            .expression(id)
            .ok_or_else(|| RuntimeShapeFailure::Unsupported(fallback_span(program)))?;
        match &expression.kind {
            ExpressionKind::Literal(
                Literal::Unit
                | Literal::Boolean(_)
                | Literal::Integer(_)
                | Literal::Float(_)
                | Literal::String(_)
                | Literal::Bytes(_),
            )
            | ExpressionKind::Reference(
                Definition::Local(_)
                | Definition::Parameter(_)
                | Definition::Declaration(_)
                | Definition::Variant(_),
            )
            // A leading-dot variant (`.name`, bare or as a call callee) is a
            // resolved-candidate leaf with no further sub-expressions to
            // walk, exactly like the qualified `Reference(Variant(_))` case
            // above; its expected-type intersection happens later, in the
            // full runtime expression analyzer.
            | ExpressionKind::DotName { .. }
            | ExpressionKind::Interpolate(_) => {}
            ExpressionKind::Call { callee, arguments } => {
                if let Some(ExpressionKind::Reference(Definition::Declaration(declaration))) =
                    program
                        .expression(*callee)
                        .map(|expression| &expression.kind)
                {
                    if program.declaration(declaration.declaration).is_some_and(|record| {
                        matches!(record.kind, DeclarationKind::Function(_))
                    }) {
                        reserve_runtime_shape(
                            callees,
                            1,
                            request.limits.fact_edges,
                            "runtime callee scratch",
                        )?;
                        callees.push(declaration.declaration);
                    }
                }
                let additional = arguments.len().checked_add(1).ok_or({
                    RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit {
                        resource: "runtime expression scratch",
                        limit,
                    })
                })?;
                reserve_runtime_shape(
                    &mut pending,
                    additional,
                    limit,
                    "runtime expression scratch",
                )?;
                pending.push(*callee);
                for argument in arguments {
                    match &argument.value {
                        wrela_hir::CallArgumentValue::Value(value) => pending.push(*value),
                        wrela_hir::CallArgumentValue::Exclusive { place, .. } => {
                            pending.extend(place.projections.iter().filter_map(|projection| {
                                match projection {
                                    wrela_hir::PlaceProjection::Index(index) => Some(*index),
                                    _ => None,
                                }
                            }));
                        }
                    }
                }
            }
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::Await,
                operand,
            } if color == FunctionColor::Async => {
                reserve_runtime_shape(&mut pending, 1, limit, "runtime expression scratch")?;
                pending.push(*operand);
            }
            ExpressionKind::Try(operand) | ExpressionKind::TrySend(operand) => {
                reserve_runtime_shape(&mut pending, 1, limit, "runtime expression scratch")?;
                pending.push(*operand);
            }
            ExpressionKind::IsPattern { value, .. } => {
                reserve_runtime_shape(&mut pending, 1, limit, "runtime expression scratch")?;
                pending.push(*value);
            }
            ExpressionKind::Unary {
                operator:
                    wrela_hir::UnaryOperator::Negate
                    | wrela_hir::UnaryOperator::BitNot
                    | wrela_hir::UnaryOperator::BoolNot
                    | wrela_hir::UnaryOperator::Copy,
                operand,
            }
            | ExpressionKind::Cast { value: operand, .. } => {
                reserve_runtime_shape(&mut pending, 1, limit, "runtime expression scratch")?;
                pending.push(*operand);
            }
            ExpressionKind::Binary {
                operator:
                    wrela_hir::BinaryOperator::Add
                    | wrela_hir::BinaryOperator::AddWrapping
                    | wrela_hir::BinaryOperator::Subtract
                    | wrela_hir::BinaryOperator::SubtractWrapping
                    | wrela_hir::BinaryOperator::Multiply
                    | wrela_hir::BinaryOperator::MultiplyWrapping
                    | wrela_hir::BinaryOperator::Divide
                    | wrela_hir::BinaryOperator::Remainder
                    | wrela_hir::BinaryOperator::BitOr
                    | wrela_hir::BinaryOperator::BitXor
                    | wrela_hir::BinaryOperator::BitAnd
                    | wrela_hir::BinaryOperator::ShiftLeft
                    | wrela_hir::BinaryOperator::ShiftRight,
                left,
                right,
            }
            | ExpressionKind::Compare {
                left,
                operator:
                    wrela_hir::ComparisonOperator::Equal
                    | wrela_hir::ComparisonOperator::NotEqual
                    | wrela_hir::ComparisonOperator::Less
                    | wrela_hir::ComparisonOperator::LessEqual
                    | wrela_hir::ComparisonOperator::Greater
                    | wrela_hir::ComparisonOperator::GreaterEqual,
                right,
            } => {
                reserve_runtime_shape(&mut pending, 2, limit, "runtime expression scratch")?;
                pending.push(*right);
                pending.push(*left);
            }
            ExpressionKind::Range { start, end, .. } => {
                reserve_runtime_shape(&mut pending, 2, limit, "runtime expression scratch")?;
                pending.push(*end);
                pending.push(*start);
            }
            ExpressionKind::Field { base, .. } => {
                reserve_runtime_shape(&mut pending, 1, limit, "runtime expression scratch")?;
                pending.push(*base);
            }
            ExpressionKind::If {
                condition,
                then_branch,
                elif_branches,
                else_branch,
            } => {
                let additional = elif_branches
                    .len()
                    .checked_mul(2)
                    .and_then(|elif| elif.checked_add(3))
                    .ok_or({
                        RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit {
                            resource: "runtime expression scratch",
                            limit,
                        })
                    })?;
                reserve_runtime_shape(
                    &mut pending,
                    additional,
                    limit,
                    "runtime expression scratch",
                )?;
                pending.push(*else_branch);
                for (elif_condition, elif_branch) in elif_branches.iter().rev() {
                    pending.push(*elif_branch);
                    pending.push(*elif_condition);
                }
                pending.push(*then_branch);
                pending.push(*condition);
            }
            _ => return Err(RuntimeShapeFailure::Unsupported(expression.source)),
        }
    }
    Ok(())
}

fn reserve_runtime_shape<T>(
    output: &mut Vec<T>,
    additional: usize,
    limit: u64,
    resource: &'static str,
) -> Result<(), RuntimeShapeFailure> {
    let required = output
        .len()
        .checked_add(additional)
        .and_then(|required| u64::try_from(required).ok())
        .ok_or({
            RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit { resource, limit })
        })?;
    if required > limit {
        return Err(RuntimeShapeFailure::Failure(
            AnalysisFailure::ResourceLimit { resource, limit },
        ));
    }
    output.try_reserve_exact(additional).map_err(|_| {
        RuntimeShapeFailure::Failure(AnalysisFailure::ResourceLimit { resource, limit })
    })
}

fn test_result_is_unit(result: Option<&wrela_hir::TypeExpression>) -> bool {
    match result {
        None => true,
        Some(result) => matches!(
            &result.kind,
            TypeExpressionKind::Named {
                definition: Definition::Builtin(wrela_hir::Builtin::Unit),
                arguments,
            } if arguments.is_empty()
        ),
    }
}

fn actor_reply_result_is_u64(result: Option<&wrela_hir::TypeExpression>) -> bool {
    matches!(
        result.map(|result| &result.kind),
        Some(TypeExpressionKind::Named {
            definition: Definition::Builtin(wrela_hir::Builtin::U64),
            arguments,
        }) if arguments.is_empty()
    )
}

fn test_source_diagnostic(source: Span, code: &str, message: &str) -> Diagnostic {
    let mut diagnostic = Diagnostic::error(Category::COMPTIME, source, message);
    diagnostic.code = Some(code.to_owned());
    diagnostic
}

fn append_source_test_function(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    test: &SupportedSourceTest,
    runtime_aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Result<FunctionInstanceId, Diagnostic>, AnalysisFailure> {
    let checkpoint = RuntimeCheckpoint::new(partial);
    let aggregate_checkpoint = runtime_aggregate_work.comparisons;
    let result = append_source_test_function_inner(
        request,
        partial,
        test,
        runtime_aggregate_work,
        is_cancelled,
    );
    if !matches!(&result, Ok(Ok(_))) {
        checkpoint.rollback(partial);
        runtime_aggregate_work.comparisons = aggregate_checkpoint;
    }
    result
}

fn append_source_test_function_inner(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    test: &SupportedSourceTest,
    runtime_aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Result<FunctionInstanceId, Diagnostic>, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    // `test.color` no longer signals the tier (there is no comptime color);
    // `test.checked_comptime` is the sole tier signal, set by `check_source_test`
    // when the closure was found comptime-legal.
    let checked_comptime = match test.checked_comptime.as_ref() {
        Some(checked)
            if checked
                .declarations
                .first()
                .is_some_and(|record| record.declaration == test.declaration) =>
        {
            Some(checked)
        }
        None => None,
        Some(_) => return Err(AnalysisFailure::RequestMismatch),
    };
    let proof_count = 2usize;
    if partial.functions.len() >= request.limits.monomorphizations as usize
        || partial
            .proofs
            .len()
            .checked_add(proof_count)
            .is_none_or(|count| count > request.limits.proofs as usize)
        || partial
            .statements
            .len()
            .checked_add(test.runtime_statements.len())
            .is_none_or(|count| count > request.limits.statement_facts as usize)
    {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic test functions, proofs, or statements",
            limit: u64::from(request.limits.monomorphizations),
        });
    }
    partial
        .functions
        .try_reserve(1)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "monomorphizations",
            limit: u64::from(request.limits.monomorphizations),
        })?;
    partial
        .proofs
        .try_reserve(proof_count)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        })?;
    partial
        .statements
        .try_reserve(test.runtime_statements.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "statement facts",
            limit: u64::from(request.limits.statement_facts),
        })?;
    let function_id = FunctionInstanceId(u32::try_from(partial.functions.len()).map_err(|_| {
        AnalysisFailure::ResourceLimit {
            resource: "monomorphizations",
            limit: u64::from(request.limits.monomorphizations),
        }
    })?);
    let first_proof = ProofId(u32::try_from(partial.proofs.len()).map_err(|_| {
        AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        }
    })?);
    let (type_sources, type_bound, type_explanation) = if let Some(checked) = checked_comptime {
        let source_count = u64::try_from(checked.declarations.len()).map_err(|_| {
            AnalysisFailure::ResourceLimit {
                resource: "semantic fact edges",
                limit: request.limits.fact_edges,
            }
        })?;
        if source_count > request.limits.fact_edges {
            return Err(AnalysisFailure::ResourceLimit {
                resource: "semantic fact edges",
                limit: request.limits.fact_edges,
            });
        }
        let mut sources = Vec::new();
        sources
            .try_reserve_exact(checked.declarations.len())
            .map_err(|_| AnalysisFailure::ResourceLimit {
                resource: "semantic fact edges",
                limit: request.limits.fact_edges,
            })?;
        for record in &checked.declarations {
            sources.push(record.source);
        }
        (
            sources,
            Some(checked.work_count),
            vec![SOURCE_COMPTIME_CLOSURE_PROOF_MARKER.to_owned()],
        )
    } else {
        (
            vec![test.source],
            None,
            vec![
                "the supported runtime scalar test body and unit result are well typed".to_owned(),
            ],
        )
    };
    partial.proofs.push(Proof {
        id: first_proof,
        kind: ProofKind::TypeChecked,
        subject: bounded_test_fact(request, "test type: ", &test.name, is_cancelled)?,
        sources: type_sources,
        depends_on: Vec::new(),
        bound: type_bound,
        explanation: type_explanation,
    });
    let effect_proof = ProofId(first_proof.0.checked_add(1).ok_or(
        AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        },
    )?);
    partial.proofs.push(Proof {
        id: effect_proof,
        kind: ProofKind::EffectsAllowed,
        subject: bounded_test_fact(request, "test effects: ", &test.name, is_cancelled)?,
        sources: vec![test.source],
        depends_on: vec![first_proof],
        bound: Some(if checked_comptime.is_some() {
            request
                .limits
                .evaluator_steps
                .min(request.build.profile.comptime.steps)
        } else {
            test.work_bound
        }),
        explanation: vec![if checked_comptime.is_some() {
            "the test executes only inside the bounded comptime evaluator".to_owned()
        } else {
            match test.color {
                FunctionColor::Sync | FunctionColor::Async => {
                    "the selected runtime test body admits only bounded scalar effects and MAY_FAIL assertion paths"
                        .to_owned()
                }
                FunctionColor::Isr => return Err(AnalysisFailure::RequestMismatch),
            }
        }],
    });
    partial.functions.push(FunctionInstance {
        id: function_id,
        key: test.key,
        name: copy_analysis_text(&test.name, request.limits.fact_bytes, is_cancelled)?,
        origin: FunctionOrigin::Source {
            declaration: test.declaration,
            body: test.body,
        },
        role: FunctionRole::Test,
        color: test.color,
        generic_arguments: Vec::new(),
        parameters: Vec::new(),
        result: SemanticTypeId(0),
        effects: EffectSet(0),
        stack_bytes_bound: 0,
        frame_bytes_bound: 0,
        uninterrupted_work_bound: Some(if checked_comptime.is_some() {
            request
                .limits
                .evaluator_steps
                .min(request.build.profile.comptime.steps)
        } else {
            test.work_bound
        }),
        recursive_depth_bound: Some(if checked_comptime.is_some() {
            request
                .build
                .profile
                .comptime
                .call_depth
                .min(COMPTIME_HOST_CALL_DEPTH)
        } else {
            1
        }),
        proofs: vec![first_proof, effect_proof],
        source: Some(test.source),
    });
    if checked_comptime.is_none() {
        match populate_runtime_body(
            request,
            partial,
            RuntimeBodyTarget {
                function: function_id,
                declaration: test.declaration,
                body: test.body,
                allow_assertions: true,
            },
            runtime_aggregate_work,
            is_cancelled,
        ) {
            Ok(()) => {}
            Err(RuntimeFailure::Diagnostic(diagnostic)) => {
                return Ok(Err(*diagnostic));
            }
            Err(RuntimeFailure::Analysis(error)) => return Err(error),
        }
    }
    Ok(Ok(function_id))
}

#[derive(Debug)]
enum RuntimeFailure {
    Diagnostic(Box<Diagnostic>),
    Analysis(AnalysisFailure),
}

impl From<AnalysisFailure> for RuntimeFailure {
    fn from(value: AnalysisFailure) -> Self {
        Self::Analysis(value)
    }
}

type RuntimeResult<T> = Result<T, RuntimeFailure>;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum RuntimeAuthority {
    Read,
    Mutate,
    Own,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum RuntimeBindingOrigin {
    Local(LocalId),
    Parameter(wrela_hir::ParameterId),
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct RuntimeBinding {
    value: ValueId,
    state: OwnershipState,
    authority: RuntimeAuthority,
    origin: RuntimeBindingOrigin,
    source: Span,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct RuntimeExpression {
    ty: SemanticTypeId,
    result: Option<ValueId>,
    referenced: Option<ValueId>,
    effects: EffectSet,
}

#[derive(Debug, Clone, Copy)]
struct RuntimeExpressionRequest {
    expected: Option<SemanticTypeId>,
    desired_result: Option<ValueId>,
    access: AccessMode,
}

struct RuntimeState<'a> {
    locals: &'a mut [Option<RuntimeBinding>],
    parameters: &'a mut [Option<RuntimeBinding>],
    aggregate_work: &'a mut RuntimeAggregateWork,
    allow_assertions: bool,
    allow_scope_call: bool,
}

#[derive(Debug, Default)]
struct RuntimeAggregateWork {
    comparisons: u64,
    // The stack of enum `DeclarationId`s whose resolution is currently in
    // progress on the active recursion path. A payload enum whose id is already
    // on this stack is (directly or transitively) its own payload and therefore
    // has no finite machine layout; `ensure_closed_scalar_enum_type` fails closed
    // BEFORE recursing again rather than looping, blowing the stack, or leaning on
    // the `comparisons` budget to eventually stop. Threaded through the existing
    // aggregate-work context so call sites are unchanged.
    resolving_enums: Vec<DeclarationId>,
    // Exact source-function specializations on the active population path.
    // This is checked before completed-instance lookup so direct and mutual
    // recursion cannot observe a half-populated semantic instance.
    resolving_functions: Vec<(DeclarationId, Vec<SemanticArgument>)>,
}

fn charge_runtime_aggregate_lookup(
    request: &AnalysisRequest<'_>,
    work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    work.comparisons = work
        .comparisons
        .checked_add(1)
        .ok_or(AnalysisFailure::ResourceLimit {
            resource: "runtime type and aggregate lookup work",
            limit: request.limits.runtime_aggregate_lookup_work,
        })?;
    if work.comparisons > request.limits.runtime_aggregate_lookup_work {
        Err(AnalysisFailure::ResourceLimit {
            resource: "runtime type and aggregate lookup work",
            limit: request.limits.runtime_aggregate_lookup_work,
        })
    } else {
        Ok(())
    }
}

#[derive(Clone, Copy)]
struct RuntimeDirectCall<'a> {
    expression: ExpressionId,
    source: Span,
    callee: ExpressionId,
    arguments: &'a [wrela_hir::CallArgument],
}

#[derive(Clone, Copy)]
struct RuntimeScopeCall<'a> {
    direct: RuntimeDirectCall<'a>,
    declaration: DeclarationId,
}

#[derive(Clone, Copy)]
struct ScopeEnterContext<'a> {
    scope: &'a wrela_hir::ScopeDeclaration,
    parameter_types: &'a [SemanticParameter],
}

#[derive(Debug, Clone, Copy)]
struct RuntimeAwait {
    expression: ExpressionId,
    source: Span,
    operand: ExpressionId,
}

#[derive(Debug, Clone, Copy)]
struct RuntimeUnary {
    expression: ExpressionId,
    source: Span,
    operator: wrela_hir::UnaryOperator,
    operand: ExpressionId,
}

#[derive(Debug, Clone, Copy)]
enum RuntimeBinaryOperator {
    Arithmetic(wrela_hir::BinaryOperator),
    Compare(wrela_hir::ComparisonOperator),
}

#[derive(Debug, Clone, Copy)]
struct RuntimeBinary {
    expression: ExpressionId,
    source: Span,
    operator: RuntimeBinaryOperator,
    left: ExpressionId,
    right: ExpressionId,
}

#[derive(Debug, Clone, Copy)]
struct RuntimeCast<'a> {
    expression: ExpressionId,
    source: Span,
    value: ExpressionId,
    destination: &'a TypeExpression,
}

struct RuntimeStatementPost<'a> {
    effects: EffectSet,
    definitions: Vec<LocalDefinition>,
    locals: &'a [Option<RuntimeBinding>],
    parameters: &'a [Option<RuntimeBinding>],
}

struct RuntimeExpressionFact {
    function: FunctionInstanceId,
    expression: ExpressionId,
    ty: SemanticTypeId,
    result: Option<ValueId>,
    resolution: ExpressionResolution,
    effects: EffectSet,
    ownership_before: OwnershipState,
    ownership_after: OwnershipState,
}

#[derive(Debug, Clone, Copy)]
struct RuntimeCheckpoint {
    types: usize,
    functions: usize,
    values: usize,
    expressions: usize,
    statements: usize,
    actor_state_accesses: usize,
    region_assignments: usize,
    promotions: usize,
    proofs: usize,
    projection_protocols: usize,
    lexical_views: usize,
    scope_protocols: usize,
    scope_activations: usize,
}

impl RuntimeCheckpoint {
    fn new(partial: &PartialAnalysis) -> Self {
        Self {
            types: partial.types.len(),
            functions: partial.functions.len(),
            values: partial.values.len(),
            expressions: partial.expressions.len(),
            statements: partial.statements.len(),
            actor_state_accesses: partial.actor_state_accesses.len(),
            region_assignments: partial.region_assignments.len(),
            promotions: partial.promotions.len(),
            proofs: partial.proofs.len(),
            projection_protocols: partial.projection_protocols.len(),
            lexical_views: partial.lexical_views.len(),
            scope_protocols: partial.scope_protocols.len(),
            scope_activations: partial.scope_activations.len(),
        }
    }

    fn rollback(self, partial: &mut PartialAnalysis) {
        partial.types.truncate(self.types);
        partial.functions.truncate(self.functions);
        partial.values.truncate(self.values);
        partial.expressions.truncate(self.expressions);
        partial.statements.truncate(self.statements);
        partial
            .actor_state_accesses
            .truncate(self.actor_state_accesses);
        partial.region_assignments.truncate(self.region_assignments);
        partial.promotions.truncate(self.promotions);
        partial.proofs.truncate(self.proofs);
        partial
            .projection_protocols
            .truncate(self.projection_protocols);
        partial.lexical_views.truncate(self.lexical_views);
        partial.scope_protocols.truncate(self.scope_protocols);
        partial.scope_activations.truncate(self.scope_activations);
    }
}

fn runtime_ownership_diagnostic(
    request: &AnalysisRequest<'_>,
    primary: Span,
    code: &'static str,
    message: &'static str,
    binding: Option<RuntimeBinding>,
    note: &'static str,
    help: &'static str,
) -> Result<Diagnostic, AnalysisFailure> {
    let mut diagnostic = Diagnostic::error(Category::OWNERSHIP, primary, message);
    diagnostic.code = Some(copy_static_analysis_text(code, request.limits.fact_bytes)?);
    if let Some(binding) = binding {
        diagnostic
            .labels
            .try_reserve_exact(1)
            .map_err(|_| fact_resource(request, "ownership diagnostic labels"))?;
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: binding.source,
            message: copy_static_analysis_text(
                match binding.origin {
                    RuntimeBindingOrigin::Local(_) => "the local value is introduced here",
                    RuntimeBindingOrigin::Parameter(_) => {
                        "the parameter access contract is declared here"
                    }
                },
                request.limits.fact_bytes,
            )?,
        });
    }
    diagnostic
        .notes
        .try_reserve_exact(1)
        .map_err(|_| fact_resource(request, "ownership diagnostic notes"))?;
    diagnostic
        .notes
        .push(copy_static_analysis_text(note, request.limits.fact_bytes)?);
    diagnostic
        .help
        .try_reserve_exact(1)
        .map_err(|_| fact_resource(request, "ownership diagnostic help"))?;
    diagnostic
        .help
        .push(copy_static_analysis_text(help, request.limits.fact_bytes)?);
    Ok(diagnostic)
}

fn runtime_diagnostic(
    request: &AnalysisRequest<'_>,
    primary: Span,
    code: &'static str,
    message: &'static str,
    binding: Option<RuntimeBinding>,
    note: &'static str,
    help: &'static str,
) -> RuntimeFailure {
    match runtime_ownership_diagnostic(request, primary, code, message, binding, note, help) {
        Ok(diagnostic) => RuntimeFailure::Diagnostic(Box::new(diagnostic)),
        Err(error) => RuntimeFailure::Analysis(error),
    }
}

fn runtime_type_diagnostic(
    request: &AnalysisRequest<'_>,
    primary: Span,
    code: &'static str,
    message: &'static str,
    note: &'static str,
    help: &'static str,
) -> RuntimeFailure {
    let build = || -> Result<Diagnostic, AnalysisFailure> {
        let mut diagnostic = Diagnostic::error(Category::TYPE, primary, message);
        diagnostic.code = Some(copy_static_analysis_text(code, request.limits.fact_bytes)?);
        diagnostic
            .notes
            .try_reserve_exact(1)
            .map_err(|_| fact_resource(request, "scalar diagnostic notes"))?;
        diagnostic
            .notes
            .push(copy_static_analysis_text(note, request.limits.fact_bytes)?);
        diagnostic
            .help
            .try_reserve_exact(1)
            .map_err(|_| fact_resource(request, "scalar diagnostic help"))?;
        diagnostic
            .help
            .push(copy_static_analysis_text(help, request.limits.fact_bytes)?);
        Ok(diagnostic)
    };
    match build() {
        Ok(diagnostic) => RuntimeFailure::Diagnostic(Box::new(diagnostic)),
        Err(error) => RuntimeFailure::Analysis(error),
    }
}

fn runtime_authority(access: AccessMode) -> RuntimeAuthority {
    match access {
        AccessMode::Value | AccessMode::Read => RuntimeAuthority::Read,
        AccessMode::Mutate => RuntimeAuthority::Mutate,
        AccessMode::Take => RuntimeAuthority::Own,
    }
}

fn accesses_conflict(first: AccessMode, second: AccessMode) -> bool {
    !matches!(
        (first, second),
        (
            AccessMode::Value | AccessMode::Read,
            AccessMode::Value | AccessMode::Read
        )
    )
}

fn runtime_binding_by_value(
    locals: &[Option<RuntimeBinding>],
    parameters: &[Option<RuntimeBinding>],
    value: ValueId,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<Option<RuntimeBinding>> {
    for slot in locals.iter().chain(parameters) {
        check_cancelled(is_cancelled)?;
        if slot.is_some_and(|binding| binding.value == value) {
            return Ok(*slot);
        }
    }
    Ok(None)
}

fn join_runtime_branches(
    request: &AnalysisRequest<'_>,
    source: Span,
    destination: &mut [Option<RuntimeBinding>],
    then_bindings: &[Option<RuntimeBinding>],
    else_bindings: &[Option<RuntimeBinding>],
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    if destination.len() != then_bindings.len() || destination.len() != else_bindings.len() {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    for index in 0..destination.len() {
        check_cancelled(is_cancelled)?;
        let Some(original) = destination[index] else {
            continue;
        };
        let Some(then_binding) = then_bindings[index] else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        let Some(else_binding) = else_bindings[index] else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if then_binding.value != original.value
            || else_binding.value != original.value
            || then_binding.authority != original.authority
            || else_binding.authority != original.authority
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        if then_binding.state != else_binding.state {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-branch-ownership-mismatch",
                "branches leave a value in inconsistent ownership states",
                Some(original),
                "every path through a conditional must agree whether the value remains owned",
                "take the value on every branch or preserve it on every branch",
            ));
        }
        destination[index] = Some(then_binding);
    }
    Ok(())
}

struct RuntimeLocalBranchJoin<'a> {
    source: Span,
    destination: &'a mut [Option<RuntimeBinding>],
    then_bindings: &'a [Option<RuntimeBinding>],
    else_bindings: &'a [Option<RuntimeBinding>],
    definitions: &'a mut Vec<LocalDefinition>,
}

fn join_runtime_local_branches(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    join: RuntimeLocalBranchJoin<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    let RuntimeLocalBranchJoin {
        source,
        destination,
        then_bindings,
        else_bindings,
        definitions,
    } = join;
    if destination.len() != then_bindings.len() || destination.len() != else_bindings.len() {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    for index in 0..destination.len() {
        check_cancelled(is_cancelled)?;
        let Some(original) = destination[index] else {
            continue;
        };
        let Some(then_binding) = then_bindings[index] else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        let Some(else_binding) = else_bindings[index] else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if then_binding.authority != original.authority
            || else_binding.authority != original.authority
            || then_binding.origin != original.origin
            || else_binding.origin != original.origin
            || then_binding.source != original.source
            || else_binding.source != original.source
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        if then_binding.state != else_binding.state {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-branch-ownership-mismatch",
                "branches leave a value in inconsistent ownership states",
                Some(original),
                "every path through a conditional must agree whether the value remains owned",
                "take the value on every branch or preserve it on every branch",
            ));
        }
        if then_binding.value == else_binding.value {
            destination[index] = Some(then_binding);
            continue;
        }
        if then_binding.state != OwnershipState::Owned
            || then_binding.authority != RuntimeAuthority::Own
        {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-branch-value-join-state",
                "branch-assigned values cannot converge after ownership was consumed",
                Some(original),
                "a scalar value join requires one live owned value from every branch",
                "join the assigned value before taking or moving it",
            ));
        }
        let RuntimeBindingOrigin::Local(local) = original.origin else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if local.0 as usize != index {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        let original_value = partial
            .values
            .get(original.value.0 as usize)
            .filter(|value| value.function == function)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let then_value = partial
            .values
            .get(then_binding.value.0 as usize)
            .filter(|value| value.function == function)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let else_value = partial
            .values
            .get(else_binding.value.0 as usize)
            .filter(|value| value.function == function)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if original_value.ty != then_value.ty || original_value.ty != else_value.ty {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-branch-value-type-mismatch",
                "branch-assigned local values have incompatible types",
                "every incoming value of an SSA join must have the local's exact scalar type",
                "assign the same declared scalar type on every branch",
            ));
        }
        let local_record = request
            .hir
            .as_program()
            .locals
            .get(local.0 as usize)
            .filter(|record| record.id == local)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let merged = append_semantic_value(
            request,
            partial,
            function,
            original_value.ty,
            (
                SemanticValueOrigin::Local(local),
                Some(local_record.source),
                Some(local_record.name.as_str()),
            ),
            is_cancelled,
        )?;
        if u64::try_from(definitions.len()).map_or(true, |count| count >= request.limits.fact_edges)
        {
            return Err(fact_resource(request, "branch local definitions").into());
        }
        definitions
            .try_reserve(1)
            .map_err(|_| fact_resource(request, "branch local definitions"))?;
        definitions.push(LocalDefinition {
            local,
            value: merged,
        });
        destination[index] = Some(RuntimeBinding {
            value: merged,
            state: OwnershipState::Owned,
            ..original
        });
    }
    Ok(())
}

fn validate_runtime_exit(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
    locals: &[Option<RuntimeBinding>],
    parameters: &[Option<RuntimeBinding>],
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    for binding in locals.iter().chain(parameters).flatten() {
        check_cancelled(is_cancelled)?;
        let value = partial
            .values
            .get(binding.value.0 as usize)
            .filter(|value| value.function == function)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let ty = partial
            .types
            .get(value.ty.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if binding.authority == RuntimeAuthority::Own
            && binding.state == OwnershipState::Owned
            && ty.linearity == Linearity::StrictLinear
        {
            return Err(runtime_diagnostic(
                request,
                binding.source,
                "semantic-linear-value-not-consumed",
                "strict linear value is not consumed exactly once",
                Some(*binding),
                "strict linear ownership must be transferred before the function exits",
                "pass the value to a take parameter on every exit path",
            ));
        }
    }
    Ok(())
}

#[derive(Debug, Clone, Copy)]
struct RuntimeBodyTarget {
    function: FunctionInstanceId,
    declaration: DeclarationId,
    body: BodyId,
    allow_assertions: bool,
}

fn populate_runtime_body(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    target: RuntimeBodyTarget,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    let RuntimeBodyTarget {
        function,
        declaration,
        body,
        allow_assertions,
    } = target;
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let function_record = partial
        .functions
        .get(function.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let source = program
        .declaration(declaration)
        .and_then(|record| match &record.kind {
            DeclarationKind::Function(source) if source.body == Some(body) => Some(source),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if function_record.parameters.len() != source.parameters.len() {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let mut locals = optional_binding_map(program.locals.len(), request.limits.values)?;
    let mut parameters = optional_binding_map(program.parameters.len(), request.limits.values)?;
    for (source_id, semantic) in source.parameters.iter().zip(&function_record.parameters) {
        if semantic.parameter != *source_id {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        let source_parameter = program
            .parameters
            .get(source_id.0 as usize)
            .filter(|parameter| parameter.id == *source_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let slot = parameters
            .get_mut(source_id.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot
            .replace(RuntimeBinding {
                value: semantic.value,
                state: OwnershipState::Owned,
                authority: runtime_authority(semantic.access),
                origin: RuntimeBindingOrigin::Parameter(*source_id),
                source: source_parameter.source,
            })
            .is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    analyze_runtime_body(
        request,
        partial,
        function,
        body,
        &mut locals,
        &mut parameters,
        allow_assertions,
        aggregate_work,
        is_cancelled,
    )?;
    finalize_scope_activations(request, partial, function, is_cancelled)?;
    let body_effects = partial
        .statements
        .iter()
        .filter(|statement| statement.function == function)
        .fold(0u64, |effects, statement| effects | statement.effects.0);
    partial
        .functions
        .get_mut(function.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .effects
        .0 |= body_effects;
    validate_runtime_exit(
        request,
        partial,
        function,
        &locals,
        &parameters,
        is_cancelled,
    )?;
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn analyze_runtime_body(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    body_id: BodyId,
    locals: &mut [Option<RuntimeBinding>],
    parameters: &mut [Option<RuntimeBinding>],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    check_cancelled(is_cancelled)?;
    let body = request
        .hir
        .as_program()
        .body(body_id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    for &statement_id in &body.statements {
        check_cancelled(is_cancelled)?;
        let statement = request
            .hir
            .as_program()
            .statement(statement_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if statement.body != body_id || !statement.attributes.is_empty() {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        let mut definitions = Vec::new();
        let mut statement_effects = EffectSet(0);
        match &statement.kind {
            StatementKind::Pass => {}
            StatementKind::Initialize { local, value } => {
                let local_record = request
                    .hir
                    .as_program()
                    .locals
                    .get(local.0 as usize)
                    .filter(|record| record.id == *local && record.body == body_id)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let inferred_data_ty = if local_record.ty.is_none() {
                    match request
                        .hir
                        .as_program()
                        .expression(*value)
                        .map(|expression| &expression.kind)
                    {
                        Some(ExpressionKind::Literal(
                            literal @ (Literal::String(_) | Literal::Bytes(_)),
                        )) => Some(ensure_static_literal_type(
                            request,
                            partial,
                            literal,
                            &mut *aggregate_work,
                            is_cancelled,
                        )?),
                        Some(ExpressionKind::Interpolate(parts)) => {
                            let expression = request
                                .hir
                                .as_program()
                                .expression(*value)
                                .ok_or(AnalysisFailure::RequestMismatch)?;
                            Some(ensure_bounded_interpolation_type(
                                request,
                                partial,
                                parts,
                                expression.source,
                                &*locals,
                                &*parameters,
                                &mut *aggregate_work,
                                is_cancelled,
                            )?)
                        }
                        _ => return Err(AnalysisFailure::RequestMismatch.into()),
                    }
                } else {
                    None
                };
                if local_record.ty.is_some()
                    && request
                        .hir
                        .as_program()
                        .expression(*value)
                        .is_some_and(|expression| {
                            matches!(
                                expression.kind,
                                ExpressionKind::Literal(Literal::String(_) | Literal::Bytes(_))
                            )
                        })
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        request
                            .hir
                            .as_program()
                            .expression(*value)
                            .map_or(local_record.source, |expression| expression.source),
                        "semantic-static-data-context-pending",
                        "static literal cannot initialize an explicit runtime value context",
                        "Static[Str] and Static[Bytes[N]] are compiler-minted literal types; no implicit owned String or Bytes conversion is defined",
                        "use an unannotated local binding and do not consume it until static-data lowering lands",
                    ));
                }
                if local_record.ty.is_some()
                    && request
                        .hir
                        .as_program()
                        .expression(*value)
                        .is_some_and(|expression| {
                            matches!(expression.kind, ExpressionKind::Interpolate(_))
                        })
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        request
                            .hir
                            .as_program()
                            .expression(*value)
                            .map_or(local_record.source, |expression| expression.source),
                        "semantic-bounded-interpolation-context-pending",
                        "bounded interpolation cannot initialize an explicit runtime type",
                        "this slice mints the exact BoundedString capacity only for an inferred local",
                        "remove the annotation and leave the interpolation result unconsumed",
                    ));
                }
                let inferred_is_bounded = inferred_data_ty.is_some_and(|ty| {
                    partial.types.get(ty.0 as usize).is_some_and(|record| {
                        matches!(record.kind, SemanticTypeKind::BoundedString { .. })
                    })
                });
                if inferred_is_bounded
                    && partial
                        .functions
                        .get(function.0 as usize)
                        .is_some_and(|function| matches!(function.role, FunctionRole::Isr(_)))
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        local_record.source,
                        "semantic-bounded-interpolation-isr",
                        "bounded interpolation is forbidden in an interrupt handler",
                        "formatting work and destination storage are not admitted in ISR context",
                        "compute the bounded string in ordinary synchronous code",
                    ));
                }
                if inferred_is_bounded
                    && partial
                        .functions
                        .get(function.0 as usize)
                        .is_some_and(|function| function.color == FunctionColor::Async)
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        local_record.source,
                        "semantic-bounded-interpolation-persistence-pending",
                        "bounded interpolation result would persist in an asynchronous frame",
                        "this analysis slice has no BoundedString frame storage or ABI",
                        "compute the bounded string in ordinary synchronous code",
                    ));
                }
                if inferred_data_ty.is_some()
                    && partial
                        .functions
                        .get(function.0 as usize)
                        .is_some_and(|function| function.color == FunctionColor::Async)
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        local_record.source,
                        "semantic-static-data-persistence-pending",
                        "static literal binding would persist in an asynchronous frame",
                        "this analysis slice does not define the ABI or lifetime of a static-data handle across suspension",
                        "keep the inferred static binding in a synchronous helper until static-data lowering lands",
                    ));
                }
                if local_record.ty.as_ref().is_some_and(|local_ty| {
                    matches!(local_ty.kind, TypeExpressionKind::View { .. })
                }) && !request
                    .hir
                    .as_program()
                    .expression(*value)
                    .and_then(|expression| match &expression.kind {
                        ExpressionKind::Call { callee, .. } => {
                            request.hir.as_program().expression(*callee)
                        }
                        _ => None,
                    })
                    .and_then(|callee| match &callee.kind {
                        ExpressionKind::Reference(Definition::Declaration(resolved)) => {
                            request.hir.as_program().declaration(resolved.declaration)
                        }
                        _ => None,
                    })
                    .is_some_and(|declaration| {
                        matches!(declaration.kind, DeclarationKind::Projection(_))
                    })
                {
                    let local_ty = local_record
                        .ty
                        .as_ref()
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    return Err(runtime_type_diagnostic(
                        request,
                        local_ty.source,
                        "semantic-view-escape",
                        "borrowed view cannot escape into ordinary runtime value state",
                        "a lexical view local must be introduced directly by an authenticated projection call",
                        "bind a free projection call directly or use an owned value type",
                    ));
                }
                let (ty, category) = match local_record.ty.as_ref().map(|ty| &ty.kind) {
                    Some(TypeExpressionKind::View { mutable, target }) => (
                        semantic_type_from_source(
                            request,
                            partial,
                            target,
                            &mut *aggregate_work,
                            is_cancelled,
                        )?,
                        if *mutable {
                            ValueCategory::MutableView
                        } else {
                            ValueCategory::SharedView
                        },
                    ),
                    Some(_) => (
                        semantic_type_from_source(
                            request,
                            partial,
                            local_record
                                .ty
                                .as_ref()
                                .ok_or(AnalysisFailure::RequestMismatch)?,
                            &mut *aggregate_work,
                            is_cancelled,
                        )?,
                        ValueCategory::Value,
                    ),
                    None => (
                        inferred_data_ty.ok_or(AnalysisFailure::RequestMismatch)?,
                        ValueCategory::Value,
                    ),
                };
                let value_id = append_semantic_value_with_category(
                    request,
                    partial,
                    function,
                    ty,
                    category,
                    (
                        SemanticValueOrigin::Local(*local),
                        Some(local_record.source),
                        Some(local_record.name.as_str()),
                    ),
                    is_cancelled,
                )?;
                let outcome = analyze_runtime_expression(
                    request,
                    partial,
                    function,
                    *value,
                    RuntimeExpressionRequest {
                        expected: if inferred_data_ty.is_some() {
                            None
                        } else {
                            Some(ty)
                        },
                        desired_result: Some(value_id),
                        access: if category == ValueCategory::Value {
                            AccessMode::Value
                        } else {
                            AccessMode::Read
                        },
                    },
                    &mut RuntimeState {
                        locals: &mut *locals,
                        parameters: &mut *parameters,
                        aggregate_work: &mut *aggregate_work,
                        allow_assertions,
                        allow_scope_call: false,
                    },
                    is_cancelled,
                )?;
                statement_effects = outcome.effects;
                if matches!(
                    category,
                    ValueCategory::SharedView | ValueCategory::MutableView
                ) {
                    record_lexical_view_initialization(
                        request,
                        partial,
                        function,
                        statement_id,
                        *local,
                        *value,
                        value_id,
                        category,
                        &mut *aggregate_work,
                        is_cancelled,
                    )?;
                }
                let slot = locals.get_mut(local.0 as usize).ok_or_else(|| {
                    AnalysisFailure::InternalInvariant(
                        "runtime initializer local slot is missing".to_owned(),
                    )
                })?;
                if slot
                    .replace(RuntimeBinding {
                        value: value_id,
                        state: OwnershipState::Owned,
                        authority: RuntimeAuthority::Own,
                        origin: RuntimeBindingOrigin::Local(*local),
                        source: local_record.source,
                    })
                    .is_some()
                {
                    return Err(AnalysisFailure::InternalInvariant(
                        "runtime initializer local slot is already occupied".to_owned(),
                    )
                    .into());
                }
                definitions
                    .try_reserve_exact(1)
                    .map_err(|_| fact_resource(request, "statement local definitions"))?;
                definitions.push(LocalDefinition {
                    local: *local,
                    value: value_id,
                });
            }
            StatementKind::Assign {
                targets,
                operator,
                value,
            } => {
                let [target] = targets.as_slice() else {
                    return Err(runtime_type_diagnostic(
                        request,
                        statement.source,
                        "semantic-assignment-target",
                        "scalar assignment requires exactly one local target",
                        "tuple and multi-place assignment require aggregate ownership lowering",
                        "assign one initialized scalar local",
                    ));
                };
                if let Some(effects) = analyze_actor_state_assignment(
                    request,
                    partial,
                    function,
                    statement_id,
                    statement.source,
                    target,
                    *operator,
                    *value,
                    locals,
                    parameters,
                    allow_assertions,
                    &mut *aggregate_work,
                    is_cancelled,
                )? {
                    statement_effects = effects;
                } else {
                    let Definition::Local(local) = target.root else {
                        if !target.projections.is_empty() {
                            return Err(runtime_type_diagnostic(
                                request,
                                target.source,
                                "semantic-projected-assignment-root-pending",
                                "projected assignment currently requires an owned local root",
                                "parameter, declaration, and receiver roots require place authority to survive aggregate replacement",
                                "copy the aggregate into a typed local before assigning one of its fields",
                            ));
                        }
                        return Err(runtime_type_diagnostic(
                            request,
                            target.source,
                            "semantic-assignment-target",
                            "scalar assignment target must be a local value",
                            "parameters, declarations, and projected places are not local SSA bindings",
                            "assign an initialized scalar local",
                        ));
                    };
                    let current = locals
                    .get(local.0 as usize)
                    .copied()
                    .flatten()
                    .ok_or_else(|| {
                        runtime_diagnostic(
                            request,
                            target.source,
                            "semantic-assignment-uninitialized",
                            "assignment target is not initialized on this path",
                            None,
                            "SSA reassignment requires an existing local value on every reaching path",
                            "initialize the local before the conditional",
                        )
                    })?;
                    reject_live_lexical_rebind(
                        request,
                        partial,
                        function,
                        current.value,
                        local,
                        target.source,
                        is_cancelled,
                    )?;
                    if current.state != OwnershipState::Owned
                        || current.authority != RuntimeAuthority::Own
                    {
                        return Err(runtime_diagnostic(
                            request,
                            target.source,
                            "semantic-assignment-ownership",
                            "assignment target is not a live owned scalar value",
                            Some(current),
                            "a taken, moved, or borrowed value cannot be overwritten through this SSA path",
                            "assign before transferring or borrowing the value",
                        ));
                    }
                    let current_ty = partial
                        .values
                        .get(current.value.0 as usize)
                        .filter(|record| record.function == function)
                        .map(|record| record.ty)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    let local_record = request
                        .hir
                        .as_program()
                        .locals
                        .get(local.0 as usize)
                        .filter(|record| record.id == local)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    if !target.projections.is_empty() {
                        if *operator != AssignmentOperator::Assign {
                            return Err(runtime_type_diagnostic(
                                request,
                                target.source,
                                "semantic-projected-assignment-compound-pending",
                                "compound projected assignment is not yet supported",
                                "read-modify-write field operations require an explicit projected-place reservation",
                                "compute the replacement scalar separately and use plain field assignment",
                            ));
                        }
                        let [projection] = target.projections.as_slice() else {
                            return Err(runtime_type_diagnostic(
                                request,
                                target.source,
                                "semantic-projected-assignment-nested-pending",
                                "nested projected assignment is not yet supported",
                                "revision 0.1 currently replaces one field of one owned local aggregate",
                                "assign through exactly one direct field projection",
                            ));
                        };
                        let wrela_hir::PlaceProjection::Field(field_name) = projection else {
                            return Err(runtime_type_diagnostic(
                                request,
                                target.source,
                                "semantic-projected-assignment-shape-pending",
                                "projected assignment currently supports named structure fields only",
                                "tuple and indexed places require their own aggregate layout and bounds proofs",
                                "assign one named field of a flat runtime structure",
                            ));
                        };
                        let (declaration, field_ty, field_public) = {
                            let record = partial
                                .types
                                .get(current_ty.0 as usize)
                                .ok_or(AnalysisFailure::RequestMismatch)?;
                            let SemanticTypeKind::Structure {
                                declaration,
                                arguments,
                                fields,
                            } = &record.kind
                            else {
                                return Err(runtime_type_diagnostic(
                                    request,
                                    target.source,
                                    "semantic-projected-assignment-base",
                                    "projected assignment requires a flat runtime structure local",
                                    "scalar and unsupported aggregate locals do not expose replaceable named fields",
                                    "use a flat structure with stored copy-scalar fields and generic arguments",
                                ));
                            };
                            if !runtime_structure_arguments_supported(partial, arguments, fields) {
                                return Err(runtime_type_diagnostic(
                                    request,
                                    target.source,
                                    "semantic-projected-assignment-base",
                                    "projected assignment requires a supported flat runtime structure",
                                    "non-scalar generic arguments and non-flat aggregate replacement remain outside this lowering slice",
                                    "use a flat structure specialized only with stored copy-scalar types",
                                ));
                            }
                            let mut selected = None;
                            for (index, field) in fields.iter().enumerate() {
                                charge_runtime_aggregate_lookup(
                                    request,
                                    &mut *aggregate_work,
                                    is_cancelled,
                                )?;
                                if field.name == field_name.as_str()
                                    && selected.replace(index).is_some()
                                {
                                    return Err(runtime_type_diagnostic(
                                        request,
                                        target.source,
                                        "semantic-projected-assignment-field",
                                        "projected assignment field name is ambiguous",
                                        "field replacement requires one exact structure declaration field",
                                        "remove the duplicate field declaration",
                                    ));
                                }
                            }
                            let index = selected.ok_or_else(|| {
                                runtime_type_diagnostic(
                                    request,
                                    target.source,
                                    "semantic-projected-assignment-field",
                                    "projected assignment does not name a declared structure field",
                                    "field names are matched exactly and nominally",
                                    "assign one of the structure's declared fields",
                                )
                            })?;
                            (*declaration, fields[index].ty, fields[index].public)
                        };
                        if runtime_function_module(request, partial, function)?
                            != request
                                .hir
                                .as_program()
                                .declaration(declaration)
                                .ok_or(AnalysisFailure::RequestMismatch)?
                                .module
                            && !field_public
                        {
                            return Err(runtime_type_diagnostic(
                                request,
                                target.source,
                                "semantic-runtime-field-private",
                                "runtime structure field is private to its declaring module",
                                "projected assignment from another module preserves source visibility",
                                "expose a public mutator from the declaring module",
                            ));
                        }
                        *locals
                            .get_mut(local.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)? = Some(RuntimeBinding {
                            state: OwnershipState::BorrowedMut,
                            ..current
                        });
                        let outcome = analyze_runtime_expression(
                            request,
                            partial,
                            function,
                            *value,
                            RuntimeExpressionRequest {
                                expected: Some(field_ty),
                                desired_result: None,
                                access: AccessMode::Value,
                            },
                            &mut RuntimeState {
                                locals: &mut *locals,
                                parameters: &mut *parameters,
                                aggregate_work: &mut *aggregate_work,
                                allow_assertions,
                                allow_scope_call: false,
                            },
                            is_cancelled,
                        )?;
                        statement_effects = outcome.effects;
                        let reserved = locals
                            .get(local.0 as usize)
                            .copied()
                            .flatten()
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        if reserved
                            != (RuntimeBinding {
                                state: OwnershipState::BorrowedMut,
                                ..current
                            })
                        {
                            return Err(AnalysisFailure::RequestMismatch.into());
                        }
                        let value_id = append_semantic_value(
                            request,
                            partial,
                            function,
                            current_ty,
                            (
                                SemanticValueOrigin::Local(local),
                                Some(local_record.source),
                                Some(local_record.name.as_str()),
                            ),
                            is_cancelled,
                        )?;
                        *locals
                            .get_mut(local.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)? = Some(RuntimeBinding {
                            value: value_id,
                            state: OwnershipState::Owned,
                            ..current
                        });
                        definitions
                            .try_reserve_exact(1)
                            .map_err(|_| fact_resource(request, "statement local definitions"))?;
                        definitions.push(LocalDefinition {
                            local,
                            value: value_id,
                        });
                    } else {
                        let compound = compound_assignment_binary_operator(*operator);
                        if compound.is_some()
                            && !matches!(
                                runtime_scalar_type(partial, current_ty),
                                Some(RuntimeScalarType::Integer { .. })
                            )
                        {
                            return Err(runtime_type_diagnostic(
                                request,
                                statement.source,
                                "semantic-compound-assignment-type",
                                "compound assignment requires an integer local",
                                "revision 0.1 defines compound arithmetic, bitwise, and shift assignment only for integers",
                                "use an integer local or write an explicitly supported operation",
                            ));
                        }
                        let value_id = if compound.is_some() {
                            *locals
                                .get_mut(local.0 as usize)
                                .ok_or(AnalysisFailure::RequestMismatch)? = Some(RuntimeBinding {
                                state: OwnershipState::BorrowedMut,
                                ..current
                            });
                            let outcome = analyze_runtime_expression(
                                request,
                                partial,
                                function,
                                *value,
                                RuntimeExpressionRequest {
                                    expected: Some(current_ty),
                                    desired_result: None,
                                    access: AccessMode::Value,
                                },
                                &mut RuntimeState {
                                    locals: &mut *locals,
                                    parameters: &mut *parameters,
                                    aggregate_work: &mut *aggregate_work,
                                    allow_assertions,
                                    allow_scope_call: false,
                                },
                                is_cancelled,
                            )?;
                            statement_effects = outcome.effects;
                            let reserved = locals
                                .get(local.0 as usize)
                                .copied()
                                .flatten()
                                .ok_or(AnalysisFailure::RequestMismatch)?;
                            if reserved
                                != (RuntimeBinding {
                                    state: OwnershipState::BorrowedMut,
                                    ..current
                                })
                            {
                                return Err(AnalysisFailure::RequestMismatch.into());
                            }
                            append_semantic_value(
                                request,
                                partial,
                                function,
                                current_ty,
                                (
                                    SemanticValueOrigin::Local(local),
                                    Some(local_record.source),
                                    Some(local_record.name.as_str()),
                                ),
                                is_cancelled,
                            )?
                        } else {
                            let value_id = append_semantic_value(
                                request,
                                partial,
                                function,
                                current_ty,
                                (
                                    SemanticValueOrigin::Local(local),
                                    Some(local_record.source),
                                    Some(local_record.name.as_str()),
                                ),
                                is_cancelled,
                            )?;
                            let outcome = analyze_runtime_expression(
                                request,
                                partial,
                                function,
                                *value,
                                RuntimeExpressionRequest {
                                    expected: Some(current_ty),
                                    desired_result: Some(value_id),
                                    access: AccessMode::Value,
                                },
                                &mut RuntimeState {
                                    locals: &mut *locals,
                                    parameters: &mut *parameters,
                                    aggregate_work: &mut *aggregate_work,
                                    allow_assertions,
                                    allow_scope_call: false,
                                },
                                is_cancelled,
                            )?;
                            statement_effects = outcome.effects;
                            value_id
                        };
                        *locals
                            .get_mut(local.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)? = Some(RuntimeBinding {
                            value: value_id,
                            state: OwnershipState::Owned,
                            ..current
                        });
                        definitions
                            .try_reserve_exact(1)
                            .map_err(|_| fact_resource(request, "statement local definitions"))?;
                        definitions.push(LocalDefinition {
                            local,
                            value: value_id,
                        });
                    }
                }
            }
            StatementKind::Expression(expression) => {
                let outcome = analyze_runtime_expression(
                    request,
                    partial,
                    function,
                    *expression,
                    RuntimeExpressionRequest {
                        expected: None,
                        desired_result: None,
                        access: AccessMode::Value,
                    },
                    &mut RuntimeState {
                        locals: &mut *locals,
                        parameters: &mut *parameters,
                        aggregate_work: &mut *aggregate_work,
                        allow_assertions,
                        allow_scope_call: false,
                    },
                    is_cancelled,
                )?;
                statement_effects = outcome.effects;
            }
            StatementKind::Send(expression) => {
                if request
                    .hir
                    .as_program()
                    .expression(*expression)
                    .is_some_and(|expression| {
                        matches!(
                            expression.kind,
                            ExpressionKind::Literal(Literal::String(_) | Literal::Bytes(_))
                        )
                    })
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        request
                            .hir
                            .as_program()
                            .expression(*expression)
                            .map_or(statement.source, |expression| expression.source),
                        "semantic-static-data-consumer-pending",
                        "static literal cannot be sent as a runtime actor request",
                        "actor transport has no authenticated Static[Str] or Static[Bytes[N]] ABI representation",
                        "use a supported actor request call until static-data transport lowering lands",
                    ));
                }
                let outcome = analyze_actor_send_expression(
                    request,
                    partial,
                    function,
                    *expression,
                    &mut RuntimeState {
                        locals: &mut *locals,
                        parameters: &mut *parameters,
                        aggregate_work: &mut *aggregate_work,
                        allow_assertions,
                        allow_scope_call: false,
                    },
                    is_cancelled,
                )?;
                statement_effects = outcome.effects;
            }
            StatementKind::Assert {
                condition,
                expression,
                witness: _,
                message,
                comptime: false,
            } if allow_assertions => {
                if message.as_ref().is_some_and(|message| {
                    message.len() > MAX_RUNTIME_ASSERTION_EXPRESSION_BYTES
                        || message.chars().all(char::is_whitespace)
                }) {
                    return Err(runtime_type_diagnostic(
                        request,
                        statement.source,
                        "semantic-runtime-assertion-message-limit",
                        "runtime assertion message is empty or exceeds its bounded report payload",
                        "a present assertion message must contain 1 through 4096 UTF-8 bytes",
                        "provide a shorter nonempty message or omit it",
                    ));
                }
                if expression.len() > MAX_RUNTIME_ASSERTION_EXPRESSION_BYTES
                    || expression.chars().all(char::is_whitespace)
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        statement.source,
                        "semantic-runtime-assertion-expression-limit",
                        "runtime assertion condition source exceeds its bounded report payload",
                        "the exact declared-source condition must fit the 4096-byte assertion bound",
                        "simplify the assertion condition or call a boolean helper",
                    ));
                }
                let _condition_source = request
                    .hir
                    .as_program()
                    .expression(*condition)
                    .filter(|record| record.source.range.start <= record.source.range.end)
                    .map(|record| record.source)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let bool_ty = ensure_primitive_type(
                    request,
                    partial,
                    PrimitiveSemanticType::Bool,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                let outcome = analyze_runtime_expression(
                    request,
                    partial,
                    function,
                    *condition,
                    RuntimeExpressionRequest {
                        expected: Some(bool_ty),
                        desired_result: None,
                        access: AccessMode::Value,
                    },
                    &mut RuntimeState {
                        locals: &mut *locals,
                        parameters: &mut *parameters,
                        aggregate_work: &mut *aggregate_work,
                        allow_assertions,
                        allow_scope_call: false,
                    },
                    is_cancelled,
                )?;
                if outcome.ty != bool_ty {
                    return Err(AnalysisFailure::RequestMismatch.into());
                }
                statement_effects = EffectSet(outcome.effects.0 | EffectSet::MAY_FAIL);
            }
            StatementKind::Return(expression) => {
                let result = partial
                    .functions
                    .get(function.0 as usize)
                    .map(|record| record.result)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                match *expression {
                    Some(expression) => {
                        let outcome = analyze_runtime_expression(
                            request,
                            partial,
                            function,
                            expression,
                            RuntimeExpressionRequest {
                                expected: Some(result),
                                desired_result: None,
                                access: AccessMode::Value,
                            },
                            &mut RuntimeState {
                                locals: &mut *locals,
                                parameters: &mut *parameters,
                                aggregate_work: &mut *aggregate_work,
                                allow_assertions,
                                allow_scope_call: false,
                            },
                            is_cancelled,
                        )?;
                        statement_effects = outcome.effects;
                    }
                    None if result == SemanticTypeId(0) => {}
                    None => return Err(AnalysisFailure::RequestMismatch.into()),
                }
            }
            StatementKind::If {
                branches,
                else_body,
            } => {
                let [(condition, then_body)] = branches.as_slice() else {
                    return Err(AnalysisFailure::RequestMismatch.into());
                };
                let bool_ty = ensure_primitive_type(
                    request,
                    partial,
                    PrimitiveSemanticType::Bool,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                let condition = analyze_runtime_expression(
                    request,
                    partial,
                    function,
                    *condition,
                    RuntimeExpressionRequest {
                        expected: Some(bool_ty),
                        desired_result: None,
                        access: AccessMode::Value,
                    },
                    &mut RuntimeState {
                        locals: &mut *locals,
                        parameters: &mut *parameters,
                        aggregate_work: &mut *aggregate_work,
                        allow_assertions,
                        allow_scope_call: false,
                    },
                    is_cancelled,
                )?;
                statement_effects = condition.effects;
                let branch_fact_start = partial.statements.len();
                let mut then_locals = copy_binding_map(locals, request.limits.values)?;
                let mut then_parameters = copy_binding_map(parameters, request.limits.values)?;
                analyze_runtime_body(
                    request,
                    partial,
                    function,
                    *then_body,
                    &mut then_locals,
                    &mut then_parameters,
                    allow_assertions,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                let mut else_locals = copy_binding_map(locals, request.limits.values)?;
                let mut else_parameters = copy_binding_map(parameters, request.limits.values)?;
                if let Some(otherwise) = *else_body {
                    analyze_runtime_body(
                        request,
                        partial,
                        function,
                        otherwise,
                        &mut else_locals,
                        &mut else_parameters,
                        allow_assertions,
                        &mut *aggregate_work,
                        is_cancelled,
                    )?;
                }
                join_runtime_local_branches(
                    request,
                    partial,
                    function,
                    RuntimeLocalBranchJoin {
                        source: statement.source,
                        destination: locals,
                        then_bindings: &then_locals,
                        else_bindings: &else_locals,
                        definitions: &mut definitions,
                    },
                    is_cancelled,
                )?;
                for branch in partial
                    .statements
                    .get(branch_fact_start..)
                    .ok_or(AnalysisFailure::RequestMismatch)?
                {
                    statement_effects.0 |= branch.effects.0;
                }
                join_runtime_branches(
                    request,
                    statement.source,
                    parameters,
                    &then_parameters,
                    &else_parameters,
                    is_cancelled,
                )?;
            }
            StatementKind::For {
                take_binding,
                binding,
                take_iterable,
                iterable,
                body,
            } => {
                statement_effects = analyze_closed_range_for(
                    request,
                    partial,
                    function,
                    statement_id,
                    *take_binding,
                    *binding,
                    *take_iterable,
                    *iterable,
                    *body,
                    locals,
                    parameters,
                    allow_assertions,
                    &mut *aggregate_work,
                    &mut definitions,
                    is_cancelled,
                )?;
            }
            StatementKind::While { condition, body } => {
                let bound = bounded_while_shape(request.hir.as_program(), *condition, *body)
                    .ok_or_else(|| {
                        runtime_type_diagnostic(
                            request,
                            statement.source,
                            "semantic-sync-while-bound-unproved",
                            "synchronous while-loop bound is not proved",
                            "the supported loop requires `local < integer` and a first-body `local += 1` induction step",
                            "use the canonical finite induction form or remove the synchronous loop",
                        )
                    })?;
                let mut exits = copy_binding_map(locals, request.limits.values)?;
                for (index, slot) in locals.iter_mut().enumerate() {
                    let Some(current) = *slot else { continue };
                    let RuntimeBindingOrigin::Local(local) = current.origin else {
                        continue;
                    };
                    if partial
                        .values
                        .get(current.value.0 as usize)
                        .is_some_and(|value| {
                            value.class == SemanticValueClass::Ephemeral(EphemeralKind::View)
                        })
                    {
                        continue;
                    }
                    let ty = partial
                        .values
                        .get(current.value.0 as usize)
                        .filter(|value| value.function == function)
                        .map(|value| value.ty)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    let local_record = request
                        .hir
                        .as_program()
                        .locals
                        .get(index)
                        .filter(|record| record.id == local)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    let header = append_semantic_value(
                        request,
                        partial,
                        function,
                        ty,
                        (
                            SemanticValueOrigin::Local(local),
                            Some(local_record.source),
                            Some(local_record.name.as_str()),
                        ),
                        is_cancelled,
                    )?;
                    definitions.push(LocalDefinition {
                        local,
                        value: header,
                    });
                    *slot = Some(RuntimeBinding {
                        value: header,
                        ..current
                    });
                }
                for (index, slot) in exits.iter_mut().enumerate() {
                    let Some(current) = *slot else { continue };
                    let RuntimeBindingOrigin::Local(local) = current.origin else {
                        continue;
                    };
                    if partial
                        .values
                        .get(current.value.0 as usize)
                        .is_some_and(|value| {
                            value.class == SemanticValueClass::Ephemeral(EphemeralKind::View)
                        })
                    {
                        continue;
                    }
                    let ty = partial.values[current.value.0 as usize].ty;
                    let local_record = &request.hir.as_program().locals[index];
                    let exit = append_semantic_value(
                        request,
                        partial,
                        function,
                        ty,
                        (
                            SemanticValueOrigin::Local(local),
                            Some(local_record.source),
                            Some(local_record.name.as_str()),
                        ),
                        is_cancelled,
                    )?;
                    definitions.push(LocalDefinition { local, value: exit });
                    *slot = Some(RuntimeBinding {
                        value: exit,
                        ..current
                    });
                }
                let bool_ty = ensure_primitive_type(
                    request,
                    partial,
                    PrimitiveSemanticType::Bool,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                let condition = analyze_runtime_expression(
                    request,
                    partial,
                    function,
                    *condition,
                    RuntimeExpressionRequest {
                        expected: Some(bool_ty),
                        desired_result: None,
                        access: AccessMode::Value,
                    },
                    &mut RuntimeState {
                        locals: &mut *locals,
                        parameters: &mut *parameters,
                        aggregate_work: &mut *aggregate_work,
                        allow_assertions,
                        allow_scope_call: false,
                    },
                    is_cancelled,
                )?;
                let loop_fact_start = partial.statements.len();
                analyze_runtime_body(
                    request,
                    partial,
                    function,
                    *body,
                    locals,
                    parameters,
                    allow_assertions,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                statement_effects = condition.effects;
                for nested in partial
                    .statements
                    .get(loop_fact_start..)
                    .ok_or(AnalysisFailure::RequestMismatch)?
                {
                    statement_effects.0 |= nested.effects.0;
                }
                let body_work = u64::try_from(
                    request
                        .hir
                        .as_program()
                        .body(*body)
                        .ok_or(AnalysisFailure::RequestMismatch)?
                        .statements
                        .len(),
                )
                .map_err(|_| fact_resource(request, "synchronous while work bound"))?;
                let _proven_work =
                    bound
                        .checked_mul(body_work.checked_add(1).ok_or_else(|| {
                            fact_resource(request, "synchronous while work bound")
                        })?)
                        .ok_or_else(|| fact_resource(request, "synchronous while work bound"))?;
                locals.clone_from_slice(&exits);
            }
            StatementKind::Break | StatementKind::Continue => {}
            StatementKind::Match { scrutinee, arms } => {
                statement_effects = analyze_closed_enum_match(
                    request,
                    partial,
                    function,
                    *scrutinee,
                    arms,
                    locals,
                    parameters,
                    allow_assertions,
                    &mut *aggregate_work,
                    &mut definitions,
                    is_cancelled,
                )?;
            }
            StatementKind::With {
                value,
                binding,
                region,
                body,
            } => {
                statement_effects = analyze_runtime_with(
                    request,
                    partial,
                    function,
                    statement_id,
                    *value,
                    *binding,
                    *region,
                    *body,
                    locals,
                    parameters,
                    allow_assertions,
                    &mut *aggregate_work,
                    &mut definitions,
                    is_cancelled,
                )?;
            }
            _ => return Err(AnalysisFailure::RequestMismatch.into()),
        }
        append_statement_fact(
            request,
            partial,
            function,
            statement_id,
            RuntimeStatementPost {
                effects: statement_effects,
                definitions,
                locals,
                parameters,
            },
            is_cancelled,
        )?;
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn analyze_closed_range_for(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    statement: StatementId,
    take_binding: bool,
    binding: LocalId,
    take_iterable: bool,
    iterable: ExpressionId,
    body: BodyId,
    locals: &mut [Option<RuntimeBinding>],
    parameters: &mut [Option<RuntimeBinding>],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    definitions: &mut Vec<LocalDefinition>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<EffectSet> {
    let program = request.hir.as_program();
    let statement_record = program
        .statement(statement)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let iterable_record = program
        .expression(iterable)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let ExpressionKind::Range { inclusive, .. } = iterable_record.kind else {
        return Err(runtime_type_diagnostic(
            request,
            iterable_record.source,
            "semantic-for-iteration-target",
            "for-loop target is not an admitted closed iterator",
            "revision 0.1 has no user-defined iteration protocol; fixed arrays and standard-container iterators require their own authenticated producers",
            "use a half-open literal integer range in this analysis slice",
        ));
    };
    if take_binding || take_iterable {
        return Err(runtime_type_diagnostic(
            request,
            statement_record.source,
            "semantic-for-range-take-forbidden",
            "integer range iteration cannot use take syntax",
            "range elements are generated copyable integers rather than elements moved from owned storage",
            "remove both take markers from the range loop",
        ));
    }
    if inclusive {
        return Err(runtime_type_diagnostic(
            request,
            iterable_record.source,
            "semantic-for-inclusive-range-pending",
            "inclusive range iteration is not yet admitted by this analysis slice",
            "maximum-endpoint execution needs its distinct non-overflowing lowering contract",
            "use a half-open literal range until inclusive range lowering lands",
        ));
    }
    let Some((start_expression, end_expression, start_constant, end_constant)) =
        closed_literal_range_shape(program, iterable)
    else {
        return Err(runtime_type_diagnostic(
            request,
            iterable_record.source,
            "semantic-for-range-bound-not-constant",
            "range bounds are not both nonnegative integer literals",
            "this slice authenticates an exact finite trip count directly from the two HIR literal spellings",
            "use two u64-representable integer literals or retain a canonical bounded while loop",
        ));
    };
    let maximum_iterations = half_open_trip_count(start_constant, end_constant);
    let element_ty = ensure_primitive_type(
        request,
        partial,
        PrimitiveSemanticType::Integer {
            signed: false,
            bits: 64,
            pointer_sized: false,
        },
        aggregate_work,
        is_cancelled,
    )?;
    // Retain the exact comparison result type required by the canonical
    // lowering of this analyzed iterator. The range expression itself is
    // intentionally not a first-class value, but its loop header is.
    let _condition_ty = ensure_primitive_type(
        request,
        partial,
        PrimitiveSemanticType::Bool,
        aggregate_work,
        is_cancelled,
    )?;
    let mut state = RuntimeState {
        locals: &mut *locals,
        parameters: &mut *parameters,
        aggregate_work: &mut *aggregate_work,
        allow_assertions,
        allow_scope_call: false,
    };
    let start = analyze_runtime_expression(
        request,
        partial,
        function,
        start_expression,
        RuntimeExpressionRequest {
            expected: Some(element_ty),
            desired_result: None,
            access: AccessMode::Value,
        },
        &mut state,
        is_cancelled,
    )?;
    let end = analyze_runtime_expression(
        request,
        partial,
        function,
        end_expression,
        RuntimeExpressionRequest {
            expected: Some(element_ty),
            desired_result: None,
            access: AccessMode::Value,
        },
        &mut state,
        is_cancelled,
    )?;
    let (Some(start_value), Some(end_value)) = (start.result, end.result) else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: iterable,
            ty: element_ty,
            result: None,
            resolution: ExpressionResolution::ClosedRange {
                start: start_value,
                end: end_value,
                inclusive: false,
                maximum_iterations,
            },
            effects: EffectSet(start.effects.0 | end.effects.0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    let local_record = program
        .locals
        .get(binding.0 as usize)
        .filter(|record| record.id == binding && record.body == body && record.ty.is_none())
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let binding_value = append_semantic_value(
        request,
        partial,
        function,
        element_ty,
        (
            SemanticValueOrigin::Local(binding),
            Some(local_record.source),
            Some(local_record.name.as_str()),
        ),
        is_cancelled,
    )?;
    definitions
        .try_reserve_exact(1)
        .map_err(|_| fact_resource(request, "for-loop binding definitions"))?;
    definitions.push(LocalDefinition {
        local: binding,
        value: binding_value,
    });
    let mut body_locals = copy_binding_map(locals, request.limits.values)?;
    let slot = body_locals
        .get_mut(binding.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if slot
        .replace(RuntimeBinding {
            value: binding_value,
            state: OwnershipState::Owned,
            authority: RuntimeAuthority::Own,
            origin: RuntimeBindingOrigin::Local(binding),
            source: local_record.source,
        })
        .is_some()
    {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let mut body_parameters = copy_binding_map(parameters, request.limits.values)?;
    let nested_fact_start = partial.statements.len();
    analyze_runtime_body(
        request,
        partial,
        function,
        body,
        &mut body_locals,
        &mut body_parameters,
        allow_assertions,
        aggregate_work,
        is_cancelled,
    )?;
    for (index, (before, after)) in locals.iter().zip(&body_locals).enumerate() {
        check_cancelled(is_cancelled)?;
        let local_is_nested = program
            .locals
            .get(index)
            .is_some_and(|local| body_is_ancestor(program, body, local.body));
        if !local_is_nested && before != after {
            return Err(runtime_type_diagnostic(
                request,
                statement_record.source,
                "semantic-for-loop-carried-state-pending",
                "range loop mutates state declared outside its body",
                "this analysis slice proves the loop binding and finite trip count but does not yet construct aggregate loop-carried SSA joins",
                "keep mutations local to the loop body or use the canonical bounded while form",
            ));
        }
    }
    if body_parameters != parameters {
        return Err(runtime_type_diagnostic(
            request,
            statement_record.source,
            "semantic-for-loop-carried-state-pending",
            "range loop changes parameter ownership state",
            "repeated parameter ownership transitions need a separately authenticated loop-carried state",
            "avoid moving or mutating parameters inside this range loop",
        ));
    }
    let binding_after = body_locals
        .get(binding.0 as usize)
        .copied()
        .flatten()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if binding_after.value != binding_value
        || binding_after.state != OwnershipState::Owned
        || binding_after.authority != RuntimeAuthority::Own
    {
        return Err(runtime_type_diagnostic(
            request,
            statement_record.source,
            "semantic-for-binding-mutated",
            "range loop binding is reassigned or consumed by its body",
            "the canonical binding is regenerated for every proved iteration and remains immutable in this slice",
            "read the binding without assigning, moving, or taking it",
        ));
    }
    let mut effects = EffectSet(start.effects.0 | end.effects.0);
    for nested in partial
        .statements
        .get(nested_fact_start..)
        .ok_or(AnalysisFailure::RequestMismatch)?
    {
        effects.0 |= nested.effects.0;
    }
    Ok(effects)
}

#[allow(clippy::too_many_arguments)]
fn analyze_runtime_with(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    statement: StatementId,
    value: ExpressionId,
    binding: Option<LocalId>,
    region: Option<wrela_hir::RegionId>,
    body: BodyId,
    locals: &mut [Option<RuntimeBinding>],
    parameters: &mut [Option<RuntimeBinding>],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    definitions: &mut Vec<LocalDefinition>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<EffectSet> {
    let program = request.hir.as_program();
    let statement_record = program
        .statement(statement)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if region.is_some() {
        return Err(runtime_type_diagnostic(
            request,
            statement_record.source,
            "semantic-with-region-pending",
            "region-branded with activation is not yet supported",
            "this slice proves scope cleanup semantics without region allocation",
            "omit the with region until region lowering lands",
        ));
    }
    let value_record = program
        .expression(value)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let ExpressionKind::Call { callee, .. } = value_record.kind else {
        return Err(runtime_type_diagnostic(
            request,
            value_record.source,
            "semantic-with-scope-call-required",
            "with acquisition requires one direct scope call",
            "an arbitrary value does not carry a statically resolved cleanup protocol",
            "write `with scope_name(...) as binding:`",
        ));
    };
    let callee_record = program
        .expression(callee)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if matches!(callee_record.kind, ExpressionKind::Field { .. }) {
        return Err(runtime_type_diagnostic(
            request,
            callee_record.source,
            "semantic-with-receiver-scope-pending",
            "receiver-form scope acquisition is not yet supported",
            "scope method resolution depends on the receiver-call subsystem",
            "call a module-level free scope declaration",
        ));
    }
    let ExpressionKind::Reference(Definition::Declaration(resolved)) = &callee_record.kind else {
        return Err(runtime_type_diagnostic(
            request,
            callee_record.source,
            "semantic-with-scope-call-required",
            "with acquisition callee is not a resolved free scope declaration",
            "closures and computed callees cannot establish a closed cleanup protocol",
            "call a module-level scope declaration directly",
        ));
    };
    if !program
        .declaration(resolved.declaration)
        .is_some_and(|declaration| matches!(declaration.kind, DeclarationKind::Scope(_)))
    {
        return Err(runtime_type_diagnostic(
            request,
            callee_record.source,
            "semantic-with-scope-callee",
            "with acquisition callee is not a scope declaration",
            "ordinary functions do not carry abort and exit cleanup contracts",
            "declare and call a scope",
        ));
    }
    let protocol = ensure_scope_protocol(
        request,
        partial,
        resolved.declaration,
        aggregate_work,
        is_cancelled,
    )?;
    let state_type = partial
        .scope_protocols
        .get(protocol.0 as usize)
        .map(|protocol| protocol.result)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let binding_value = if let Some(local) = binding {
        let local_record = program
            .locals
            .get(local.0 as usize)
            .filter(|record| record.id == local && record.body == body)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if let Some(annotation) = &local_record.ty {
            let annotation = semantic_type_from_source(
                request,
                partial,
                annotation,
                aggregate_work,
                is_cancelled,
            )?;
            if annotation != state_type {
                return Err(runtime_type_diagnostic(
                    request,
                    local_record.source,
                    "semantic-with-binding-type",
                    "with binding annotation does not match the scope state type",
                    "the binding receives the exact value produced by scope enter",
                    "remove the annotation or use the scope's declared result type",
                ));
            }
        }
        Some(append_semantic_value(
            request,
            partial,
            function,
            state_type,
            (
                SemanticValueOrigin::Local(local),
                Some(local_record.source),
                Some(local_record.name.as_str()),
            ),
            is_cancelled,
        )?)
    } else {
        None
    };
    let acquisition = analyze_runtime_expression(
        request,
        partial,
        function,
        value,
        RuntimeExpressionRequest {
            expected: Some(state_type),
            desired_result: binding_value,
            access: AccessMode::Value,
        },
        &mut RuntimeState {
            locals: &mut *locals,
            parameters: &mut *parameters,
            aggregate_work: &mut *aggregate_work,
            allow_assertions,
            allow_scope_call: true,
        },
        is_cancelled,
    )?;
    if acquisition.ty != state_type {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    if let (Some(local), Some(value)) = (binding, binding_value) {
        let local_record = program
            .locals
            .get(local.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let slot = locals
            .get_mut(local.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot
            .replace(RuntimeBinding {
                value,
                state: OwnershipState::Owned,
                authority: RuntimeAuthority::Own,
                origin: RuntimeBindingOrigin::Local(local),
                source: local_record.source,
            })
            .is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        definitions.push(LocalDefinition { local, value });
    }
    let activation_start = partial.scope_activations.len();
    let nested_fact_start = partial.statements.len();
    analyze_runtime_body(
        request,
        partial,
        function,
        body,
        locals,
        parameters,
        allow_assertions,
        aggregate_work,
        is_cancelled,
    )?;
    let mut effects = acquisition.effects;
    for nested in partial
        .statements
        .get(nested_fact_start..)
        .ok_or(AnalysisFailure::RequestMismatch)?
    {
        effects.0 |= nested.effects.0;
    }
    if let Some(local) = binding {
        *locals
            .get_mut(local.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)? = None;
    }
    if partial.scope_activations.len() >= request.limits.scope_activations as usize {
        return Err(fact_resource(request, "scope activations").into());
    }
    let mut cleanup_dependencies = partial
        .scope_activations
        .get(activation_start..)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .iter()
        .filter(|activation| activation.function == function)
        .map(|activation| activation.statement)
        .collect::<Vec<_>>();
    cancellable_stable_sort_by(
        &mut cleanup_dependencies,
        request.limits.fact_edges,
        "scope cleanup dependency sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )?;
    cancellable_dedup(&mut cleanup_dependencies, is_cancelled)?;
    let protocol_proof = partial
        .scope_protocols
        .get(protocol.0 as usize)
        .map(|protocol| protocol.proof)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    partial.scope_activations.push(ScopeActivation {
        statement,
        function,
        protocol,
        state_type,
        cleanup_dependencies,
        reverse_source_order: 0,
        proof: protocol_proof,
    });
    Ok(effects)
}

fn cleanup_cycle_participants(
    activations: &[ScopeActivation],
    function: FunctionInstanceId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Option<Vec<StatementId>>, AnalysisFailure> {
    let nodes = activations
        .iter()
        .enumerate()
        .filter(|(_, activation)| activation.function == function)
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    let mut colors = vec![0u8; nodes.len()];
    let mut path = Vec::<usize>::new();
    let mut stack = Vec::<(usize, usize)>::new();
    for root in 0..nodes.len() {
        check_cancelled(is_cancelled)?;
        if colors[root] != 0 {
            continue;
        }
        colors[root] = 1;
        path.push(root);
        stack.push((root, 0));
        while let Some((node, next_dependency)) = stack.last_mut() {
            check_cancelled(is_cancelled)?;
            let activation = &activations[nodes[*node]];
            if *next_dependency >= activation.cleanup_dependencies.len() {
                colors[*node] = 2;
                stack.pop();
                path.pop();
                continue;
            }
            let dependency = activation.cleanup_dependencies[*next_dependency];
            *next_dependency = next_dependency
                .checked_add(1)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let target = nodes
                .iter()
                .position(|index| activations[*index].statement == dependency)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            match colors[target] {
                0 => {
                    colors[target] = 1;
                    path.push(target);
                    stack.push((target, 0));
                }
                1 => {
                    let start = path
                        .iter()
                        .position(|candidate| *candidate == target)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    let mut participants = path[start..]
                        .iter()
                        .map(|node| activations[nodes[*node]].statement)
                        .collect::<Vec<_>>();
                    participants.sort_unstable();
                    participants.dedup();
                    return Ok(Some(participants));
                }
                2 => {}
                _ => return Err(AnalysisFailure::RequestMismatch),
            }
        }
    }
    Ok(None)
}

fn finalize_scope_activations(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    let indices = partial
        .scope_activations
        .iter()
        .enumerate()
        .filter(|(_, activation)| activation.function == function)
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    if indices.is_empty() {
        return Ok(());
    }
    if let Some(participants) =
        cleanup_cycle_participants(&partial.scope_activations, function, is_cancelled)?
    {
        let primary = participants
            .first()
            .and_then(|statement| request.hir.as_program().statement(*statement))
            .map_or_else(
                || fallback_span(request.hir.as_program()),
                |statement| statement.source,
            );
        let mut diagnostic = Diagnostic::error(
            Category::OWNERSHIP,
            primary,
            "scope cleanup dependencies contain a cycle",
        );
        diagnostic.code = Some(copy_static_analysis_text(
            "semantic-cleanup-cycle",
            request.limits.fact_bytes,
        )?);
        diagnostic
            .labels
            .try_reserve_exact(participants.len())
            .map_err(|_| fact_resource(request, "scope cleanup cycle labels"))?;
        for participant in participants {
            let statement = request
                .hir
                .as_program()
                .statement(participant)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            diagnostic.labels.push(wrela_diagnostics::Label {
                span: statement.source,
                message: copy_analysis_text(
                    &format!("cleanup participant statement {}", participant.0),
                    request.limits.fact_bytes,
                    is_cancelled,
                )?,
            });
        }
        diagnostic.notes.push(copy_static_analysis_text(
            "every scope teardown must have a finite reverse-topological order",
            request.limits.fact_bytes,
        )?);
        diagnostic.help.push(copy_static_analysis_text(
            "remove the cleanup dependency back edge",
            request.limits.fact_bytes,
        )?);
        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
    }
    if partial.proofs.len() >= request.limits.proofs as usize {
        return Err(fact_resource(request, "scope activation proofs").into());
    }
    let mut ordered = indices.clone();
    ordered.sort_by_key(|index| partial.scope_activations[*index].statement);
    let count = u32::try_from(ordered.len())
        .map_err(|_| fact_resource(request, "scope activation order"))?;
    let mut sources = Vec::new();
    let mut dependencies = Vec::new();
    let mut edge_count = 0u64;
    for (source_order, index) in ordered.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let activation = &partial.scope_activations[*index];
        sources.push(
            request
                .hir
                .as_program()
                .statement(activation.statement)
                .ok_or(AnalysisFailure::RequestMismatch)?
                .source,
        );
        dependencies.push(
            partial
                .scope_protocols
                .get(activation.protocol.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?
                .proof,
        );
        edge_count = edge_count
            .checked_add(
                u64::try_from(activation.cleanup_dependencies.len())
                    .map_err(|_| fact_resource(request, "scope cleanup edges"))?,
            )
            .ok_or_else(|| fact_resource(request, "scope cleanup edges"))?;
        partial.scope_activations[*index].reverse_source_order = count
            .checked_sub(1)
            .and_then(|maximum| maximum.checked_sub(source_order as u32))
            .ok_or(AnalysisFailure::RequestMismatch)?;
    }
    dependencies.sort_unstable();
    dependencies.dedup();
    let proof = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "scope activation proofs"))?,
    );
    let function_name = partial
        .functions
        .get(function.0 as usize)
        .map(|function| function.name.as_str())
        .ok_or(AnalysisFailure::RequestMismatch)?;
    partial.proofs.push(Proof {
        id: proof,
        kind: ProofKind::CleanupAcyclic,
        subject: bounded_test_fact(
            request,
            "scope cleanup DAG: ",
            function_name,
            is_cancelled,
        )?,
        sources,
        depends_on: dependencies,
        bound: Some(edge_count),
        explanation: vec![
            "lexically nested scope activations form an acyclic cleanup DAG; ready cleanup runs in reverse source order"
                .to_owned(),
        ],
    });
    for index in indices {
        partial.scope_activations[index].proof = proof;
    }
    partial.scope_activations.sort_by_key(|activation| {
        (
            activation.function,
            activation.reverse_source_order,
            activation.statement,
        )
    });
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn analyze_closed_enum_match(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    scrutinee_id: ExpressionId,
    arms: &[wrela_hir::MatchArm],
    locals: &mut [Option<RuntimeBinding>],
    parameters: &mut [Option<RuntimeBinding>],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    definitions: &mut Vec<LocalDefinition>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<EffectSet> {
    let scrutinee_source = request
        .hir
        .as_program()
        .expression(scrutinee_id)
        .map(|record| record.source)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let scrutinee = analyze_runtime_expression(
        request,
        partial,
        function,
        scrutinee_id,
        RuntimeExpressionRequest {
            expected: None,
            desired_result: None,
            access: AccessMode::Read,
        },
        &mut RuntimeState {
            locals: &mut *locals,
            parameters: &mut *parameters,
            aggregate_work: &mut *aggregate_work,
            allow_assertions,
            allow_scope_call: false,
        },
        is_cancelled,
    )?;
    let (enumeration, variants) = partial
        .types
        .get(scrutinee.ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Enumeration {
                declaration,
                variants,
                ..
            } if !variants.is_empty() => Some((*declaration, variants.len())),
            _ => None,
        })
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                scrutinee_source,
                "semantic-runtime-match-scrutinee",
                "runtime match requires a supported closed enum",
                "R1 matching dispatches only on a canonical dense enum tag",
                "match a closed enum value with supported copy-scalar type arguments",
            )
        })?;
    let mut covered = Vec::new();
    covered
        .try_reserve_exact(variants)
        .map_err(|_| fact_resource(request, "runtime match coverage"))?;
    covered.resize(variants, false);
    let mut effects = scrutinee.effects;
    let mut seen_wildcard = false;
    for (arm_index, arm) in arms.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        if seen_wildcard {
            return Err(runtime_type_diagnostic(
                request,
                arm.source,
                "semantic-runtime-match-unreachable-arm",
                "runtime enum match arm follows a catch-all wildcard",
                "a trailing `_` arm already covers every remaining variant",
                "remove arms after the catch-all wildcard",
            ));
        }
        let pattern = request
            .hir
            .as_program()
            .patterns
            .get(arm.pattern.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if pattern.alternatives.len() > 1 {
            if arm.guard.is_some() {
                return Err(runtime_type_diagnostic(
                    request,
                    arm.source,
                    "semantic-runtime-match-alternative-guard-pending",
                    "runtime enum pattern alternatives cannot carry a guard yet",
                    "guarded alternative coverage needs one shared fallthrough proof",
                    "split the guarded alternatives into separate constructor arms",
                ));
            }
            let mut alternative_variants = Vec::new();
            alternative_variants
                .try_reserve_exact(pattern.alternatives.len())
                .map_err(|_| fact_resource(request, "runtime match alternatives"))?;
            let mut alternative_binding: Option<(LocalId, SemanticTypeId)> = None;
            let mut saw_unit_variant = false;
            for alternative in &pattern.alternatives {
                check_cancelled(is_cancelled)?;
                let wrela_hir::PrimaryPattern::Constructor {
                    candidates,
                    arguments,
                    ..
                } = &alternative.kind
                else {
                    return Err(runtime_type_diagnostic(
                        request,
                        alternative.source,
                        "semantic-runtime-match-alternative-shape",
                        "runtime enum alternative must name one unit constructor",
                        "wildcards, literals, bindings, and nested patterns do not identify one disjoint tag",
                        "use distinct payload-free enum constructors in this alternative arm",
                    ));
                };
                let [candidate] = candidates.as_slice() else {
                    return Err(runtime_type_diagnostic(
                        request,
                        alternative.source,
                        "semantic-runtime-match-alternative-shape",
                        "runtime enum alternative constructor is ambiguous or unresolved",
                        "closed alternative coverage requires one exact variant identity",
                        "import or qualify one declared unit variant",
                    ));
                };
                let variant_index = candidate.variant as usize;
                let payload_ty = partial
                    .types
                    .get(scrutinee.ty.0 as usize)
                    .and_then(|record| match &record.kind {
                        SemanticTypeKind::Enumeration { variants, .. } => variants
                            .get(variant_index)
                            .map(|variant| variant.fields.first().map(|field| field.ty)),
                        _ => None,
                    })
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if candidate.enumeration.declaration != enumeration || variant_index >= variants {
                    return Err(runtime_type_diagnostic(
                        request,
                        alternative.source,
                        "semantic-runtime-match-alternative-shape",
                        "runtime enum alternative names a constructor outside the scrutinee enum",
                        "closed alternative coverage requires one exact nominal enum identity",
                        "use variants declared by the matched enum",
                    ));
                }
                match payload_ty {
                    None => {
                        if !arguments.is_empty() {
                            return Err(runtime_type_diagnostic(
                                request,
                                alternative.source,
                                "semantic-runtime-match-alternative-binding-shape",
                                "unit enum alternative cannot bind a payload",
                                "this variant declares no payload field",
                                "remove the payload pattern from the unit alternative",
                            ));
                        }
                        if alternative_binding.is_some() {
                            return Err(runtime_type_diagnostic(
                                request,
                                alternative.source,
                                "semantic-runtime-match-alternative-payload-type",
                                "runtime enum alternatives mix unit and payload variants",
                                "one shared arm binding requires every alternative to expose the same payload type",
                                "split the unit and payload variants into separate arms",
                            ));
                        }
                        saw_unit_variant = true;
                    }
                    Some(payload_ty) => {
                        if saw_unit_variant {
                            return Err(runtime_type_diagnostic(
                                request,
                                alternative.source,
                                "semantic-runtime-match-alternative-payload-type",
                                "runtime enum alternatives mix unit and payload variants",
                                "one shared arm binding requires every alternative to expose the same payload type",
                                "split the unit and payload variants into separate arms",
                            ));
                        }
                        let [argument] = arguments.as_slice() else {
                            return Err(runtime_type_diagnostic(
                                request,
                                alternative.source,
                                "semantic-runtime-match-alternative-binding-shape",
                                "payload enum alternative requires one shared binding",
                                "every alternative must bind its one payload to the same local name",
                                "bind the payload once with the same name in every alternative",
                            ));
                        };
                        if argument.take {
                            return Err(runtime_type_diagnostic(
                                request,
                                argument.source,
                                "semantic-runtime-match-alternative-binding-shape",
                                "runtime enum alternative payload cannot use `take`",
                                "the admitted shared payload is copied into one arm-local binding",
                                "remove `take` from the alternative payload binding",
                            ));
                        }
                        let payload_pattern = request
                            .hir
                            .as_program()
                            .patterns
                            .get(argument.pattern.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        let [payload_alternative] = payload_pattern.alternatives.as_slice() else {
                            return Err(runtime_type_diagnostic(
                                request,
                                payload_pattern.source,
                                "semantic-runtime-match-alternative-binding-shape",
                                "runtime enum alternative payload requires one binding pattern",
                                "nested or alternative payload patterns do not establish one shared local",
                                "bind the payload directly with the same name",
                            ));
                        };
                        let wrela_hir::PrimaryPattern::Bind(local) = payload_alternative.kind
                        else {
                            return Err(runtime_type_diagnostic(
                                request,
                                payload_alternative.source,
                                "semantic-runtime-match-alternative-binding-shape",
                                "runtime enum alternatives require one shared payload name",
                                "wildcard or nested payload patterns do not create a value for the shared arm body",
                                "bind every payload to the same local name",
                            ));
                        };
                        if alternative_binding
                            .is_some_and(|(existing, ty)| existing != local || ty != payload_ty)
                        {
                            return Err(runtime_type_diagnostic(
                                request,
                                payload_alternative.source,
                                "semantic-runtime-match-alternative-payload-type",
                                "runtime enum alternatives do not share one payload type and binding",
                                "the arm body must receive one local with one exact semantic type on every path",
                                "split differently typed variants into separate arms",
                            ));
                        }
                        alternative_binding = Some((local, payload_ty));
                    }
                }
                if covered[variant_index] || alternative_variants.contains(&variant_index) {
                    return Err(runtime_type_diagnostic(
                        request,
                        alternative.source,
                        "semantic-runtime-match-unreachable-arm",
                        "runtime enum alternative is unreachable after an earlier cover",
                        "each unguarded alternative must contribute one previously uncovered variant",
                        "remove the duplicate alternative",
                    ));
                }
                alternative_variants.push(variant_index);
            }
            for variant in alternative_variants {
                covered[variant] = true;
            }
            let mut arm_locals = copy_binding_map(locals, request.limits.values)?;
            let mut arm_parameters = copy_binding_map(parameters, request.limits.values)?;
            let binding_local = if let Some((local, payload_ty)) = alternative_binding {
                let local_record = request
                    .hir
                    .as_program()
                    .locals
                    .get(local.0 as usize)
                    .filter(|record| record.id == local && record.body == arm.body)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let value = append_semantic_value(
                    request,
                    partial,
                    function,
                    payload_ty,
                    (
                        SemanticValueOrigin::Local(local),
                        Some(local_record.source),
                        Some(local_record.name.as_str()),
                    ),
                    is_cancelled,
                )?;
                definitions
                    .try_reserve(1)
                    .map_err(|_| fact_resource(request, "runtime match bindings"))?;
                definitions.push(LocalDefinition { local, value });
                let slot = arm_locals
                    .get_mut(local.0 as usize)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if slot
                    .replace(RuntimeBinding {
                        value,
                        state: OwnershipState::Owned,
                        authority: RuntimeAuthority::Own,
                        origin: RuntimeBindingOrigin::Local(local),
                        source: local_record.source,
                    })
                    .is_some()
                {
                    return Err(AnalysisFailure::RequestMismatch.into());
                }
                Some(local)
            } else {
                None
            };
            let fact_start = partial.statements.len();
            analyze_runtime_body(
                request,
                partial,
                function,
                arm.body,
                &mut arm_locals,
                &mut arm_parameters,
                allow_assertions,
                &mut *aggregate_work,
                is_cancelled,
            )?;
            let mut state_changed =
                arm_parameters.len() != parameters.len() || arm_locals.len() != locals.len();
            for (left, right) in arm_parameters.iter().zip(parameters.iter()) {
                check_cancelled(is_cancelled)?;
                state_changed |= left != right;
            }
            for (index, (left, right)) in arm_locals.iter().zip(locals.iter()).enumerate() {
                check_cancelled(is_cancelled)?;
                if binding_local.is_none_or(|local| index != local.0 as usize) {
                    state_changed |= left != right;
                }
            }
            if state_changed {
                return Err(runtime_type_diagnostic(
                    request,
                    arm.source,
                    "semantic-runtime-match-state-change-not-supported",
                    "runtime enum alternative arm changes outer local state",
                    "alternative arms share one body but this slice does not join outer SSA assignments",
                    "return from the arm or move the assignment after the match",
                ));
            }
            for statement in partial
                .statements
                .get(fact_start..)
                .ok_or(AnalysisFailure::RequestMismatch)?
            {
                check_cancelled(is_cancelled)?;
                effects.0 |= statement.effects.0;
            }
            continue;
        }
        let [alternative] = pattern.alternatives.as_slice() else {
            return Err(runtime_type_diagnostic(
                request,
                pattern.source,
                "semantic-runtime-match-alternatives-not-supported",
                "runtime enum match arm requires one pattern",
                "pattern alternatives are outside this exact constructor-only slice",
                "write one arm per variant",
            ));
        };
        if matches!(alternative.kind, wrela_hir::PrimaryPattern::Wildcard) {
            if arm.guard.is_some() {
                return Err(runtime_type_diagnostic(
                    request,
                    arm.source,
                    "semantic-runtime-match-guarded-wildcard",
                    "runtime enum catch-all wildcard must be unguarded",
                    "a guarded `_` arm cannot prove closed exhaustiveness",
                    "drop the guard or name the remaining constructors explicitly",
                ));
            }
            if arm_index + 1 != arms.len() {
                return Err(runtime_type_diagnostic(
                    request,
                    arm.source,
                    "semantic-runtime-match-unreachable-arm",
                    "runtime enum catch-all wildcard must be last",
                    "a `_` arm covers every remaining variant",
                    "move the `_` arm to the end",
                ));
            }
            let mut remaining = false;
            for slot in &mut covered {
                check_cancelled(is_cancelled)?;
                if !*slot {
                    *slot = true;
                    remaining = true;
                }
            }
            if !remaining {
                return Err(runtime_type_diagnostic(
                    request,
                    alternative.source,
                    "semantic-runtime-match-unreachable-arm",
                    "runtime enum catch-all wildcard is unreachable",
                    "every variant is already covered by an earlier unguarded constructor arm",
                    "remove the redundant `_` arm",
                ));
            }
            seen_wildcard = true;
            let mut arm_locals = copy_binding_map(locals, request.limits.values)?;
            let mut arm_parameters = copy_binding_map(parameters, request.limits.values)?;
            let fact_start = partial.statements.len();
            analyze_runtime_body(
                request,
                partial,
                function,
                arm.body,
                &mut arm_locals,
                &mut arm_parameters,
                allow_assertions,
                &mut *aggregate_work,
                is_cancelled,
            )?;
            let mut state_changed =
                arm_parameters.len() != parameters.len() || arm_locals.len() != locals.len();
            for (left, right) in arm_parameters.iter().zip(parameters.iter()) {
                check_cancelled(is_cancelled)?;
                state_changed |= left != right;
            }
            for (left, right) in arm_locals.iter().zip(locals.iter()) {
                check_cancelled(is_cancelled)?;
                state_changed |= left != right;
            }
            if state_changed {
                return Err(runtime_type_diagnostic(
                    request,
                    arm.source,
                    "semantic-runtime-match-state-change-not-supported",
                    "runtime enum match arm changes outer local state",
                    "match arms may return or perform effects, but this slice does not join outer SSA assignments",
                    "return from each arm or move the assignment after the match",
                ));
            }
            for statement in partial
                .statements
                .get(fact_start..)
                .ok_or(AnalysisFailure::RequestMismatch)?
            {
                check_cancelled(is_cancelled)?;
                effects.0 |= statement.effects.0;
            }
            continue;
        }
        let wrela_hir::PrimaryPattern::Constructor {
            candidates,
            arguments,
            ..
        } = &alternative.kind
        else {
            return Err(runtime_type_diagnostic(
                request,
                alternative.source,
                "semantic-runtime-match-constructor-only",
                "runtime enum match arm must use an explicit constructor",
                "literal, binding-only, tuple, and array arms hide the closed variant set",
                "name one declared enum variant in each arm",
            ));
        };
        let [candidate] = candidates.as_slice() else {
            return Err(runtime_type_diagnostic(
                request,
                alternative.source,
                "semantic-runtime-match-constructor-only",
                "runtime enum constructor pattern is ambiguous or unresolved",
                "closed dispatch requires one exact declaration and variant identity",
                "import or qualify one declared variant",
            ));
        };
        let variant_index = candidate.variant as usize;
        if candidate.enumeration.declaration != enumeration || variant_index >= variants {
            return Err(runtime_type_diagnostic(
                request,
                alternative.source,
                "semantic-runtime-match-nonexhaustive",
                "runtime enum match substitutes a variant from another enum",
                "every arm must name a variant of the scrutinee's exact enum type",
                "use a declared variant of the matched enum",
            ));
        }
        if covered[variant_index] {
            return Err(runtime_type_diagnostic(
                request,
                alternative.source,
                "semantic-runtime-match-unreachable-arm",
                "runtime enum match arm is unreachable after an unguarded cover",
                "an earlier unguarded arm already covers this variant",
                "remove the duplicate arm or move guarded arms before the unguarded cover",
            ));
        }
        let payload_ty = partial
            .types
            .get(scrutinee.ty.0 as usize)
            .and_then(|record| match &record.kind {
                SemanticTypeKind::Enumeration { variants, .. } => variants
                    .get(variant_index)
                    .map(|variant| variant.fields.first().map(|field| field.ty)),
                _ => None,
            })
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let mut arm_locals = copy_binding_map(locals, request.limits.values)?;
        let mut arm_parameters = copy_binding_map(parameters, request.limits.values)?;
        let binding_local = match payload_ty {
            None => {
                if !arguments.is_empty() {
                    return Err(runtime_type_diagnostic(
                        request,
                        alternative.source,
                        "semantic-runtime-match-payload-shape",
                        "unit enum pattern cannot bind a payload",
                        "this variant declares no payload fields",
                        "remove the payload pattern from this unit variant arm",
                    ));
                }
                None
            }
            Some(payload_ty) => {
                let [argument] = arguments.as_slice() else {
                    return Err(runtime_type_diagnostic(
                        request,
                        alternative.source,
                        "semantic-runtime-match-payload-shape",
                        "payload enum pattern requires one binding",
                        "this variant declares exactly one payload field",
                        "bind the variant payload once",
                    ));
                };
                if argument.take {
                    return Err(runtime_type_diagnostic(
                        request,
                        argument.source,
                        "semantic-runtime-match-take-not-supported",
                        "runtime enum pattern payload cannot use `take`",
                        "the admitted ADT payload subset is copied into an arm-local binding",
                        "remove `take` from the payload binding",
                    ));
                }
                let payload_pattern = request
                    .hir
                    .as_program()
                    .patterns
                    .get(argument.pattern.0 as usize)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let [payload_alternative] = payload_pattern.alternatives.as_slice() else {
                    return Err(runtime_type_diagnostic(
                        request,
                        payload_pattern.source,
                        "semantic-runtime-match-alternatives-not-supported",
                        "runtime enum payload requires one binding pattern",
                        "payload alternatives are outside the admitted ADT match subset",
                        "bind the payload directly",
                    ));
                };
                match &payload_alternative.kind {
                    wrela_hir::PrimaryPattern::Bind(local) => {
                        let local_record = request
                            .hir
                            .as_program()
                            .locals
                            .get(local.0 as usize)
                            .filter(|record| record.id == *local && record.body == arm.body)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        let value = append_semantic_value(
                            request,
                            partial,
                            function,
                            payload_ty,
                            (
                                SemanticValueOrigin::Local(*local),
                                Some(local_record.source),
                                Some(local_record.name.as_str()),
                            ),
                            is_cancelled,
                        )?;
                        definitions
                            .try_reserve(1)
                            .map_err(|_| fact_resource(request, "runtime match bindings"))?;
                        definitions.push(LocalDefinition {
                            local: *local,
                            value,
                        });
                        let slot = arm_locals
                            .get_mut(local.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        if slot
                            .replace(RuntimeBinding {
                                value,
                                state: OwnershipState::Owned,
                                authority: RuntimeAuthority::Own,
                                origin: RuntimeBindingOrigin::Local(*local),
                                source: local_record.source,
                            })
                            .is_some()
                        {
                            return Err(AnalysisFailure::RequestMismatch.into());
                        }
                        Some(*local)
                    }
                    wrela_hir::PrimaryPattern::Wildcard => None,
                    _ => {
                        return Err(runtime_type_diagnostic(
                            request,
                            payload_alternative.source,
                            "semantic-runtime-match-payload-shape",
                            "runtime enum payload pattern must bind one name or `_`",
                            "nested payload destructuring remains outside the admitted ADT match subset",
                            "bind the payload to a local name or discard it with `_`",
                        ));
                    }
                }
            }
        };
        if let Some(guard) = arm.guard {
            let bool_ty = ensure_primitive_type(
                request,
                partial,
                PrimitiveSemanticType::Bool,
                &mut *aggregate_work,
                is_cancelled,
            )?;
            let guard_outcome = analyze_runtime_expression(
                request,
                partial,
                function,
                guard,
                RuntimeExpressionRequest {
                    expected: Some(bool_ty),
                    desired_result: None,
                    access: AccessMode::Value,
                },
                &mut RuntimeState {
                    locals: &mut arm_locals,
                    parameters: &mut arm_parameters,
                    aggregate_work: &mut *aggregate_work,
                    allow_assertions,
                    allow_scope_call: false,
                },
                is_cancelled,
            )?;
            if guard_outcome.ty != bool_ty {
                return Err(AnalysisFailure::RequestMismatch.into());
            }
            effects.0 |= guard_outcome.effects.0;
        } else {
            covered[variant_index] = true;
        }
        let fact_start = partial.statements.len();
        analyze_runtime_body(
            request,
            partial,
            function,
            arm.body,
            &mut arm_locals,
            &mut arm_parameters,
            allow_assertions,
            &mut *aggregate_work,
            is_cancelled,
        )?;
        let mut state_changed =
            arm_parameters.len() != parameters.len() || arm_locals.len() != locals.len();
        for (left, right) in arm_parameters.iter().zip(parameters.iter()) {
            check_cancelled(is_cancelled)?;
            state_changed |= left != right;
        }
        for (index, (left, right)) in arm_locals.iter().zip(locals.iter()).enumerate() {
            check_cancelled(is_cancelled)?;
            if binding_local.is_none_or(|local| index != local.0 as usize) {
                state_changed |= left != right;
            }
        }
        if state_changed {
            return Err(runtime_type_diagnostic(
                request,
                arm.source,
                "semantic-runtime-match-state-change-not-supported",
                "runtime enum match arm changes outer local state",
                "R1 match arms may consume the payload and return or perform effects, but do not join outer SSA assignments",
                "return from each arm or move the assignment after the match",
            ));
        }
        for statement in partial
            .statements
            .get(fact_start..)
            .ok_or(AnalysisFailure::RequestMismatch)?
        {
            check_cancelled(is_cancelled)?;
            effects.0 |= statement.effects.0;
        }
    }
    let mut missing = false;
    for covered in &covered {
        check_cancelled(is_cancelled)?;
        missing |= !covered;
    }
    if missing {
        return Err(runtime_type_diagnostic(
            request,
            fallback_span(request.hir.as_program()),
            "semantic-runtime-match-nonexhaustive",
            "runtime enum match omits a variant",
            "every variant must be covered by an unguarded constructor arm or trailing `_`",
            "add an unguarded arm for the missing variant",
        ));
    }
    Ok(effects)
}

fn analyze_runtime_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression_id: ExpressionId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    check_cancelled(is_cancelled)?;
    let expression = request
        .hir
        .as_program()
        .expression(expression_id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    // A qualified field/reference such as `Inner.a` is a complete value when
    // `a` is a unit variant. Payload-bearing variants routed through this path
    // retain the constructor's named arity rejection; calls continue through
    // `analyze_direct_call` below.
    if let Some(resolved) =
        exact_resolved_enum_constructor(request.hir.as_program(), expression_id, is_cancelled)?
    {
        return analyze_closed_enum_constructor(
            request,
            partial,
            function,
            RuntimeDirectCall {
                expression: expression_id,
                source: expression.source,
                callee: expression_id,
                arguments: &[],
            },
            &resolved,
            expression_request,
            state,
            is_cancelled,
        );
    }
    match &expression.kind {
        ExpressionKind::Literal(literal) => {
            if !matches!(
                expression_request.access,
                AccessMode::Value | AccessMode::Read
            ) {
                return Err(runtime_diagnostic(
                    request,
                    expression.source,
                    "semantic-access-temporary",
                    "mutable or take access requires an owned source value",
                    None,
                    "a literal is a temporary value, not caller-owned mutable storage",
                    "bind the value to a local before requesting mutable or take access",
                ));
            }
            if matches!(literal, Literal::String(_) | Literal::Bytes(_)) {
                if expression_request.expected.is_none()
                    && expression_request.desired_result.is_none()
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        expression.source,
                        "semantic-static-data-consumer-pending",
                        "static literal is used without an inferred local binding",
                        "return, call, storage, capture, send, and discarded expression consumption need an authenticated static-data ABI",
                        "bind the literal to an unannotated synchronous local and leave it unconsumed",
                    ));
                }
                if expression_request.expected.is_some() {
                    return Err(runtime_type_diagnostic(
                        request,
                        expression.source,
                        "semantic-static-data-context-pending",
                        "static literal cannot initialize an explicit runtime value context",
                        "Static[Str] and Static[Bytes[N]] are compiler-minted literal types; no implicit owned String or Bytes conversion is defined",
                        "use an unannotated local binding and do not consume it until static-data lowering lands",
                    ));
                }
                let ty = ensure_static_literal_type(
                    request,
                    partial,
                    literal,
                    &mut *state.aggregate_work,
                    is_cancelled,
                )?;
                let constant = copy_static_literal_constant(request, literal, is_cancelled)?;
                let value = expression_result(
                    request,
                    partial,
                    function,
                    (expression_id, expression.source),
                    ty,
                    expression_request.desired_result,
                    is_cancelled,
                )?;
                append_expression_fact(
                    request,
                    partial,
                    RuntimeExpressionFact {
                        function,
                        expression: expression_id,
                        ty,
                        result: Some(value),
                        resolution: ExpressionResolution::Constant(constant),
                        effects: EffectSet(0),
                        ownership_before: OwnershipState::Owned,
                        ownership_after: OwnershipState::Owned,
                    },
                )?;
                return Ok(RuntimeExpression {
                    ty,
                    result: Some(value),
                    referenced: None,
                    effects: EffectSet(0),
                });
            }
            let ty = match (expression_request.expected, literal) {
                (Some(ty), _) => ty,
                (None, Literal::Unit) => SemanticTypeId(0),
                (None, Literal::Boolean(_)) => ensure_primitive_type(
                    request,
                    partial,
                    PrimitiveSemanticType::Bool,
                    &mut *state.aggregate_work,
                    is_cancelled,
                )?,
                (None, Literal::Integer(_)) => ensure_primitive_type(
                    request,
                    partial,
                    PrimitiveSemanticType::Integer {
                        signed: true,
                        bits: 64,
                        pointer_sized: false,
                    },
                    &mut *state.aggregate_work,
                    is_cancelled,
                )?,
                (None, Literal::Float(_)) => {
                    return Err(runtime_type_diagnostic(
                        request,
                        expression.source,
                        "semantic-float-context-required",
                        "floating literal requires an explicit f32 or f64 context",
                        "revision 0.1 does not silently choose a floating-point width",
                        "bind the literal to a typed local or convert an explicitly typed value",
                    ));
                }
                (None, _) => return Err(AnalysisFailure::RequestMismatch.into()),
            };
            let constant = lower_scalar_literal(request, partial, ty, literal, is_cancelled)
                .map_err(|error| {
                    if error == AnalysisFailure::RequestMismatch {
                        runtime_type_diagnostic(
                            request,
                            expression.source,
                            "semantic-literal-type-mismatch",
                            "literal does not fit its required scalar type",
                            "literal spelling and contextual type must describe one exact value",
                            "change the literal or its explicit scalar type",
                        )
                    } else {
                        RuntimeFailure::Analysis(error)
                    }
                })?;
            let value = expression_result(
                request,
                partial,
                function,
                (expression_id, expression.source),
                ty,
                expression_request.desired_result,
                is_cancelled,
            )?;
            append_expression_fact(
                request,
                partial,
                RuntimeExpressionFact {
                    function,
                    expression: expression_id,
                    ty,
                    result: Some(value),
                    resolution: ExpressionResolution::Constant(constant),
                    effects: EffectSet(0),
                    ownership_before: OwnershipState::Owned,
                    ownership_after: OwnershipState::Owned,
                },
            )?;
            Ok(RuntimeExpression {
                ty,
                result: Some(value),
                referenced: None,
                effects: EffectSet(0),
            })
        }
        ExpressionKind::Reference(Definition::Local(local)) => {
            let slot = state
                .locals
                .get_mut(local.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let binding = slot.as_ref().copied().ok_or_else(|| {
                runtime_diagnostic(
                    request,
                    expression.source,
                    "semantic-use-before-initialize",
                    "local value is used before it is initialized",
                    None,
                    "every local must be initialized on every incoming control-flow path",
                    "initialize the local before this expression",
                )
            })?;
            let inferred_data_kind = partial
                .values
                .get(binding.value.0 as usize)
                .and_then(|value| partial.types.get(value.ty.0 as usize))
                .map(|ty| &ty.kind);
            if inferred_data_kind
                .is_some_and(|kind| matches!(kind, SemanticTypeKind::BoundedString { .. }))
            {
                return Err(runtime_type_diagnostic(
                    request,
                    expression.source,
                    "semantic-bounded-string-consumer-pending",
                    "bounded interpolation result is consumed by an unsupported runtime context",
                    "return, call, storage, capture, send, and discarded-expression consumers need a BoundedString ABI",
                    "leave the inferred bounded string local unconsumed until lowering lands",
                ));
            }
            if inferred_data_kind.is_some_and(|kind| {
                matches!(
                    kind,
                    SemanticTypeKind::StaticString { .. } | SemanticTypeKind::StaticBytes { .. }
                )
            }) {
                return Err(runtime_type_diagnostic(
                    request,
                    expression.source,
                    "semantic-static-data-consumer-pending",
                    "static literal value is consumed by an unsupported runtime context",
                    "return, call, storage, capture, and general expression consumption need an authenticated static-data ABI",
                    "leave the inferred static binding unconsumed until static-data lowering lands",
                ));
            }
            reference_operand(
                request,
                partial,
                (function, expression_id),
                binding,
                expression_request,
                slot,
                is_cancelled,
            )
        }
        ExpressionKind::Reference(Definition::Parameter(parameter)) => {
            let slot = state
                .parameters
                .get_mut(parameter.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let binding = slot
                .as_ref()
                .copied()
                .ok_or(AnalysisFailure::RequestMismatch)?;
            reference_operand(
                request,
                partial,
                (function, expression_id),
                binding,
                expression_request,
                slot,
                is_cancelled,
            )
        }
        ExpressionKind::Call { callee, arguments } => {
            if !matches!(
                expression_request.access,
                AccessMode::Value | AccessMode::Read
            ) {
                return Err(runtime_diagnostic(
                    request,
                    expression.source,
                    "semantic-access-temporary",
                    "mutable or take access requires a named owned value",
                    None,
                    "revision 0.1 does not extend mutable or take access through call temporaries",
                    "bind the call result to a local before transferring it",
                ));
            }
            analyze_direct_call(
                request,
                partial,
                function,
                RuntimeDirectCall {
                    expression: expression_id,
                    source: expression.source,
                    callee: *callee,
                    arguments,
                },
                expression_request,
                state,
                is_cancelled,
            )
        }
        ExpressionKind::Field { base, name } => analyze_flat_structure_field(
            request,
            partial,
            function,
            expression_id,
            expression.source,
            *base,
            name,
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::Unary {
            operator:
                operator @ (wrela_hir::UnaryOperator::Negate
                | wrela_hir::UnaryOperator::BitNot
                | wrela_hir::UnaryOperator::BoolNot
                | wrela_hir::UnaryOperator::Copy),
            operand,
        } => analyze_scalar_unary(
            request,
            partial,
            function,
            RuntimeUnary {
                expression: expression_id,
                source: expression.source,
                operator: *operator,
                operand: *operand,
            },
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::Binary {
            operator,
            left,
            right,
        } if !matches!(
            operator,
            wrela_hir::BinaryOperator::LogicalOr | wrela_hir::BinaryOperator::LogicalAnd
        ) =>
        {
            analyze_scalar_binary(
                request,
                partial,
                function,
                RuntimeBinary {
                    expression: expression_id,
                    source: expression.source,
                    operator: RuntimeBinaryOperator::Arithmetic(*operator),
                    left: *left,
                    right: *right,
                },
                expression_request,
                state,
                is_cancelled,
            )
        }
        ExpressionKind::Compare {
            left,
            operator,
            right,
        } if !matches!(
            operator,
            wrela_hir::ComparisonOperator::In | wrela_hir::ComparisonOperator::NotIn
        ) =>
        {
            analyze_scalar_binary(
                request,
                partial,
                function,
                RuntimeBinary {
                    expression: expression_id,
                    source: expression.source,
                    operator: RuntimeBinaryOperator::Compare(*operator),
                    left: *left,
                    right: *right,
                },
                expression_request,
                state,
                is_cancelled,
            )
        }
        ExpressionKind::Cast { value, ty } => analyze_scalar_cast(
            request,
            partial,
            function,
            RuntimeCast {
                expression: expression_id,
                source: expression.source,
                value: *value,
                destination: ty,
            },
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::Unary {
            operator: wrela_hir::UnaryOperator::Await,
            operand,
        } => analyze_await_expression(
            request,
            partial,
            function,
            RuntimeAwait {
                expression: expression_id,
                source: expression.source,
                operand: *operand,
            },
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::Try(operand) => analyze_result_try_expression(
            request,
            partial,
            function,
            expression_id,
            expression.source,
            *operand,
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::TrySend(operand) => analyze_actor_try_send_expression(
            request,
            partial,
            function,
            expression_id,
            expression.source,
            *operand,
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::IsPattern {
            value,
            negated: _,
            pattern,
        } => analyze_closed_enum_is_pattern(
            request,
            partial,
            function,
            expression_id,
            expression.source,
            *value,
            *pattern,
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::DotName { candidates, .. } => {
            let resolved = resolve_dot_variant_candidate(
                request,
                partial,
                candidates,
                expression_request.expected,
                expression.source,
            )?;
            analyze_closed_enum_constructor(
                request,
                partial,
                function,
                RuntimeDirectCall {
                    expression: expression_id,
                    source: expression.source,
                    callee: expression_id,
                    arguments: &[],
                },
                &resolved,
                expression_request,
                state,
                is_cancelled,
            )
        }
        ExpressionKind::If {
            condition,
            then_branch,
            elif_branches,
            else_branch,
        } => analyze_inline_if_expression(
            request,
            partial,
            function,
            expression_id,
            expression.source,
            *condition,
            *then_branch,
            elif_branches,
            *else_branch,
            expression_request,
            state,
            is_cancelled,
        ),
        ExpressionKind::Interpolate(parts) => analyze_bounded_interpolation(
            request,
            partial,
            function,
            expression_id,
            expression.source,
            parts,
            expression_request,
            state,
            is_cancelled,
        ),
        _ => Err(AnalysisFailure::RequestMismatch.into()),
    }
}

#[allow(clippy::too_many_arguments)]
fn analyze_bounded_interpolation(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression: ExpressionId,
    source: Span,
    parts: &[wrela_hir::InterpolationPart],
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    require_scalar_temporary_access(request, source, expression_request.access)?;
    if expression_request.expected.is_some() {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-bounded-interpolation-context-pending",
            "bounded interpolation cannot satisfy an explicit runtime type context",
            "the exact BoundedString capacity is compiler-minted only for an inferred local",
            "bind directly to an unannotated synchronous local",
        ));
    }
    if expression_request.desired_result.is_none() {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-bounded-string-consumer-pending",
            "bounded interpolation is consumed outside its admitted local binding",
            "return, call, storage, capture, send, and discarded-expression consumers need a BoundedString ABI",
            "bind to an unannotated synchronous local and leave the result unconsumed",
        ));
    }
    if partial
        .functions
        .get(function.0 as usize)
        .is_some_and(|function| matches!(function.role, FunctionRole::Isr(_)))
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-bounded-interpolation-isr",
            "bounded interpolation is forbidden in an interrupt handler",
            "formatting work and destination storage are not admitted in ISR context",
            "compute the bounded string in ordinary synchronous code",
        ));
    }
    let ty = ensure_bounded_interpolation_type(
        request,
        partial,
        parts,
        source,
        &*state.locals,
        &*state.parameters,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    let capacity = partial
        .types
        .get(ty.0 as usize)
        .and_then(|record| match record.kind {
            SemanticTypeKind::BoundedString { capacity } => Some(capacity),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut resolved = Vec::new();
    resolved
        .try_reserve(parts.len())
        .map_err(|_| fact_resource(request, "bounded interpolation parts"))?;
    let mut effects = EffectSet(0);
    for part in parts {
        check_cancelled(is_cancelled)?;
        match part {
            wrela_hir::InterpolationPart::Text { value, source } => {
                resolved.push(BoundedInterpolationPart::Text {
                    value: copy_analysis_text(value, request.limits.fact_bytes, is_cancelled)?,
                    source: *source,
                });
            }
            wrela_hir::InterpolationPart::Value {
                expression: child,
                format: None,
                format_source: None,
            } => {
                let child_record = request
                    .hir
                    .as_program()
                    .expression(*child)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let (value_ty, maximum_bytes) = bounded_interpolation_value_type(
                    request,
                    partial,
                    *child,
                    &*state.locals,
                    &*state.parameters,
                    &mut *state.aggregate_work,
                    is_cancelled,
                )?;
                let value_kind = partial
                    .types
                    .get(value_ty.0 as usize)
                    .map(|ty| &ty.kind)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let outcome = if matches!(value_kind, SemanticTypeKind::StaticString { .. }) {
                    analyze_bounded_static_string_value(
                        request,
                        partial,
                        function,
                        *child,
                        value_ty,
                        state,
                        is_cancelled,
                    )?
                } else {
                    analyze_runtime_expression(
                        request,
                        partial,
                        function,
                        *child,
                        RuntimeExpressionRequest {
                            expected: Some(value_ty),
                            desired_result: None,
                            access: AccessMode::Value,
                        },
                        state,
                        is_cancelled,
                    )?
                };
                if outcome.ty != value_ty {
                    return Err(runtime_type_diagnostic(
                        request,
                        child_record.source,
                        "semantic-bounded-interpolation-value-type",
                        "bounded interpolation value is not an admitted bounded value",
                        "this slice proves exact capacity only for core bool, char, primitive integer, and Static[Str] values",
                        "interpolate a bool, char, primitive integer, or exact static string without a format specifier",
                    ));
                }
                let value = outcome
                    .referenced
                    .or(outcome.result)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                effects.0 |= outcome.effects.0;
                let value_kind = partial
                    .types
                    .get(value_ty.0 as usize)
                    .map(|ty| &ty.kind)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if matches!(value_kind, SemanticTypeKind::Bool) {
                    resolved.push(BoundedInterpolationPart::Bool {
                        expression: *child,
                        value,
                    });
                } else if matches!(value_kind, SemanticTypeKind::Character) {
                    resolved.push(BoundedInterpolationPart::Character {
                        expression: *child,
                        value,
                    });
                } else if matches!(value_kind, SemanticTypeKind::StaticString { .. }) {
                    resolved.push(BoundedInterpolationPart::StaticString {
                        expression: *child,
                        value,
                        ty: value_ty,
                    });
                } else {
                    resolved.push(BoundedInterpolationPart::Integer {
                        expression: *child,
                        value,
                        ty: value_ty,
                        maximum_bytes,
                    });
                }
            }
            wrela_hir::InterpolationPart::Value { format_source, .. } => {
                return Err(runtime_type_diagnostic(
                    request,
                    format_source.unwrap_or(source),
                    "semantic-bounded-interpolation-format-pending",
                    "bounded interpolation does not admit a format specifier",
                    "the exact capacity proof currently uses canonical boolean, character, decimal integer, and verbatim static-string spelling only",
                    "remove the format specifier",
                ));
            }
        }
    }
    let result = expression_result(
        request,
        partial,
        function,
        (expression, source),
        ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression,
            ty,
            result: Some(result),
            resolution: ExpressionResolution::BoundedInterpolation {
                capacity,
                parts: resolved,
            },
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

#[allow(clippy::too_many_arguments)]
fn analyze_bounded_static_string_value(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression: ExpressionId,
    expected: SemanticTypeId,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    check_cancelled(is_cancelled)?;
    let expression_record = request
        .hir
        .as_program()
        .expression(expression)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    match &expression_record.kind {
        ExpressionKind::Literal(literal @ Literal::String(_)) => {
            let ty = ensure_static_literal_type(
                request,
                partial,
                literal,
                &mut *state.aggregate_work,
                is_cancelled,
            )?;
            if ty != expected {
                return Err(AnalysisFailure::RequestMismatch.into());
            }
            let constant = copy_static_literal_constant(request, literal, is_cancelled)?;
            let value = expression_result(
                request,
                partial,
                function,
                (expression, expression_record.source),
                ty,
                None,
                is_cancelled,
            )?;
            append_expression_fact(
                request,
                partial,
                RuntimeExpressionFact {
                    function,
                    expression,
                    ty,
                    result: Some(value),
                    resolution: ExpressionResolution::Constant(constant),
                    effects: EffectSet(0),
                    ownership_before: OwnershipState::Owned,
                    ownership_after: OwnershipState::Owned,
                },
            )?;
            Ok(RuntimeExpression {
                ty,
                result: Some(value),
                referenced: None,
                effects: EffectSet(0),
            })
        }
        ExpressionKind::Reference(Definition::Local(local)) => {
            let slot = state
                .locals
                .get_mut(local.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let binding = slot
                .as_ref()
                .copied()
                .ok_or(AnalysisFailure::RequestMismatch)?;
            reference_operand(
                request,
                partial,
                (function, expression),
                binding,
                RuntimeExpressionRequest {
                    expected: Some(expected),
                    desired_result: None,
                    access: AccessMode::Read,
                },
                slot,
                is_cancelled,
            )
        }
        ExpressionKind::Reference(Definition::Parameter(parameter)) => {
            let slot = state
                .parameters
                .get_mut(parameter.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let binding = slot
                .as_ref()
                .copied()
                .ok_or(AnalysisFailure::RequestMismatch)?;
            reference_operand(
                request,
                partial,
                (function, expression),
                binding,
                RuntimeExpressionRequest {
                    expected: Some(expected),
                    desired_result: None,
                    access: AccessMode::Read,
                },
                slot,
                is_cancelled,
            )
        }
        _ => Err(AnalysisFailure::RequestMismatch.into()),
    }
}

fn ensure_static_literal_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    literal: &Literal,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    check_cancelled(is_cancelled)?;
    let bytes = match literal {
        Literal::String(value) => u64::try_from(value.len()),
        Literal::Bytes(value) => u64::try_from(value.len()),
        _ => return Err(AnalysisFailure::RequestMismatch.into()),
    }
    .map_err(|_| semantic_fact_bytes_resource(request))?;
    if bytes > request.limits.fact_bytes {
        return Err(semantic_fact_bytes_resource(request).into());
    }
    let kind = match literal {
        Literal::String(_) => SemanticTypeKind::StaticString { bytes },
        Literal::Bytes(_) => SemanticTypeKind::StaticBytes { bytes },
        _ => return Err(AnalysisFailure::RequestMismatch.into()),
    };
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
        if existing.kind == kind {
            return Ok(existing.id);
        }
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind,
        linearity: Linearity::ExplicitCopy,
        size_upper_bound: None,
        alignment_lower_bound: 1,
        source: None,
    });
    Ok(id)
}

#[allow(clippy::too_many_arguments)]
fn ensure_bounded_interpolation_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    parts: &[wrela_hir::InterpolationPart],
    source: Span,
    locals: &[Option<RuntimeBinding>],
    parameters: &[Option<RuntimeBinding>],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    check_cancelled(is_cancelled)?;
    let mut capacity = 0_u64;
    let mut value_count = 0_u64;
    for part in parts {
        check_cancelled(is_cancelled)?;
        match part {
            wrela_hir::InterpolationPart::Text { value, .. } => {
                let bytes = u64::try_from(value.len())
                    .map_err(|_| semantic_fact_bytes_resource(request))?;
                capacity = capacity
                    .checked_add(bytes)
                    .ok_or_else(|| semantic_fact_bytes_resource(request))?;
            }
            wrela_hir::InterpolationPart::Value {
                expression,
                format,
                format_source,
                ..
            } => {
                if format.is_some() || format_source.is_some() {
                    return Err(runtime_type_diagnostic(
                        request,
                        format_source.unwrap_or(source),
                        "semantic-bounded-interpolation-format-pending",
                        "bounded interpolation does not admit a format specifier",
                        "the exact capacity proof currently uses canonical boolean, character, decimal integer, and verbatim static-string spelling only",
                        "remove the format specifier",
                    ));
                }
                let (_, maximum_bytes) = bounded_interpolation_value_type(
                    request,
                    partial,
                    *expression,
                    locals,
                    parameters,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                capacity = capacity
                    .checked_add(maximum_bytes)
                    .ok_or_else(|| semantic_fact_bytes_resource(request))?;
                value_count = value_count.saturating_add(1);
            }
        }
        if capacity > request.limits.fact_bytes {
            return Err(semantic_fact_bytes_resource(request).into());
        }
    }
    if value_count == 0 {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-bounded-interpolation-value-required",
            "bounded interpolation requires at least one formatted value",
            "plain text already has the exact Static[Str] literal representation",
            "use a plain string literal or interpolate a bool, char, primitive integer, or exact static string",
        ));
    }
    let kind = SemanticTypeKind::BoundedString { capacity };
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
        if existing.kind == kind {
            return Ok(existing.id);
        }
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind,
        linearity: Linearity::ReclaimableLinear,
        size_upper_bound: None,
        alignment_lower_bound: 1,
        source: None,
    });
    Ok(id)
}

#[allow(clippy::too_many_arguments)]
fn bounded_interpolation_value_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    expression: ExpressionId,
    locals: &[Option<RuntimeBinding>],
    parameters: &[Option<RuntimeBinding>],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<(SemanticTypeId, u64)> {
    check_cancelled(is_cancelled)?;
    let expression_record = request
        .hir
        .as_program()
        .expression(expression)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if matches!(
        expression_record.kind,
        ExpressionKind::Literal(Literal::Unit | Literal::Float(_) | Literal::Bytes(_))
    ) {
        return Err(runtime_type_diagnostic(
            request,
            expression_record.source,
            "semantic-bounded-interpolation-value-type",
            "bounded interpolation value is not an admitted bounded value",
            "this slice proves exact capacity only for core bool, char, primitive integer, and Static[Str] values",
            "interpolate a bool, char, primitive integer, or exact static string without a format specifier",
        ));
    }
    let known = match &expression_record.kind {
        ExpressionKind::Literal(Literal::Boolean(_))
        | ExpressionKind::Compare { .. }
        | ExpressionKind::IsPattern { .. }
        | ExpressionKind::Unary {
            operator: wrela_hir::UnaryOperator::BoolNot,
            ..
        }
        | ExpressionKind::Binary {
            operator: wrela_hir::BinaryOperator::LogicalAnd | wrela_hir::BinaryOperator::LogicalOr,
            ..
        } => Some(ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Bool,
            &mut *aggregate_work,
            is_cancelled,
        )?),
        ExpressionKind::Literal(Literal::Integer(_)) => Some(ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Integer {
                signed: true,
                bits: 64,
                pointer_sized: false,
            },
            &mut *aggregate_work,
            is_cancelled,
        )?),
        ExpressionKind::Literal(Literal::Character(_)) => Some(ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Character,
            &mut *aggregate_work,
            is_cancelled,
        )?),
        ExpressionKind::Literal(literal @ Literal::String(_)) => Some(ensure_static_literal_type(
            request,
            partial,
            literal,
            &mut *aggregate_work,
            is_cancelled,
        )?),
        ExpressionKind::Unary {
            operator: wrela_hir::UnaryOperator::Negate,
            operand,
        } if request
            .hir
            .as_program()
            .expression(*operand)
            .is_some_and(|operand| {
                matches!(operand.kind, ExpressionKind::Literal(Literal::Integer(_)))
            }) =>
        {
            Some(ensure_primitive_type(
                request,
                partial,
                PrimitiveSemanticType::Integer {
                    signed: true,
                    bits: 64,
                    pointer_sized: false,
                },
                &mut *aggregate_work,
                is_cancelled,
            )?)
        }
        ExpressionKind::Reference(Definition::Local(local)) => locals
            .get(local.0 as usize)
            .and_then(|binding| *binding)
            .and_then(|binding| partial.values.get(binding.value.0 as usize))
            .map(|value| value.ty),
        ExpressionKind::Reference(Definition::Parameter(parameter)) => parameters
            .get(parameter.0 as usize)
            .and_then(|binding| *binding)
            .and_then(|binding| partial.values.get(binding.value.0 as usize))
            .map(|value| value.ty),
        _ => None,
    };
    let Some(ty) = known else {
        return Err(runtime_type_diagnostic(
            request,
            expression_record.source,
            "semantic-bounded-interpolation-expression-pending",
            "bounded interpolation expression is outside the admitted bounded subset",
            "this analysis increment accepts boolean expressions, supported scalar literals, exact static strings, and direct supported bindings",
            "bind the value to a bool, char, primitive integer, or exact static string local before interpolating it",
        ));
    };
    let maximum_bytes = partial
        .types
        .get(ty.0 as usize)
        .and_then(|ty| bounded_interpolation_maximum_bytes(&ty.kind))
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                expression_record.source,
                "semantic-bounded-interpolation-value-type",
                "bounded interpolation value is not an admitted bounded value",
                "this slice proves exact capacity only for core bool, char, primitive integer, and Static[Str] values",
                "interpolate a bool, char, primitive integer, or exact static string without a format specifier",
            )
        })?;
    Ok((ty, maximum_bytes))
}

fn copy_static_literal_constant(
    request: &AnalysisRequest<'_>,
    literal: &Literal,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ConstantValue, AnalysisFailure> {
    match literal {
        Literal::String(value) => Ok(ConstantValue::String(copy_analysis_text(
            value,
            request.limits.fact_bytes,
            is_cancelled,
        )?)),
        Literal::Bytes(value) => {
            check_cancelled(is_cancelled)?;
            if u64::try_from(value.len()).map_or(true, |bytes| bytes > request.limits.fact_bytes) {
                return Err(semantic_fact_bytes_resource(request));
            }
            let mut copy = Vec::new();
            copy.try_reserve_exact(value.len())
                .map_err(|_| semantic_fact_bytes_resource(request))?;
            for chunk in value.chunks(COMPTIME_SOURCE_COPY_CHUNK_BYTES) {
                check_cancelled(is_cancelled)?;
                copy.extend_from_slice(chunk);
            }
            Ok(ConstantValue::Bytes(copy))
        }
        _ => Err(AnalysisFailure::RequestMismatch),
    }
}

#[allow(clippy::too_many_arguments)]
fn analyze_closed_enum_is_pattern(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression: ExpressionId,
    source: Span,
    value: ExpressionId,
    pattern: wrela_hir::PatternId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    require_scalar_temporary_access(request, source, expression_request.access)?;
    let scrutinee = analyze_runtime_expression(
        request,
        partial,
        function,
        value,
        RuntimeExpressionRequest {
            expected: None,
            desired_result: None,
            access: AccessMode::Read,
        },
        state,
        is_cancelled,
    )?;
    let enumeration_ty = scrutinee.ty;
    let enumeration = partial
        .types
        .get(scrutinee.ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Enumeration {
                declaration,
                variants,
                ..
            } if !variants.is_empty() => Some(*declaration),
            _ => None,
        })
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-is-scrutinee",
                "runtime `is` requires a supported closed enum",
                "the admitted pattern test dispatches on one canonical enum tag",
                "test a closed enum value with supported copy-scalar type arguments",
            )
        })?;
    let pattern = request
        .hir
        .as_program()
        .patterns
        .get(pattern.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let [alternative] = pattern.alternatives.as_slice() else {
        return Err(runtime_type_diagnostic(
            request,
            pattern.source,
            "semantic-runtime-is-pattern-shape",
            "runtime `is` requires one constructor pattern",
            "pattern alternatives are not one exact enum-tag test",
            "test one explicit enum variant",
        ));
    };
    let wrela_hir::PrimaryPattern::Constructor {
        candidates,
        arguments,
        ..
    } = &alternative.kind
    else {
        return Err(runtime_type_diagnostic(
            request,
            alternative.source,
            "semantic-runtime-is-pattern-shape",
            "runtime `is` requires an explicit enum constructor pattern",
            "wildcard, literal, binding-only, tuple, and array tests are outside this ADT slice",
            "name one declared enum variant",
        ));
    };
    let [candidate] = candidates.as_slice() else {
        return Err(runtime_type_diagnostic(
            request,
            alternative.source,
            "semantic-runtime-is-pattern-shape",
            "runtime `is` constructor is ambiguous or unresolved",
            "tag testing requires one exact declaration and variant identity",
            "qualify one visible enum variant",
        ));
    };
    if candidate.enumeration.declaration != enumeration {
        return Err(runtime_type_diagnostic(
            request,
            alternative.source,
            "semantic-runtime-is-pattern-type",
            "runtime `is` pattern belongs to a different enum",
            "closed enum identities are never substituted by layout",
            "test a variant declared by the scrutinee enum",
        ));
    }
    let payload_ty = partial
        .types
        .get(scrutinee.ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Enumeration { variants, .. } => variants
                .get(candidate.variant as usize)
                .map(|variant| variant.fields.first().map(|field| field.ty)),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    match payload_ty {
        None if arguments.is_empty() => {}
        None => {
            return Err(runtime_type_diagnostic(
                request,
                alternative.source,
                "semantic-runtime-is-pattern-shape",
                "unit enum variant has no payload to test",
                "this variant declares no payload fields",
                "remove the payload pattern",
            ));
        }
        Some(_) => {
            let [argument] = arguments.as_slice() else {
                return Err(runtime_type_diagnostic(
                    request,
                    alternative.source,
                    "semantic-runtime-is-pattern-shape",
                    "payload enum variant requires one payload pattern",
                    "this variant declares exactly one payload field",
                    "use `_` when only the variant tag matters",
                ));
            };
            if argument.take {
                return Err(runtime_type_diagnostic(
                    request,
                    argument.source,
                    "semantic-runtime-is-pattern-shape",
                    "runtime `is` cannot take a payload",
                    "a boolean pattern test does not transfer payload ownership",
                    "remove `take` from the payload pattern",
                ));
            }
            let payload = request
                .hir
                .as_program()
                .patterns
                .get(argument.pattern.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let [payload_alternative] = payload.alternatives.as_slice() else {
                return Err(AnalysisFailure::RequestMismatch.into());
            };
            if !matches!(
                payload_alternative.kind,
                wrela_hir::PrimaryPattern::Wildcard
            ) {
                return Err(runtime_type_diagnostic(
                    request,
                    payload_alternative.source,
                    "semantic-runtime-is-binding-pending",
                    "runtime `is` payload bindings are not yet supported",
                    "this slice admits tag tests; success-dominated payload bindings require branch-local flow facts",
                    "use `_` to test only the variant tag, or use exhaustive `match` to bind the payload",
                ));
            }
        }
    }
    let bool_ty = ensure_primitive_type(
        request,
        partial,
        PrimitiveSemanticType::Bool,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    if expression_request
        .expected
        .is_some_and(|expected| expected != bool_ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-is-result",
            "runtime `is` produces bool",
            "pattern tests have one fixed boolean result type",
            "use the test in a boolean context",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (expression, source),
        bool_ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression,
            ty: bool_ty,
            result: Some(result),
            resolution: ExpressionResolution::EnumTypeTest {
                enumeration: enumeration_ty,
                variant: candidate.variant,
                scrutinee: scrutinee
                    .referenced
                    .or(scrutinee.result)
                    .ok_or(AnalysisFailure::RequestMismatch)?,
            },
            effects: scrutinee.effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: bool_ty,
        result: Some(result),
        referenced: None,
        effects: scrutinee.effects,
    })
}

#[allow(clippy::too_many_arguments)]
fn analyze_result_try_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression: ExpressionId,
    source: Span,
    operand: ExpressionId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    if !matches!(
        expression_request.access,
        AccessMode::Value | AccessMode::Read
    ) {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-access",
            "postfix question produces a temporary payload value",
            "mutable and take access cannot target the branch-merged result of propagation",
            "bind the propagated payload before requesting exclusive access",
        ));
    }
    let named_operand = request
        .hir
        .as_program()
        .expression(operand)
        .and_then(|operand| match operand.kind {
            ExpressionKind::Reference(Definition::Local(local)) => state
                .locals
                .get(local.0 as usize)
                .and_then(Option::as_ref)
                .copied(),
            ExpressionKind::Reference(Definition::Parameter(parameter)) => state
                .parameters
                .get(parameter.0 as usize)
                .and_then(Option::as_ref)
                .copied(),
            _ => None,
        });
    if let Some(kind) = named_operand
        .and_then(|binding| partial.values.get(binding.value.0 as usize))
        .and_then(|value| match value.class {
            SemanticValueClass::Ephemeral(kind) if !kind.permits(EphemeralUse::Question) => {
                Some(kind)
            }
            _ => None,
        })
    {
        return Err(ephemeral_question_diagnostic(request, source, kind));
    }
    if request
        .hir
        .as_program()
        .expression(operand)
        .is_some_and(|operand| {
            matches!(
                operand.kind,
                ExpressionKind::Reference(Definition::Local(_) | Definition::Parameter(_))
                    | ExpressionKind::Field { .. }
            )
        })
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-rvalue-required",
            "postfix question requires an owned Result rvalue",
            "named-place consumption and its cleanup semantics are outside this bounded slice",
            "propagate a freshly returned or constructed Result value",
        ));
    }
    let program = request.hir.as_program();
    let contextual_constructor = program
        .expression(operand)
        .is_some_and(|operand| match &operand.kind {
            ExpressionKind::Reference(Definition::Variant(_)) | ExpressionKind::DotName { .. } => {
                true
            }
            ExpressionKind::Call { callee, .. } => {
                program.expression(*callee).is_some_and(|callee| {
                    matches!(
                        callee.kind,
                        ExpressionKind::Reference(Definition::Variant(_))
                            | ExpressionKind::DotName { .. }
                    )
                })
            }
            _ => false,
        });
    let constructor_context = contextual_constructor
        .then(|| {
            partial
                .functions
                .get(function.0 as usize)
                .map(|function| function.result)
        })
        .flatten();
    let operand_outcome = analyze_runtime_expression(
        request,
        partial,
        function,
        operand,
        RuntimeExpressionRequest {
            expected: constructor_context,
            desired_result: None,
            access: AccessMode::Value,
        },
        state,
        is_cancelled,
    )?;
    if let Some(kind) = operand_outcome
        .result
        .and_then(|value| partial.values.get(value.0 as usize))
        .and_then(|value| match value.class {
            SemanticValueClass::Ephemeral(kind) if !kind.permits(EphemeralUse::Question) => {
                Some(kind)
            }
            _ => None,
        })
    {
        return Err(ephemeral_question_diagnostic(request, source, kind));
    }
    if operand_outcome.result.is_none() || operand_outcome.referenced.is_some() {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-rvalue-required",
            "postfix question requires an owned Result rvalue",
            "named-place consumption and its cleanup semantics are outside this bounded slice",
            "propagate a freshly returned or constructed Result value",
        ));
    }
    let result_type = operand_outcome.ty;
    let Some(result_record) = partial.types.get(result_type.0 as usize) else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let SemanticTypeKind::Enumeration {
        declaration,
        arguments,
        variants,
    } = &result_record.kind
    else {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-result-required",
            "postfix question operand is not the authenticated core Result specialization",
            "R3 accepts only owned rvalues of core.result.Result[T, E]",
            "return or construct a supported core Result value before applying `?`",
        ));
    };
    let result_declaration = request
        .hir
        .as_program()
        .declaration(*declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let result_module = request
        .hir
        .as_program()
        .modules
        .get(result_declaration.module.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let resolved = wrela_hir::ResolvedDeclaration {
        package: result_module.package,
        module: result_declaration.module,
        declaration: *declaration,
    };
    let option_supported = is_exact_core_option_declaration(request, &resolved, result_declaration)
        && matches!(arguments.as_slice(), [SemanticArgument::Type(_)])
        && matches!(variants.as_slice(), [some, none]
            if some.name == "Some"
                && matches!(some.fields.as_slice(), [field]
                    if matches!(arguments.as_slice(), [SemanticArgument::Type(argument)]
                        if field.ty == *argument))
                && none.name == "None"
                && none.fields.is_empty());
    if option_supported {
        let payload_type = variants[0].fields[0].ty;
        if runtime_scalar_type(partial, payload_type).is_none() {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-option-question-payload",
                "postfix question Option payload is outside the supported scalar subset",
                "linear, nominal, and aggregate propagation require cleanup-aware Option semantics",
                "use Option[S] with a supported stored copy scalar S",
            ));
        }
        let enclosing_result = partial
            .functions
            .get(function.0 as usize)
            .map(|function| function.result)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if enclosing_result != result_type {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-option-question-enclosing",
                "postfix question requires the enclosing function to return the same Option type",
                "the None branch returns early without conversion",
                "change the function result to the exact operand Option[S] specialization",
            ));
        }
        if expression_request
            .expected
            .is_some_and(|expected| expected != payload_type)
        {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-option-question-payload",
                "postfix question Option payload does not match its required context",
                "the Some branch yields the exact scalar stored by Option[S]",
                "use the propagated scalar directly or change the surrounding type",
            ));
        }
        let some_payload = append_semantic_value(
            request,
            partial,
            function,
            payload_type,
            (
                SemanticValueOrigin::Expression(expression),
                Some(source),
                None,
            ),
            is_cancelled,
        )?;
        let propagated = append_semantic_value(
            request,
            partial,
            function,
            result_type,
            (
                SemanticValueOrigin::Expression(expression),
                Some(source),
                None,
            ),
            is_cancelled,
        )?;
        let result = expression_result(
            request,
            partial,
            function,
            (expression, source),
            payload_type,
            expression_request.desired_result,
            is_cancelled,
        )?;
        append_expression_fact(
            request,
            partial,
            RuntimeExpressionFact {
                function,
                expression,
                ty: payload_type,
                result: Some(result),
                resolution: ExpressionResolution::OptionTry {
                    option_type: result_type,
                    some_variant: 0,
                    none_variant: 1,
                    some_payload,
                    propagated,
                },
                effects: operand_outcome.effects,
                ownership_before: OwnershipState::Owned,
                ownership_after: OwnershipState::Owned,
            },
        )?;
        return Ok(RuntimeExpression {
            ty: payload_type,
            result: Some(result),
            referenced: None,
            effects: operand_outcome.effects,
        });
    }
    let supported = is_exact_core_result_declaration(request, &resolved, result_declaration)
        && matches!(arguments.as_slice(), [SemanticArgument::Type(ok), SemanticArgument::Type(err)]
            if runtime_scalar_type(partial, *ok).is_some()
                && runtime_scalar_type(partial, *err).is_some())
        && matches!(variants.as_slice(), [ok, err]
            if ok.name == "Ok"
                && err.name == "Err"
                && matches!((ok.fields.as_slice(), err.fields.as_slice()), ([ok_field], [err_field])
                    if matches!(arguments.as_slice(), [SemanticArgument::Type(ok), SemanticArgument::Type(err)]
                        if ok_field.ty == *ok && err_field.ty == *err)));
    if !supported {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-result-required",
            "postfix question operand is not the authenticated core Result specialization",
            "R3 accepts only exact core.result.Result[T, E] with its canonical Ok and Err variants",
            "use the supported core Result declaration with two stored copy-scalar payloads",
        ));
    }
    let ok_payload_type = variants[0].fields[0].ty;
    let err_payload_type = variants[1].fields[0].ty;
    if runtime_scalar_type(partial, ok_payload_type).is_none()
        || runtime_scalar_type(partial, err_payload_type).is_none()
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-result-required",
            "postfix question Result payload is outside the supported scalar subset",
            "linear, nominal, and aggregate propagation require later cleanup semantics",
            "use Result[T, E] with supported copy scalars T and E",
        ));
    }
    let enclosing_result = partial
        .functions
        .get(function.0 as usize)
        .map(|function| function.result)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if enclosing_result != result_type {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-enclosing-result",
            "postfix question requires the enclosing function to return the same Result type",
            "the Err branch returns early without conversion or From semantics",
            "change the function result to the exact operand Result[T, E] specialization",
        ));
    }
    if expression_request
        .expected
        .is_some_and(|expected| expected != ok_payload_type)
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-try-result-required",
            "postfix question payload does not match its required context",
            "the Ok branch yields the exact T scalar stored by Result[T, E]",
            "use the propagated scalar directly or change the surrounding type",
        ));
    }
    let append_internal = |partial: &mut PartialAnalysis, ty| {
        append_semantic_value(
            request,
            partial,
            function,
            ty,
            (
                SemanticValueOrigin::Expression(expression),
                Some(source),
                None,
            ),
            is_cancelled,
        )
    };
    let ok_payload = append_internal(partial, ok_payload_type)?;
    let err_payload = append_internal(partial, err_payload_type)?;
    let propagated = append_internal(partial, result_type)?;
    let result = expression_result(
        request,
        partial,
        function,
        (expression, source),
        ok_payload_type,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression,
            ty: ok_payload_type,
            result: Some(result),
            resolution: ExpressionResolution::ResultTry {
                result_type,
                ok_variant: 0,
                err_variant: 1,
                ok_payload,
                err_payload,
                propagated,
            },
            effects: operand_outcome.effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: ok_payload_type,
        result: Some(result),
        referenced: None,
        effects: operand_outcome.effects,
    })
}

fn ephemeral_question_diagnostic(
    request: &AnalysisRequest<'_>,
    source: Span,
    kind: EphemeralKind,
) -> RuntimeFailure {
    let message = match kind {
        EphemeralKind::View => "postfix question is not a permitted consumer for an ephemeral view",
        EphemeralKind::ProjectionCarrier => {
            "postfix question is not a permitted consumer for this projection carrier"
        }
        EphemeralKind::AdmissionResult => {
            "postfix question is not a permitted consumer for ephemeral AdmissionResult"
        }
        EphemeralKind::AsyncOutcome => {
            "postfix question is not a permitted consumer for a structured async outcome"
        }
        EphemeralKind::OwnershipConditionedActorCallOutcome => {
            "postfix question is not a permitted consumer for this ownership-conditioned outcome"
        }
    };
    runtime_type_diagnostic(
        request,
        source,
        "semantic-ephemeral-question-forbidden",
        message,
        "ephemeral carriers have an explicit, closed consumption policy",
        "consume this carrier with one of its permitted immediate forms",
    )
}

#[allow(clippy::too_many_arguments)]
fn analyze_actor_try_send_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression: ExpressionId,
    source: Span,
    operand: ExpressionId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    check_cancelled(is_cancelled)?;
    let usage = exact_admission_result_use(request, expression, is_cancelled)?;
    if !matches!(
        usage,
        EphemeralUse::PatternMatch | EphemeralUse::TypeTest | EphemeralUse::Question
    ) {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-admission-result-consumer-pending",
            "try send AdmissionResult is not consumed by an admitted immediate form",
            "this bounded slice accepts the producer only as the direct scrutinee of match or is; postfix question reaches its dedicated ephemeral rejection",
            "consume `try send` directly with exhaustive match or an is-pattern",
        ));
    }
    if !matches!(
        expression_request.access,
        AccessMode::Value | AccessMode::Read
    ) || expression_request.desired_result.is_some()
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-admission-result-consumer-pending",
            "try send AdmissionResult cannot be stored or granted place access",
            "AdmissionResult is an ephemeral control-flow carrier without persistent storage",
            "consume `try send` directly with exhaustive match or an is-pattern",
        ));
    }
    let resolved = resolve_self_actor_send(request, partial, function, operand, is_cancelled)?;
    let request_outcome =
        analyze_actor_send_expression(request, partial, function, operand, state, is_cancelled)?;
    if request_outcome.effects != EffectSet(EffectSet::ACTOR) {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let ty = ensure_core_admission_result_type(
        request,
        partial,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    if expression_request
        .expected
        .is_some_and(|expected| expected != ty)
    {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let result = expression_result(
        request,
        partial,
        function,
        (expression, source),
        ty,
        None,
        is_cancelled,
    )?;
    partial
        .values
        .get_mut(result.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .class = SemanticValueClass::Ephemeral(EphemeralKind::AdmissionResult);
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression,
            ty,
            result: Some(result),
            resolution: ExpressionResolution::Builtin(IntrinsicOperation::ActorTrySend {
                actor: resolved.actor,
            }),
            effects: EffectSet(EffectSet::ACTOR),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty,
        result: Some(result),
        referenced: None,
        effects: EffectSet(EffectSet::ACTOR),
    })
}

fn exact_admission_result_use(
    request: &AnalysisRequest<'_>,
    expression: ExpressionId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<EphemeralUse, AnalysisFailure> {
    let program = request.hir.as_program();
    let mut usage = None;
    let mut record = |candidate| -> Result<(), AnalysisFailure> {
        if usage.replace(candidate).is_some() {
            return Err(AnalysisFailure::RequestMismatch);
        }
        Ok(())
    };
    for statement in &program.statements {
        check_cancelled(is_cancelled)?;
        if matches!(statement.kind, StatementKind::Match { scrutinee, .. } if scrutinee == expression)
        {
            record(EphemeralUse::PatternMatch)?;
        }
    }
    for parent in &program.expressions {
        check_cancelled(is_cancelled)?;
        match parent.kind {
            ExpressionKind::IsPattern { value, .. } if value == expression => {
                record(EphemeralUse::TypeTest)?;
            }
            ExpressionKind::Try(operand) if operand == expression => {
                record(EphemeralUse::Question)?;
            }
            _ => {}
        }
    }
    Ok(usage.unwrap_or(EphemeralUse::DirectBinding))
}

fn exact_async_outcome_use(
    request: &AnalysisRequest<'_>,
    expression: ExpressionId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<EphemeralUse, AnalysisFailure> {
    let usage = exact_admission_result_use(request, expression, is_cancelled)?;
    if usage == EphemeralUse::PatternMatch
        && !exact_async_outcome_nested_match(request.hir.as_program(), expression)
    {
        return Ok(EphemeralUse::DirectBinding);
    }
    Ok(usage)
}

fn exact_async_outcome_nested_match(
    program: &wrela_hir::Program,
    expression: ExpressionId,
) -> bool {
    let mut matches = program
        .statements
        .iter()
        .filter_map(|statement| match &statement.kind {
            StatementKind::Match { scrutinee, arms } if *scrutinee == expression => Some(arms),
            _ => None,
        });
    let Some(arms) = matches.next() else {
        return false;
    };
    if matches.next().is_some() || arms.len() != 2 {
        return false;
    }
    let mut ok_seen = false;
    let mut err_binding = None;
    let mut err_body = None;
    for arm in arms {
        if arm.guard.is_some() {
            return false;
        }
        let Some((candidate, arguments)) = exact_constructor_pattern(program, arm.pattern) else {
            return false;
        };
        let Some(declaration) = program.declaration(candidate.enumeration.declaration) else {
            return false;
        };
        if declaration.name.as_ref().map(wrela_hir::Name::as_str) != Some("Result") {
            return false;
        }
        match candidate.variant {
            0 if !ok_seen && arguments.len() == 1 => ok_seen = true,
            1 if err_binding.is_none() && arguments.len() == 1 => {
                let Some(local) = constructor_pattern_binding(program, &arguments[0]) else {
                    return false;
                };
                err_binding = Some(local);
                err_body = Some(arm.body);
            }
            _ => return false,
        }
    }
    let (Some(binding), Some(body)) = (err_binding, err_body) else {
        return false;
    };
    let Some(body) = program.body(body) else {
        return false;
    };
    let [statement] = body.statements.as_slice() else {
        return false;
    };
    let Some(StatementKind::Match { scrutinee, arms }) = program
        .statement(*statement)
        .map(|statement| &statement.kind)
    else {
        return false;
    };
    if !program.expression(*scrutinee).is_some_and(|expression| {
        expression.kind == ExpressionKind::Reference(Definition::Local(binding))
    }) || arms.len() != 4
    {
        return false;
    }
    for (expected_variant, arm) in arms.iter().enumerate() {
        if arm.guard.is_some() {
            return false;
        }
        let Some((candidate, arguments)) = exact_constructor_pattern(program, arm.pattern) else {
            return false;
        };
        let Some(declaration) = program.declaration(candidate.enumeration.declaration) else {
            return false;
        };
        if declaration.name.as_ref().map(wrela_hir::Name::as_str) != Some("AsyncExit")
            || candidate.variant as usize != expected_variant
            || arguments.len() != 1
        {
            return false;
        }
    }
    true
}

fn exact_constructor_pattern(
    program: &wrela_hir::Program,
    pattern: wrela_hir::PatternId,
) -> Option<(&wrela_hir::ResolvedVariant, &[wrela_hir::PatternArgument])> {
    let pattern = program.patterns.get(pattern.0 as usize)?;
    let [alternative] = pattern.alternatives.as_slice() else {
        return None;
    };
    let wrela_hir::PrimaryPattern::Constructor {
        candidates,
        arguments,
        ..
    } = &alternative.kind
    else {
        return None;
    };
    let [candidate] = candidates.as_slice() else {
        return None;
    };
    Some((candidate, arguments))
}

fn constructor_pattern_binding(
    program: &wrela_hir::Program,
    argument: &wrela_hir::PatternArgument,
) -> Option<LocalId> {
    if argument.take {
        return None;
    }
    let pattern = program.patterns.get(argument.pattern.0 as usize)?;
    let [alternative] = pattern.alternatives.as_slice() else {
        return None;
    };
    match alternative.kind {
        wrela_hir::PrimaryPattern::Bind(local) => Some(local),
        _ => None,
    }
}

fn analyze_actor_send_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression_id: ExpressionId,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let resolved =
        resolve_self_actor_send(request, partial, function, expression_id, is_cancelled)?;
    let target = partial
        .functions
        .get(resolved.method.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if partial
        .types
        .get(target.result.0 as usize)
        .is_none_or(|ty| ty.kind != SemanticTypeKind::Unit)
    {
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            resolved.source,
            "semantic-actor-send-reply-discarded",
            "one-way send cannot discard a typed actor reply",
            "await the request from one bounded startup task, or make the actor turn return unit",
        ));
    }
    analyze_actor_request_expression(
        request,
        partial,
        function,
        expression_id,
        None,
        state,
        is_cancelled,
    )
}

fn analyze_actor_request_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression_id: ExpressionId,
    reply: Option<ProofId>,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    check_cancelled(is_cancelled)?;
    let resolved =
        resolve_self_actor_send(request, partial, function, expression_id, is_cancelled)?;
    let permit = partial
        .proofs
        .iter()
        .filter(|proof| {
            proof.kind == ProofKind::CapacityBound
                && proof.bound == Some(1)
                && proof.sources.as_slice() == [resolved.source]
                && proof.depends_on.as_slice() == [resolved.mailbox_proof]
        })
        .map(|proof| proof.id)
        .next()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let callee = match request
        .hir
        .as_program()
        .expression(expression_id)
        .map(|expression| &expression.kind)
    {
        Some(ExpressionKind::Call { callee, .. }) => *callee,
        _ => return Err(AnalysisFailure::RequestMismatch.into()),
    };
    let receiver_ty = partial
        .functions
        .get(function.0 as usize)
        .and_then(|function| function.parameters.first())
        .map(|parameter| parameter.ty)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let _receiver = analyze_runtime_expression(
        request,
        partial,
        function,
        resolved.receiver,
        RuntimeExpressionRequest {
            expected: Some(receiver_ty),
            desired_result: None,
            access: AccessMode::Read,
        },
        state,
        is_cancelled,
    )?;
    if let Some(handle) = resolved.handle {
        let handle_source = request
            .hir
            .as_program()
            .expression(handle)
            .map(|expression| expression.source)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let handle_class = partial
            .graph
            .as_ref()
            .and_then(|graph| graph.actors.get(resolved.actor.0 as usize))
            .map(|actor| actor.class)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let handle_ty = ensure_actor_handle_type(request, partial, handle_class)?;
        let handle_value = expression_result(
            request,
            partial,
            function,
            (handle, handle_source),
            handle_ty,
            None,
            is_cancelled,
        )?;
        append_expression_fact(
            request,
            partial,
            RuntimeExpressionFact {
                function,
                expression: handle,
                ty: handle_ty,
                result: Some(handle_value),
                resolution: ExpressionResolution::Field { index: 0 },
                effects: EffectSet(0),
                ownership_before: OwnershipState::Owned,
                ownership_after: OwnershipState::Owned,
            },
        )?;
    }
    let target = partial
        .functions
        .get(resolved.method.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let target_color = target.color;
    let target_result = target.result;
    let target_parameters = target
        .parameters
        .get(1..)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .to_vec();
    let function_ty = ensure_function_type(
        request,
        partial,
        target_color,
        &target_parameters,
        target_result,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: callee,
            ty: function_ty,
            result: None,
            resolution: ExpressionResolution::Function(resolved.method),
            effects: EffectSet(0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    let result_ty = if reply.is_some() {
        target_result
    } else {
        partial
            .types
            .iter()
            .find(|ty| ty.kind == SemanticTypeKind::Reservation)
            .map(|ty| ty.id)
            .ok_or(AnalysisFailure::RequestMismatch)?
    };
    let result = expression_result(
        request,
        partial,
        function,
        (expression_id, resolved.source),
        result_ty,
        None,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: expression_id,
            ty: result_ty,
            result: Some(result),
            resolution: ExpressionResolution::ActorRequest {
                actor: resolved.actor,
                method: resolved.method,
                permit,
                reply,
            },
            effects: EffectSet(EffectSet::ACTOR),
            ownership_before: OwnershipState::Owned,
            ownership_after: if reply.is_some() {
                OwnershipState::Owned
            } else {
                OwnershipState::Taken
            },
        },
    )?;
    Ok(RuntimeExpression {
        ty: result_ty,
        result: Some(result),
        referenced: None,
        effects: EffectSet(EffectSet::ACTOR),
    })
}

fn compound_assignment_binary_operator(
    operator: AssignmentOperator,
) -> Option<wrela_hir::BinaryOperator> {
    Some(match operator {
        AssignmentOperator::Assign => return None,
        AssignmentOperator::Add => wrela_hir::BinaryOperator::Add,
        AssignmentOperator::Subtract => wrela_hir::BinaryOperator::Subtract,
        AssignmentOperator::Multiply => wrela_hir::BinaryOperator::Multiply,
        AssignmentOperator::Divide => wrela_hir::BinaryOperator::Divide,
        AssignmentOperator::Remainder => wrela_hir::BinaryOperator::Remainder,
        AssignmentOperator::BitAnd => wrela_hir::BinaryOperator::BitAnd,
        AssignmentOperator::BitOr => wrela_hir::BinaryOperator::BitOr,
        AssignmentOperator::BitXor => wrela_hir::BinaryOperator::BitXor,
        AssignmentOperator::ShiftLeft => wrela_hir::BinaryOperator::ShiftLeft,
        AssignmentOperator::ShiftRight => wrela_hir::BinaryOperator::ShiftRight,
    })
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum RuntimeScalarType {
    Bool,
    Integer { signed: bool, bits: u16 },
    Float { bits: u16 },
}

fn runtime_struct_declaration(
    partial: &PartialAnalysis,
    ty: SemanticTypeId,
) -> Option<DeclarationId> {
    match &partial.types.get(ty.0 as usize)?.kind {
        SemanticTypeKind::Structure { declaration, .. } => Some(*declaration),
        _ => None,
    }
}

fn runtime_scalar_type(partial: &PartialAnalysis, ty: SemanticTypeId) -> Option<RuntimeScalarType> {
    match partial.types.get(ty.0 as usize)?.kind {
        SemanticTypeKind::Bool => Some(RuntimeScalarType::Bool),
        SemanticTypeKind::Integer { signed, bits, .. } => {
            Some(RuntimeScalarType::Integer { signed, bits })
        }
        SemanticTypeKind::Float { bits } => Some(RuntimeScalarType::Float { bits }),
        _ => None,
    }
}

fn known_runtime_expression_type(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    state: &mut RuntimeState<'_>,
    expression: ExpressionId,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<Option<SemanticTypeId>> {
    let Some(expression) = request.hir.as_program().expression(expression) else {
        return Ok(None);
    };
    Ok(match &expression.kind {
        ExpressionKind::Literal(Literal::Unit) => Some(SemanticTypeId(0)),
        ExpressionKind::Literal(Literal::Boolean(_)) => {
            let mut found = None;
            for ty in &partial.types {
                charge_runtime_aggregate_lookup(request, &mut *state.aggregate_work, is_cancelled)?;
                if ty.kind == SemanticTypeKind::Bool {
                    found = Some(ty.id);
                    break;
                }
            }
            found
        }
        ExpressionKind::Reference(Definition::Local(local)) => state
            .locals
            .get(local.0 as usize)
            .and_then(|binding| *binding)
            .and_then(|binding| partial.values.get(binding.value.0 as usize))
            .map(|value| value.ty),
        ExpressionKind::Reference(Definition::Parameter(parameter)) => state
            .parameters
            .get(parameter.0 as usize)
            .and_then(|binding| *binding)
            .and_then(|binding| partial.values.get(binding.value.0 as usize))
            .map(|value| value.ty),
        _ => None,
    })
}

fn require_scalar_temporary_access(
    request: &AnalysisRequest<'_>,
    source: Span,
    access: AccessMode,
) -> RuntimeResult<()> {
    if matches!(access, AccessMode::Value | AccessMode::Read) {
        Ok(())
    } else {
        Err(runtime_diagnostic(
            request,
            source,
            "semantic-access-temporary",
            "mutable or take access requires a named owned value",
            None,
            "a scalar operator result is a temporary value",
            "bind the result to a local before requesting exclusive access",
        ))
    }
}

fn analyze_scalar_unary(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    unary: RuntimeUnary,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    require_scalar_temporary_access(request, unary.source, expression_request.access)?;
    let operand = analyze_runtime_expression(
        request,
        partial,
        function,
        unary.operand,
        RuntimeExpressionRequest {
            expected: expression_request.expected,
            desired_result: None,
            access: AccessMode::Value,
        },
        state,
        is_cancelled,
    )?;
    let scalar = runtime_scalar_type(partial, operand.ty);
    let valid = match unary.operator {
        wrela_hir::UnaryOperator::Negate => matches!(
            scalar,
            Some(RuntimeScalarType::Integer { signed: true, .. } | RuntimeScalarType::Float { .. })
        ),
        wrela_hir::UnaryOperator::BitNot => {
            matches!(scalar, Some(RuntimeScalarType::Integer { .. }))
        }
        wrela_hir::UnaryOperator::BoolNot => scalar == Some(RuntimeScalarType::Bool),
        wrela_hir::UnaryOperator::Copy => {
            partial.types.get(operand.ty.0 as usize).is_some_and(|ty| {
                matches!(
                    ty.linearity,
                    Linearity::ExplicitCopy | Linearity::ScalarCopy
                )
            })
        }
        wrela_hir::UnaryOperator::Await
        | wrela_hir::UnaryOperator::Take
        | wrela_hir::UnaryOperator::Comptime => false,
    };
    if !valid {
        return Err(runtime_type_diagnostic(
            request,
            unary.source,
            "semantic-unary-type",
            "unary operator is not defined for this scalar type",
            "negation requires a signed integer or float, `~` requires an integer, and `not` requires bool",
            "change the operand type or choose the matching scalar operator",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (unary.expression, unary.source),
        operand.ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: unary.expression,
            ty: operand.ty,
            result: Some(result),
            resolution: ExpressionResolution::Value(result),
            effects: operand.effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: operand.ty,
        result: Some(result),
        referenced: None,
        effects: operand.effects,
    })
}

fn analyze_scalar_binary(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    binary: RuntimeBinary,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    require_scalar_temporary_access(request, binary.source, expression_request.access)?;
    let comparison = matches!(binary.operator, RuntimeBinaryOperator::Compare(_));
    let operand_expected = if !comparison && expression_request.expected.is_some() {
        expression_request.expected
    } else {
        let known_left =
            known_runtime_expression_type(request, partial, state, binary.left, is_cancelled)?;
        let known_right = if known_left.is_none() {
            known_runtime_expression_type(request, partial, state, binary.right, is_cancelled)?
        } else {
            None
        };
        known_left.or(known_right)
    };
    let operand_access = if matches!(
        binary.operator,
        RuntimeBinaryOperator::Compare(
            wrela_hir::ComparisonOperator::Equal | wrela_hir::ComparisonOperator::NotEqual
        )
    ) && operand_expected
        .is_some_and(|ty| runtime_struct_declaration(partial, ty).is_some())
    {
        AccessMode::Read
    } else {
        AccessMode::Value
    };
    let left = analyze_runtime_expression(
        request,
        partial,
        function,
        binary.left,
        RuntimeExpressionRequest {
            expected: operand_expected,
            desired_result: None,
            access: operand_access,
        },
        state,
        is_cancelled,
    )?;
    let right = analyze_runtime_expression(
        request,
        partial,
        function,
        binary.right,
        RuntimeExpressionRequest {
            expected: Some(left.ty),
            desired_result: None,
            access: operand_access,
        },
        state,
        is_cancelled,
    )?;
    if left.ty != right.ty {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-type-mismatch",
            "binary operands must have exactly the same scalar type",
            "revision 0.1 performs no implicit numeric widening",
            "convert one operand explicitly with checked `as`",
        ));
    }
    if let Some(struct_declaration) = runtime_struct_declaration(partial, left.ty) {
        if matches!(
            binary.operator,
            RuntimeBinaryOperator::Compare(
                wrela_hir::ComparisonOperator::Equal | wrela_hir::ComparisonOperator::NotEqual
            )
        ) {
            return analyze_derived_equality(
                request,
                partial,
                function,
                binary,
                struct_declaration,
                left,
                right,
                expression_request,
                state,
                is_cancelled,
            );
        }
        return analyze_operator_interface_binary(
            request,
            partial,
            function,
            binary,
            struct_declaration,
            left,
            right,
            expression_request,
            state,
            is_cancelled,
        );
    }
    let operand = runtime_scalar_type(partial, left.ty).ok_or_else(|| {
        runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-operand",
            "binary operator requires primitive scalar operands",
            "the operand type has no built-in scalar binary meaning",
            "use bool, integer, f32, or f64 operands",
        )
    })?;
    let valid = match binary.operator {
        RuntimeBinaryOperator::Arithmetic(operator) => match operator {
            wrela_hir::BinaryOperator::Add
            | wrela_hir::BinaryOperator::AddWrapping
            | wrela_hir::BinaryOperator::Subtract
            | wrela_hir::BinaryOperator::SubtractWrapping
            | wrela_hir::BinaryOperator::Multiply
            | wrela_hir::BinaryOperator::MultiplyWrapping
            | wrela_hir::BinaryOperator::Divide
            | wrela_hir::BinaryOperator::Remainder
            | wrela_hir::BinaryOperator::BitOr
            | wrela_hir::BinaryOperator::BitXor
            | wrela_hir::BinaryOperator::BitAnd
            | wrela_hir::BinaryOperator::ShiftLeft
            | wrela_hir::BinaryOperator::ShiftRight => {
                matches!(operand, RuntimeScalarType::Integer { .. })
            }
            wrela_hir::BinaryOperator::LogicalOr | wrela_hir::BinaryOperator::LogicalAnd => false,
        },
        RuntimeBinaryOperator::Compare(operator) => match operand {
            RuntimeScalarType::Bool => matches!(
                operator,
                wrela_hir::ComparisonOperator::Equal | wrela_hir::ComparisonOperator::NotEqual
            ),
            RuntimeScalarType::Integer { .. } | RuntimeScalarType::Float { .. } => true,
        },
    };
    if !valid {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-type",
            "binary operator is not defined for this scalar type",
            "arithmetic, bitwise, and shifts require integers; bool supports equality only",
            "change the operands or choose an operator defined for their exact type",
        ));
    }
    let result_ty = if comparison {
        ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Bool,
            &mut *state.aggregate_work,
            is_cancelled,
        )?
    } else {
        left.ty
    };
    if expression_request
        .expected
        .is_some_and(|expected| expected != result_ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-result",
            "binary result type does not match its required context",
            "comparisons produce bool and integer operators preserve their operand type",
            "change the context or convert the result explicitly",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (binary.expression, binary.source),
        result_ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    let effects = EffectSet(left.effects.0 | right.effects.0);
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: binary.expression,
            ty: result_ty,
            result: Some(result),
            resolution: ExpressionResolution::Value(result),
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: result_ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

#[allow(clippy::too_many_arguments)]
fn analyze_derived_equality(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    binary: RuntimeBinary,
    declaration: DeclarationId,
    left: RuntimeExpression,
    right: RuntimeExpression,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let declaration_record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(source) = &declaration_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if !source.deriving.iter().any(|name| name.as_str() == "Eq") {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-derived-eq-required",
            "nominal structure equality requires `deriving(Eq)`",
            "structure identity alone does not synthesize equality behavior",
            "add `deriving(Eq)` to the structure declaration or compare a field explicitly",
        ));
    }
    let (semantic_fields, exact_shape) = partial
        .types
        .get(left.ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Structure {
                declaration: record_declaration,
                arguments,
                fields,
            } => Some((
                fields.as_slice(),
                *record_declaration == declaration
                    && arguments.is_empty()
                    && !fields.is_empty()
                    && source.generics.is_empty()
                    && source.fields.len() == fields.len(),
            )),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut field_types = Vec::new();
    field_types
        .try_reserve(semantic_fields.len())
        .map_err(|_| fact_resource(request, "derived equality fields"))?;
    field_types.extend(semantic_fields.iter().map(|field| field.ty));
    if !exact_shape {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-deriving-eq-shape-pending",
            "derived equality is not implemented for this structure shape",
            "the executable subset is a nonempty nongeneric flat structure with stored copy-scalar fields",
            "compare fields explicitly or use a supported flat structure",
        ));
    }
    if field_types
        .iter()
        .any(|field_ty| runtime_scalar_type(partial, *field_ty).is_none())
    {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-deriving-eq-shape-pending",
            "derived equality field is outside the stored copy-scalar subset",
            "nested nominal, view, and linear fields require recursive derived-method lowering",
            "compare a supported scalar field explicitly",
        ));
    }
    let bool_ty = ensure_primitive_type(
        request,
        partial,
        PrimitiveSemanticType::Bool,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    if expression_request
        .expected
        .is_some_and(|expected| expected != bool_ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-result",
            "derived equality result does not match its required context",
            "`==` and `!=` always produce bool",
            "use the comparison in a bool context",
        ));
    }
    let left_value = left
        .referenced
        .or(left.result)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let right_value = right
        .referenced
        .or(right.result)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let is_equal = matches!(
        binary.operator,
        RuntimeBinaryOperator::Compare(wrela_hir::ComparisonOperator::Equal)
    );
    let mut derived_fields = Vec::new();
    derived_fields
        .try_reserve(field_types.len())
        .map_err(|_| fact_resource(request, "derived equality fields"))?;
    for (field_index, field_ty) in field_types.iter().copied().enumerate() {
        check_cancelled(is_cancelled)?;
        let left_field = append_semantic_value(
            request,
            partial,
            function,
            field_ty,
            (
                SemanticValueOrigin::Expression(binary.expression),
                Some(binary.source),
                None,
            ),
            is_cancelled,
        )?;
        let right_field = append_semantic_value(
            request,
            partial,
            function,
            field_ty,
            (
                SemanticValueOrigin::Expression(binary.expression),
                Some(binary.source),
                None,
            ),
            is_cancelled,
        )?;
        let comparison = if field_types.len() == 1 && is_equal {
            expression_result(
                request,
                partial,
                function,
                (binary.expression, binary.source),
                bool_ty,
                expression_request.desired_result,
                is_cancelled,
            )?
        } else {
            append_semantic_value(
                request,
                partial,
                function,
                bool_ty,
                (
                    SemanticValueOrigin::Expression(binary.expression),
                    Some(binary.source),
                    None,
                ),
                is_cancelled,
            )?
        };
        derived_fields.push(DerivedEqualityField {
            field: u32::try_from(field_index)
                .map_err(|_| fact_resource(request, "derived equality fields"))?,
            left: left_field,
            right: right_field,
            comparison,
        });
    }
    let mut conjunctions = Vec::new();
    conjunctions
        .try_reserve(field_types.len().saturating_sub(1))
        .map_err(|_| fact_resource(request, "derived equality conjunctions"))?;
    for fold_index in 1..field_types.len() {
        check_cancelled(is_cancelled)?;
        let conjunction = if fold_index + 1 == field_types.len() && is_equal {
            expression_result(
                request,
                partial,
                function,
                (binary.expression, binary.source),
                bool_ty,
                expression_request.desired_result,
                is_cancelled,
            )?
        } else {
            append_semantic_value(
                request,
                partial,
                function,
                bool_ty,
                (
                    SemanticValueOrigin::Expression(binary.expression),
                    Some(binary.source),
                    None,
                ),
                is_cancelled,
            )?
        };
        conjunctions.push(conjunction);
    }
    let result = if is_equal {
        conjunctions
            .last()
            .copied()
            .unwrap_or(derived_fields[0].comparison)
    } else {
        expression_result(
            request,
            partial,
            function,
            (binary.expression, binary.source),
            bool_ty,
            expression_request.desired_result,
            is_cancelled,
        )?
    };
    let effects = EffectSet(left.effects.0 | right.effects.0);
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: binary.expression,
            ty: bool_ty,
            result: Some(result),
            resolution: ExpressionResolution::DerivedEquality {
                aggregate: left.ty,
                left: left_value,
                right: right_value,
                fields: derived_fields,
                conjunctions,
            },
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: bool_ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

/// Desugar `+ - < <= > >=` on a value of a nominal struct type into a direct
/// call to the unique visible `core.ops` impl method (chapter 10 §12). Both
/// operands are already evaluated left-to-right as written by the caller;
/// only the argument *binding* is swapped for `> <= >=`, and `<= >=` also
/// negate the raw call result.
#[allow(clippy::too_many_arguments)]
fn analyze_operator_interface_binary(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    binary: RuntimeBinary,
    struct_declaration: DeclarationId,
    left: RuntimeExpression,
    right: RuntimeExpression,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let operator = match binary.operator {
        RuntimeBinaryOperator::Arithmetic(operator) => {
            crate::interfaces::DesugarOperator::from_binary(operator)
        }
        RuntimeBinaryOperator::Compare(operator) => {
            crate::interfaces::DesugarOperator::from_comparison(operator)
        }
    };
    let Some(operator) = operator else {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-operand",
            "binary operator is not defined for this scalar type",
            "arithmetic, bitwise, and shifts require integers; bool supports equality only",
            "change the operands or choose an operator defined for their exact type",
        ));
    };
    let (model, _) = crate::interfaces::collect_interface_model(
        request.hir.as_program(),
        request.standard_library_package,
        is_cancelled,
    )?;
    let Some(resolution) =
        model.resolve_operator(request.hir.as_program(), operator, struct_declaration)
    else {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-interface-operator-missing",
            "no visible implementation defines this operator for the operand type",
            "operators on a nominal struct desugar only through a unique visible core.ops impl",
            "add `impl Add`/`Sub`/`Ord for <Type>:` with the matching method",
        ));
    };
    let target = ensure_ordinary_source_function(
        request,
        partial,
        resolution.function,
        &[],
        state.allow_assertions,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    let target_record = partial
        .functions
        .get(target.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if target_record.parameters.len() != 2 {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let self_parameter = target_record.parameters[0];
    let other_parameter = target_record.parameters[1];
    let raw_result_ty = target_record.result;
    let target_effects = target_record.effects;

    let (self_operand, self_source_index, other_operand, other_source_index) = if resolution.swap {
        (&right, 1u32, &left, 0u32)
    } else {
        (&left, 0u32, &right, 1u32)
    };
    // A reference operand (parameter or local read) carries its value in
    // `referenced` rather than materializing an expression result; both
    // operand shapes are legal `read` arguments, matching the direct-call
    // argument path.
    let self_value = self_operand
        .referenced
        .or(self_operand.result)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let other_value = other_operand
        .referenced
        .or(other_operand.result)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let arguments = vec![
        ResolvedCallArgument {
            source_index: self_source_index,
            parameter_index: 0,
            access: self_parameter.access,
            value: self_value,
        },
        ResolvedCallArgument {
            source_index: other_source_index,
            parameter_index: 1,
            access: other_parameter.access,
            value: other_value,
        },
    ];

    let final_ty = if resolution.negate {
        ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Bool,
            &mut *state.aggregate_work,
            is_cancelled,
        )?
    } else {
        raw_result_ty
    };
    if expression_request
        .expected
        .is_some_and(|expected| expected != final_ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            binary.source,
            "semantic-binary-result",
            "binary result type does not match its required context",
            "comparisons produce bool and interface operators preserve their declared result type",
            "change the context or convert the result explicitly",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (binary.expression, binary.source),
        final_ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    let raw_result = if resolution.negate {
        append_semantic_value(
            request,
            partial,
            function,
            raw_result_ty,
            (
                SemanticValueOrigin::Expression(binary.expression),
                Some(binary.source),
                None,
            ),
            is_cancelled,
        )?
    } else {
        result
    };
    let effects = EffectSet(left.effects.0 | right.effects.0 | target_effects.0);
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: binary.expression,
            ty: final_ty,
            result: Some(result),
            resolution: ExpressionResolution::OperatorCall {
                function: target,
                arguments,
                raw_result,
                negate: resolution.negate,
            },
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: final_ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

fn analyze_scalar_cast(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    cast: RuntimeCast<'_>,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    require_scalar_temporary_access(request, cast.source, expression_request.access)?;
    let destination = semantic_type_from_source(
        request,
        partial,
        cast.destination,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    if expression_request
        .expected
        .is_some_and(|expected| expected != destination)
    {
        return Err(runtime_type_diagnostic(
            request,
            cast.source,
            "semantic-conversion-result",
            "conversion destination does not match its required context",
            "the explicit `as` type is the exact result type",
            "change the destination type or the surrounding type annotation",
        ));
    }
    let value = analyze_runtime_expression(
        request,
        partial,
        function,
        cast.value,
        RuntimeExpressionRequest {
            expected: None,
            desired_result: None,
            access: AccessMode::Value,
        },
        state,
        is_cancelled,
    )?;
    if runtime_scalar_type(partial, value.ty).is_none_or(|source| {
        !matches!(
            source,
            RuntimeScalarType::Integer { .. } | RuntimeScalarType::Float { .. }
        )
    }) || runtime_scalar_type(partial, destination).is_none_or(|destination| {
        !matches!(
            destination,
            RuntimeScalarType::Integer { .. } | RuntimeScalarType::Float { .. }
        )
    }) {
        return Err(runtime_type_diagnostic(
            request,
            cast.source,
            "semantic-conversion-type",
            "`as` requires numeric source and destination types",
            "revision 0.1 does not expose representations, brands, or enum discriminants through casts",
            "use an integer or floating-point destination",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (cast.expression, cast.source),
        destination,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: cast.expression,
            ty: destination,
            result: Some(result),
            resolution: ExpressionResolution::Value(result),
            effects: value.effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: destination,
        result: Some(result),
        referenced: None,
        effects: value.effects,
    })
}

fn analyze_await_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    await_expression: RuntimeAwait,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let color = partial
        .functions
        .get(function.0 as usize)
        .map(|function| function.color)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if color != FunctionColor::Async {
        let mut diagnostic = Diagnostic::error(
            Category::ASYNC,
            await_expression.source,
            "only an async function may suspend at `await`",
        );
        diagnostic.code = Some("semantic-await-in-sync-function".to_owned());
        diagnostic
            .help
            .push("make the enclosing function async or remove the await".to_owned());
        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
    }
    for view in &partial.lexical_views {
        check_cancelled(is_cancelled)?;
        if view.function != function {
            continue;
        }
        let initialization = request
            .hir
            .as_program()
            .statement(view.initialization)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if let Some(terminal) =
            lexical_view_blocking_terminal(request.hir.as_program(), view, await_expression.source)
        {
            let protocol = partial
                .projection_protocols
                .get(view.protocol.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let mut diagnostic = Diagnostic::error(
                Category::OWNERSHIP,
                await_expression.source,
                format!(
                    "lexical view from projection `{}` remains live across await",
                    protocol.name
                ),
            );
            diagnostic.code = Some("semantic-view-across-await".to_owned());
            diagnostic
                .labels
                .try_reserve_exact(2)
                .map_err(|_| fact_resource(request, "view across await diagnostic labels"))?;
            diagnostic.labels.push(wrela_diagnostics::Label {
                span: initialization.source,
                message: "the lexical view binding begins here".to_owned(),
            });
            diagnostic.labels.push(wrela_diagnostics::Label {
                span: terminal.source,
                message: "this terminal use keeps the view live across suspension".to_owned(),
            });
            diagnostic.notes.push(
                "regionless views are second-class values and cannot be retained by an async frame"
                    .to_owned(),
            );
            diagnostic.help.push(
                "consume the view before awaiting, or create a new projection after resumption"
                    .to_owned(),
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
    }
    if !matches!(
        expression_request.access,
        AccessMode::Value | AccessMode::Read
    ) {
        return Err(runtime_diagnostic(
            request,
            await_expression.source,
            "semantic-access-temporary",
            "mutable or take access cannot target an awaited temporary",
            None,
            "await completion creates a new owned result value",
            "bind the awaited result before requesting exclusive access",
        ));
    }
    let program = request.hir.as_program();
    let actor_dependency_call = program
        .expression(await_expression.operand)
        .and_then(|operand| match operand.kind {
            ExpressionKind::Call { callee, .. } => program.expression(callee),
            _ => None,
        })
        .and_then(|callee| match callee.kind {
            ExpressionKind::Field { base, .. } => program.expression(base),
            _ => None,
        })
        .is_some_and(|base| matches!(base.kind, ExpressionKind::Field { .. }));
    let mut awaited = if actor_dependency_call {
        let resolved = resolve_self_actor_send(
            request,
            partial,
            function,
            await_expression.operand,
            is_cancelled,
        )?;
        let permit = partial
            .proofs
            .iter()
            .find(|proof| {
                proof.kind == ProofKind::CapacityBound
                    && proof.bound == Some(1)
                    && proof.sources.as_slice() == [resolved.source]
                    && proof.depends_on.as_slice() == [resolved.mailbox_proof]
            })
            .map(|proof| proof.id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let reply = partial
            .proofs
            .iter()
            .find(|proof| {
                proof.kind == ProofKind::ActorReplyExactlyOnce
                    && proof.bound == Some(1)
                    && proof.sources.as_slice() == [resolved.source]
                    && proof.depends_on.contains(&permit)
            })
            .map(|proof| proof.id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let outcome = analyze_actor_request_expression(
            request,
            partial,
            function,
            await_expression.operand,
            Some(reply),
            state,
            is_cancelled,
        )?;
        if expression_request
            .expected
            .is_some_and(|expected| expected != outcome.ty)
        {
            return Err(actor_runtime_diagnostic(
                Category::TYPE,
                await_expression.source,
                "semantic-actor-reply-type-mismatch",
                "awaited actor reply does not match the required result type",
                "bind the reply as u64 in the admitted typed-reply subset",
            ));
        }
        outcome
    } else {
        analyze_runtime_expression(
            request,
            partial,
            function,
            await_expression.operand,
            RuntimeExpressionRequest {
                expected: None,
                desired_result: None,
                access: AccessMode::Value,
            },
            state,
            is_cancelled,
        )?
    };
    let target = partial
        .expressions
        .iter()
        .find(|fact| fact.function == function && fact.expression == await_expression.operand)
        .and_then(|fact| match fact.resolution {
            ExpressionResolution::DirectCall {
                function: target, ..
            }
            | ExpressionResolution::ActorRequest { method: target, .. } => Some(target),
            _ => None,
        })
        .and_then(|target| {
            partial
                .functions
                .get(target.0 as usize)
                .map(|record| (target, record))
        });
    if target.is_none_or(|(_, target)| target.color != FunctionColor::Async) {
        let mut diagnostic = Diagnostic::error(
            Category::ASYNC,
            await_expression.source,
            "await operand is not a statically known async activation",
        );
        diagnostic.code = Some("semantic-await-operand".to_owned());
        diagnostic.notes.push(
            "revision 0.1 admits only closed-world direct async calls and actor requests"
                .to_owned(),
        );
        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
    }
    let direct_fallible =
        if actor_dependency_call {
            None
        } else {
            target.and_then(|(_, target)| {
                let record = partial.types.get(target.result.0 as usize)?;
                let SemanticTypeKind::Enumeration {
                    declaration,
                    arguments,
                    variants,
                } = &record.kind
                else {
                    return None;
                };
                let declaration_record = request.hir.as_program().declaration(*declaration)?;
                let resolved = wrela_hir::ResolvedDeclaration {
                    package: request.standard_library_package,
                    module: declaration_record.module,
                    declaration: *declaration,
                };
                is_exact_core_result_declaration(request, &resolved, declaration_record)
                    .then_some((*declaration, arguments.clone(), variants.clone()))
            })
        };
    let mut structured_async_outcome = false;
    if let Some((result_declaration, arguments, variants)) = direct_fallible {
        let u64_ty = ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Integer {
                signed: false,
                bits: 64,
                pointer_sized: false,
            },
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
        let exact_declared = matches!(arguments.as_slice(),
                [SemanticArgument::Type(ok), SemanticArgument::Type(err)]
                    if *ok == u64_ty && *err == u64_ty)
            && matches!(variants.as_slice(), [ok, err]
                if ok.name == "Ok"
                    && err.name == "Err"
                    && matches!((ok.fields.as_slice(), err.fields.as_slice()), ([ok], [err])
                        if ok.ty == u64_ty && err.ty == u64_ty));
        if !exact_declared {
            return Err(runtime_type_diagnostic(
                request,
                await_expression.source,
                "semantic-async-outcome-type-pending",
                "fallible async activation result is outside the bounded structured outcome specialization",
                "this increment accepts exactly direct non-actor async Result[u64, u64]",
                "use Result[u64, u64] until wider AsyncExit specialization lands",
            ));
        }
        let usage = exact_async_outcome_use(request, await_expression.expression, is_cancelled)?;
        match usage {
            EphemeralUse::Question => {
                return Err(runtime_type_diagnostic(
                    request,
                    await_expression.source,
                    "semantic-async-outcome-question-pending",
                    "postfix question cannot yet propagate a structured async outcome",
                    "AsyncExit conversion and abnormal cleanup are not implemented by this analysis slice",
                    "consume the await directly with exhaustive match or an is-pattern",
                ));
            }
            EphemeralUse::PatternMatch | EphemeralUse::TypeTest => {}
            EphemeralUse::DirectBinding | EphemeralUse::ImmediateRead => {
                return Err(runtime_type_diagnostic(
                    request,
                    await_expression.source,
                    "semantic-async-outcome-consumer-pending",
                    "structured async outcome is not consumed by an admitted immediate form",
                    "this bounded slice permits only an exhaustive nested match or direct is-pattern",
                    "consume the awaited Result directly with nested match or is",
                ));
            }
        }
        let async_exit = ensure_core_async_exit_type(
            request,
            partial,
            u64_ty,
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
        let effective = ensure_core_result_type_from_semantic_arguments(
            request,
            partial,
            result_declaration,
            u64_ty,
            async_exit,
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
        if expression_request
            .expected
            .is_some_and(|expected| expected != effective)
        {
            return Err(runtime_type_diagnostic(
                request,
                await_expression.source,
                "semantic-async-outcome-consumer-pending",
                "structured async outcome cannot be stored in its declared Result type",
                "await widens the declared operation error to AsyncExit at the suspension boundary",
                "consume the effective outcome immediately with nested match or is",
            ));
        }
        awaited.ty = effective;
        structured_async_outcome = true;
    }
    if expression_request
        .expected
        .is_some_and(|expected| expected != awaited.ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            await_expression.source,
            "semantic-await-result-type",
            "awaited activation result does not match its required context",
            "await preserves the declared result for ordinary activations and widens fallible errors to the structured outcome taxonomy",
            "change the destination type or consume the structured outcome immediately",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (await_expression.expression, await_expression.source),
        awaited.ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    if structured_async_outcome {
        partial
            .values
            .get_mut(result.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?
            .class = SemanticValueClass::Ephemeral(EphemeralKind::AsyncOutcome);
    }
    let effects = EffectSet(awaited.effects.0 | EffectSet::SUSPEND);
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: await_expression.expression,
            ty: awaited.ty,
            result: Some(result),
            resolution: ExpressionResolution::Builtin(IntrinsicOperation::Await),
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: awaited.ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

fn reference_operand(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    identity: (FunctionInstanceId, ExpressionId),
    mut binding: RuntimeBinding,
    expression_request: RuntimeExpressionRequest,
    slot: &mut Option<RuntimeBinding>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let (function, expression) = identity;
    let source = request
        .hir
        .as_program()
        .expression(expression)
        .map(|expression| expression.source)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let category = partial
        .values
        .get(binding.value.0 as usize)
        .filter(|value| value.function == function)
        .map(|value| value.category)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let (ty, before) = access_runtime_binding(
        request,
        partial,
        function,
        source,
        &mut binding,
        expression_request.expected,
        expression_request.access,
        expression_request.desired_result.is_some(),
        slot,
        is_cancelled,
    )?;
    let result = expression_request
        .desired_result
        .map(|desired| {
            expression_result(
                request,
                partial,
                function,
                (expression, source),
                ty,
                Some(desired),
                is_cancelled,
            )
        })
        .transpose()?;
    append_expression_fact_with_category(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression,
            ty,
            result,
            resolution: ExpressionResolution::Value(binding.value),
            effects: EffectSet(0),
            ownership_before: before,
            ownership_after: binding.state,
        },
        category,
        None,
    )?;
    Ok(RuntimeExpression {
        ty,
        result,
        referenced: Some(binding.value),
        effects: EffectSet(0),
    })
}

#[allow(clippy::too_many_arguments)]
fn access_runtime_binding(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
    source: Span,
    binding: &mut RuntimeBinding,
    expected: Option<SemanticTypeId>,
    access: AccessMode,
    copy_requested: bool,
    slot: &mut Option<RuntimeBinding>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<(SemanticTypeId, OwnershipState)> {
    let record = partial
        .values
        .get(binding.value.0 as usize)
        .filter(|record| record.function == function)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    for view in &partial.lexical_views {
        check_cancelled(is_cancelled)?;
        let Some(retained) = view.sources.iter().find(|retained| {
            retained.value == binding.value && accesses_conflict(retained.access, access)
        }) else {
            continue;
        };
        let Some(terminal) = lexical_view_blocking_terminal(request.hir.as_program(), view, source)
        else {
            continue;
        };
        let protocol = partial
            .projection_protocols
            .get(view.protocol.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let parameter_name = request
            .hir
            .as_program()
            .parameters
            .get(retained.parameter.0 as usize)
            .and_then(|parameter| parameter.name.as_ref())
            .map_or("_", wrela_hir::Name::as_str);
        let source_mutation = matches!(retained.access, AccessMode::Value | AccessMode::Read)
            && matches!(access, AccessMode::Mutate | AccessMode::Take);
        let message = if source_mutation {
            format!(
                "cannot mutate frozen projection parameter `{parameter_name}` while view from `{}` remains live",
                protocol.name
            )
        } else {
            format!(
                "access to projection parameter `{parameter_name}` overlaps the live exclusive view from `{}`",
                protocol.name
            )
        };
        let mut diagnostic = Diagnostic::error(
            Category::OWNERSHIP,
            source,
            copy_analysis_text(&message, request.limits.fact_bytes, &|| false)?,
        );
        diagnostic.code = Some(
            if source_mutation {
                "semantic-view-source-mutated"
            } else {
                "semantic-overlapping-access"
            }
            .to_owned(),
        );
        diagnostic
            .labels
            .try_reserve_exact(2)
            .map_err(|_| fact_resource(request, "view access conflict diagnostic labels"))?;
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: retained.argument_source,
            message: format!(
                "`{parameter_name}` is conservatively retained by projection `{}`",
                protocol.name
            ),
        });
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: terminal.source,
            message: "the blocking view's terminal use is here".to_owned(),
        });
        diagnostic.notes.push(
            "all declared projection sources remain frozen until the lexical view's final use"
                .to_owned(),
        );
        diagnostic.help.push(
            "move the conflicting access after the terminal view use or use a distinct source root"
                .to_owned(),
        );
        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
    }
    match record.category {
        ValueCategory::SharedView | ValueCategory::MutableView
            if copy_requested || access == AccessMode::Take =>
        {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-view-escape",
                "lexical view cannot be copied, moved, returned, or rebound as an owned value",
                "a view is a regionless second-class projection whose lifetime is confined to its explicit binding",
                "consume the view through a read parameter before its lexical lifetime ends",
            ));
        }
        ValueCategory::SharedView if access == AccessMode::Mutate => {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-view-read-only",
                "read-only view cannot grant mutable access",
                "only a `mut view` projection carries exclusive mutation authority",
                "use read access or bind a mutable projection",
            ));
        }
        ValueCategory::SharedView | ValueCategory::MutableView => {}
        ValueCategory::Value => {}
        ValueCategory::Place | ValueCategory::TypeValue | ValueCategory::Error => {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    if expected.is_some_and(|expected| expected != record.ty) {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-scalar-type-mismatch",
            "scalar expression type does not match its required context",
            "revision 0.1 performs no implicit numeric conversion",
            "use an explicit checked `as` conversion",
        ));
    }
    let ty = record.ty;
    if copy_requested
        && partial
            .types
            .get(ty.0 as usize)
            .is_some_and(|ty| ty.linearity == Linearity::ExplicitCopy)
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-explicit-copy-required",
            "aggregate value cannot be implicitly copied into a new binding",
            "flat runtime structures preserve nominal ownership and require an explicit copy operation",
            "construct a fresh value, return the existing value, or use an explicitly supported copy form",
        ));
    }
    let before = binding.state;
    if before == OwnershipState::BorrowedMut {
        return Err(runtime_diagnostic(
            request,
            source,
            "semantic-compound-overlap",
            "compound assignment right-hand side overlaps its reserved destination",
            Some(*binding),
            "the destination place is reserved before the right-hand side is evaluated",
            "compute the right-hand side without reading, taking, or borrowing the destination local",
        ));
    }
    if before != OwnershipState::Owned {
        return Err(runtime_diagnostic(
            request,
            source,
            if access == AccessMode::Take {
                "semantic-double-take"
            } else {
                "semantic-use-after-take"
            },
            if access == AccessMode::Take {
                "value is taken more than once"
            } else {
                "value is used after ownership was taken"
            },
            Some(*binding),
            "take access leaves its source uninitialized",
            "reinitialize the value before using it again",
        ));
    }
    match access {
        AccessMode::Value | AccessMode::Read => {}
        AccessMode::Mutate if binding.authority == RuntimeAuthority::Read => {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-mutate-read-only",
                "cannot request mutable access through a read-only binding",
                Some(*binding),
                "read access permits observation but not mutation",
                "declare a mutable parameter or mutate an owned local instead",
            ));
        }
        AccessMode::Mutate => {}
        AccessMode::Take if binding.authority != RuntimeAuthority::Own => {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-take-borrowed",
                "cannot take ownership through a borrowed binding",
                Some(*binding),
                "read and mutable parameters return ownership to their caller",
                "declare the parameter with take access to transfer ownership",
            ));
        }
        AccessMode::Take => binding.state = OwnershipState::Taken,
    }
    *slot = Some(*binding);
    Ok((ty, before))
}

fn reject_live_lexical_rebind(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
    value: ValueId,
    local: LocalId,
    source: Span,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    let category = partial
        .values
        .get(value.0 as usize)
        .filter(|record| record.function == function)
        .map(|record| record.category)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    for view in &partial.lexical_views {
        check_cancelled(is_cancelled)?;
        if view.function != function {
            continue;
        }
        let retained = view.sources.iter().find(|retained| retained.value == value);
        let is_view_binding = view.binding == local
            && matches!(
                category,
                ValueCategory::SharedView | ValueCategory::MutableView
            );
        if retained.is_none() && !is_view_binding {
            continue;
        }
        let Some(terminal) = lexical_view_blocking_terminal(request.hir.as_program(), view, source)
        else {
            continue;
        };
        let protocol = partial
            .projection_protocols
            .get(view.protocol.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let retained_name = retained
            .and_then(|retained| {
                request
                    .hir
                    .as_program()
                    .parameters
                    .get(retained.parameter.0 as usize)
                    .and_then(|parameter| parameter.name.as_ref())
            })
            .map_or("view carrier", wrela_hir::Name::as_str);
        let mut diagnostic = Diagnostic::error(
            Category::OWNERSHIP,
            source,
            format!(
                "cannot rebind `{retained_name}` while projection `{}` remains live",
                protocol.name
            ),
        );
        diagnostic.code = Some("semantic-projection-carrier-rebound".to_owned());
        diagnostic
            .labels
            .try_reserve_exact(2)
            .map_err(|_| fact_resource(request, "projection carrier rebound diagnostic labels"))?;
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: retained.map_or(source, |retained| retained.argument_source),
            message: format!(
                "`{retained_name}` is retained by projection `{}`",
                protocol.name
            ),
        });
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: terminal.source,
            message: "the blocking view's terminal use is here".to_owned(),
        });
        diagnostic.notes.push(
            "neither a projection source nor its regionless view carrier may be replaced while the view is live"
                .to_owned(),
        );
        diagnostic.help.push(
            "move the assignment after the terminal use or initialize a distinct local".to_owned(),
        );
        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
    }
    Ok(())
}

fn analyze_runtime_place(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
    place: &wrela_hir::PlaceTarget,
    target: FunctionParameter,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    if !place.projections.is_empty() {
        return Err(runtime_type_diagnostic(
            request,
            place.source,
            "semantic-exclusive-place-projection",
            "projected exclusive call access is not yet supported",
            "the place is preserved explicitly, but aggregate place ownership lowering is not implemented",
            "bind the projected value to an owned local before passing it with `mut` or `take`",
        ));
    }
    let slot = match place.root {
        Definition::Local(local) => state.locals.get_mut(local.0 as usize),
        Definition::Parameter(parameter) => state.parameters.get_mut(parameter.0 as usize),
        _ => None,
    }
    .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut binding = slot.ok_or(AnalysisFailure::RequestMismatch)?;
    let (ty, _) = access_runtime_binding(
        request,
        partial,
        function,
        place.source,
        &mut binding,
        Some(target.ty),
        target.access,
        false,
        slot,
        is_cancelled,
    )?;
    Ok(RuntimeExpression {
        ty,
        result: None,
        referenced: Some(binding.value),
        effects: EffectSet(0),
    })
}

/// Structs no longer come in two source-level flavors; the initializer
/// protocol now applies to any struct that declares an `init` member
/// (formerly the exclusive province of `class`), while structs without one
/// keep the flat field-construction call form.
fn aggregate_has_initializer(program: &wrela_hir::Program, declaration: DeclarationId) -> bool {
    let Some(record) = program.declaration(declaration) else {
        return false;
    };
    let DeclarationKind::Structure(aggregate) = &record.kind else {
        return false;
    };
    aggregate.members.iter().any(|member| {
        program
            .declaration(*member)
            .is_some_and(|member| matches!(member.kind, DeclarationKind::Initializer(_)))
    })
}

fn structure_initializer(
    program: &wrela_hir::Program,
    declaration: DeclarationId,
) -> Option<(DeclarationId, &wrela_hir::InitializerDeclaration)> {
    let record = program.declaration(declaration)?;
    let DeclarationKind::Structure(aggregate) = &record.kind else {
        return None;
    };
    aggregate.members.iter().find_map(|member| {
        program.declaration(*member).and_then(|record| {
            if let DeclarationKind::Initializer(initializer) = &record.kind {
                Some((*member, initializer))
            } else {
                None
            }
        })
    })
}

#[allow(clippy::too_many_arguments)]
fn validate_infallible_initializer(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    initializer_id: DeclarationId,
    initializer: &wrela_hir::InitializerDeclaration,
    ty: SemanticTypeId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let declaration_record = program
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let initializer_record = program
        .declaration(initializer_id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(aggregate) = &declaration_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if !aggregate.generics.is_empty() {
        return Err(runtime_type_diagnostic(
            request,
            initializer_record.source,
            "semantic-init-generic-pending",
            "generic structure initializers are not in the admitted constructor slice",
            "this increment authenticates one closed nominal structure and its exact scalar fields",
            "use a nongeneric structure until generic initializer monomorphization is implemented",
        ));
    }
    if initializer.result.is_some() {
        return Err(runtime_type_diagnostic(
            request,
            initializer_record.source,
            "semantic-init-fallible-rollback-pending",
            "fallible initializer rollback is not yet executable",
            "Result-returning init requires partial-value teardown on every error edge",
            "use an infallible initializer or construct the Result in an ordinary function",
        ));
    }
    if aggregate.linear || aggregate.copy {
        return Err(runtime_type_diagnostic(
            request,
            initializer_record.source,
            "semantic-init-linearity-pending",
            "linear and copy-annotated initializer protocols are not yet executable",
            "the first initializer slice is limited to ordinary owned flat structures",
            "use an ordinary struct until initializer ownership obligations are implemented",
        ));
    }
    if aggregate.fields.is_empty() {
        return Err(runtime_type_diagnostic(
            request,
            initializer_record.source,
            "semantic-init-zero-sized-pending",
            "zero-sized initializer protocols are not yet executable",
            "this increment authenticates at least one primitive field assignment",
            "omit init on the zero-sized structure until its construction contract is implemented",
        ));
    }
    if aggregate.fields.iter().any(|field| {
        field.visibility != wrela_hir::Visibility::Public
            || !field.attributes.is_empty()
            || field.default.is_some()
    }) {
        return Err(runtime_type_diagnostic(
            request,
            initializer_record.source,
            "semantic-init-field-contract-pending",
            "initializer fields must be public, attribute-free, and have no defaults in this slice",
            "private/defaulted/attributed fields need a dedicated initializer-only lowering boundary",
            "use plain public fields for this initializer increment",
        ));
    }
    let semantic_fields = partial
        .types
        .get(ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Structure {
                declaration: candidate,
                fields,
                ..
            } if *candidate == declaration => Some(fields.clone()),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if initializer.parameters.len() != aggregate.fields.len().saturating_add(1) {
        return Err(runtime_type_diagnostic(
            request,
            initializer_record.source,
            "semantic-init-parameter-shape",
            "initializer must declare one value parameter for every structure field",
            "the admitted call-site desugar has an exact one-to-one field parameter map",
            "declare `mut self` followed by one same-named parameter per field",
        ));
    }
    let receiver = initializer
        .parameters
        .first()
        .and_then(|parameter| program.parameters.get(parameter.0 as usize))
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if !receiver.receiver
        || receiver.access != wrela_hir::AccessMode::Mutate
        || receiver.name.is_some()
        || receiver.ty.is_some()
    {
        return Err(runtime_type_diagnostic(
            request,
            receiver.source,
            "semantic-init-receiver-shape",
            "initializer must begin with the exact `mut self` receiver",
            "init owns one partially initialized receiver and cannot read, take, or relabel it",
            "write `init(mut self, ...)`",
        ));
    }
    for (index, ((field, semantic_field), parameter_id)) in aggregate
        .fields
        .iter()
        .zip(&semantic_fields)
        .zip(initializer.parameters.iter().skip(1))
        .enumerate()
    {
        check_cancelled(is_cancelled)?;
        let parameter = program
            .parameters
            .get(parameter_id.0 as usize)
            .filter(|parameter| parameter.id == *parameter_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let parameter_source_ty = parameter
            .ty
            .as_ref()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let parameter_ty = semantic_type_from_source(
            request,
            partial,
            parameter_source_ty,
            aggregate_work,
            is_cancelled,
        )?;
        if parameter.receiver
            || parameter.access != wrela_hir::AccessMode::Value
            || parameter.positional_only
            || parameter.name.as_ref() != Some(&field.name)
            || parameter_ty != semantic_field.ty
            || runtime_scalar_type(partial, semantic_field.ty).is_none()
        {
            return Err(runtime_type_diagnostic(
                request,
                parameter.source,
                "semantic-init-parameter-shape",
                "initializer parameters must exactly mirror structure fields",
                "field order, spelling, scalar type, and value access are authenticated before call-site desugaring",
                "declare one same-named value parameter per field in declaration order",
            ));
        }
        let _ = index;
    }
    let body = program
        .body(initializer.body)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut initialized = Vec::new();
    initialized
        .try_reserve_exact(aggregate.fields.len())
        .map_err(|_| fact_resource(request, "initializer fields"))?;
    initialized.resize(aggregate.fields.len(), false);
    for statement_id in &body.statements {
        check_cancelled(is_cancelled)?;
        let statement = program
            .statement(*statement_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let StatementKind::Assign {
            targets,
            operator: wrela_hir::AssignmentOperator::Assign,
            value,
        } = &statement.kind
        else {
            return Err(runtime_type_diagnostic(
                request,
                statement.source,
                "semantic-init-control-flow-pending",
                "initializer body contains control flow or an operation beyond direct field initialization",
                "the admitted body is exactly one `self.field = field` assignment per field",
                "move computation into ordinary functions and keep init as direct assignments",
            ));
        };
        let [target] = targets.as_slice() else {
            return Err(runtime_type_diagnostic(
                request,
                statement.source,
                "semantic-init-assignment-shape",
                "initializer assignment must target exactly one direct self field",
                "parallel and projected stores do not have partial-initialization lowering",
                "write one `self.field = field` assignment",
            ));
        };
        let [wrela_hir::PlaceProjection::Field(field_name)] = target.projections.as_slice() else {
            return Err(runtime_type_diagnostic(
                request,
                target.source,
                "semantic-init-assignment-shape",
                "initializer assignment must target one direct self field",
                "nested and indexed partial places are not represented in this slice",
                "write `self.field = field`",
            ));
        };
        let receiver_matches =
            matches!(target.root, Definition::Parameter(parameter) if parameter == receiver.id);
        let Some(field_index) = aggregate
            .fields
            .iter()
            .position(|field| field.name == *field_name)
        else {
            return Err(runtime_type_diagnostic(
                request,
                target.source,
                "semantic-init-assignment-shape",
                "initializer assignment names no declared field",
                "field identities are nominal and matched exactly",
                "assign one of the structure's declared fields",
            ));
        };
        let rhs_matches = program.expression(*value).is_some_and(|expression| {
            matches!(expression.kind, ExpressionKind::Reference(Definition::Parameter(parameter))
                if initializer.parameters.get(field_index.saturating_add(1)) == Some(&parameter))
        });
        if !receiver_matches || !rhs_matches || initialized[field_index] {
            return Err(runtime_type_diagnostic(
                request,
                statement.source,
                "semantic-init-assignment-shape",
                "initializer must assign each self field exactly once from its matching parameter",
                "the call-site desugar preserves only the authenticated one-to-one field map",
                "write one `self.field = field` assignment for every field",
            ));
        }
        initialized[field_index] = true;
    }
    if initialized.iter().any(|field| !field) {
        return Err(runtime_type_diagnostic(
            request,
            body.source,
            "semantic-init-partial",
            "initializer success path leaves a field uninitialized",
            "every field must be assigned exactly once before normal completion",
            "assign the missing field directly from its matching initializer parameter",
        ));
    }
    Ok(())
}

fn parameter_is_effectively_positional(
    parameter: &wrela_hir::Parameter,
    non_receiver_count: usize,
) -> bool {
    if parameter.receiver {
        return true;
    }
    non_receiver_count <= 1 || parameter.positional_only
}

fn resolve_declaration_owned_argument(
    request: &AnalysisRequest<'_>,
    target_parameters: &[FunctionParameter],
    argument: &wrela_hir::CallArgument,
    resolved_arguments: &[Option<ResolvedCallArgument>],
    non_receiver_count: usize,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<usize> {
    match &argument.name {
        Some(name) => {
            let mut found = None;
            for (index, parameter) in target_parameters.iter().enumerate() {
                check_cancelled(is_cancelled)?;
                let hir_parameter = request
                    .hir
                    .as_program()
                    .parameters
                    .get(parameter.parameter.0 as usize)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let matches = hir_parameter
                    .name
                    .as_ref()
                    .is_some_and(|parameter_name| parameter_name == name);
                if matches && found.replace(index).is_some() {
                    return Err(runtime_diagnostic(
                        request,
                        argument.source,
                        "semantic-argument-duplicate",
                        "call argument label matches more than one parameter",
                        None,
                        "declaration-owned labels require one exact parameter match",
                        "rename one of the parameters so each label is unique",
                    ));
                }
            }
            let Some(parameter_index) = found else {
                return Err(runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-argument-unknown-label",
                    "call argument label does not name a declared parameter",
                    None,
                    "argument labels are matched exactly against the selected declaration",
                    "use the parameter's declared name, or omit the label for a positional-only parameter",
                ));
            };
            let hir_parameter = request
                .hir
                .as_program()
                .parameters
                .get(target_parameters[parameter_index].parameter.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            if parameter_is_effectively_positional(hir_parameter, non_receiver_count) {
                return Err(runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-argument-label-forbidden",
                    "this parameter is positional-only and must not be labeled",
                    None,
                    "unary non-receiver parameters and `_` parameters omit their labels at call sites",
                    "remove the argument label",
                ));
            }
            Ok(parameter_index)
        }
        None => {
            let mut found = None;
            for (index, parameter) in target_parameters.iter().enumerate() {
                check_cancelled(is_cancelled)?;
                if resolved_arguments.get(index).is_some_and(Option::is_some) {
                    continue;
                }
                let hir_parameter = request
                    .hir
                    .as_program()
                    .parameters
                    .get(parameter.parameter.0 as usize)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if !parameter_is_effectively_positional(hir_parameter, non_receiver_count) {
                    continue;
                }
                found = Some(index);
                break;
            }
            found.ok_or_else(|| {
                runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-argument-label-required",
                    "this call needs a labeled argument for a remaining parameter",
                    None,
                    "multi-parameter declarations require labels unless a parameter is declared with `_`",
                    "write the parameter label, or declare the parameter positional-only with `_`",
                )
            })
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn analyze_inline_if_expression(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression_id: ExpressionId,
    source: Span,
    condition: ExpressionId,
    then_branch: ExpressionId,
    elif_branches: &[(ExpressionId, ExpressionId)],
    else_branch: ExpressionId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let bool_ty = ensure_primitive_type(
        request,
        partial,
        PrimitiveSemanticType::Bool,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    let condition_outcome = analyze_runtime_expression(
        request,
        partial,
        function,
        condition,
        RuntimeExpressionRequest {
            expected: Some(bool_ty),
            desired_result: None,
            access: AccessMode::Value,
        },
        state,
        is_cancelled,
    )?;
    let then_outcome = analyze_runtime_expression(
        request,
        partial,
        function,
        then_branch,
        RuntimeExpressionRequest {
            expected: expression_request.expected,
            desired_result: None,
            access: AccessMode::Value,
        },
        state,
        is_cancelled,
    )?;
    let mut effects = condition_outcome.effects;
    effects.0 |= then_outcome.effects.0;
    let arm_ty = then_outcome.ty;
    for (elif_condition, elif_branch) in elif_branches {
        check_cancelled(is_cancelled)?;
        let elif_condition_outcome = analyze_runtime_expression(
            request,
            partial,
            function,
            *elif_condition,
            RuntimeExpressionRequest {
                expected: Some(bool_ty),
                desired_result: None,
                access: AccessMode::Value,
            },
            state,
            is_cancelled,
        )?;
        effects.0 |= elif_condition_outcome.effects.0;
        let elif_outcome = analyze_runtime_expression(
            request,
            partial,
            function,
            *elif_branch,
            RuntimeExpressionRequest {
                expected: Some(arm_ty),
                desired_result: None,
                access: AccessMode::Value,
            },
            state,
            is_cancelled,
        )?;
        effects.0 |= elif_outcome.effects.0;
        if elif_outcome.ty != arm_ty {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-if-expression-type",
                "inline `if` expression arms must agree on one result type",
                "each branch produces a value of the same type",
                "change an arm so every branch yields the same type",
            ));
        }
    }
    let else_outcome = analyze_runtime_expression(
        request,
        partial,
        function,
        else_branch,
        RuntimeExpressionRequest {
            expected: Some(arm_ty),
            desired_result: None,
            access: AccessMode::Value,
        },
        state,
        is_cancelled,
    )?;
    effects.0 |= else_outcome.effects.0;
    if else_outcome.ty != arm_ty {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-if-expression-type",
            "inline `if` expression arms must agree on one result type",
            "each branch produces a value of the same type",
            "change an arm so every branch yields the same type",
        ));
    }
    if expression_request
        .expected
        .is_some_and(|expected| expected != arm_ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-scalar-type-mismatch",
            "scalar expression type does not match its required context",
            "revision 0.1 performs no implicit numeric conversion",
            "use an explicit checked `as` conversion",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (expression_id, source),
        arm_ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: expression_id,
            ty: arm_ty,
            result: Some(result),
            resolution: ExpressionResolution::Value(result),
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: arm_ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

fn analyze_scope_direct_call(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    call: RuntimeScopeCall<'_>,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let RuntimeScopeCall {
        direct: call,
        declaration,
    } = call;
    if !state.allow_scope_call {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-scope-call-outside-with",
            "scope acquisition may only appear as the value of a with statement",
            "a scope call creates cleanup obligations that require lexical activation tracking",
            "write `with scope_name(...) as binding:`",
        ));
    }
    let protocol_id = ensure_scope_protocol(
        request,
        partial,
        declaration,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    let protocol = partial
        .scope_protocols
        .get(protocol_id.0 as usize)
        .cloned()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if expression_request
        .expected
        .is_some_and(|expected| expected != protocol.result)
        || call.arguments.len() != protocol.parameters.len()
    {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-scope-call-signature",
            "scope acquisition arguments or result context do not match the protocol",
            "scope calls use the declaration's exact parameter access and state type",
            "match the scope declaration's arguments and with binding type",
        ));
    }
    let DeclarationKind::Scope(source_scope) = &request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .kind
    else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let mut target_parameters = Vec::new();
    target_parameters
        .try_reserve_exact(protocol.parameters.len())
        .map_err(|_| fact_resource(request, "scope call parameters"))?;
    for (parameter, semantic) in source_scope
        .parameters
        .iter()
        .filter(|parameter| **parameter != source_scope.exit_parameter)
        .zip(&protocol.parameters)
    {
        target_parameters.push(FunctionParameter {
            parameter: *parameter,
            value: ValueId(0),
            access: semantic.access,
            ty: semantic.ty,
        });
    }
    let callable_ty = ensure_callable_type(
        request,
        partial,
        FunctionColor::Sync,
        protocol.parameters.clone(),
        protocol.result,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.callee,
            ty: callable_ty,
            result: None,
            resolution: ExpressionResolution::Scope(protocol_id),
            effects: EffectSet(0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    let mut resolved = optional_call_map(call.arguments.len(), request.limits.fact_edges)?;
    let mut effects = EffectSet(0);
    let mut accesses: Vec<(ValueId, AccessMode, Span)> = Vec::new();
    accesses
        .try_reserve_exact(call.arguments.len())
        .map_err(|_| fact_resource(request, "scope call ownership accesses"))?;
    for (source_index, argument) in call.arguments.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let parameter_index = resolve_declaration_owned_argument(
            request,
            &target_parameters,
            argument,
            &resolved,
            target_parameters.len(),
            is_cancelled,
        )?;
        let target = target_parameters
            .get(parameter_index)
            .copied()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let access = match (&argument.value, target.access) {
            (wrela_hir::CallArgumentValue::Value(_), AccessMode::Value | AccessMode::Read) => {
                target.access
            }
            (wrela_hir::CallArgumentValue::Exclusive { .. }, expected)
                if lower_access(argument.access()) == expected =>
            {
                expected
            }
            _ => {
                return Err(runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-access-marker-mismatch",
                    "scope argument access does not match the parameter contract",
                    None,
                    "the source access marker must exactly name the scope parameter access",
                    "change the argument marker to match the declared parameter",
                ));
            }
        };
        let outcome = match &argument.value {
            wrela_hir::CallArgumentValue::Value(value) => analyze_runtime_expression(
                request,
                partial,
                function,
                *value,
                RuntimeExpressionRequest {
                    expected: Some(target.ty),
                    desired_result: None,
                    access,
                },
                state,
                is_cancelled,
            )?,
            wrela_hir::CallArgumentValue::Exclusive { place, .. } => analyze_runtime_place(
                request,
                partial,
                function,
                place,
                target,
                state,
                is_cancelled,
            )?,
        };
        effects.0 |= outcome.effects.0;
        let value = outcome
            .referenced
            .or(outcome.result)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if let Some((_, _, first_source)) = accesses.iter().find(|(prior, prior_access, _)| {
            *prior == value && accesses_conflict(*prior_access, access)
        }) {
            let mut diagnostic = runtime_ownership_diagnostic(
                request,
                argument.source,
                "semantic-overlapping-access",
                "one scope acquisition requests overlapping exclusive access to the same value",
                runtime_binding_by_value(state.locals, state.parameters, value, is_cancelled)?,
                "mutable and take access are exclusive for the complete acquisition",
                "move one argument into a distinct local or use read access only",
            )?;
            diagnostic.labels.insert(
                0,
                wrela_diagnostics::Label {
                    span: *first_source,
                    message: "the first overlapping access begins here".to_owned(),
                },
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
        accesses.push((value, access, argument.source));
        let slot = resolved
            .get_mut(parameter_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot
            .replace(ResolvedCallArgument {
                source_index: u32::try_from(source_index)
                    .map_err(|_| fact_resource(request, "scope call arguments"))?,
                parameter_index: u32::try_from(parameter_index)
                    .map_err(|_| fact_resource(request, "scope call arguments"))?,
                access,
                value,
            })
            .is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    let mut arguments = Vec::new();
    arguments
        .try_reserve_exact(resolved.len())
        .map_err(|_| fact_resource(request, "scope call arguments"))?;
    for argument in resolved {
        arguments.push(argument.ok_or(AnalysisFailure::RequestMismatch)?);
    }
    let result = expression_result(
        request,
        partial,
        function,
        (call.expression, call.source),
        protocol.result,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.expression,
            ty: protocol.result,
            result: Some(result),
            resolution: ExpressionResolution::ScopeCall {
                protocol: protocol_id,
                arguments,
            },
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: protocol.result,
        result: Some(result),
        referenced: None,
        effects,
    })
}

#[allow(clippy::too_many_arguments)]
fn analyze_projection_direct_call(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    call: RuntimeDirectCall<'_>,
    declaration: DeclarationId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let protocol_id = ensure_projection_protocol(
        request,
        partial,
        declaration,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    let protocol = partial
        .projection_protocols
        .get(protocol_id.0 as usize)
        .filter(|protocol| protocol.id == protocol_id)
        .cloned()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let expected_category = if protocol.mutable {
        ValueCategory::MutableView
    } else {
        ValueCategory::SharedView
    };
    let Some(result_value) = expression_request.desired_result else {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-projection-carrier-rebound",
            "projection result must initialize one explicit view binding",
            "a regionless projection view has one lexical carrier and cannot exist as a temporary or owned value",
            "bind the call directly as `name: view T = projection(...)`",
        ));
    };
    if expression_request
        .expected
        .is_some_and(|expected| expected != protocol.target)
        || call.arguments.len() != protocol.parameters.len()
        || partial
            .values
            .get(result_value.0 as usize)
            .is_none_or(|value| {
                value.function != function
                    || value.ty != protocol.target
                    || value.category != expected_category
            })
    {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-projection-call-signature",
            "projection arguments or view binding do not match the declared protocol",
            "projection calls preserve the declaration's exact access contract and carrier mutability",
            "match every projection parameter and bind the declared view kind",
        ));
    }
    let source_projection = request
        .hir
        .as_program()
        .declaration(declaration)
        .and_then(|record| match &record.kind {
            DeclarationKind::Projection(projection) => Some(projection),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut target_parameters = Vec::new();
    target_parameters
        .try_reserve_exact(protocol.parameters.len())
        .map_err(|_| fact_resource(request, "projection call parameters"))?;
    for (parameter, semantic) in source_projection
        .parameters
        .iter()
        .zip(&protocol.parameters)
    {
        target_parameters.push(FunctionParameter {
            parameter: *parameter,
            value: ValueId(0),
            access: semantic.access,
            ty: semantic.ty,
        });
    }
    let mut callable_parameters = Vec::new();
    callable_parameters
        .try_reserve_exact(protocol.parameters.len())
        .map_err(|_| fact_resource(request, "projection callable parameters"))?;
    for parameter in &protocol.parameters {
        check_cancelled(is_cancelled)?;
        callable_parameters.push(SemanticParameter {
            access: parameter.access,
            ty: parameter.ty,
        });
    }
    let callable_ty = ensure_callable_type(
        request,
        partial,
        FunctionColor::Sync,
        callable_parameters,
        protocol.target,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.callee,
            ty: callable_ty,
            result: None,
            resolution: ExpressionResolution::Projection(protocol_id),
            effects: EffectSet(0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    let mut resolved = optional_call_map(call.arguments.len(), request.limits.fact_edges)?;
    let mut effects = EffectSet(0);
    let mut accesses: Vec<(ValueId, AccessMode, Span)> = Vec::new();
    accesses
        .try_reserve_exact(call.arguments.len())
        .map_err(|_| fact_resource(request, "projection call ownership accesses"))?;
    for (source_index, argument) in call.arguments.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let parameter_index = resolve_declaration_owned_argument(
            request,
            &target_parameters,
            argument,
            &resolved,
            target_parameters.len(),
            is_cancelled,
        )?;
        let target = target_parameters
            .get(parameter_index)
            .copied()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let access = match (&argument.value, target.access) {
            (wrela_hir::CallArgumentValue::Value(_), AccessMode::Value | AccessMode::Read) => {
                target.access
            }
            (wrela_hir::CallArgumentValue::Exclusive { .. }, expected)
                if lower_access(argument.access()) == expected =>
            {
                expected
            }
            _ => {
                return Err(runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-access-marker-mismatch",
                    "projection argument access does not match the source parameter",
                    None,
                    "the call-site access marker must preserve the projection's source authority",
                    "change the argument marker to match the projection declaration",
                ));
            }
        };
        let outcome = match &argument.value {
            wrela_hir::CallArgumentValue::Value(value) => analyze_runtime_expression(
                request,
                partial,
                function,
                *value,
                RuntimeExpressionRequest {
                    expected: Some(target.ty),
                    desired_result: None,
                    access,
                },
                state,
                is_cancelled,
            )?,
            wrela_hir::CallArgumentValue::Exclusive { place, .. } => analyze_runtime_place(
                request,
                partial,
                function,
                place,
                target,
                state,
                is_cancelled,
            )?,
        };
        effects.0 |= outcome.effects.0;
        let value = outcome.referenced.ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                argument.source,
                "semantic-projection-argument-place-pending",
                "projection source must be a direct named place",
                "temporary and projected arguments do not yet have exact retained-root overlap facts",
                "bind the source to a local or pass a parameter directly",
            )
        })?;
        if let Some((_, _, first_source)) = accesses.iter().find(|(prior, prior_access, _)| {
            *prior == value && accesses_conflict(*prior_access, access)
        }) {
            let mut diagnostic = runtime_ownership_diagnostic(
                request,
                argument.source,
                "semantic-overlapping-access",
                "one projection activation requests overlapping exclusive access to one source",
                runtime_binding_by_value(state.locals, state.parameters, value, is_cancelled)?,
                "mutable projection sources are exclusive for the activation",
                "use distinct source roots or read-only access",
            )?;
            diagnostic.labels.insert(
                0,
                wrela_diagnostics::Label {
                    span: *first_source,
                    message: "the first overlapping projection source begins here".to_owned(),
                },
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
        accesses.push((value, access, argument.source));
        let slot = resolved
            .get_mut(parameter_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot
            .replace(ResolvedCallArgument {
                source_index: u32::try_from(source_index)
                    .map_err(|_| fact_resource(request, "projection call arguments"))?,
                parameter_index: u32::try_from(parameter_index)
                    .map_err(|_| fact_resource(request, "projection call arguments"))?,
                access,
                value,
            })
            .is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    let mut arguments = Vec::new();
    arguments
        .try_reserve_exact(resolved.len())
        .map_err(|_| fact_resource(request, "projection call arguments"))?;
    for argument in resolved {
        arguments.push(argument.ok_or(AnalysisFailure::RequestMismatch)?);
    }
    let view = LexicalViewId(
        u32::try_from(partial.lexical_views.len())
            .map_err(|_| fact_resource(request, "lexical views"))?,
    );
    append_expression_fact_with_category(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.expression,
            ty: protocol.target,
            result: Some(result_value),
            resolution: ExpressionResolution::ProjectionCall {
                protocol: protocol_id,
                arguments,
                view,
            },
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
        expected_category,
        None,
    )?;
    Ok(RuntimeExpression {
        ty: protocol.target,
        result: Some(result_value),
        referenced: None,
        effects,
    })
}

#[derive(Clone, Copy)]
enum GenericCallForm {
    Function,
    Method,
}

impl GenericCallForm {
    fn code(self, function: &'static str, method: &'static str) -> &'static str {
        match self {
            Self::Function => function,
            Self::Method => method,
        }
    }
}

fn generic_call_signature_position(
    request: &AnalysisRequest<'_>,
    _declaration: DeclarationId,
    generics: &[wrela_hir::GenericParameterId],
    source: &TypeExpression,
    form: GenericCallForm,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<Option<usize>> {
    match &source.kind {
        TypeExpressionKind::Named {
            definition: Definition::Builtin(_),
            arguments,
        } if arguments.is_empty() => Ok(None),
        TypeExpressionKind::Named {
            definition: Definition::Generic(generic),
            arguments,
        } if arguments.is_empty() => {
            for (index, candidate) in generics.iter().enumerate() {
                charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
                if candidate == generic {
                    return Ok(Some(index));
                }
            }
            Err(runtime_type_diagnostic(
                request,
                source.source,
                form.code(
                    "semantic-generic-function-signature-pending",
                    "semantic-generic-method-signature-pending",
                ),
                "generic callable signature refers to a type parameter owned elsewhere",
                "closed-world specialization substitutes only this callable's ordered parameters",
                "use one of the callable's own unbounded type parameters",
            ))
        }
        _ => Err(runtime_type_diagnostic(
            request,
            source.source,
            form.code(
                "semantic-generic-function-signature-pending",
                "semantic-generic-method-signature-pending",
            ),
            "generic callable signature is outside the copy-scalar specialization subset",
            "nested nominal, generic, view, tuple, array, and function types require later monomorphization support",
            "use primitive stored copy scalars or bare unbounded type parameters",
        )),
    }
}

fn known_call_argument_type(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    argument: &wrela_hir::CallArgument,
    state: &RuntimeState<'_>,
) -> Option<SemanticTypeId> {
    let binding = match &argument.value {
        wrela_hir::CallArgumentValue::Value(expression) => {
            match request.hir.as_program().expression(*expression)?.kind {
                ExpressionKind::Reference(Definition::Local(local)) => {
                    state.locals.get(local.0 as usize)?.as_ref()?
                }
                ExpressionKind::Reference(Definition::Parameter(parameter)) => {
                    state.parameters.get(parameter.0 as usize)?.as_ref()?
                }
                _ => return None,
            }
        }
        wrela_hir::CallArgumentValue::Exclusive { place, .. } => match place.root {
            Definition::Local(local) => state.locals.get(local.0 as usize)?.as_ref()?,
            Definition::Parameter(parameter) => {
                state.parameters.get(parameter.0 as usize)?.as_ref()?
            }
            _ => return None,
        },
    };
    partial
        .values
        .get(binding.value.0 as usize)
        .map(|value| value.ty)
}

#[allow(clippy::too_many_arguments)]
fn infer_generic_call_arguments(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    call: RuntimeDirectCall<'_>,
    declaration: DeclarationId,
    source: &wrela_hir::FunctionDeclaration,
    expected: Option<SemanticTypeId>,
    form: GenericCallForm,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<Vec<SemanticArgument>> {
    const MAX_KEYED_ARGUMENTS: usize = 26;
    let declaration_record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let receiver_offset = match form {
        GenericCallForm::Function
            if source.color == FunctionColor::Sync
                && matches!(
                    declaration_record.owner,
                    wrela_hir::DeclarationOwner::Module(_)
                ) =>
        {
            0
        }
        GenericCallForm::Method
            if source.color == FunctionColor::Sync
                && crate::interfaces::receiver_concrete_struct(
                    request.hir.as_program(),
                    declaration,
                )
                .is_some()
                && source
                    .parameters
                    .first()
                    .and_then(|parameter| request.hir.as_program().parameter(*parameter))
                    .is_some_and(|parameter| parameter.receiver) =>
        {
            1
        }
        _ => {
            let (code, message, note, help) = match form {
                GenericCallForm::Function => (
                    "semantic-generic-function-signature-pending",
                    "generic runtime specialization currently requires a module-level synchronous function",
                    "methods, receivers, async functions, and nested declarations require later specialization and lowering contracts",
                    "use a module-level `fn` with copy-scalar parameters and result",
                ),
                GenericCallForm::Method => (
                    "semantic-generic-method-shape-pending",
                    "generic method specialization requires one concrete synchronous receiver method",
                    "associated, asynchronous, and malformed receiver methods require later dispatch contracts",
                    "use a synchronous method with one leading `read self` receiver",
                ),
            };
            return Err(runtime_type_diagnostic(
                request,
                declaration_record.source,
                code,
                message,
                note,
                help,
            ));
        }
    };
    if source.generics.is_empty() {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            form.code(
                "semantic-generic-function-signature-pending",
                "semantic-generic-method-shape-pending",
            ),
            "generic specialization was requested for a callable without type parameters",
            "the specialization key is reserved for nonempty ordered type arguments",
            "use the ordinary concrete-call path",
        ));
    }
    if source.generics.len() > MAX_KEYED_ARGUMENTS {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            form.code(
                "semantic-generic-function-parameter-count",
                "semantic-generic-method-parameter-count",
            ),
            "generic callable declares more type parameters than the bounded specialization key supports",
            "this analysis slice authenticates at most 26 ordered primitive type arguments",
            "split the function into smaller generic helpers",
        ));
    }
    for generic_id in &source.generics {
        check_cancelled(is_cancelled)?;
        let generic = request
            .hir
            .as_program()
            .generic_parameter(*generic_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if generic.owner != declaration
            || !matches!(
                generic.kind,
                wrela_hir::GenericParameterKind::Type { bound: None }
            )
        {
            return Err(runtime_type_diagnostic(
                request,
                generic.source,
                form.code(
                    "semantic-generic-function-parameter-kind",
                    "semantic-generic-method-parameter-kind",
                ),
                "generic runtime callable parameter is outside the unbounded type-only subset",
                "constant, region, and bounded type parameters require later inference and specialization contracts",
                "use an unbounded type parameter specialized by a primitive stored copy scalar",
            ));
        }
    }
    let explicit_parameter_count = source
        .parameters
        .len()
        .checked_sub(receiver_offset)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if call.arguments.len() != explicit_parameter_count {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            form.code(
                "semantic-generic-function-argument-count",
                "semantic-method-call-argument-count",
            ),
            "generic callable has the wrong number of explicit value arguments",
            "inference requires one exact call argument for every declared parameter",
            "supply every declared function argument exactly once",
        ));
    }

    let mut inferred = Vec::new();
    inferred
        .try_reserve_exact(source.generics.len())
        .map_err(|_| fact_resource(request, "generic function inference"))?;
    inferred.resize(source.generics.len(), None);
    let constrain = |inferred: &mut [Option<SemanticTypeId>],
                     position: usize,
                     ty: SemanticTypeId,
                     source_span: Span|
     -> RuntimeResult<()> {
        let record = partial
            .types
            .get(ty.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if !is_stored_copy_scalar_type(record) {
            return Err(runtime_type_diagnostic(
                request,
                source_span,
                form.code(
                    "semantic-generic-function-argument-type",
                    "semantic-generic-method-argument-type",
                ),
                "generic callable inference produced a non-scalar type argument",
                "this specialization slice admits only bool, integer, and f32/f64 stored copy scalars",
                "pass a supported copy-scalar value",
            ));
        }
        let slot = inferred
            .get_mut(position)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot.is_some_and(|existing| existing != ty) {
            return Err(runtime_type_diagnostic(
                request,
                source_span,
                form.code(
                    "semantic-generic-function-inference-conflict",
                    "semantic-generic-method-inference-conflict",
                ),
                "generic callable constraints infer different types for one parameter",
                "expected result and typed arguments must agree on each ordered type argument",
                "make every use of this type parameter the same primitive copy-scalar type",
            ));
        }
        *slot = Some(ty);
        Ok(())
    };

    if let (Some(result), Some(expected)) = (&source.result, expected) {
        if let Some(position) = generic_call_signature_position(
            request,
            declaration,
            &source.generics,
            result,
            form,
            &mut *state.aggregate_work,
            is_cancelled,
        )? {
            constrain(&mut inferred, position, expected, result.source)?;
        }
    } else if let Some(result) = &source.result {
        generic_call_signature_position(
            request,
            declaration,
            &source.generics,
            result,
            form,
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
    }

    let mut inference_parameters = Vec::new();
    inference_parameters
        .try_reserve_exact(explicit_parameter_count)
        .map_err(|_| fact_resource(request, "generic function inference parameters"))?;
    for parameter_id in source.parameters.iter().skip(receiver_offset) {
        check_cancelled(is_cancelled)?;
        let parameter = request
            .hir
            .as_program()
            .parameter(*parameter_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if parameter.receiver {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        inference_parameters.push(FunctionParameter {
            parameter: *parameter_id,
            value: ValueId(0),
            access: lower_access(parameter.access),
            ty: SemanticTypeId(0),
        });
    }
    let mut resolved = optional_call_map(call.arguments.len(), request.limits.fact_edges)?;
    for (source_index, argument) in call.arguments.iter().enumerate() {
        let parameter_index = resolve_declaration_owned_argument(
            request,
            &inference_parameters,
            argument,
            &resolved,
            explicit_parameter_count,
            is_cancelled,
        )?;
        let parameter = request
            .hir
            .as_program()
            .parameter(inference_parameters[parameter_index].parameter)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let parameter_ty = parameter
            .ty
            .as_ref()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if let Some(position) = generic_call_signature_position(
            request,
            declaration,
            &source.generics,
            parameter_ty,
            form,
            &mut *state.aggregate_work,
            is_cancelled,
        )? && let Some(ty) = known_call_argument_type(request, partial, argument, state)
        {
            constrain(&mut inferred, position, ty, argument.source)?;
        }
        resolved[parameter_index] = Some(ResolvedCallArgument {
            source_index: u32::try_from(source_index)
                .map_err(|_| fact_resource(request, "generic function inference arguments"))?,
            parameter_index: u32::try_from(parameter_index)
                .map_err(|_| fact_resource(request, "generic function inference arguments"))?,
            access: AccessMode::Value,
            value: ValueId(0),
        });
    }

    let mut arguments = Vec::new();
    arguments
        .try_reserve_exact(inferred.len())
        .map_err(|_| fact_resource(request, "generic function arguments"))?;
    for (position, inferred) in inferred.into_iter().enumerate() {
        let Some(ty) = inferred else {
            let source_span = source
                .generics
                .get(position)
                .and_then(|generic| request.hir.as_program().generic_parameter(*generic))
                .map_or(declaration_record.source, |generic| generic.source);
            return Err(runtime_type_diagnostic(
                request,
                source_span,
                form.code(
                    "semantic-generic-function-inference-required",
                    "semantic-generic-method-inference-required",
                ),
                "generic callable type argument is unconstrained at this call",
                "every type parameter must be fixed by an expected result or a typed named argument",
                "add an explicit result context or pass a previously typed local or parameter",
            ));
        };
        arguments.push(SemanticArgument::Type(ty));
    }
    Ok(arguments)
}

fn method_is_visible_from(
    program: &wrela_hir::Program,
    method: DeclarationId,
    caller_module: wrela_package::ModuleId,
) -> bool {
    let Some(record) = program.declaration(method) else {
        return false;
    };
    if record.module == caller_module {
        return true;
    }
    let wrela_hir::DeclarationOwner::Declaration(owner) = record.owner else {
        return false;
    };
    match program.declaration(owner).map(|record| &record.kind) {
        Some(DeclarationKind::Structure(_)) => record.visibility == wrela_hir::Visibility::Public,
        Some(DeclarationKind::Implementation(implementation)) => {
            let visible_nominal = |ty: &wrela_hir::TypeExpression, applied: bool| {
                let TypeExpressionKind::Named {
                    definition: Definition::Declaration(resolved),
                    arguments,
                } = &ty.kind
                else {
                    return false;
                };
                (applied || arguments.is_empty())
                    && program
                        .declaration(resolved.declaration)
                        .is_some_and(|record| record.visibility == wrela_hir::Visibility::Public)
            };
            visible_nominal(&implementation.interface, true)
                && visible_nominal(&implementation.implementing_type, false)
        }
        _ => false,
    }
}

fn method_caller_module(
    partial: &PartialAnalysis,
    program: &wrela_hir::Program,
    caller: FunctionInstanceId,
) -> Option<wrela_package::ModuleId> {
    let FunctionOrigin::Source { declaration, .. } =
        partial.functions.get(caller.0 as usize)?.origin
    else {
        return None;
    };
    program.declaration(declaration).map(|record| record.module)
}

#[allow(clippy::too_many_arguments)]
fn analyze_concrete_method_call(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    call: RuntimeDirectCall<'_>,
    receiver_expression: ExpressionId,
    method_name: &wrela_hir::Name,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let program = request.hir.as_program();
    let receiver_source = program
        .expression(receiver_expression)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if !matches!(
        receiver_source.kind,
        ExpressionKind::Reference(Definition::Local(_) | Definition::Parameter(_))
    ) {
        return Err(runtime_type_diagnostic(
            request,
            receiver_source.source,
            "semantic-method-call-receiver-expression-pending",
            "method receiver is not a live named local or parameter",
            "the concrete method-call substrate does not extend receiver authority through temporaries, fields, indexes, or associated names",
            "bind the complete receiver value to a local before calling a read-receiver method",
        ));
    }
    let receiver = analyze_runtime_expression(
        request,
        partial,
        function,
        receiver_expression,
        RuntimeExpressionRequest {
            expected: None,
            desired_result: None,
            access: AccessMode::Read,
        },
        state,
        is_cancelled,
    )?;
    let receiver_value = receiver
        .referenced
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let receiver_declaration = match partial
        .types
        .get(receiver.ty.0 as usize)
        .map(|record| &record.kind)
    {
        Some(SemanticTypeKind::Structure {
            declaration,
            arguments,
            fields,
        }) if arguments.is_empty()
            && fields.iter().all(|field| {
                partial
                    .types
                    .get(field.ty.0 as usize)
                    .is_some_and(is_stored_copy_scalar_type)
            }) =>
        {
            *declaration
        }
        Some(SemanticTypeKind::Structure {
            arguments, fields, ..
        }) if !arguments.is_empty()
            && fields.iter().all(|field| {
                partial
                    .types
                    .get(field.ty.0 as usize)
                    .is_some_and(is_stored_copy_scalar_type)
            }) =>
        {
            return Err(runtime_type_diagnostic(
                request,
                receiver_source.source,
                "semantic-generic-method-receiver-pending",
                "method receiver is itself a generic structure specialization",
                "this increment specializes method-owned type parameters only; receiver-owned substitution requires a distinct dispatch key",
                "use a nongeneric flat structure receiver until generic receiver dispatch lands",
            ));
        }
        _ => {
            return Err(runtime_type_diagnostic(
                request,
                receiver_source.source,
                "semantic-method-call-not-found",
                "no concrete read-receiver method applies to this value",
                "this increment resolves methods only on nongeneric flat stored-copy structures",
                "call a free function or use a supported concrete structure receiver",
            ));
        }
    };
    if let Some(DeclarationKind::Structure(structure)) = program
        .declaration(receiver_declaration)
        .map(|record| &record.kind)
    {
        for member in &structure.members {
            check_cancelled(is_cancelled)?;
            let Some(member) = program.declaration(*member) else {
                continue;
            };
            if member.name.as_ref() != Some(method_name) {
                continue;
            }
            match member.kind {
                DeclarationKind::Projection(_) => {
                    return Err(runtime_type_diagnostic(
                        request,
                        call.source,
                        "semantic-projection-receiver-call-pending",
                        "receiver projection calls are not yet supported",
                        "projection protocols retain a distinct lexical-view contract and take precedence over ordinary method lookup",
                        "use a supported free projection until receiver projection binding lands",
                    ));
                }
                DeclarationKind::Scope(_) => {
                    return Err(runtime_type_diagnostic(
                        request,
                        call.source,
                        "semantic-with-receiver-scope-pending",
                        "receiver-form scope acquisition is not yet supported",
                        "scope protocols retain a distinct cleanup contract and take precedence over ordinary method lookup",
                        "use a supported free scope until receiver scope binding lands",
                    ));
                }
                _ => {}
            }
        }
    }
    let caller_module =
        method_caller_module(partial, program, function).ok_or(AnalysisFailure::RequestMismatch)?;
    let mut candidates = Vec::new();
    for declaration in &program.declarations {
        check_cancelled(is_cancelled)?;
        if declaration.name.as_ref() != Some(method_name)
            || !matches!(declaration.kind, DeclarationKind::Function(_))
            || crate::interfaces::receiver_concrete_struct(program, declaration.id)
                != Some(receiver_declaration)
            || !method_is_visible_from(program, declaration.id, caller_module)
        {
            continue;
        }
        candidates
            .try_reserve(1)
            .map_err(|_| fact_resource(request, "method-call candidates"))?;
        candidates.push(declaration.id);
    }
    let target_declaration = match candidates.as_slice() {
        [] => {
            return Err(runtime_type_diagnostic(
                request,
                call.source,
                "semantic-method-call-not-found",
                "no visible method with this name applies to the receiver",
                "method lookup considers visible inherent members and concrete interface implementations",
                "declare one visible read-receiver method or correct the method name",
            ));
        }
        [target] => *target,
        _ => {
            let mut diagnostic = Diagnostic::error(
                Category::TYPE,
                call.source,
                "more than one visible method with this name applies to the receiver",
            );
            diagnostic.code = Some("semantic-method-call-ambiguous".to_owned());
            diagnostic.help.push(
                "rename one method or call an unambiguous free function until qualified method selection is specified"
                    .to_owned(),
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
    };
    let target_source = match &program
        .declaration(target_declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .kind
    {
        DeclarationKind::Function(source) => source,
        _ => return Err(AnalysisFailure::RequestMismatch.into()),
    };
    if target_source.color != FunctionColor::Sync {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-method-call-shape-pending",
            "asynchronous method calls are not in the direct method-call substrate",
            "this increment admits only synchronous methods with a concrete receiver",
            "use a synchronous read-receiver method until async dispatch lowering lands",
        ));
    }
    let receiver_parameter = target_source
        .parameters
        .first()
        .and_then(|parameter| program.parameter(*parameter))
        .filter(|parameter| parameter.receiver)
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                call.source,
                "semantic-method-call-shape-pending",
                "selected method does not have one leading receiver parameter",
                "method-call syntax requires the declaration's first parameter to be `self`",
                "declare a leading `read self` receiver",
            )
        })?;
    if receiver_parameter.access != wrela_hir::AccessMode::Read {
        return Err(runtime_type_diagnostic(
            request,
            receiver_parameter.source,
            "semantic-method-call-receiver-access-pending",
            "mutable and take receiver method calls are not yet supported",
            "the concrete method-call substrate preserves only a shared read loan for the complete call",
            "use a `read self` method until receiver mutation/take lowering lands",
        ));
    }
    let generic_arguments = if target_source.generics.is_empty() {
        Vec::new()
    } else {
        infer_generic_call_arguments(
            request,
            partial,
            call,
            target_declaration,
            target_source,
            expression_request.expected,
            GenericCallForm::Method,
            state,
            is_cancelled,
        )?
    };
    let target = ensure_ordinary_source_function(
        request,
        partial,
        target_declaration,
        &generic_arguments,
        state.allow_assertions,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    if target == function {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-runtime-recursive-call-pending",
            "recursive runtime method call is outside the bounded subset",
            "a source method may not re-enter its active analysis instance",
            "rewrite the recursion as a statically bounded loop or helper",
        ));
    }
    let target_record = partial
        .functions
        .get(target.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let target_result = target_record.result;
    let target_effects = target_record.effects;
    let target_parameters = target_record.parameters.clone();
    let Some(receiver_semantic) = target_parameters.first() else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if receiver_semantic.access != AccessMode::Read || receiver_semantic.ty != receiver.ty {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let explicit_parameters = target_parameters
        .get(1..)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let function_ty = ensure_function_type(
        request,
        partial,
        FunctionColor::Sync,
        explicit_parameters,
        target_result,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.callee,
            ty: function_ty,
            result: None,
            resolution: ExpressionResolution::Function(target),
            effects: EffectSet(0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    if expression_request
        .expected
        .is_some_and(|expected| expected != target_result)
    {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-method-call-result-type",
            "method result does not match the type required at this call site",
            "the selected concrete method has one exact declared result type",
            "change the destination type or call a method with the required result",
        ));
    }
    if call.arguments.len() != explicit_parameters.len() {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-method-call-argument-count",
            "method call has the wrong number of explicit arguments",
            "the implicit receiver does not count as a written argument",
            "supply exactly the method's non-receiver parameters",
        ));
    }
    let mut resolved_arguments =
        optional_call_map(call.arguments.len(), request.limits.fact_edges)?;
    let non_receiver_count = explicit_parameters.len();
    let mut accesses = vec![(receiver_value, AccessMode::Read, receiver_source.source)];
    for (source_index, argument) in call.arguments.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let relative_parameter = resolve_declaration_owned_argument(
            request,
            explicit_parameters,
            argument,
            &resolved_arguments,
            non_receiver_count,
            is_cancelled,
        )?;
        let parameter_index = relative_parameter
            .checked_add(1)
            .ok_or_else(|| fact_resource(request, "method-call parameter index"))?;
        let parameter = target_parameters
            .get(parameter_index)
            .copied()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let access = match (&argument.value, parameter.access) {
            (wrela_hir::CallArgumentValue::Value(_), AccessMode::Value | AccessMode::Read) => {
                parameter.access
            }
            (wrela_hir::CallArgumentValue::Exclusive { .. }, expected)
                if lower_access(argument.access()) == expected =>
            {
                expected
            }
            _ => {
                return Err(runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-access-marker-mismatch",
                    "call argument access does not match the method parameter contract",
                    None,
                    "the source access marker must exactly name the method parameter access",
                    "change the argument marker to match the declaration",
                ));
            }
        };
        let outcome = match &argument.value {
            wrela_hir::CallArgumentValue::Value(value) => analyze_runtime_expression(
                request,
                partial,
                function,
                *value,
                RuntimeExpressionRequest {
                    expected: Some(parameter.ty),
                    desired_result: None,
                    access,
                },
                state,
                is_cancelled,
            )?,
            wrela_hir::CallArgumentValue::Exclusive { place, .. } => analyze_runtime_place(
                request,
                partial,
                function,
                place,
                parameter,
                state,
                is_cancelled,
            )?,
        };
        let value = outcome
            .referenced
            .or(outcome.result)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if let Some((_, _, previous_source)) = accesses
            .iter()
            .find(|previous| previous.0 == value && accesses_conflict(previous.1, access))
        {
            let mut diagnostic = runtime_ownership_diagnostic(
                request,
                argument.source,
                "semantic-overlapping-access",
                "method call requests overlapping exclusive access to its receiver or another argument",
                runtime_binding_by_value(state.locals, state.parameters, value, is_cancelled)?,
                "the read receiver remains borrowed for the complete call",
                "move the argument into a distinct local or use read access only",
            )?;
            diagnostic
                .labels
                .try_reserve(1)
                .map_err(|_| fact_resource(request, "method-call ownership labels"))?;
            diagnostic.labels.insert(
                0,
                wrela_diagnostics::Label {
                    span: *previous_source,
                    message: "the earlier overlapping access begins here".to_owned(),
                },
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
        accesses.push((value, access, argument.source));
        let slot = resolved_arguments
            .get_mut(relative_parameter)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot
            .replace(ResolvedCallArgument {
                source_index: u32::try_from(source_index)
                    .map_err(|_| fact_resource(request, "method-call arguments"))?,
                parameter_index: u32::try_from(parameter_index)
                    .map_err(|_| fact_resource(request, "method-call arguments"))?,
                access,
                value,
            })
            .is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    let mut exact_arguments = Vec::new();
    exact_arguments
        .try_reserve_exact(resolved_arguments.len())
        .map_err(|_| fact_resource(request, "method-call arguments"))?;
    for argument in resolved_arguments {
        exact_arguments.push(argument.ok_or(AnalysisFailure::RequestMismatch)?);
    }
    let result = expression_result(
        request,
        partial,
        function,
        (call.expression, call.source),
        target_result,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.expression,
            ty: target_result,
            result: Some(result),
            resolution: ExpressionResolution::MethodCall {
                function: target,
                receiver: receiver_value,
                receiver_access: AccessMode::Read,
                arguments: exact_arguments,
            },
            effects: EffectSet(receiver.effects.0 | target_effects.0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: target_result,
        result: Some(result),
        referenced: None,
        effects: EffectSet(receiver.effects.0 | target_effects.0),
    })
}

fn analyze_direct_call(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    call: RuntimeDirectCall<'_>,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let callee_expression = request
        .hir
        .as_program()
        .expression(call.callee)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if let Some(resolved) =
        exact_resolved_enum_constructor(request.hir.as_program(), call.callee, is_cancelled)?
    {
        return analyze_closed_enum_constructor(
            request,
            partial,
            function,
            call,
            &resolved,
            expression_request,
            state,
            is_cancelled,
        );
    }
    if let ExpressionKind::DotName { candidates, .. } = &callee_expression.kind {
        let resolved = resolve_dot_variant_candidate(
            request,
            partial,
            candidates,
            expression_request.expected,
            call.source,
        )?;
        return analyze_closed_enum_constructor(
            request,
            partial,
            function,
            call,
            &resolved,
            expression_request,
            state,
            is_cancelled,
        );
    }
    if let ExpressionKind::Field { base, name } = &callee_expression.kind {
        return analyze_concrete_method_call(
            request,
            partial,
            function,
            call,
            *base,
            name,
            expression_request,
            state,
            is_cancelled,
        );
    }
    let ExpressionKind::Reference(Definition::Declaration(resolved)) = &callee_expression.kind
    else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if request
        .hir
        .as_program()
        .declaration(resolved.declaration)
        .is_some_and(|record| matches!(record.kind, DeclarationKind::Projection(_)))
    {
        return analyze_projection_direct_call(
            request,
            partial,
            function,
            call,
            resolved.declaration,
            expression_request,
            state,
            is_cancelled,
        );
    }
    if request
        .hir
        .as_program()
        .declaration(resolved.declaration)
        .is_some_and(|record| matches!(record.kind, DeclarationKind::Scope(_)))
    {
        return analyze_scope_direct_call(
            request,
            partial,
            function,
            RuntimeScopeCall {
                direct: call,
                declaration: resolved.declaration,
            },
            expression_request,
            state,
            is_cancelled,
        );
    }
    let is_struct = request
        .hir
        .as_program()
        .declaration(resolved.declaration)
        .is_some_and(|record| matches!(&record.kind, DeclarationKind::Structure(_)));
    let has_initializer = aggregate_has_initializer(request.hir.as_program(), resolved.declaration);
    if is_struct && !has_initializer {
        return analyze_flat_structure_constructor(
            request,
            partial,
            function,
            call,
            resolved.declaration,
            expression_request,
            state,
            is_cancelled,
        );
    }
    if has_initializer {
        let (initializer_id, initializer) =
            structure_initializer(request.hir.as_program(), resolved.declaration)
                .ok_or(AnalysisFailure::RequestMismatch)?;
        let ty = ensure_flat_structure_type(
            request,
            partial,
            resolved.declaration,
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
        validate_infallible_initializer(
            request,
            partial,
            resolved.declaration,
            initializer_id,
            initializer,
            ty,
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
        if call.arguments.len() != initializer.parameters.len().saturating_sub(1) {
            return Err(runtime_type_diagnostic(
                request,
                call.source,
                "semantic-init-argument",
                "initializer construction must supply every initializer parameter exactly once",
                "the admitted init protocol has an exact, closed parameter list",
                "supply one argument for every non-receiver initializer parameter",
            ));
        }
        let outcome = analyze_flat_structure_constructor(
            request,
            partial,
            function,
            call,
            resolved.declaration,
            expression_request,
            state,
            is_cancelled,
        )?;
        let fact = partial
            .expressions
            .iter_mut()
            .rev()
            .find(|fact| fact.function == function && fact.expression == call.expression)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if !matches!(
            fact.resolution,
            ExpressionResolution::Constructor {
                ty: candidate,
                variant: None,
            } if candidate == ty
        ) {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        fact.resolution = ExpressionResolution::InitializerConstruction {
            ty,
            initializer: initializer_id,
        };
        return Ok(outcome);
    }
    let generic_arguments = match request
        .hir
        .as_program()
        .declaration(resolved.declaration)
        .map(|record| &record.kind)
    {
        Some(DeclarationKind::Function(source)) if !source.generics.is_empty() => {
            infer_generic_call_arguments(
                request,
                partial,
                call,
                resolved.declaration,
                source,
                expression_request.expected,
                GenericCallForm::Function,
                state,
                is_cancelled,
            )?
        }
        _ => Vec::new(),
    };
    let target = ensure_ordinary_source_function(
        request,
        partial,
        resolved.declaration,
        &generic_arguments,
        state.allow_assertions,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    if target == function {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-runtime-recursive-call-pending",
            "recursive runtime call is outside the bounded specialization subset",
            "a source function may not re-enter an in-progress monomorphization",
            "rewrite the recursion as a statically bounded loop or an iterative helper",
        ));
    }
    let target_record = partial
        .functions
        .get(target.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if u64::try_from(target_record.parameters.len())
        .map_or(true, |count| count > request.limits.fact_edges)
    {
        return Err(fact_resource(request, "direct-call target parameters").into());
    }
    let target_color = target_record.color;
    let target_result = target_record.result;
    let target_effects = target_record.effects;
    let mut target_parameters = Vec::new();
    target_parameters
        .try_reserve_exact(target_record.parameters.len())
        .map_err(|_| fact_resource(request, "direct-call target parameters"))?;
    for parameter in &target_record.parameters {
        check_cancelled(is_cancelled)?;
        target_parameters.push(*parameter);
    }
    if target_color == FunctionColor::Async {
        let caller_is_async = partial
            .functions
            .get(function.0 as usize)
            .is_some_and(|function| function.color == FunctionColor::Async);
        let mut await_parents = 0u32;
        for parent in &request.hir.as_program().expressions {
            check_cancelled(is_cancelled)?;
            if matches!(
                parent.kind,
                ExpressionKind::Unary {
                    operator: wrela_hir::UnaryOperator::Await,
                    operand,
                } if operand == call.expression
            ) {
                await_parents = await_parents
                    .checked_add(1)
                    .ok_or_else(|| fact_resource(request, "async await parents"))?;
            }
        }
        if !caller_is_async || await_parents != 1 {
            let mut diagnostic = Diagnostic::error(
                Category::ASYNC,
                call.source,
                if caller_is_async {
                    "async activation must be consumed by exactly one immediate await"
                } else {
                    "a synchronous function cannot directly activate async work"
                },
            );
            diagnostic.code = Some(if caller_is_async {
                "semantic-async-result-not-awaited".to_owned()
            } else {
                "semantic-async-call-in-sync-function".to_owned()
            });
            diagnostic.help.push(
                "await the call in an async function or install a statically bounded @task entry"
                    .to_owned(),
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
    }
    if expression_request
        .expected
        .is_some_and(|expected| expected != target_result)
        || call.arguments.len() != target_parameters.len()
    {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let function_ty = ensure_function_type(
        request,
        partial,
        target_color,
        &target_parameters,
        target_result,
        &mut *state.aggregate_work,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.callee,
            ty: function_ty,
            result: None,
            resolution: ExpressionResolution::Function(target),
            effects: EffectSet(0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;

    let mut resolved_arguments =
        optional_call_map(call.arguments.len(), request.limits.fact_edges)?;
    let mut accesses: Vec<(ValueId, AccessMode, Span)> = Vec::new();
    accesses
        .try_reserve_exact(call.arguments.len())
        .map_err(|_| fact_resource(request, "direct-call ownership accesses"))?;
    let non_receiver_count = {
        let mut count = 0usize;
        for parameter in &target_parameters {
            check_cancelled(is_cancelled)?;
            let hir_parameter = request
                .hir
                .as_program()
                .parameters
                .get(parameter.parameter.0 as usize)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            if !hir_parameter.receiver {
                count = count
                    .checked_add(1)
                    .ok_or_else(|| fact_resource(request, "direct-call target parameters"))?;
            }
        }
        count
    };
    for (source_index, argument) in call.arguments.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let parameter_index = resolve_declaration_owned_argument(
            request,
            &target_parameters,
            argument,
            &resolved_arguments,
            non_receiver_count,
            is_cancelled,
        )?;
        let target_parameter = target_parameters
            .get(parameter_index)
            .copied()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let access = match (&argument.value, target_parameter.access) {
            (wrela_hir::CallArgumentValue::Value(_), AccessMode::Value | AccessMode::Read) => {
                target_parameter.access
            }
            (wrela_hir::CallArgumentValue::Exclusive { .. }, expected)
                if lower_access(argument.access()) == expected =>
            {
                expected
            }
            _ => {
                return Err(runtime_diagnostic(
                    request,
                    argument.source,
                    "semantic-access-marker-mismatch",
                    "call argument access does not match the parameter contract",
                    None,
                    "the source access marker must exactly name the callee parameter access",
                    "change the argument marker to match the declared parameter",
                ));
            }
        };
        let outcome = match &argument.value {
            wrela_hir::CallArgumentValue::Value(value) => analyze_runtime_expression(
                request,
                partial,
                function,
                *value,
                RuntimeExpressionRequest {
                    expected: Some(target_parameter.ty),
                    desired_result: None,
                    access: target_parameter.access,
                },
                state,
                is_cancelled,
            )?,
            wrela_hir::CallArgumentValue::Exclusive { place, .. } => analyze_runtime_place(
                request,
                partial,
                function,
                place,
                target_parameter,
                state,
                is_cancelled,
            )?,
        };
        if let Some(value) = outcome.referenced {
            let mut conflict = None;
            for previous in &accesses {
                check_cancelled(is_cancelled)?;
                if previous.0 == value && accesses_conflict(previous.1, target_parameter.access) {
                    conflict = Some(*previous);
                    break;
                }
            }
            if let Some((_, previous_access, previous_source)) = conflict {
                let binding =
                    runtime_binding_by_value(state.locals, state.parameters, value, is_cancelled)?;
                let mut diagnostic = runtime_ownership_diagnostic(
                    request,
                    argument.source,
                    "semantic-overlapping-access",
                    "one call requests overlapping exclusive access to the same value",
                    binding,
                    "mutable and take access are exclusive for the complete call",
                    "move one argument into a distinct local or use read access only",
                )?;
                diagnostic
                    .labels
                    .try_reserve(1)
                    .map_err(|_| fact_resource(request, "ownership diagnostic labels"))?;
                diagnostic.labels.insert(
                    0,
                    wrela_diagnostics::Label {
                        span: previous_source,
                        message: copy_static_analysis_text(
                            if previous_access == AccessMode::Mutate {
                                "the first mutable access begins here"
                            } else if previous_access == AccessMode::Take {
                                "the first ownership transfer begins here"
                            } else {
                                "the first overlapping read begins here"
                            },
                            request.limits.fact_bytes,
                        )?,
                    },
                );
                return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
            }
            accesses.push((value, target_parameter.access, argument.source));
        }
        let slot = resolved_arguments
            .get_mut(parameter_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot
            .replace(ResolvedCallArgument {
                source_index: u32::try_from(source_index)
                    .map_err(|_| fact_resource(request, "direct-call arguments"))?,
                parameter_index: u32::try_from(parameter_index)
                    .map_err(|_| fact_resource(request, "direct-call arguments"))?,
                access,
                value: outcome
                    .referenced
                    .or(outcome.result)
                    .ok_or(AnalysisFailure::RequestMismatch)?,
            })
            .is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    let mut exact_arguments = Vec::new();
    exact_arguments
        .try_reserve_exact(resolved_arguments.len())
        .map_err(|_| fact_resource(request, "direct-call arguments"))?;
    for argument in resolved_arguments {
        exact_arguments.push(argument.ok_or(AnalysisFailure::RequestMismatch)?);
    }
    let result = expression_result(
        request,
        partial,
        function,
        (call.expression, call.source),
        target_result,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.expression,
            ty: target_result,
            result: Some(result),
            resolution: ExpressionResolution::DirectCall {
                function: target,
                arguments: exact_arguments,
            },
            effects: target_effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: target_result,
        result: Some(result),
        referenced: None,
        effects: target_effects,
    })
}

#[allow(clippy::too_many_arguments)]
/// Resolves an expression-position leading-dot variant (`.name` / `.name(args)`,
/// lowered to HIR as `DotName { spelling, candidates }`) against the expected
/// type flowing from its surrounding context.
///
/// Per docs/language/02-source-language.md §3.3, `.name` in expression
/// position denotes an enum variant only when the expected type at that
/// position is a known enum; resolution intersects the HIR-resolved
/// same-spelling candidate set with that one enum. No expected enum type
/// available, or an expected enum that does not declare a same-spelling
/// variant, are both stable diagnostics rather than silent fallback to the
/// qualified form.
fn resolve_dot_variant_candidate(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    candidates: &[wrela_hir::ResolvedVariant],
    expected: Option<SemanticTypeId>,
    source: Span,
) -> RuntimeResult<wrela_hir::ResolvedVariant> {
    let Some(expected) = expected else {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-dot-variant-context-required",
            "leading-dot variant has no contextual enum type",
            "expression-position `.name` resolves only against a known enum type from its surrounding context",
            "use the fully qualified `Enum.variant` form, or give this position an explicit enum-typed annotation",
        ));
    };
    let declaration =
        partial
            .types
            .get(expected.0 as usize)
            .and_then(|record| match &record.kind {
                SemanticTypeKind::Enumeration { declaration, .. } => Some(*declaration),
                _ => None,
            });
    let Some(declaration) = declaration else {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-dot-variant-context-required",
            "leading-dot variant's contextual type is not an enum",
            "expression-position `.name` resolves only against a known enum type from its surrounding context",
            "use the fully qualified `Enum.variant` form, or give this position an explicit enum-typed annotation",
        ));
    };
    candidates
        .iter()
        .find(|candidate| candidate.enumeration.declaration == declaration)
        .cloned()
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                source,
                "semantic-dot-variant-unknown-variant",
                "the contextual enum does not declare this leading-dot variant",
                "leading-dot variant resolution requires the contextual enum to declare a same-spelling variant",
                "use one of the contextual enum's declared variant names",
            )
        })
}

#[allow(clippy::too_many_arguments)]
fn analyze_closed_enum_constructor(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    call: RuntimeDirectCall<'_>,
    resolved: &wrela_hir::ResolvedVariant,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    let declaration = request
        .hir
        .resolved_declaration(&resolved.enumeration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Enumeration(enumeration) = &declaration.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if is_exact_core_async_exit_declaration(request, &resolved.enumeration, declaration) {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-core-outcome-construction-forbidden",
            "source code cannot construct a sealed core AsyncExit cause",
            "structured cancellation, deadline, and operation exits are minted only by the compiler/runtime await boundary",
            "consume the AsyncExit value delivered by await instead of constructing one",
        ));
    }
    let ty = if enumeration.generics.is_empty() {
        ensure_closed_scalar_enum_type(
            request,
            partial,
            resolved.enumeration.declaration,
            &mut *state.aggregate_work,
            is_cancelled,
        )?
    } else {
        let core_result =
            is_exact_core_result_declaration(request, &resolved.enumeration, declaration);
        let Some(expected) = expression_request.expected else {
            let (code, message, explanation, help) = if core_result {
                (
                    "semantic-runtime-result-constructor-context",
                    "core Result constructor requires an exact contextual Result[T, E] type",
                    "R2 does not infer generic Result arguments from a context-free payload",
                    "add an explicit Result[T, E] local, parameter, or return type",
                )
            } else {
                (
                    "semantic-runtime-generic-enum-inference-required",
                    "generic enum constructor requires an expected specialized type",
                    "constructor payloads do not infer a closed-world specialization in this bounded slice",
                    "add a local, parameter, or result type naming the complete enum specialization",
                )
            };
            return Err(runtime_type_diagnostic(
                request,
                call.source,
                code,
                message,
                explanation,
                help,
            ));
        };
        let valid_expected = partial.types.get(expected.0 as usize).is_some_and(|record| {
            matches!(&record.kind, SemanticTypeKind::Enumeration {
                declaration,
                arguments,
                ..
            } if *declaration == resolved.enumeration.declaration
                && if core_result {
                    matches!(arguments.as_slice(), [SemanticArgument::Type(_), SemanticArgument::Type(_)])
                } else {
                    arguments.len() == enumeration.generics.len()
                        && arguments.iter().all(|argument| matches!(argument, SemanticArgument::Type(_)))
                })
        });
        if !valid_expected {
            let (code, message, explanation, help) = if core_result {
                (
                    "semantic-runtime-result-constructor-context",
                    "core Result constructor context is not the exact supported specialization",
                    "the constructor must target authenticated Result[T, E] with supported stored copy scalars",
                    "construct the Result variant in an explicit matching Result[T, E] context",
                )
            } else {
                (
                    "semantic-runtime-generic-enum-constructor-context",
                    "generic enum constructor context is not the exact declared specialization",
                    "a constructor can only produce the same nominal enum and complete type arguments required by its context",
                    "construct the variant in a context naming its exact enum specialization",
                )
            };
            return Err(runtime_type_diagnostic(
                request,
                call.source,
                code,
                message,
                explanation,
                help,
            ));
        }
        expected
    };
    if expression_request
        .expected
        .is_some_and(|expected| expected != ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-constructor-result-type",
            "enum constructor does not produce the required nominal type",
            "closed enum identities are never substituted by layout",
            "construct the exact enum named by the surrounding type",
        ));
    }
    // `None` marks a unit variant (no payload slot); `Some` carries THIS
    // variant's own scalar payload type (payloads may differ per variant). A
    // missing variant/enum is a real internal invariant.
    let variant_payload_ty = partial
        .types
        .get(ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Enumeration { variants, .. } => variants
                .get(resolved.variant as usize)
                .map(|variant| variant.fields.first().map(|field| field.ty)),
            _ => None,
        })
        .ok_or_else(|| {
            AnalysisFailure::InternalInvariant(
                "runtime enum constructor variant is missing".to_owned(),
            )
        })?;
    let payload_effects = match variant_payload_ty {
        None => {
            if !call.arguments.is_empty() || call.expression != call.callee {
                return Err(runtime_type_diagnostic(
                    request,
                    call.source,
                    "semantic-runtime-enum-unit-constructor-shape",
                    "unit enum variant construction takes no argument list",
                    "a fieldless variant is the complete value and has no payload call",
                    "write the unit variant without parentheses or arguments",
                ));
            }
            EffectSet(0)
        }
        Some(payload_ty) => {
            // The callee sub-expression fact precedes the payload it applies to.
            append_expression_fact(
                request,
                partial,
                RuntimeExpressionFact {
                    function,
                    expression: call.callee,
                    ty,
                    result: None,
                    resolution: ExpressionResolution::Constructor {
                        ty,
                        variant: Some(resolved.variant),
                    },
                    effects: EffectSet(0),
                    ownership_before: OwnershipState::Owned,
                    ownership_after: OwnershipState::Owned,
                },
            )?;
            let [argument] = call.arguments else {
                return Err(runtime_type_diagnostic(
                    request,
                    call.source,
                    "semantic-runtime-enum-constructor-argument",
                    "runtime enum constructor requires exactly one positional payload",
                    "R1 variants have one shared scalar payload slot",
                    "supply one positional scalar argument",
                ));
            };
            if argument.name.is_some() {
                return Err(runtime_type_diagnostic(
                    request,
                    argument.source,
                    "semantic-runtime-enum-constructor-argument",
                    "runtime enum constructor payload must be positional",
                    "named payload arguments are not part of the canonical R1 representation",
                    "remove the argument name",
                ));
            }
            let wrela_hir::CallArgumentValue::Value(payload_expression) = argument.value else {
                return Err(runtime_type_diagnostic(
                    request,
                    argument.source,
                    "semantic-runtime-enum-constructor-access",
                    "runtime enum constructor payload uses value access",
                    "borrow, mutate, and take markers do not initialize the owned payload slot",
                    "remove the access marker",
                ));
            };
            let payload = analyze_runtime_expression(
                request,
                partial,
                function,
                payload_expression,
                RuntimeExpressionRequest {
                    expected: Some(payload_ty),
                    desired_result: None,
                    access: AccessMode::Value,
                },
                state,
                is_cancelled,
            )?;
            payload.effects
        }
    };
    let result = expression_result(
        request,
        partial,
        function,
        (call.expression, call.source),
        ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.expression,
            ty,
            result: Some(result),
            resolution: ExpressionResolution::Constructor {
                ty,
                variant: Some(resolved.variant),
            },
            effects: payload_effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty,
        result: Some(result),
        referenced: None,
        effects: payload_effects,
    })
}

#[allow(clippy::too_many_arguments)]
fn analyze_flat_structure_constructor(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    call: RuntimeDirectCall<'_>,
    declaration: DeclarationId,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let record = program
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(aggregate) = &record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let ty = if aggregate.generics.is_empty() {
        ensure_flat_structure_type(
            request,
            partial,
            declaration,
            &mut *state.aggregate_work,
            is_cancelled,
        )?
    } else if let Some(expected) = expression_request.expected {
        let exact_specialization = partial.types.get(expected.0 as usize).is_some_and(|ty| {
            matches!(&ty.kind, SemanticTypeKind::Structure {
                declaration: candidate,
                arguments,
                ..
            } if *candidate == declaration && arguments.len() == aggregate.generics.len())
        });
        if !exact_specialization {
            return Err(runtime_type_diagnostic(
                request,
                call.source,
                "semantic-constructor-result-type",
                "generic structure constructor does not produce the required specialization",
                "expected-type-directed construction preserves the exact nominal type arguments",
                "construct the generic structure in a context requiring its exact specialization",
            ));
        }
        expected
    } else {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-runtime-generic-structure-inference-required",
            "generic structure constructor requires an expected specialized type",
            "this first monomorphization slice does not infer type arguments from constructor values",
            "add a local, parameter, or result type that names the complete structure specialization",
        ));
    };
    if expression_request
        .expected
        .is_some_and(|expected| expected != ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-constructor-result-type",
            "structure constructor does not produce the required nominal type",
            "nominal structure identities are never substituted by layout",
            "construct the exact structure named by the surrounding type",
        ));
    }
    if call.arguments.len() != aggregate.fields.len() {
        return Err(runtime_type_diagnostic(
            request,
            call.source,
            "semantic-runtime-constructor-argument",
            "runtime structure construction must supply every field exactly once",
            "defaults and partial aggregate initialization are outside the flat runtime structure subset",
            "supply one value for every declared field",
        ));
    }
    let semantic_fields = partial
        .types
        .get(ty.0 as usize)
        .and_then(|record| match &record.kind {
            SemanticTypeKind::Structure {
                declaration: candidate,
                fields,
                ..
            } if *candidate == declaration => Some(fields),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut field_types = Vec::new();
    field_types
        .try_reserve_exact(semantic_fields.len())
        .map_err(|_| fact_resource(request, "runtime constructor field types"))?;
    for field in semantic_fields {
        charge_runtime_aggregate_lookup(request, &mut *state.aggregate_work, is_cancelled)?;
        field_types.push(field.ty);
    }
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.callee,
            ty,
            result: None,
            resolution: ExpressionResolution::Constructor { ty, variant: None },
            effects: EffectSet(0),
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;

    let caller_module = runtime_function_module(request, partial, function)?;
    let mut resolved = optional_call_map(aggregate.fields.len(), request.limits.fact_edges)?;
    let mut effects = EffectSet(0);
    for (source_index, argument) in call.arguments.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let wrela_hir::CallArgumentValue::Value(argument_value) = &argument.value else {
            return Err(runtime_type_diagnostic(
                request,
                argument.source,
                "semantic-runtime-constructor-access",
                "runtime structure constructor fields use value access",
                "borrow, mutate, and take markers do not describe aggregate field initialization",
                "remove the access marker from this constructor argument",
            ));
        };
        if aggregate.fields.len() != 1 && argument.name.is_none() {
            return Err(runtime_type_diagnostic(
                request,
                argument.source,
                "semantic-runtime-constructor-argument",
                "a runtime structure with multiple fields requires named constructor arguments",
                "named fields make source-to-layout ordering explicit and deterministic",
                "name every constructor argument",
            ));
        }
        let field_index = if let Some(name) = &argument.name {
            let mut selected = None;
            for (index, field) in aggregate.fields.iter().enumerate() {
                charge_runtime_aggregate_lookup(request, &mut *state.aggregate_work, is_cancelled)?;
                if field.name == *name && selected.replace(index).is_some() {
                    return Err(runtime_type_diagnostic(
                        request,
                        argument.source,
                        "semantic-runtime-constructor-argument",
                        "runtime structure field name is ambiguous",
                        "constructor field selection requires one exact declaration",
                        "remove the duplicate field declaration",
                    ));
                }
            }
            selected.ok_or_else(|| {
                runtime_type_diagnostic(
                    request,
                    argument.source,
                    "semantic-runtime-constructor-argument",
                    "runtime constructor argument does not name a declared field",
                    "field names are matched exactly and nominally",
                    "use one of the structure's declared field names",
                )
            })?
        } else {
            source_index
        };
        let field = aggregate
            .fields
            .get(field_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if caller_module != record.module && field.visibility == wrela_hir::Visibility::Private {
            return Err(runtime_type_diagnostic(
                request,
                argument.source,
                "semantic-runtime-field-private",
                "runtime structure field is private to its declaring module",
                "construction from another module may initialize only visible fields",
                "make the field public or construct the value inside its declaring module",
            ));
        }
        let slot = resolved
            .get_mut(field_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if slot.is_some() {
            return Err(runtime_type_diagnostic(
                request,
                argument.source,
                "semantic-runtime-constructor-argument",
                "runtime constructor supplies one field more than once",
                "each field has exactly one deterministic initializer",
                "remove the duplicate field argument",
            ));
        }
        let outcome = analyze_runtime_expression(
            request,
            partial,
            function,
            *argument_value,
            RuntimeExpressionRequest {
                expected: field_types.get(field_index).copied(),
                desired_result: None,
                access: AccessMode::Value,
            },
            state,
            is_cancelled,
        )?;
        effects.0 |= outcome.effects.0;
        *slot = Some(ResolvedCallArgument {
            source_index: u32::try_from(source_index)
                .map_err(|_| fact_resource(request, "runtime constructor arguments"))?,
            parameter_index: u32::try_from(field_index)
                .map_err(|_| fact_resource(request, "runtime constructor arguments"))?,
            access: AccessMode::Value,
            value: outcome
                .referenced
                .or(outcome.result)
                .ok_or(AnalysisFailure::RequestMismatch)?,
        });
    }
    for field in &resolved {
        charge_runtime_aggregate_lookup(request, &mut *state.aggregate_work, is_cancelled)?;
        if field.is_none() {
            return Err(runtime_type_diagnostic(
                request,
                call.source,
                "semantic-runtime-constructor-argument",
                "runtime structure construction must supply every field exactly once",
                "one or more declared fields have no initializer",
                "supply one value for every declared field",
            ));
        }
    }
    let result = expression_result(
        request,
        partial,
        function,
        (call.expression, call.source),
        ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression: call.expression,
            ty,
            result: Some(result),
            resolution: ExpressionResolution::Constructor { ty, variant: None },
            effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty,
        result: Some(result),
        referenced: None,
        effects,
    })
}

#[allow(clippy::too_many_arguments)]
fn analyze_flat_structure_field(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    expression: ExpressionId,
    source: Span,
    base: ExpressionId,
    name: &wrela_hir::Name,
    expression_request: RuntimeExpressionRequest,
    state: &mut RuntimeState<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<RuntimeExpression> {
    if !matches!(
        expression_request.access,
        AccessMode::Value | AccessMode::Read
    ) {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-field-access",
            "flat runtime field projection supports read access only",
            "projected mutation and ownership transfer require place-level aggregate lowering",
            "read the field value or reconstruct the enclosing structure",
        ));
    }
    let base_value = analyze_runtime_expression(
        request,
        partial,
        function,
        base,
        RuntimeExpressionRequest {
            expected: None,
            desired_result: None,
            access: AccessMode::Read,
        },
        state,
        is_cancelled,
    )?;
    if let Some(state_access) = canonical_actor_state_access(
        request,
        partial,
        function,
        base,
        base_value.ty,
        name,
        source,
    )? {
        let field_ty = ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Integer {
                signed: false,
                bits: 64,
                pointer_sized: false,
            },
            &mut *state.aggregate_work,
            is_cancelled,
        )?;
        if expression_request
            .expected
            .is_some_and(|expected| expected != field_ty)
        {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-actor-state-field-type",
                "actor state field does not match its required type",
                "the canonical actor state cell is exactly one u64",
                "use the state value in a u64 context",
            ));
        }
        let result = expression_result(
            request,
            partial,
            function,
            (expression, source),
            field_ty,
            expression_request.desired_result,
            is_cancelled,
        )?;
        append_expression_fact_with_category(
            request,
            partial,
            RuntimeExpressionFact {
                function,
                expression,
                ty: field_ty,
                result: Some(result),
                resolution: ExpressionResolution::Field {
                    index: state_access.field,
                },
                effects: EffectSet(EffectSet::ACTOR),
                ownership_before: OwnershipState::Owned,
                ownership_after: OwnershipState::Owned,
            },
            ValueCategory::Value,
            Some(state_access.region),
        )?;
        let fact = partial
            .expressions
            .last_mut()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if !fact.proofs.contains(&state_access.capacity) {
            fact.proofs
                .try_reserve(1)
                .map_err(|_| fact_resource(request, "actor state access proofs"))?;
            fact.proofs.push(state_access.capacity);
            fact.proofs.sort_unstable();
        }
        partial
            .actor_state_accesses
            .try_reserve(1)
            .map_err(|_| fact_resource(request, "actor state accesses"))?;
        partial.actor_state_accesses.push(ActorStateAccess {
            function,
            actor: state_access.actor,
            receiver: state_access.receiver,
            class: state_access.class,
            field: state_access.field,
            region: state_access.region,
            capacity: state_access.capacity,
            source,
            kind: ActorStateAccessKind::Read { expression, result },
        });
        return Ok(RuntimeExpression {
            ty: field_ty,
            result: Some(result),
            referenced: None,
            effects: EffectSet(EffectSet::ACTOR),
        });
    }
    let (declaration, field_index, field_ty) = {
        let record = partial
            .types
            .get(base_value.ty.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let SemanticTypeKind::Structure {
            declaration,
            fields,
            ..
        } = &record.kind
        else {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-field-base",
                "field projection requires a supported flat runtime structure",
                "scalar and unsupported aggregate values do not have runtime fields",
                "project a field from a nongeneric structure with scalar fields",
            ));
        };
        let mut selected = None;
        for (index, field) in fields.iter().enumerate() {
            charge_runtime_aggregate_lookup(request, &mut *state.aggregate_work, is_cancelled)?;
            if field.name == name.as_str() && selected.replace(index).is_some() {
                return Err(runtime_type_diagnostic(
                    request,
                    source,
                    "semantic-runtime-field",
                    "runtime structure field name is ambiguous",
                    "field selection requires one exact declaration",
                    "remove the duplicate field declaration",
                ));
            }
        }
        let index = selected.ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-field",
                "runtime structure does not declare the selected field",
                "field names are matched exactly and nominally",
                "select one of the structure's declared fields",
            )
        })?;
        (*declaration, index, fields[index].ty)
    };
    let declaration_record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(aggregate) = &declaration_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let field = aggregate
        .fields
        .get(field_index)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if runtime_function_module(request, partial, function)? != declaration_record.module
        && field.visibility == wrela_hir::Visibility::Private
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-field-private",
            "runtime structure field is private to its declaring module",
            "field projection from another module preserves source visibility",
            "expose a public accessor from the declaring module",
        ));
    }
    if expression_request
        .expected
        .is_some_and(|expected| expected != field_ty)
    {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-runtime-field-type",
            "projected field does not match its required type",
            "runtime structure fields preserve their exact declared scalar types",
            "use the field in a matching context",
        ));
    }
    let result = expression_result(
        request,
        partial,
        function,
        (expression, source),
        field_ty,
        expression_request.desired_result,
        is_cancelled,
    )?;
    let index = u32::try_from(field_index)
        .map_err(|_| fact_resource(request, "runtime structure fields"))?;
    append_expression_fact(
        request,
        partial,
        RuntimeExpressionFact {
            function,
            expression,
            ty: field_ty,
            result: Some(result),
            resolution: ExpressionResolution::Field { index },
            effects: base_value.effects,
            ownership_before: OwnershipState::Owned,
            ownership_after: OwnershipState::Owned,
        },
    )?;
    Ok(RuntimeExpression {
        ty: field_ty,
        result: Some(result),
        referenced: None,
        effects: base_value.effects,
    })
}

#[derive(Debug, Clone, Copy)]
struct CanonicalActorStateAccess {
    actor: ActorId,
    receiver: wrela_hir::ParameterId,
    class: DeclarationId,
    field: u32,
    region: RegionId,
    capacity: ProofId,
}

fn canonical_actor_state_access(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
    base: ExpressionId,
    base_ty: SemanticTypeId,
    name: &wrela_hir::Name,
    source: Span,
) -> RuntimeResult<Option<CanonicalActorStateAccess>> {
    let Some(FunctionRole::ActorTurn(actor)) = partial
        .functions
        .get(function.0 as usize)
        .map(|record| record.role)
    else {
        return Ok(None);
    };
    let actor_class = partial
        .graph
        .as_ref()
        .and_then(|graph| graph.actors.get(actor.0 as usize))
        .map(|actor| actor.class)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if base_ty != actor_class {
        return Ok(None);
    }
    let Some(base_record) = request.hir.as_program().expression(base) else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let ExpressionKind::Reference(Definition::Parameter(receiver)) = base_record.kind else {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-actor-state-root-pending",
            "actor state access requires the turn's direct self receiver",
            "aliases, temporaries, and other parameter roots cannot authenticate actor-owned storage",
            "access the canonical field directly as `self.value`",
        ));
    };
    canonical_actor_state_for_receiver(request, partial, function, receiver, name, source)
}

fn canonical_actor_state_for_receiver(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
    receiver: wrela_hir::ParameterId,
    name: &wrela_hir::Name,
    source: Span,
) -> RuntimeResult<Option<CanonicalActorStateAccess>> {
    let function_record = partial
        .functions
        .get(function.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let FunctionRole::ActorTurn(actor) = function_record.role else {
        return Ok(None);
    };
    let Some(receiver_binding) = function_record.parameters.first() else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if receiver_binding.parameter != receiver || receiver_binding.access != AccessMode::Mutate {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-actor-state-receiver",
            "actor state access requires the actor-owned mutable turn receiver",
            "state is isolated to one non-reentrant actor turn",
            "declare and use `mut self` in a public actor turn method",
        ));
    }
    let graph = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let actor_record = graph
        .actors
        .get(actor.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let class = actor_class_declaration(partial, actor_record.class)?;
    let class_record = request
        .hir
        .as_program()
        .declaration(class)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(class_source) = &class_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let [field] = class_source.fields.as_slice() else {
        return Ok(None);
    };
    if name.as_str() != field.name.as_str() {
        return Err(runtime_type_diagnostic(
            request,
            source,
            "semantic-actor-state-field-pending",
            "actor state access names an unsupported field",
            "this lowering slice authenticates exactly the canonical `value: u64 = 0` cell",
            "access `self.value` or keep other state fail-closed",
        ));
    }
    let region = graph
        .regions
        .iter()
        .find(|region| {
            region.owner == ImageOwner::Actor(actor)
                && region.class == RegionClass::Image
                && region.name.strip_suffix(".state") == Some(actor_record.name.as_str())
        })
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                source,
                "semantic-actor-state-region-missing",
                "actor state access has no canonical actor-owned image region",
                "state access cannot manufacture storage from the erased receiver value",
                "install the canonical stateful actor in the selected image",
            )
        })?;
    Ok(Some(CanonicalActorStateAccess {
        actor,
        receiver,
        class,
        field: 0,
        region: region.id,
        capacity: region.proof,
    }))
}

#[allow(clippy::too_many_arguments)]
fn analyze_actor_state_assignment(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    statement: StatementId,
    source: Span,
    target: &wrela_hir::PlaceTarget,
    operator: AssignmentOperator,
    value_expression: ExpressionId,
    locals: &mut [Option<RuntimeBinding>],
    parameters: &mut [Option<RuntimeBinding>],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<Option<EffectSet>> {
    let Definition::Parameter(receiver) = target.root else {
        return Ok(None);
    };
    let [wrela_hir::PlaceProjection::Field(name)] = target.projections.as_slice() else {
        return Err(runtime_type_diagnostic(
            request,
            target.source,
            "semantic-actor-state-place-shape-pending",
            "actor state assignment requires one direct named field",
            "nested, tuple, and indexed actor state places do not have authenticated layouts",
            "assign directly to `self.value`",
        ));
    };
    let Some(access) = canonical_actor_state_for_receiver(
        request,
        partial,
        function,
        receiver,
        name,
        target.source,
    )?
    else {
        return Ok(None);
    };
    if !matches!(
        operator,
        AssignmentOperator::Assign | AssignmentOperator::Add
    ) {
        return Err(runtime_type_diagnostic(
            request,
            target.source,
            "semantic-actor-state-compound-assignment-pending",
            "this compound actor state assignment is not yet supported",
            "the canonical state path authenticates plain assignment and checked u64 addition only",
            "use `self.value = replacement` or `self.value += increment`",
        ));
    }
    let receiver_binding = parameters
        .get(receiver.0 as usize)
        .copied()
        .flatten()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if receiver_binding.state != OwnershipState::Owned
        || receiver_binding.authority != RuntimeAuthority::Mutate
    {
        return Err(runtime_diagnostic(
            request,
            target.source,
            "semantic-actor-state-authority",
            "actor state assignment requires live exclusive turn authority",
            Some(receiver_binding),
            "state storage is isolated to its non-reentrant actor turn",
            "store before transferring or borrowing the receiver",
        ));
    }
    let u64_ty = ensure_primitive_type(
        request,
        partial,
        PrimitiveSemanticType::Integer {
            signed: false,
            bits: 64,
            pointer_sized: false,
        },
        &mut *aggregate_work,
        is_cancelled,
    )?;
    let outcome = analyze_runtime_expression(
        request,
        partial,
        function,
        value_expression,
        RuntimeExpressionRequest {
            expected: Some(u64_ty),
            desired_result: None,
            access: AccessMode::Value,
        },
        &mut RuntimeState {
            locals,
            parameters,
            aggregate_work,
            allow_assertions,
            allow_scope_call: false,
        },
        is_cancelled,
    )?;
    let value = outcome.result.ok_or(AnalysisFailure::RequestMismatch)?;
    let compound_values = if operator == AssignmentOperator::Add {
        let current = append_semantic_value(
            request,
            partial,
            function,
            u64_ty,
            (
                SemanticValueOrigin::ActorStateLoad(statement),
                Some(source),
                None,
            ),
            is_cancelled,
        )?;
        let result = append_semantic_value(
            request,
            partial,
            function,
            u64_ty,
            (
                SemanticValueOrigin::ActorStateCompoundResult(statement),
                Some(source),
                None,
            ),
            is_cancelled,
        )?;
        Some((current, result))
    } else {
        None
    };
    partial
        .actor_state_accesses
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "actor state accesses"))?;
    partial.actor_state_accesses.push(ActorStateAccess {
        function,
        actor: access.actor,
        receiver: access.receiver,
        class: access.class,
        field: access.field,
        region: access.region,
        capacity: access.capacity,
        source,
        kind: match compound_values {
            Some((current, result)) => ActorStateAccessKind::CompoundAssign {
                statement,
                value_expression,
                value,
                current,
                result,
            },
            None => ActorStateAccessKind::Write {
                statement,
                value_expression,
                value,
            },
        },
    });
    Ok(Some(EffectSet(outcome.effects.0 | EffectSet::ACTOR)))
}

fn no_promote_attribute(attributes: &[wrela_hir::Attribute]) -> Option<&wrela_hir::Attribute> {
    attributes.iter().find(|attribute| {
        matches!(
            attribute.identity,
            wrela_hir::AttributeIdentity::Builtin(wrela_hir::BuiltinAttribute::NoPromote)
        )
    })
}

fn no_promote_escape_diagnostic(
    request: &AnalysisRequest<'_>,
    source: Span,
    allocation: &str,
) -> RuntimeFailure {
    let build = || -> Result<Diagnostic, AnalysisFailure> {
        let message = format!(
            "@no_promote forbids allocation `{allocation}` from being promoted under build profile `{}`",
            request.build.profile.name
        );
        let mut diagnostic = Diagnostic::error(Category::OWNERSHIP, source, message);
        diagnostic.code = Some(copy_static_analysis_text(
            "semantic-no-promote-escape",
            request.limits.fact_bytes,
        )?);
        diagnostic.notes.push(copy_static_analysis_text(
            ACTOR_STATE_PROMOTION_REASON,
            request.limits.fact_bytes,
        )?);
        diagnostic.help.push(copy_static_analysis_text(
            "remove @no_promote or keep the value within the actor turn",
            request.limits.fact_bytes,
        )?);
        Ok(diagnostic)
    };
    match build() {
        Ok(diagnostic) => RuntimeFailure::Diagnostic(Box::new(diagnostic)),
        Err(error) => RuntimeFailure::Analysis(error),
    }
}

fn no_promote_target_diagnostic(request: &AnalysisRequest<'_>, source: Span) -> RuntimeFailure {
    let message = format!(
        "@no_promote is not supported on this source target under build profile `{}`",
        request.build.profile.name
    );
    let mut diagnostic = Diagnostic::error(Category::OWNERSHIP, source, message);
    diagnostic.code = Some("semantic-no-promote-target".to_owned());
    diagnostic.help.push(
        "place @no_promote on a function, actor, or supported allocation declaration".to_owned(),
    );
    RuntimeFailure::Diagnostic(Box::new(diagnostic))
}

fn actor_state_promotion_candidate(
    kind: ActorStateAccessKind,
) -> Option<(StatementId, ValueId, &'static str)> {
    match kind {
        ActorStateAccessKind::Write {
            statement, value, ..
        } => Some((statement, value, "actor-state-store")),
        ActorStateAccessKind::CompoundAssign {
            statement, result, ..
        } => Some((statement, result, "actor-state-compound-store")),
        ActorStateAccessKind::Read { .. } => None,
    }
}

fn infer_actor_state_promotions(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    let program = request.hir.as_program();
    let mut promotion_count = 0usize;
    for access in &partial.actor_state_accesses {
        check_cancelled(is_cancelled)?;
        if actor_state_promotion_candidate(access.kind).is_some() {
            promotion_count = promotion_count
                .checked_add(1)
                .ok_or_else(|| fact_resource(request, "actor state promotion facts"))?;
        }
    }
    if promotion_count > request.limits.image_nodes as usize
        || partial
            .proofs
            .len()
            .checked_add(promotion_count)
            .is_none_or(|count| count > request.limits.proofs as usize)
    {
        return Err(fact_resource(request, "actor state promotion facts").into());
    }
    let mut candidates = Vec::new();
    candidates
        .try_reserve_exact(promotion_count)
        .map_err(|_| fact_resource(request, "actor state promotion work"))?;
    for access in &partial.actor_state_accesses {
        check_cancelled(is_cancelled)?;
        if let Some((statement, value, name)) = actor_state_promotion_candidate(access.kind) {
            candidates.push((*access, statement, value, name));
        }
    }
    partial
        .region_assignments
        .try_reserve_exact(promotion_count)
        .map_err(|_| fact_resource(request, "actor state region assignments"))?;
    partial
        .promotions
        .try_reserve_exact(promotion_count)
        .map_err(|_| fact_resource(request, "actor state promotions"))?;

    for (access, statement, value, name) in candidates {
        check_cancelled(is_cancelled)?;
        let id = AllocationId(
            u32::try_from(partial.region_assignments.len())
                .map_err(|_| fact_resource(request, "actor state region assignments"))?,
        );
        let allocation = format!("alloc:{}:{name}", id.0);
        let statement_record = program
            .statement(statement)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let function = partial
            .functions
            .get(access.function.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let FunctionOrigin::Source { declaration, .. } = function.origin else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        let method = program
            .declaration(declaration)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let graph = partial
            .graph
            .as_ref()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let actor = graph
            .actors
            .get(access.actor.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let class_declaration = actor_class_declaration(partial, actor.class)?;
        let class = program
            .declaration(class_declaration)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let class_field_attribute = match &class.kind {
            DeclarationKind::Structure(aggregate) => aggregate
                .fields
                .get(access.field as usize)
                .and_then(|field| no_promote_attribute(&field.attributes)),
            _ => None,
        };
        if let Some(attribute) = no_promote_attribute(&method.attributes)
            .or_else(|| no_promote_attribute(&class.attributes))
            .or(class_field_attribute)
            .or_else(|| no_promote_attribute(&statement_record.attributes))
        {
            return Err(no_promote_escape_diagnostic(
                request,
                attribute.source,
                &allocation,
            ));
        }
        let source_region = graph
            .regions
            .iter()
            .find(|region| {
                region.owner == ImageOwner::Actor(access.actor)
                    && region.class == RegionClass::TaskFrame
                    && region.name.ends_with(".turn-frame")
            })
            .map(|region| region.id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let proof = ProofId(
            u32::try_from(partial.proofs.len())
                .map_err(|_| fact_resource(request, "actor state promotion proofs"))?,
        );
        partial.proofs.push(Proof {
            id: proof,
            kind: ProofKind::RegionBound,
            subject: copy_analysis_text(&allocation, request.limits.fact_bytes, is_cancelled)?,
            sources: vec![access.source],
            depends_on: Vec::new(),
            bound: Some(8),
            explanation: vec![ACTOR_STATE_PROMOTION_REASON.to_owned()],
        });
        partial.region_assignments.push(RegionAssignment {
            id,
            name: name.to_owned(),
            function: access.function,
            statement,
            value,
            region: access.region,
            source: access.source,
        });
        partial.promotions.push(Promotion {
            allocation: id,
            value,
            source_region,
            destination: access.region,
            proof,
            reason: ACTOR_STATE_PROMOTION_REASON.to_owned(),
            source: access.source,
        });
    }

    let graph = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    for declaration in &program.declarations {
        check_cancelled(is_cancelled)?;
        let allowed_declaration = matches!(declaration.kind, DeclarationKind::Function(_))
            || matches!(declaration.kind, DeclarationKind::Structure(_))
                && graph.actors.iter().any(|actor| {
                    actor_class_declaration(partial, actor.class) == Ok(declaration.id)
                });
        if let Some(attribute) = no_promote_attribute(&declaration.attributes)
            && (!allowed_declaration || !attribute.arguments.is_empty())
        {
            return Err(no_promote_target_diagnostic(request, attribute.source));
        }
        if let DeclarationKind::Structure(aggregate) = &declaration.kind {
            for field in &aggregate.fields {
                if let Some(attribute) = no_promote_attribute(&field.attributes)
                    && (!attribute.arguments.is_empty()
                        || !graph.actors.iter().any(|actor| {
                            actor_class_declaration(partial, actor.class) == Ok(declaration.id)
                        }))
                {
                    return Err(no_promote_target_diagnostic(request, attribute.source));
                }
            }
        }
    }
    for statement in &program.statements {
        check_cancelled(is_cancelled)?;
        if let Some(attribute) = no_promote_attribute(&statement.attributes) {
            return Err(no_promote_target_diagnostic(request, attribute.source));
        }
    }
    Ok(())
}

fn runtime_function_module(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
) -> RuntimeResult<wrela_package::ModuleId> {
    let declaration = partial
        .functions
        .get(function.0 as usize)
        .and_then(|function| match function.origin {
            FunctionOrigin::Source { declaration, .. } => Some(declaration),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    request
        .hir
        .as_program()
        .declaration(declaration)
        .map(|declaration| declaration.module)
        .ok_or(AnalysisFailure::RequestMismatch.into())
}

fn scope_phase_contains_await(
    program: &wrela_hir::Program,
    root: BodyId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<bool, AnalysisFailure> {
    let mut bodies = vec![root];
    let mut expressions = Vec::new();
    let mut visited = 0usize;
    while let Some(body) = bodies.pop() {
        check_cancelled(is_cancelled)?;
        visited = visited
            .checked_add(1)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if visited > program.bodies.len() {
            return Err(AnalysisFailure::RequestMismatch);
        }
        let body = program.body(body).ok_or(AnalysisFailure::RequestMismatch)?;
        for statement in &body.statements {
            check_cancelled(is_cancelled)?;
            let statement = program
                .statement(*statement)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            match &statement.kind {
                StatementKind::Initialize { value, .. }
                | StatementKind::Assign { value, .. }
                | StatementKind::Expression(value)
                | StatementKind::Send(value)
                | StatementKind::Yield(value) => expressions.push(*value),
                StatementKind::Return(Some(value)) => expressions.push(*value),
                StatementKind::Assert { condition, .. } => expressions.push(*condition),
                StatementKind::If {
                    branches,
                    else_body,
                } => {
                    for (condition, body) in branches {
                        expressions.push(*condition);
                        bodies.push(*body);
                    }
                    if let Some(body) = else_body {
                        bodies.push(*body);
                    }
                }
                StatementKind::Match { scrutinee, arms } => {
                    expressions.push(*scrutinee);
                    for arm in arms {
                        if let Some(guard) = arm.guard {
                            expressions.push(guard);
                        }
                        bodies.push(arm.body);
                    }
                }
                StatementKind::For { iterable, body, .. } => {
                    expressions.push(*iterable);
                    bodies.push(*body);
                }
                StatementKind::While { condition, body } => {
                    expressions.push(*condition);
                    bodies.push(*body);
                }
                StatementKind::Loop { body } => bodies.push(*body),
                StatementKind::With { value, body, .. } => {
                    expressions.push(*value);
                    bodies.push(*body);
                }
                StatementKind::ComptimeIf {
                    condition,
                    then_body,
                    else_body,
                } => {
                    expressions.push(*condition);
                    bodies.push(*then_body);
                    if let Some(body) = else_body {
                        bodies.push(*body);
                    }
                }
                StatementKind::Pass
                | StatementKind::Return(None)
                | StatementKind::Break
                | StatementKind::Continue
                | StatementKind::Error => {}
            }
        }
    }
    let mut expression_visits = 0usize;
    while let Some(expression) = expressions.pop() {
        check_cancelled(is_cancelled)?;
        expression_visits = expression_visits
            .checked_add(1)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if expression_visits > program.expressions.len() {
            return Err(AnalysisFailure::RequestMismatch);
        }
        let expression = program
            .expression(expression)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        match &expression.kind {
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::Await,
                ..
            } => return Ok(true),
            ExpressionKind::Unary { operand, .. }
            | ExpressionKind::Try(operand)
            | ExpressionKind::TrySend(operand) => expressions.push(*operand),
            ExpressionKind::Binary { left, right, .. }
            | ExpressionKind::Compare { left, right, .. }
            | ExpressionKind::Range {
                start: left,
                end: right,
                ..
            } => {
                expressions.push(*right);
                expressions.push(*left);
            }
            ExpressionKind::IsPattern { value, .. }
            | ExpressionKind::Cast { value, .. }
            | ExpressionKind::Field { base: value, .. } => expressions.push(*value),
            ExpressionKind::Call { callee, arguments } => {
                expressions.push(*callee);
                for argument in arguments {
                    if let wrela_hir::CallArgumentValue::Value(value) = argument.value {
                        expressions.push(value);
                    }
                }
            }
            ExpressionKind::Index { base, index } => {
                expressions.push(*index);
                expressions.push(*base);
            }
            ExpressionKind::Tuple(values) | ExpressionKind::Array(values) => {
                expressions.extend(values.iter().copied());
            }
            ExpressionKind::Interpolate(parts) => {
                for part in parts {
                    if let wrela_hir::InterpolationPart::Value { expression, .. } = part {
                        expressions.push(*expression);
                    }
                }
            }
            ExpressionKind::If {
                condition,
                then_branch,
                elif_branches,
                else_branch,
            } => {
                expressions.extend([*condition, *then_branch, *else_branch]);
                for (condition, branch) in elif_branches {
                    expressions.extend([*condition, *branch]);
                }
            }
            ExpressionKind::Closure { .. }
            | ExpressionKind::Literal(_)
            | ExpressionKind::Reference(_)
            | ExpressionKind::DotName { .. }
            | ExpressionKind::Error => {}
        }
    }
    Ok(false)
}

fn scope_phase_is_pass_only(program: &wrela_hir::Program, body: BodyId) -> bool {
    program.body(body).is_some_and(|body| {
        body.statements.iter().all(|statement| {
            program
                .statement(*statement)
                .is_some_and(|statement| matches!(statement.kind, StatementKind::Pass))
        })
    })
}

fn scope_enter_expression_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    context: ScopeEnterContext<'_>,
    expression: ExpressionId,
    expected: SemanticTypeId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let record = program
        .expression(expression)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let actual = match &record.kind {
        ExpressionKind::Reference(Definition::Parameter(parameter)) => context
            .scope
            .parameters
            .iter()
            .filter(|candidate| **candidate != context.scope.exit_parameter)
            .position(|candidate| candidate == parameter)
            .and_then(|index| context.parameter_types.get(index))
            .map(|parameter| parameter.ty)
            .ok_or(AnalysisFailure::RequestMismatch)?,
        ExpressionKind::Literal(literal) => {
            lower_scalar_literal(request, partial, expected, literal, is_cancelled)
                .map_err(RuntimeFailure::from)?;
            expected
        }
        ExpressionKind::Call { callee, arguments } => {
            let callee = program
                .expression(*callee)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let ExpressionKind::Reference(Definition::Declaration(resolved)) = &callee.kind else {
                return Err(runtime_type_diagnostic(
                    request,
                    record.source,
                    "semantic-scope-enter-form-pending",
                    "scope enter expression uses an unsupported callable form",
                    "the analysis-tier scope slice admits direct flat-structure construction, literals, and scope parameters",
                    "return a flat state value directly from enter",
                ));
            };
            let declaration = program
                .declaration(resolved.declaration)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let DeclarationKind::Structure(aggregate) = &declaration.kind else {
                return Err(runtime_type_diagnostic(
                    request,
                    record.source,
                    "semantic-scope-enter-form-pending",
                    "scope enter expression calls an unsupported declaration",
                    "ordinary function execution inside scope acquisition is deferred",
                    "construct the declared scope state directly",
                ));
            };
            if aggregate_has_initializer(program, resolved.declaration) {
                return Err(runtime_type_diagnostic(
                    request,
                    record.source,
                    "semantic-scope-enter-form-pending",
                    "initializer-based scope state construction is pending",
                    "the analysis-tier scope slice admits flat structure construction only",
                    "use a flat state structure without an init member",
                ));
            }
            let ty = ensure_flat_structure_type(
                request,
                partial,
                resolved.declaration,
                aggregate_work,
                is_cancelled,
            )?;
            if arguments.len() != aggregate.fields.len() {
                return Err(runtime_type_diagnostic(
                    request,
                    record.source,
                    "semantic-scope-enter-constructor-argument",
                    "scope state construction must initialize every field exactly once",
                    "partial scope state cannot satisfy deterministic cleanup",
                    "supply one initializer for each state field",
                ));
            }
            let field_types = partial
                .types
                .get(ty.0 as usize)
                .and_then(|record| match &record.kind {
                    SemanticTypeKind::Structure { fields, .. } => {
                        Some(fields.iter().map(|field| field.ty).collect::<Vec<_>>())
                    }
                    _ => None,
                })
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let mut resolved_fields = vec![false; aggregate.fields.len()];
            for (source_index, argument) in arguments.iter().enumerate() {
                let wrela_hir::CallArgumentValue::Value(value) = argument.value else {
                    return Err(runtime_type_diagnostic(
                        request,
                        argument.source,
                        "semantic-scope-enter-constructor-access",
                        "scope state fields use value access",
                        "exclusive access markers do not describe scope state construction",
                        "remove the access marker",
                    ));
                };
                if aggregate.fields.len() != 1 && argument.name.is_none() {
                    return Err(runtime_type_diagnostic(
                        request,
                        argument.source,
                        "semantic-scope-enter-constructor-argument",
                        "multi-field scope state construction requires labels",
                        "labels make the cleanup state layout unambiguous",
                        "label every constructor argument",
                    ));
                }
                let field_index = if let Some(name) = &argument.name {
                    aggregate
                        .fields
                        .iter()
                        .position(|field| field.name == *name)
                        .ok_or_else(|| {
                            runtime_type_diagnostic(
                                request,
                                argument.source,
                                "semantic-scope-enter-constructor-argument",
                                "scope state constructor label names no field",
                                "field labels are nominal and exact",
                                "use a declared state field name",
                            )
                        })?
                } else {
                    source_index
                };
                if resolved_fields
                    .get_mut(field_index)
                    .is_none_or(|slot| std::mem::replace(slot, true))
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        argument.source,
                        "semantic-scope-enter-constructor-argument",
                        "scope state constructor initializes one field more than once",
                        "each cleanup state field needs exactly one producer",
                        "remove the duplicate initializer",
                    ));
                }
                scope_enter_expression_type(
                    request,
                    partial,
                    context,
                    value,
                    field_types[field_index],
                    aggregate_work,
                    is_cancelled,
                )?;
            }
            ty
        }
        _ => {
            return Err(runtime_type_diagnostic(
                request,
                record.source,
                "semantic-scope-enter-form-pending",
                "scope enter expression is outside the analysis-tier state subset",
                "scope acquisition currently admits literals, parameters, and flat state construction",
                "return a directly constructed bounded state value",
            ));
        }
    };
    if actual != expected {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-scope-enter-type",
            "scope enter expression does not produce the declared state type",
            "cleanup receives exactly the value returned by enter",
            "make the declared result and enter expression types match",
        ));
    }
    Ok(actual)
}

fn ensure_scope_protocol(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<ScopeProtocolId> {
    for protocol in &partial.scope_protocols {
        check_cancelled(is_cancelled)?;
        if protocol.declaration == declaration {
            return Ok(protocol.id);
        }
    }
    let program = request.hir.as_program();
    let declaration_record = program
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Scope(scope) = &declaration_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let mut parameters = Vec::new();
    parameters
        .try_reserve_exact(scope.parameters.len())
        .map_err(|_| fact_resource(request, "scope protocol parameters"))?;
    for parameter_id in &scope.parameters {
        check_cancelled(is_cancelled)?;
        if *parameter_id == scope.exit_parameter {
            continue;
        }
        let parameter = program
            .parameters
            .get(parameter_id.0 as usize)
            .filter(|parameter| parameter.id == *parameter_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if parameter.receiver {
            return Err(runtime_type_diagnostic(
                request,
                parameter.source,
                "semantic-with-receiver-scope-pending",
                "receiver-form scope acquisition is not yet supported",
                "this slice resolves only module-level free-call scope protocols",
                "declare and call a free scope until receiver resolution lands",
            ));
        }
        let ty = semantic_type_from_source(
            request,
            partial,
            parameter
                .ty
                .as_ref()
                .ok_or(AnalysisFailure::RequestMismatch)?,
            aggregate_work,
            is_cancelled,
        )?;
        parameters.push(SemanticParameter {
            access: lower_access(parameter.access),
            ty,
        });
    }
    let result = semantic_type_from_source(
        request,
        partial,
        &scope.result,
        aggregate_work,
        is_cancelled,
    )?;
    if !scope_phase_is_pass_only(program, scope.setup) {
        return Err(runtime_type_diagnostic(
            request,
            program
                .body(scope.setup)
                .map_or(declaration_record.source, |body| body.source),
            "semantic-scope-setup-form-pending",
            "scope setup statements are outside the current analysis subset",
            "setup execution needs the scope-phase operation model",
            "keep setup empty or use pass before enter",
        ));
    }
    for (phase, body, code) in [
        ("abort", scope.abort, "semantic-scope-abort-await"),
        ("exit", Some(scope.exit), "semantic-scope-exit-await"),
    ] {
        let Some(body) = body else { continue };
        if scope_phase_contains_await(program, body, is_cancelled)? {
            return Err(runtime_type_diagnostic(
                request,
                program
                    .body(body)
                    .map_or(declaration_record.source, |body| body.source),
                code,
                if phase == "abort" {
                    "scope abort cleanup may not suspend"
                } else {
                    "scope exit cleanup may not suspend"
                },
                "cleanup must complete in bounded non-suspending order on every exit path",
                "remove await from the cleanup phase",
            ));
        }
        if !scope_phase_is_pass_only(program, body) {
            return Err(runtime_type_diagnostic(
                request,
                program
                    .body(body)
                    .map_or(declaration_record.source, |body| body.source),
                "semantic-scope-cleanup-form-pending",
                "scope cleanup body is outside the current analysis subset",
                "this sema slice proves pass-only non-suspending abort and exit bodies",
                "keep cleanup pass-only until cleanup operation lowering lands",
            ));
        }
    }
    scope_enter_expression_type(
        request,
        partial,
        ScopeEnterContext {
            scope,
            parameter_types: &parameters,
        },
        scope.enter,
        result,
        aggregate_work,
        is_cancelled,
    )?;
    if partial.scope_protocols.len() >= request.limits.scope_protocols as usize
        || partial.proofs.len() >= request.limits.proofs as usize
    {
        return Err(fact_resource(request, "scope protocols").into());
    }
    let id = ScopeProtocolId(
        u32::try_from(partial.scope_protocols.len())
            .map_err(|_| fact_resource(request, "scope protocols"))?,
    );
    let proof = ProofId(
        u32::try_from(partial.proofs.len()).map_err(|_| fact_resource(request, "scope proofs"))?,
    );
    let name = declaration_record
        .name
        .as_ref()
        .map(wrela_hir::Name::as_str)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    partial.proofs.push(Proof {
        id: proof,
        kind: ProofKind::CleanupAcyclic,
        subject: bounded_test_fact(request, "scope protocol: ", name, is_cancelled)?,
        sources: vec![declaration_record.source],
        depends_on: Vec::new(),
        bound: Some(0),
        explanation: vec![
            "the scope protocol has bounded non-suspending cleanup phases; activation dependencies are proved per source function"
                .to_owned(),
        ],
    });
    partial.scope_protocols.push(ScopeProtocol {
        id,
        declaration,
        name: copy_analysis_text(name, request.limits.fact_bytes, is_cancelled)?,
        parameters,
        result,
        setup: scope.setup,
        enter: scope.enter,
        abort: scope.abort,
        exit: scope.exit,
        suspend_safe: false,
        abort_effects: EffectSet(0),
        exit_effects: EffectSet(0),
        proof,
    });
    Ok(id)
}

fn semantic_generic_function_signature_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    generics: &[wrela_hir::GenericParameterId],
    arguments: &[SemanticArgument],
    source: &TypeExpression,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    match &source.kind {
        TypeExpressionKind::Named {
            definition: Definition::Generic(generic),
            arguments: source_arguments,
        } if source_arguments.is_empty() => {
            for (index, candidate) in generics.iter().enumerate() {
                charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
                if candidate == generic {
                    return match arguments.get(index) {
                        Some(SemanticArgument::Type(ty)) => Ok(*ty),
                        _ => Err(AnalysisFailure::RequestMismatch.into()),
                    };
                }
            }
            Err(runtime_type_diagnostic(
                request,
                source.source,
                "semantic-generic-function-signature-pending",
                "generic function signature refers to a type parameter owned elsewhere",
                "closed-world specialization substitutes only this function's ordered parameters",
                "use one of the function's own unbounded type parameters",
            ))
        }
        TypeExpressionKind::Named {
            definition: Definition::Builtin(_),
            arguments: source_arguments,
        } if source_arguments.is_empty() => {
            semantic_type_from_source(request, partial, source, aggregate_work, is_cancelled)
        }
        _ => Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-generic-function-signature-pending",
            "generic function signature is outside the copy-scalar specialization subset",
            "nested nominal, generic, view, tuple, array, and function types require later monomorphization support",
            "use primitive stored copy scalars or bare unbounded type parameters",
        )),
    }
}

fn ensure_ordinary_source_function(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    generic_arguments: &[SemanticArgument],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<FunctionInstanceId> {
    // Nongeneric async recursion is intentionally admitted far enough for the
    // wait-graph analysis to diagnose exact suspension cycles. Only generic
    // specialization needs this half-populated-instance guard.
    if generic_arguments.is_empty() {
        return ensure_ordinary_source_function_inner(
            request,
            partial,
            declaration,
            generic_arguments,
            allow_assertions,
            aggregate_work,
            is_cancelled,
        );
    }
    for (active_declaration, active_arguments) in &aggregate_work.resolving_functions {
        check_cancelled(is_cancelled)?;
        if *active_declaration == declaration && active_arguments.as_slice() == generic_arguments {
            let source = request
                .hir
                .as_program()
                .declaration(declaration)
                .map_or(fallback_span(request.hir.as_program()), |record| {
                    record.source
                });
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-runtime-recursive-call-pending",
                "recursive runtime specialization is outside the bounded call subset",
                "direct and mutual re-entry cannot consume a half-populated monomorphized function",
                "rewrite the recursion as a statically bounded loop or an iterative helper",
            ));
        }
    }
    let mut active_arguments = Vec::new();
    active_arguments
        .try_reserve_exact(generic_arguments.len())
        .map_err(|_| fact_resource(request, "active function specializations"))?;
    active_arguments.extend_from_slice(generic_arguments);
    aggregate_work
        .resolving_functions
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "active function specializations"))?;
    aggregate_work
        .resolving_functions
        .push((declaration, active_arguments));
    let result = ensure_ordinary_source_function_inner(
        request,
        partial,
        declaration,
        generic_arguments,
        allow_assertions,
        aggregate_work,
        is_cancelled,
    );
    let popped = aggregate_work.resolving_functions.pop();
    if popped.as_ref().is_none_or(|(candidate, arguments)| {
        *candidate != declaration || arguments.as_slice() != generic_arguments
    }) {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    result
}

fn ensure_ordinary_source_function_inner(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    generic_arguments: &[SemanticArgument],
    allow_assertions: bool,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<FunctionInstanceId> {
    for existing in &partial.functions {
        check_cancelled(is_cancelled)?;
        if matches!(
            existing.origin,
            FunctionOrigin::Source {
                declaration: candidate,
                ..
            } if candidate == declaration
                && existing.generic_arguments.as_slice() == generic_arguments
        ) {
            return Ok(existing.id);
        }
    }
    check_cancelled(is_cancelled)?;
    let declaration_record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Function(source_function) = &declaration_record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let body = source_function
        .body
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if !matches!(
        source_function.color,
        FunctionColor::Sync | FunctionColor::Async
    ) {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            "semantic-runtime-function-color-not-supported",
            "source function color is outside the runtime direct-call subset",
            "runtime specialization admits synchronous and asynchronous source functions only",
            "use `fn` or `async fn`",
        ));
    }
    if source_function.generics.len() != generic_arguments.len() {
        return Err(runtime_type_diagnostic(
            request,
            declaration_record.source,
            "semantic-generic-function-argument-count",
            "generic function specialization has the wrong number of type arguments",
            "every declared type parameter must have one inferred semantic argument",
            "call the function in a context that constrains every type parameter",
        ));
    }
    for (generic_id, argument) in source_function.generics.iter().zip(generic_arguments) {
        check_cancelled(is_cancelled)?;
        let generic = request
            .hir
            .as_program()
            .generic_parameter(*generic_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if generic.owner != declaration
            || !matches!(
                generic.kind,
                wrela_hir::GenericParameterKind::Type { bound: None }
            )
            || !matches!(argument, SemanticArgument::Type(ty)
                if partial.types.get(ty.0 as usize).is_some_and(is_stored_copy_scalar_type))
        {
            return Err(runtime_type_diagnostic(
                request,
                generic.source,
                "semantic-generic-function-parameter-kind",
                "generic function specialization is outside the unbounded copy-scalar type subset",
                "constant, region, bounded, and non-scalar arguments require later monomorphization semantics",
                "use unbounded type parameters inferred as primitive stored copy scalars",
            ));
        }
    }
    let mut body_statements = Vec::new();
    let mut body_callees = Vec::new();
    match inspect_runtime_body_shape(
        request,
        body,
        source_function.color,
        allow_assertions,
        &mut body_statements,
        &mut body_callees,
        is_cancelled,
    ) {
        Ok(()) => {}
        Err(RuntimeShapeFailure::Unsupported(source)) => {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-runtime-function-body-not-supported",
                "function body is outside the revision 0.1 ownership subset",
                None,
                "loops, awaits, closures, actors, and indirect calls are rejected by this path",
                "use scalar locals, direct calls, named arguments, and conditionals only",
            ));
        }
        Err(RuntimeShapeFailure::UnsupportedAssertion(source)) => {
            return Err(runtime_diagnostic(
                request,
                source,
                "semantic-runtime-assertion-not-supported",
                "runtime assertions are supported only in selected generated tests",
                None,
                "ordinary images and actor turns cannot yet abandon and supervise an assertion-failed activation",
                "move this assertion into a selected @test function",
            ));
        }
        Err(RuntimeShapeFailure::Failure(error)) => return Err(error.into()),
    }
    if source_function.color == FunctionColor::Async {
        let closure = collect_source_body_closure(request.hir.as_program(), body, is_cancelled)?;
        let mut first_await = None;
        for expression in closure.expressions {
            check_cancelled(is_cancelled)?;
            let expression = request
                .hir
                .as_program()
                .expression(expression)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            if matches!(
                expression.kind,
                ExpressionKind::Unary {
                    operator: wrela_hir::UnaryOperator::Await,
                    ..
                }
            ) {
                first_await = Some(expression.source);
                break;
            }
        }
        if let Some(await_source) = first_await {
            for parameter_id in &source_function.parameters {
                check_cancelled(is_cancelled)?;
                let parameter = request
                    .hir
                    .as_program()
                    .parameter(*parameter_id)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if matches!(
                    parameter.access,
                    wrela_hir::AccessMode::Read | wrela_hir::AccessMode::Mutate
                ) || parameter
                    .ty
                    .as_ref()
                    .is_some_and(|ty| matches!(ty.kind, TypeExpressionKind::View { .. }))
                {
                    let mut diagnostic = Diagnostic::error(
                        Category::ASYNC,
                        await_source,
                        "borrowed access may not remain live across suspension",
                    );
                    diagnostic.code = Some("semantic-view-across-await".to_owned());
                    diagnostic
                        .labels
                        .try_reserve_exact(1)
                        .map_err(|_| fact_resource(request, "async diagnostic labels"))?;
                    diagnostic.labels.push(wrela_diagnostics::Label {
                        span: parameter.source,
                        message: "this loan belongs to the caller".to_owned(),
                    });
                    diagnostic.help.push(
                        "copy or take the required value before await, then reacquire any view afterward"
                            .to_owned(),
                    );
                    return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
                }
            }
        }
    }
    let result = match source_function.result.as_ref() {
        Some(result) if source_function.generics.is_empty() => {
            semantic_type_from_source(request, partial, result, &mut *aggregate_work, is_cancelled)?
        }
        Some(result) => semantic_generic_function_signature_type(
            request,
            partial,
            &source_function.generics,
            generic_arguments,
            result,
            &mut *aggregate_work,
            is_cancelled,
        )?,
        None => SemanticTypeId(0),
    };
    let proof_count = if source_function.color == FunctionColor::Async {
        4usize
    } else {
        2usize
    };
    if partial.functions.len() >= request.limits.monomorphizations as usize
        || partial
            .proofs
            .len()
            .checked_add(proof_count)
            .is_none_or(|count| count > request.limits.proofs as usize)
    {
        return Err(fact_resource(request, "ordinary source functions").into());
    }
    let function_id = FunctionInstanceId(
        u32::try_from(partial.functions.len())
            .map_err(|_| fact_resource(request, "ordinary source functions"))?,
    );
    let type_proof = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "ordinary source proofs"))?,
    );
    let effect_proof = ProofId(
        type_proof
            .0
            .checked_add(1)
            .ok_or_else(|| fact_resource(request, "ordinary source proofs"))?,
    );
    let name = copy_test_name(request, declaration, is_cancelled)?;
    partial
        .proofs
        .try_reserve(proof_count)
        .map_err(|_| fact_resource(request, "ordinary source proofs"))?;
    partial.proofs.push(Proof {
        id: type_proof,
        kind: ProofKind::TypeChecked,
        subject: bounded_test_fact(request, "function type: ", &name, is_cancelled)?,
        sources: vec![declaration_record.source],
        depends_on: Vec::new(),
        bound: None,
        explanation: vec!["the scalar source function body is well typed".to_owned()],
    });
    partial.proofs.push(Proof {
        id: effect_proof,
        kind: ProofKind::EffectsAllowed,
        subject: bounded_test_fact(request, "function effects: ", &name, is_cancelled)?,
        sources: vec![declaration_record.source],
        depends_on: vec![type_proof],
        bound: Some(
            runtime_body_work_bound(request.hir.as_program(), body)
                .and_then(|count| count.checked_add(1))
                .ok_or_else(|| fact_resource(request, "ordinary source work bound"))?,
        ),
        explanation: vec![if source_function.color == FunctionColor::Async {
            "the closed async body may suspend only at statically resolved direct calls".to_owned()
        } else if allow_assertions {
            "the selected test helper admits only bounded scalar effects and MAY_FAIL assertion paths"
                .to_owned()
        } else {
            "the scalar source body has no source-visible effects".to_owned()
        }],
    });
    let mut function_proofs = vec![type_proof, effect_proof];
    if source_function.color == FunctionColor::Async {
        let view_proof = ProofId(
            effect_proof
                .0
                .checked_add(1)
                .ok_or_else(|| fact_resource(request, "ordinary source proofs"))?,
        );
        let cleanup_proof = ProofId(
            view_proof
                .0
                .checked_add(1)
                .ok_or_else(|| fact_resource(request, "ordinary source proofs"))?,
        );
        partial.proofs.push(Proof {
            id: view_proof,
            kind: ProofKind::ViewDoesNotEscape,
            subject: bounded_test_fact(
                request,
                "async suspension safety: ",
                &name,
                is_cancelled,
            )?,
            sources: vec![declaration_record.source],
            depends_on: vec![type_proof],
            bound: Some(0),
            explanation: vec![
                "the supported async body carries no borrowed view or external mutable loan across suspension"
                    .to_owned(),
            ],
        });
        partial.proofs.push(Proof {
            id: cleanup_proof,
            kind: ProofKind::CleanupAcyclic,
            subject: bounded_test_fact(
                request,
                "async cancellation cleanup: ",
                &name,
                is_cancelled,
            )?,
            sources: vec![declaration_record.source],
            depends_on: vec![type_proof, view_proof],
            bound: Some(
                u64::try_from(source_function.parameters.len())
                    .map_err(|_| fact_resource(request, "async cleanup bound"))?,
            ),
            explanation: vec![
                "cancellation observes a fixed frame state and destroys owned scalar values in reverse source order"
                    .to_owned(),
            ],
        });
        function_proofs.extend([view_proof, cleanup_proof]);
    }

    let mut semantic_parameters = Vec::new();
    semantic_parameters
        .try_reserve_exact(source_function.parameters.len())
        .map_err(|_| fact_resource(request, "ordinary source parameters"))?;
    for parameter_id in &source_function.parameters {
        let parameter = request
            .hir
            .as_program()
            .parameters
            .get(parameter_id.0 as usize)
            .filter(|parameter| parameter.id == *parameter_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let ty = if parameter.receiver {
            let receiver_declaration = crate::interfaces::receiver_concrete_struct(
                request.hir.as_program(),
                declaration,
            )
            .ok_or_else(|| {
                runtime_diagnostic(
                    request,
                    parameter.source,
                    "semantic-interface-unsupported",
                    "a `self` receiver here does not resolve to a concrete implementing struct",
                    None,
                    "revision 0.1's bounded interface support requires a receiver's enclosing block to name a concrete struct",
                    "declare this method inside a struct or a concrete `impl Interface for ConcreteStruct` block",
                )
            })?;
            ensure_flat_structure_type(
                request,
                partial,
                receiver_declaration,
                &mut *aggregate_work,
                is_cancelled,
            )?
        } else if source_function.generics.is_empty() {
            semantic_type_from_source(
                request,
                partial,
                parameter
                    .ty
                    .as_ref()
                    .ok_or(AnalysisFailure::RequestMismatch)?,
                &mut *aggregate_work,
                is_cancelled,
            )?
        } else {
            semantic_generic_function_signature_type(
                request,
                partial,
                &source_function.generics,
                generic_arguments,
                parameter
                    .ty
                    .as_ref()
                    .ok_or(AnalysisFailure::RequestMismatch)?,
                &mut *aggregate_work,
                is_cancelled,
            )?
        };
        let value = append_semantic_value(
            request,
            partial,
            function_id,
            ty,
            (
                SemanticValueOrigin::Parameter(*parameter_id),
                Some(parameter.source),
                // An unnamed parameter is a `self` receiver; the request
                // consistency checks apply the same fallback convention.
                Some(
                    parameter
                        .name
                        .as_ref()
                        .map_or("self", wrela_hir::Name::as_str),
                ),
            ),
            is_cancelled,
        )?;
        semantic_parameters.push(FunctionParameter {
            parameter: *parameter_id,
            value,
            access: lower_access(parameter.access),
            ty,
        });
    }
    partial
        .functions
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "ordinary source functions"))?;
    let work_bound = runtime_body_work_bound(request.hir.as_program(), body)
        .and_then(|count| count.checked_add(1))
        .ok_or_else(|| fact_resource(request, "ordinary source work bound"))?;
    let key = if generic_arguments.is_empty() {
        source_test_key(request, declaration)
    } else {
        source_function_specialization_key(
            request.build.identity.request,
            declaration,
            generic_arguments,
            partial,
        )
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                declaration_record.source,
                "semantic-generic-function-specialization-key",
                "generic function specialization cannot be represented by the bounded canonical key",
                "the key admits at most 26 ordered primitive stored copy-scalar arguments",
                "reduce the number of generic parameters or use supported primitive arguments",
            )
        })?
    };
    let mut stored_generic_arguments = Vec::new();
    stored_generic_arguments
        .try_reserve_exact(generic_arguments.len())
        .map_err(|_| fact_resource(request, "generic function arguments"))?;
    stored_generic_arguments.extend_from_slice(generic_arguments);
    partial.functions.push(FunctionInstance {
        id: function_id,
        key,
        name,
        origin: FunctionOrigin::Source { declaration, body },
        role: FunctionRole::Ordinary,
        color: source_function.color,
        generic_arguments: stored_generic_arguments,
        parameters: semantic_parameters,
        result,
        effects: EffectSet(if source_function.color == FunctionColor::Async {
            EffectSet::SUSPEND
        } else {
            0
        }),
        stack_bytes_bound: 0,
        frame_bytes_bound: if source_function.color == FunctionColor::Async {
            16
        } else {
            0
        },
        uninterrupted_work_bound: Some(work_bound),
        recursive_depth_bound: Some(1),
        proofs: function_proofs,
        source: Some(declaration_record.source),
    });
    populate_runtime_body(
        request,
        partial,
        RuntimeBodyTarget {
            function: function_id,
            declaration,
            body,
            allow_assertions,
        },
        aggregate_work,
        is_cancelled,
    )?;
    Ok(function_id)
}

fn append_expression_fact(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    fact: RuntimeExpressionFact,
) -> Result<(), AnalysisFailure> {
    append_expression_fact_with_category(request, partial, fact, ValueCategory::Value, None)
}

fn append_expression_fact_with_category(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    fact: RuntimeExpressionFact,
    category: ValueCategory,
    region: Option<RegionId>,
) -> Result<(), AnalysisFailure> {
    if partial.expressions.len() >= request.limits.expression_facts as usize {
        return Err(fact_resource(request, "expression facts"));
    }
    let proofs = copy_function_proofs(request, partial, fact.function)?;
    partial
        .expressions
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "expression facts"))?;
    partial.expressions.push(ExpressionFact {
        function: fact.function,
        expression: fact.expression,
        ty: fact.ty,
        category,
        region,
        effects: fact.effects,
        resolution: fact.resolution,
        result: fact.result,
        ownership_before: fact.ownership_before,
        ownership_after: fact.ownership_after,
        proofs,
    });
    Ok(())
}

fn append_statement_fact(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    statement: StatementId,
    post: RuntimeStatementPost<'_>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    let RuntimeStatementPost {
        effects,
        definitions,
        locals,
        parameters,
    } = post;
    if partial.statements.len() >= request.limits.statement_facts as usize {
        return Err(fact_resource(request, "statement facts"));
    }
    let proofs = copy_function_proofs(request, partial, function)?;
    let mut initialized_after = Vec::new();
    let capacity = locals
        .len()
        .checked_add(parameters.len())
        .ok_or_else(|| fact_resource(request, "statement initialized values"))?;
    if u64::try_from(capacity).map_or(true, |capacity| capacity > request.limits.fact_edges) {
        return Err(fact_resource(request, "statement initialized values"));
    }
    initialized_after
        .try_reserve_exact(capacity)
        .map_err(|_| fact_resource(request, "statement initialized values"))?;
    initialized_after.extend(
        parameters
            .iter()
            .chain(locals)
            .flatten()
            .filter(|binding| binding.state == OwnershipState::Owned)
            .map(|binding| binding.value),
    );
    cancellable_stable_sort_by(
        &mut initialized_after,
        request.limits.fact_edges,
        "statement initialized-value sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )?;
    cancellable_dedup(&mut initialized_after, is_cancelled)?;
    let mut moved_after = Vec::new();
    moved_after
        .try_reserve_exact(capacity)
        .map_err(|_| fact_resource(request, "statement moved values"))?;
    moved_after.extend(
        parameters
            .iter()
            .chain(locals)
            .flatten()
            .filter(|binding| binding.state == OwnershipState::Taken)
            .map(|binding| binding.value),
    );
    cancellable_stable_sort_by(
        &mut moved_after,
        request.limits.fact_edges,
        "statement moved-value sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )?;
    cancellable_dedup(&mut moved_after, is_cancelled)?;
    partial
        .statements
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "statement facts"))?;
    let mut live_lexical_views_after = Vec::new();
    for view in &partial.lexical_views {
        check_cancelled(is_cancelled)?;
        if view.function != function {
            continue;
        }
        if (statement == view.initialization && !view.terminal_uses.is_empty())
            || view.live_after_statements.binary_search(&statement).is_ok()
        {
            live_lexical_views_after
                .try_reserve(1)
                .map_err(|_| fact_resource(request, "live lexical views"))?;
            live_lexical_views_after.push(view.id);
        }
    }
    partial.statements.push(StatementFact {
        function,
        statement,
        effects,
        definitions,
        initialized_after,
        moved_after,
        live_loans_after: Vec::new(),
        live_lexical_views_after,
        proofs,
    });
    Ok(())
}

#[derive(Debug)]
pub(super) struct StructuredViewLiveness {
    pub(super) terminal_uses: Vec<ExpressionId>,
    pub(super) live_after_statements: Vec<StatementId>,
}

#[derive(Debug, Clone, Copy)]
pub(super) enum StructuredViewLivenessError {
    UnsupportedControlFlow(Span),
    InvalidUse(Span),
    Question(Span),
    Escape(Span),
}

pub(super) fn containing_statement_for_expression(
    program: &wrela_hir::Program,
    expression: &wrela_hir::Expression,
) -> Option<StatementId> {
    let wrela_hir::ExpressionOwner::Body(body) = expression.owner else {
        return None;
    };
    let body = program.body(body)?;
    let mut containing = None;
    let mut width = None;
    for statement in &body.statements {
        let candidate = program.statement(*statement)?;
        if candidate.source.file == expression.source.file
            && candidate.source.range.start <= expression.source.range.start
            && expression.source.range.end <= candidate.source.range.end
        {
            let candidate_width = candidate.source.range.end - candidate.source.range.start;
            if width.is_none_or(|current| candidate_width < current) {
                containing = Some(candidate.id);
                width = Some(candidate_width);
            }
        }
    }
    containing
}

fn containing_statement_for_span(
    program: &wrela_hir::Program,
    source: Span,
) -> Option<&wrela_hir::Statement> {
    let mut containing = None;
    let mut width = None;
    for candidate in &program.statements {
        if candidate.source.file == source.file
            && candidate.source.range.start <= source.range.start
            && source.range.end <= candidate.source.range.end
        {
            let candidate_width = candidate.source.range.end - candidate.source.range.start;
            if width.is_none_or(|current| candidate_width < current) {
                containing = Some(candidate);
                width = Some(candidate_width);
            }
        }
    }
    containing
}

fn lexical_view_blocking_terminal<'a>(
    program: &'a wrela_hir::Program,
    view: &LexicalView,
    source: Span,
) -> Option<&'a wrela_hir::Expression> {
    structured_view_blocking_terminal(
        program,
        &view.terminal_uses,
        &view.live_after_statements,
        source,
    )
}

fn structured_view_blocking_terminal<'a>(
    program: &'a wrela_hir::Program,
    terminal_uses: &[ExpressionId],
    live_after_statements: &[StatementId],
    source: Span,
) -> Option<&'a wrela_hir::Expression> {
    let statement = containing_statement_for_span(program, source)?;
    let terminal_in_statement = terminal_uses.iter().find_map(|terminal| {
        program.expression(*terminal).filter(|terminal| {
            statement.source.file == terminal.source.file
                && statement.source.range.start <= terminal.source.range.start
                && terminal.source.range.end <= statement.source.range.end
        })
    });
    if terminal_in_statement.is_none()
        && live_after_statements.binary_search(&statement.id).is_err()
    {
        return None;
    }
    terminal_in_statement.or_else(|| {
        terminal_uses
            .iter()
            .filter_map(|terminal| program.expression(*terminal))
            .find(|terminal| {
                terminal.source.file == source.file
                    && source.range.end <= terminal.source.range.start
            })
            .or_else(|| {
                terminal_uses
                    .first()
                    .and_then(|terminal| program.expression(*terminal))
            })
    })
}

fn direct_statement_view_references(
    program: &wrela_hir::Program,
    statement: StatementId,
    binding: LocalId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Vec<ExpressionId>, AnalysisFailure> {
    let mut references = Vec::new();
    for expression in &program.expressions {
        check_cancelled(is_cancelled)?;
        if expression.kind == ExpressionKind::Reference(Definition::Local(binding))
            && containing_statement_for_expression(program, expression) == Some(statement)
        {
            references
                .try_reserve(1)
                .map_err(|_| AnalysisFailure::ResourceLimit {
                    resource: "structured lexical-view references",
                    limit: u64::from(u32::MAX),
                })?;
            references.push(expression.id);
        }
    }
    Ok(references)
}

fn validate_structured_view_reference(
    program: &wrela_hir::Program,
    reference: ExpressionId,
    statement: &wrela_hir::Statement,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Result<(), StructuredViewLivenessError>, AnalysisFailure> {
    let reference = program
        .expression(reference)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    for candidate in &program.expressions {
        check_cancelled(is_cancelled)?;
        if candidate.kind == ExpressionKind::Try(reference.id) {
            return Ok(Err(StructuredViewLivenessError::Question(candidate.source)));
        }
    }
    if matches!(statement.kind, StatementKind::Return(_)) {
        return Ok(Err(StructuredViewLivenessError::Escape(statement.source)));
    }
    let mut consumers = 0_u32;
    for candidate in &program.expressions {
        check_cancelled(is_cancelled)?;
        if let ExpressionKind::Call { arguments, .. } = &candidate.kind
            && matches!(
                arguments.as_slice(),
                [argument]
                    if matches!(argument.value, wrela_hir::CallArgumentValue::Value(value) if value == reference.id)
            )
        {
            consumers = consumers
                .checked_add(1)
                .ok_or(AnalysisFailure::ResourceLimit {
                    resource: "structured lexical-view consumers",
                    limit: u64::from(u32::MAX),
                })?;
        }
    }
    if consumers == 1 {
        Ok(Ok(()))
    } else {
        Ok(Err(StructuredViewLivenessError::InvalidUse(
            reference.source,
        )))
    }
}

pub(super) fn derive_structured_view_liveness(
    program: &wrela_hir::Program,
    initialization: StatementId,
    binding: LocalId,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Result<StructuredViewLiveness, StructuredViewLivenessError>, AnalysisFailure> {
    #[allow(clippy::too_many_arguments)]
    fn analyze_body(
        program: &wrela_hir::Program,
        body: BodyId,
        start: usize,
        binding: LocalId,
        mut live_after: bool,
        inside_loop: bool,
        terminal_uses: &mut Vec<ExpressionId>,
        live_after_statements: &mut Vec<StatementId>,
        is_cancelled: &dyn Fn() -> bool,
    ) -> Result<Result<bool, StructuredViewLivenessError>, AnalysisFailure> {
        let body_record = program.body(body).ok_or(AnalysisFailure::RequestMismatch)?;
        for statement_id in body_record.statements[start..].iter().rev() {
            check_cancelled(is_cancelled)?;
            let statement = program
                .statement(*statement_id)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            if live_after && !matches!(statement.kind, StatementKind::Return(_)) {
                live_after_statements.try_reserve(1).map_err(|_| {
                    AnalysisFailure::ResourceLimit {
                        resource: "structured lexical-view liveness",
                        limit: u64::from(u32::MAX),
                    }
                })?;
                live_after_statements.push(statement.id);
            }
            let references =
                direct_statement_view_references(program, statement.id, binding, is_cancelled)?;
            for reference in &references {
                if let Err(error) = validate_structured_view_reference(
                    program,
                    *reference,
                    statement,
                    is_cancelled,
                )? {
                    return Ok(Err(error));
                }
            }
            let mut live_before = match &statement.kind {
                StatementKind::If {
                    branches,
                    else_body,
                } => {
                    let mut any_path_live = false;
                    for (_, branch) in branches {
                        let state = match analyze_body(
                            program,
                            *branch,
                            0,
                            binding,
                            live_after,
                            inside_loop,
                            terminal_uses,
                            live_after_statements,
                            is_cancelled,
                        )? {
                            Ok(state) => state,
                            Err(error) => return Ok(Err(error)),
                        };
                        any_path_live |= state;
                    }
                    if let Some(otherwise) = else_body {
                        let state = match analyze_body(
                            program,
                            *otherwise,
                            0,
                            binding,
                            live_after,
                            inside_loop,
                            terminal_uses,
                            live_after_statements,
                            is_cancelled,
                        )? {
                            Ok(state) => state,
                            Err(error) => return Ok(Err(error)),
                        };
                        any_path_live |= state;
                    } else {
                        any_path_live |= live_after;
                    }
                    any_path_live
                }
                StatementKind::Match { arms, .. } => {
                    let mut any_path_live = arms.is_empty() && live_after;
                    for arm in arms {
                        let state = match analyze_body(
                            program,
                            arm.body,
                            0,
                            binding,
                            live_after,
                            inside_loop,
                            terminal_uses,
                            live_after_statements,
                            is_cancelled,
                        )? {
                            Ok(state) => state,
                            Err(error) => return Ok(Err(error)),
                        };
                        any_path_live |= state;
                    }
                    any_path_live
                }
                StatementKind::While { condition, body } => {
                    if inside_loop
                        || bounded_while_shape(program, *condition, *body).is_none()
                        || !references.is_empty()
                    {
                        return Ok(Err(StructuredViewLivenessError::UnsupportedControlFlow(
                            statement.source,
                        )));
                    }
                    let body_live = match analyze_body(
                        program,
                        *body,
                        0,
                        binding,
                        live_after,
                        true,
                        terminal_uses,
                        live_after_statements,
                        is_cancelled,
                    )? {
                        Ok(state) => state,
                        Err(error) => return Ok(Err(error)),
                    };
                    if !live_after && body_live {
                        return Ok(Err(StructuredViewLivenessError::UnsupportedControlFlow(
                            statement.source,
                        )));
                    }
                    live_after || body_live
                }
                StatementKind::For { .. }
                | StatementKind::Loop { .. }
                | StatementKind::With { .. }
                | StatementKind::ComptimeIf { .. }
                    if live_after || !references.is_empty() =>
                {
                    return Ok(Err(StructuredViewLivenessError::UnsupportedControlFlow(
                        statement.source,
                    )));
                }
                // A return has no successor in this body, so continuation
                // liveness does not flow into its path. A return expression
                // that names the view was already rejected above as escape.
                StatementKind::Return(_) => false,
                StatementKind::Break | StatementKind::Continue
                    if live_after || !references.is_empty() =>
                {
                    return Ok(Err(StructuredViewLivenessError::Escape(statement.source)));
                }
                _ => live_after,
            };
            if !references.is_empty() {
                if !live_before {
                    if references.len() != 1 {
                        return Ok(Err(StructuredViewLivenessError::InvalidUse(
                            statement.source,
                        )));
                    }
                    terminal_uses
                        .try_reserve(1)
                        .map_err(|_| AnalysisFailure::ResourceLimit {
                            resource: "structured lexical-view terminals",
                            limit: u64::from(u32::MAX),
                        })?;
                    terminal_uses.push(references[0]);
                }
                live_before = true;
            }
            live_after = live_before;
        }
        Ok(Ok(live_after))
    }

    let initialization_record = program
        .statement(initialization)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let body = program
        .body(initialization_record.body)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let initialization_index = body
        .statements
        .iter()
        .position(|candidate| *candidate == initialization)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut terminal_uses = Vec::new();
    let mut live_after_statements = Vec::new();
    match analyze_body(
        program,
        initialization_record.body,
        initialization_index + 1,
        binding,
        false,
        false,
        &mut terminal_uses,
        &mut live_after_statements,
        is_cancelled,
    )? {
        Ok(_) => {}
        Err(error) => return Ok(Err(error)),
    }
    // An activation with no later reference releases at the end of its
    // initializer. It therefore has no terminal expression and is not live
    // after any statement; the empty witness is exact rather than missing.
    terminal_uses.sort_unstable();
    terminal_uses.dedup();
    live_after_statements.sort_unstable();
    live_after_statements.dedup();
    Ok(Ok(StructuredViewLiveness {
        terminal_uses,
        live_after_statements,
    }))
}

#[allow(clippy::too_many_arguments)]
fn record_lexical_view_initialization(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    initialization: StatementId,
    binding: LocalId,
    expression: ExpressionId,
    value: ValueId,
    category: ValueCategory,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    if partial.lexical_views.len() >= request.limits.lexical_views as usize {
        return Err(fact_resource(request, "lexical views").into());
    }
    let (protocol_id, arguments, view_id) = partial
        .expressions
        .iter()
        .find(|fact| fact.function == function && fact.expression == expression)
        .and_then(|fact| match &fact.resolution {
            ExpressionResolution::ProjectionCall {
                protocol,
                arguments,
                view,
            } if fact.result == Some(value) && fact.category == category => {
                Some((*protocol, arguments.as_slice(), *view))
            }
            _ => None,
        })
        .ok_or_else(|| {
            runtime_type_diagnostic(
                request,
                request
                    .hir
                    .as_program()
                    .expression(expression)
                    .map_or(fallback_span(request.hir.as_program()), |record| record.source),
                "semantic-projection-carrier-rebound",
                "view binding must be initialized directly by a projection call",
                "ordinary values and nested expressions cannot authenticate lexical view provenance",
                "bind one free projection call directly to this view local",
            )
        })?;
    if view_id.0 as usize != partial.lexical_views.len() {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let protocol = partial
        .projection_protocols
        .get(protocol_id.0 as usize)
        .filter(|protocol| protocol.id == protocol_id)
        .cloned()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let call = request
        .hir
        .as_program()
        .expression(expression)
        .and_then(|record| match &record.kind {
            ExpressionKind::Call { arguments, .. } => Some(arguments),
            _ => None,
        })
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut sources = Vec::new();
    sources
        .try_reserve_exact(protocol.provenance.len())
        .map_err(|_| fact_resource(request, "lexical view sources"))?;
    for parameter in &protocol.provenance {
        check_cancelled(is_cancelled)?;
        let parameter_index = protocol
            .parameters
            .iter()
            .position(|candidate| candidate.parameter == *parameter)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let argument = arguments
            .get(parameter_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let source = call
            .get(argument.source_index as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        sources.push(LexicalViewSource {
            parameter: *parameter,
            value: argument.value,
            access: argument.access,
            argument_source: source.source,
        });
    }
    let liveness = match derive_structured_view_liveness(
        request.hir.as_program(),
        initialization,
        binding,
        is_cancelled,
    )? {
        Ok(liveness) => liveness,
        Err(StructuredViewLivenessError::Question(source)) => {
            return Err(ephemeral_question_diagnostic(
                request,
                source,
                EphemeralKind::View,
            ));
        }
        Err(StructuredViewLivenessError::InvalidUse(source)) => {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-view-terminal-use-pending",
                "lexical view use must be one direct unary call argument",
                "operators, multi-argument calls, and nested expressions require broader ephemeral-consumption rules",
                "pass the view directly to one unary consumer",
            ));
        }
        Err(StructuredViewLivenessError::Escape(source)) => {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-view-escape",
                "lexical view remains live across an early exit",
                "a regionless view cannot be returned or carried through break/continue",
                "consume the view on every path before leaving its lexical activation",
            ));
        }
        Err(StructuredViewLivenessError::UnsupportedControlFlow(source)) => {
            return Err(runtime_type_diagnostic(
                request,
                source,
                "semantic-view-control-flow-pending",
                "control flow is outside the authenticated lexical-view liveness subset",
                "only an outer canonical bounded while whose post-loop continuation already retains the view has an exact fixed-point witness",
                "move the terminal use after one canonical loop, or consume and recreate the view around this statement",
            ));
        }
    };
    let statement_is_live_before = |candidate: &wrela_hir::Statement| {
        liveness
            .live_after_statements
            .binary_search(&candidate.id)
            .is_ok()
            || liveness.terminal_uses.iter().any(|terminal| {
                request
                    .hir
                    .as_program()
                    .expression(*terminal)
                    .is_some_and(|terminal| {
                        candidate.source.file == terminal.source.file
                            && candidate.source.range.start <= terminal.source.range.start
                            && terminal.source.range.end <= candidate.source.range.end
                    })
            })
    };
    for candidate in &request.hir.as_program().expressions {
        check_cancelled(is_cancelled)?;
        let Some(statement) =
            containing_statement_for_expression(request.hir.as_program(), candidate)
                .and_then(|statement| request.hir.as_program().statement(statement))
        else {
            continue;
        };
        if !statement_is_live_before(statement) {
            continue;
        }
        let ExpressionKind::Call { arguments, .. } = &candidate.kind else {
            continue;
        };
        for argument in arguments {
            check_cancelled(is_cancelled)?;
            let wrela_hir::CallArgumentValue::Exclusive { place, .. } = &argument.value else {
                continue;
            };
            let Some(retained) = sources.iter().find(|source| {
                partial
                    .values
                    .get(source.value.0 as usize)
                    .is_some_and(|value| match (value.origin, &place.root) {
                        (SemanticValueOrigin::Local(expected), Definition::Local(actual)) => {
                            expected == *actual
                        }
                        (
                            SemanticValueOrigin::Parameter(expected),
                            Definition::Parameter(actual),
                        ) => expected == *actual,
                        _ => false,
                    })
            }) else {
                continue;
            };
            let parameter_name = request
                .hir
                .as_program()
                .parameters
                .get(retained.parameter.0 as usize)
                .and_then(|parameter| parameter.name.as_ref())
                .map_or("_", wrela_hir::Name::as_str);
            let terminal = structured_view_blocking_terminal(
                request.hir.as_program(),
                &liveness.terminal_uses,
                &liveness.live_after_statements,
                argument.source,
            );
            let mut diagnostic = Diagnostic::error(
                Category::OWNERSHIP,
                argument.source,
                format!(
                    "cannot mutate frozen projection parameter `{parameter_name}` while view from `{}` remains live",
                    protocol.name
                ),
            );
            diagnostic.code = Some("semantic-view-source-mutated".to_owned());
            diagnostic
                .labels
                .try_reserve_exact(2)
                .map_err(|_| fact_resource(request, "view source preflight diagnostic labels"))?;
            diagnostic.labels.push(wrela_diagnostics::Label {
                span: retained.argument_source,
                message: format!(
                    "`{parameter_name}` is frozen by projection `{}`",
                    protocol.name
                ),
            });
            if let Some(terminal) = terminal {
                diagnostic.labels.push(wrela_diagnostics::Label {
                    span: terminal.source,
                    message: "this terminal use keeps the view live".to_owned(),
                });
            }
            diagnostic.notes.push(
                "a continuation-anchored loop retains the same immutable view value on every iteration"
                    .to_owned(),
            );
            diagnostic.help.push(
                "move the mutation after the terminal use or project from a distinct source"
                    .to_owned(),
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
    }
    for statement in &request.hir.as_program().statements {
        check_cancelled(is_cancelled)?;
        if !statement_is_live_before(statement) {
            continue;
        }
        let StatementKind::Assign { targets, .. } = &statement.kind else {
            continue;
        };
        let rebound = targets.iter().find_map(|target| {
            let Definition::Local(local) = target.root else {
                return None;
            };
            if local == binding {
                return Some((None, "view carrier"));
            }
            sources.iter().find_map(|source| {
                partial
                    .values
                    .get(source.value.0 as usize)
                    .is_some_and(|value| value.origin == SemanticValueOrigin::Local(local))
                    .then(|| {
                        let name = request
                            .hir
                            .as_program()
                            .parameters
                            .get(source.parameter.0 as usize)
                            .and_then(|parameter| parameter.name.as_ref())
                            .map_or("view carrier", wrela_hir::Name::as_str);
                        (Some(source), name)
                    })
            })
        });
        let Some((retained, retained_name)) = rebound else {
            continue;
        };
        let mut diagnostic = Diagnostic::error(
            Category::OWNERSHIP,
            statement.source,
            format!(
                "cannot rebind `{retained_name}` while projection `{}` remains live",
                protocol.name
            ),
        );
        diagnostic.code = Some("semantic-projection-carrier-rebound".to_owned());
        diagnostic
            .labels
            .try_reserve_exact(2)
            .map_err(|_| fact_resource(request, "view rebind preflight diagnostic labels"))?;
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: retained.map_or(statement.source, |source| source.argument_source),
            message: format!(
                "`{retained_name}` is retained by projection `{}`",
                protocol.name
            ),
        });
        if let Some(terminal) = structured_view_blocking_terminal(
            request.hir.as_program(),
            &liveness.terminal_uses,
            &liveness.live_after_statements,
            statement.source,
        ) {
            diagnostic.labels.push(wrela_diagnostics::Label {
                span: terminal.source,
                message: "the blocking view's terminal use is here".to_owned(),
            });
        }
        diagnostic.notes.push(
            "a continuation-anchored loop retains the same view and source identities".to_owned(),
        );
        diagnostic
            .help
            .push("move the assignment after the terminal use".to_owned());
        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
    }
    let liveness_edges = liveness
        .terminal_uses
        .len()
        .checked_add(liveness.live_after_statements.len())
        .ok_or_else(|| fact_resource(request, "structured lexical-view liveness"))?;
    for _ in 0..liveness_edges {
        charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
    }
    partial.lexical_views.push(LexicalView {
        id: view_id,
        function,
        protocol: protocol_id,
        expression,
        initialization,
        binding,
        value,
        sources,
        terminal_uses: liveness.terminal_uses,
        live_after_statements: liveness.live_after_statements,
    });
    Ok(())
}

fn expression_result(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    location: (ExpressionId, Span),
    ty: SemanticTypeId,
    desired: Option<ValueId>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ValueId, AnalysisFailure> {
    let (expression, source) = location;
    if let Some(value) = desired {
        let record = partial
            .values
            .get(value.0 as usize)
            .filter(|record| record.function == function && record.ty == ty)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let origin_matches = match record.origin {
            SemanticValueOrigin::Local(_) => true,
            SemanticValueOrigin::Expression(candidate) => candidate == expression,
            SemanticValueOrigin::Parameter(_)
            | SemanticValueOrigin::ActorStateLoad(_)
            | SemanticValueOrigin::ActorStateCompoundResult(_) => false,
        };
        if !origin_matches {
            return Err(AnalysisFailure::RequestMismatch);
        }
        Ok(value)
    } else {
        append_semantic_value(
            request,
            partial,
            function,
            ty,
            (
                SemanticValueOrigin::Expression(expression),
                Some(source),
                None,
            ),
            is_cancelled,
        )
    }
}

fn append_semantic_value(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    ty: SemanticTypeId,
    description: (SemanticValueOrigin, Option<Span>, Option<&str>),
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ValueId, AnalysisFailure> {
    append_semantic_value_with_category(
        request,
        partial,
        function,
        ty,
        ValueCategory::Value,
        description,
        is_cancelled,
    )
}

#[allow(clippy::too_many_arguments)]
fn append_semantic_value_with_category(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    function: FunctionInstanceId,
    ty: SemanticTypeId,
    category: ValueCategory,
    description: (SemanticValueOrigin, Option<Span>, Option<&str>),
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ValueId, AnalysisFailure> {
    let (origin, source, name) = description;
    if partial.values.len() >= request.limits.values as usize {
        return Err(fact_resource(request, "semantic values"));
    }
    let id = ValueId(
        u32::try_from(partial.values.len())
            .map_err(|_| fact_resource(request, "semantic values"))?,
    );
    let source_name = name
        .map(|name| copy_analysis_text(name, request.limits.fact_bytes, is_cancelled))
        .transpose()?;
    partial
        .values
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic values"))?;
    partial.values.push(SemanticValue {
        id,
        function,
        ty,
        category,
        class: if matches!(
            category,
            ValueCategory::SharedView | ValueCategory::MutableView
        ) {
            SemanticValueClass::Ephemeral(EphemeralKind::View)
        } else {
            SemanticValueClass::FirstClass
        },
        origin,
        source,
        source_name,
    });
    Ok(id)
}

fn copy_function_proofs(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    function: FunctionInstanceId,
) -> Result<Vec<ProofId>, AnalysisFailure> {
    let source = &partial
        .functions
        .get(function.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .proofs;
    let mut proofs = Vec::new();
    proofs
        .try_reserve_exact(source.len())
        .map_err(|_| fact_resource(request, "fact proof edges"))?;
    proofs.extend_from_slice(source);
    Ok(proofs)
}

#[derive(Debug, Clone, Copy)]
enum PrimitiveSemanticType {
    Bool,
    Character,
    Integer {
        signed: bool,
        bits: u16,
        pointer_sized: bool,
    },
    Float {
        bits: u16,
    },
}

fn semantic_type_from_source(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    source: &TypeExpression,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    match &source.kind {
        TypeExpressionKind::Named {
            definition: Definition::Builtin(Builtin::Unit),
            arguments,
        } if arguments.is_empty() => Ok(SemanticTypeId(0)),
        TypeExpressionKind::Named {
            definition: Definition::Builtin(Builtin::Bool),
            arguments,
        } if arguments.is_empty() => Ok(ensure_primitive_type(
            request,
            partial,
            PrimitiveSemanticType::Bool,
            &mut *aggregate_work,
            is_cancelled,
        )?),
        TypeExpressionKind::Named {
            definition: Definition::Builtin(builtin),
            arguments,
        } if arguments.is_empty() => {
            let Some(primitive) = primitive_from_builtin(request, *builtin) else {
                return Err(runtime_diagnostic(
                    request,
                    source.source,
                    "semantic-runtime-type-not-supported",
                    "type is outside the revision 0.1 runtime scalar subset",
                    None,
                    "this path requires a primitive boolean, integer, or floating-point type",
                    "use an explicitly supported scalar type",
                ));
            };
            Ok(ensure_primitive_type(
                request,
                partial,
                primitive,
                &mut *aggregate_work,
                is_cancelled,
            )?)
        }
        TypeExpressionKind::Named {
            definition: Definition::Declaration(resolved),
            arguments,
        } => {
            let declaration = request
                .hir
                .resolved_declaration(resolved)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            if matches!(declaration.kind, DeclarationKind::Enumeration(_)) {
                return if arguments.is_empty() {
                    ensure_closed_scalar_enum_type(
                        request,
                        partial,
                        declaration.id,
                        &mut *aggregate_work,
                        is_cancelled,
                    )
                } else if is_exact_core_result_declaration(request, resolved, declaration) {
                    ensure_core_result_type(
                        request,
                        partial,
                        resolved,
                        arguments,
                        &mut *aggregate_work,
                        is_cancelled,
                    )
                } else if is_exact_core_async_exit_declaration(request, resolved, declaration) {
                    let [argument] = arguments.as_slice() else {
                        return Err(runtime_type_diagnostic(
                            request,
                            source.source,
                            "semantic-async-outcome-type-pending",
                            "core AsyncExit requires exactly one supported operation-error type",
                            "this bounded outcome slice specializes only AsyncExit[u64]",
                            "use AsyncExit[u64] at this analysis boundary",
                        ));
                    };
                    let error = core_result_scalar_argument(
                        request,
                        partial,
                        argument,
                        aggregate_work,
                        is_cancelled,
                    )?;
                    let u64_ty = ensure_primitive_type(
                        request,
                        partial,
                        PrimitiveSemanticType::Integer {
                            signed: false,
                            bits: 64,
                            pointer_sized: false,
                        },
                        aggregate_work,
                        is_cancelled,
                    )?;
                    if error != u64_ty {
                        return Err(runtime_type_diagnostic(
                            request,
                            argument.source,
                            "semantic-async-outcome-type-pending",
                            "core AsyncExit operation error is outside the bounded specialization",
                            "this increment authenticates exactly AsyncExit[u64]",
                            "use u64 until wider async outcome specialization lands",
                        ));
                    }
                    ensure_core_async_exit_type(
                        request,
                        partial,
                        error,
                        aggregate_work,
                        is_cancelled,
                    )
                } else {
                    ensure_closed_scalar_enum_type_from_source_arguments(
                        request,
                        partial,
                        declaration.id,
                        arguments,
                        &mut *aggregate_work,
                        is_cancelled,
                    )
                };
            }
            if !matches!(declaration.kind, DeclarationKind::Structure(_)) {
                return Err(runtime_type_diagnostic(
                    request,
                    source.source,
                    "semantic-runtime-type-not-supported",
                    "nominal runtime type is outside the flat structure subset",
                    "revision 0.1 admits structures specialized over supported copy-scalar type arguments",
                    "use a flat scalar-backed structure or a supported primitive type",
                ));
            }
            ensure_flat_structure_type_from_source_arguments(
                request,
                partial,
                declaration.id,
                arguments,
                &mut *aggregate_work,
                is_cancelled,
            )
        }
        TypeExpressionKind::SelfType { owner } => {
            let Some(declaration) =
                crate::interfaces::concrete_struct_for_self_owner(request.hir.as_program(), *owner)
            else {
                return Err(runtime_diagnostic(
                    request,
                    source.source,
                    "semantic-interface-unsupported",
                    "`Self` here does not resolve to a concrete implementing struct",
                    None,
                    "revision 0.1's bounded interface support requires `Self` to name a concrete struct",
                    "use a concrete `impl Interface for ConcreteStruct` block",
                ));
            };
            ensure_flat_structure_type(
                request,
                partial,
                declaration,
                &mut *aggregate_work,
                is_cancelled,
            )
        }
        TypeExpressionKind::View { .. } => Err(runtime_diagnostic(
            request,
            source.source,
            "semantic-view-escape",
            "borrowed view cannot escape into revision 0.1 runtime value state",
            None,
            "runtime parameters, results, and branch-joined locals outlive this bounded view model",
            "pass the owned scalar value or keep the view inside an explicitly scoped borrow",
        )),
        _ => Err(runtime_diagnostic(
            request,
            source.source,
            "semantic-runtime-type-not-supported",
            "type is outside the revision 0.1 runtime ownership subset",
            None,
            "this path currently proves primitive scalar runtime value state",
            "use a supported scalar type until aggregate ownership lowering is available",
        )),
    }
}

fn ensure_core_result_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    resolved: &wrela_hir::ResolvedDeclaration,
    arguments: &[wrela_hir::GenericArgument],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let record = request
        .hir
        .resolved_declaration(resolved)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if !is_exact_core_result_declaration(request, resolved, record) {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-result-not-core",
            "runtime generic enum is not the authenticated core Result declaration",
            "user and dependency packages cannot forge the core.result.Result specialization authority",
            "import Result from core.result",
        ));
    }
    let [ok_argument, err_argument] = arguments else {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-result-argument-count",
            "core Result requires exactly two runtime type arguments",
            "R2 specializes Result[T, E] only after both type arguments are resolved",
            "supply Result[T, E] with two supported copy-scalar types",
        ));
    };
    let ok =
        core_result_scalar_argument(request, partial, ok_argument, aggregate_work, is_cancelled)?;
    let err =
        core_result_scalar_argument(request, partial, err_argument, aggregate_work, is_cancelled)?;
    let semantic_arguments = [SemanticArgument::Type(ok), SemanticArgument::Type(err)];
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        if matches!(&existing.kind, SemanticTypeKind::Enumeration {
            declaration,
            arguments,
            ..
        } if *declaration == record.id && arguments.as_slice() == semantic_arguments)
        {
            return Ok(existing.id);
        }
    }
    let ok_payload = partial
        .types
        .get(ok.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let err_payload = partial
        .types
        .get(err.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let alignment = ok_payload
        .alignment_lower_bound
        .max(err_payload.alignment_lower_bound)
        .max(1);
    let offset = (1_u64 + u64::from(alignment) - 1) & !(u64::from(alignment) - 1);
    let size = offset
        .checked_add(
            ok_payload
                .size_upper_bound
                .zip(err_payload.size_upper_bound)
                .map(|(ok, err)| ok.max(err))
                .ok_or(AnalysisFailure::RequestMismatch)?,
        )
        .and_then(|size| size.checked_add(u64::from(alignment) - 1))
        .map(|size| size & !(u64::from(alignment) - 1))
        .ok_or_else(|| fact_resource(request, "runtime Result layout"))?;
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Enumeration {
            declaration: record.id,
            arguments: semantic_arguments.to_vec(),
            variants: [("Ok", ok), ("Err", err)]
                .into_iter()
                .map(|(name, ty)| SemanticVariant {
                    name: name.to_owned(),
                    fields: vec![SemanticField {
                        name: String::new(),
                        ty,
                        public: true,
                    }],
                })
                .collect(),
        },
        linearity: Linearity::ExplicitCopy,
        size_upper_bound: Some(size),
        alignment_lower_bound: alignment,
        source: Some(record.source),
    });
    Ok(id)
}

fn core_result_scalar_argument(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    argument: &wrela_hir::GenericArgument,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let wrela_hir::GenericArgumentKind::Type(source) = &argument.kind else {
        return Err(runtime_type_diagnostic(
            request,
            argument.source,
            "semantic-runtime-result-argument-type",
            "core Result runtime arguments must be types",
            "constant, region, capacity, and unresolved arguments are outside R2",
            "supply two identical supported copy-scalar type arguments",
        ));
    };
    if !matches!(&source.kind, TypeExpressionKind::Named {
        definition: Definition::Builtin(_),
        arguments,
    } if arguments.is_empty())
    {
        return Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-runtime-result-argument-type",
            "core Result runtime argument is not a supported copy scalar",
            "nominal, nested generic, view, tuple, and function types require later specialization semantics",
            "use bool, an integer type, or f32/f64",
        ));
    }
    let ty = semantic_type_from_source(request, partial, source, aggregate_work, is_cancelled)?;
    let record = partial
        .types
        .get(ty.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if record.linearity != Linearity::ScalarCopy
        || !matches!(
            record.kind,
            SemanticTypeKind::Bool
                | SemanticTypeKind::Integer { .. }
                | SemanticTypeKind::Float { bits: 32 | 64 }
        )
    {
        return Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-runtime-result-argument-type",
            "core Result runtime argument is not a supported stored copy scalar",
            "unit and non-runtime builtins have no canonical payload slot",
            "use bool, an integer type, or f32/f64",
        ));
    }
    Ok(ty)
}

fn is_exact_core_result_declaration(
    request: &AnalysisRequest<'_>,
    resolved: &wrela_hir::ResolvedDeclaration,
    record: &wrela_hir::Declaration,
) -> bool {
    if resolved.package != request.standard_library_package
        || record.visibility != wrela_hir::Visibility::Public
        || record.name.as_ref().map(wrela_hir::Name::as_str) != Some("Result")
        || request
            .hir
            .as_program()
            .modules
            .get(resolved.module.0 as usize)
            .is_none_or(|module| module.path.dotted() != "result")
    {
        return false;
    }
    let DeclarationKind::Enumeration(enumeration) = &record.kind else {
        return false;
    };
    let [ok_generic, err_generic] = enumeration.generics.as_slice() else {
        return false;
    };
    let generic_is_type = |id| {
        request
            .hir
            .as_program()
            .generic_parameter(id)
            .is_some_and(|generic| {
                generic.owner == record.id
                    && matches!(
                        generic.kind,
                        wrela_hir::GenericParameterKind::Type { bound: None }
                    )
            })
    };
    if !generic_is_type(*ok_generic) || !generic_is_type(*err_generic) {
        return false;
    }
    let [ok, err] = enumeration.variants.as_slice() else {
        return false;
    };
    let exact_variant =
        |variant: &wrela_hir::EnumVariant, name: &str, generic: wrela_hir::GenericParameterId| {
            variant.name.as_str() == name
                && matches!(variant.fields.as_slice(), [field]
                if field.name.is_none()
                    && matches!(&field.ty.kind, TypeExpressionKind::Named {
                        definition: Definition::Generic(candidate),
                        arguments,
                    } if *candidate == generic && arguments.is_empty()))
        };
    enumeration.members.is_empty()
        && enumeration.deriving.is_empty()
        && exact_variant(ok, "Ok", *ok_generic)
        && exact_variant(err, "Err", *err_generic)
}

fn is_exact_core_option_declaration(
    request: &AnalysisRequest<'_>,
    resolved: &wrela_hir::ResolvedDeclaration,
    record: &wrela_hir::Declaration,
) -> bool {
    if resolved.package != request.standard_library_package
        || record.visibility != wrela_hir::Visibility::Public
        || record.name.as_ref().map(wrela_hir::Name::as_str) != Some("Option")
        || request
            .hir
            .as_program()
            .modules
            .get(resolved.module.0 as usize)
            .is_none_or(|module| module.path.dotted() != "option")
    {
        return false;
    }
    let DeclarationKind::Enumeration(enumeration) = &record.kind else {
        return false;
    };
    let [generic] = enumeration.generics.as_slice() else {
        return false;
    };
    let Some(generic_record) = request.hir.as_program().generic_parameter(*generic) else {
        return false;
    };
    generic_record.owner == record.id
        && matches!(
            generic_record.kind,
            wrela_hir::GenericParameterKind::Type { bound: None }
        )
        && enumeration.members.is_empty()
        && enumeration.deriving.is_empty()
        && matches!(enumeration.variants.as_slice(), [some, none]
            if some.name.as_str() == "Some"
                && matches!(some.fields.as_slice(), [field]
                    if field.name.is_none()
                        && matches!(&field.ty.kind, TypeExpressionKind::Named {
                            definition: Definition::Generic(candidate),
                            arguments,
                        } if *candidate == *generic && arguments.is_empty()))
                && none.name.as_str() == "None"
                && none.fields.is_empty())
}

#[derive(Debug, Clone, Copy)]
struct CoreAsyncExitDeclarations {
    outcome: DeclarationId,
    cancelled: DeclarationId,
    deadline_rejected: DeclarationId,
    deadline_exceeded: DeclarationId,
}

fn core_async_exit_declarations(
    request: &AnalysisRequest<'_>,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<CoreAsyncExitDeclarations> {
    let program = request.hir.as_program();
    let mut outcome = None;
    let mut cancelled = None;
    let mut deadline_rejected = None;
    let mut deadline_exceeded = None;
    for declaration in &program.declarations {
        charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
        let Some(module) = program.modules.get(declaration.module.0 as usize) else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if module.package != request.standard_library_package || module.path.dotted() != "actor" {
            continue;
        }
        let slot = match declaration.name.as_ref().map(wrela_hir::Name::as_str) {
            Some("AsyncExit") => &mut outcome,
            Some("Cancelled") => &mut cancelled,
            Some("DeadlineRejected") => &mut deadline_rejected,
            Some("DeadlineExceeded") => &mut deadline_exceeded,
            _ => continue,
        };
        if slot.replace(declaration.id).is_some() {
            return Err(runtime_type_diagnostic(
                request,
                declaration.source,
                "semantic-async-outcome-core-shape",
                "core.actor structured async outcome declarations are ambiguous",
                "the compiler authenticates one exact declaration for AsyncExit and each sealed cause",
                "restore the checked-in core.actor outcome taxonomy",
            ));
        }
    }
    let declarations = CoreAsyncExitDeclarations {
        outcome: outcome.ok_or_else(|| async_outcome_core_shape_diagnostic(request))?,
        cancelled: cancelled.ok_or_else(|| async_outcome_core_shape_diagnostic(request))?,
        deadline_rejected: deadline_rejected
            .ok_or_else(|| async_outcome_core_shape_diagnostic(request))?,
        deadline_exceeded: deadline_exceeded
            .ok_or_else(|| async_outcome_core_shape_diagnostic(request))?,
    };
    if !exact_core_async_exit_source_shape(request, declarations) {
        return Err(async_outcome_core_shape_diagnostic(request));
    }
    Ok(declarations)
}

fn async_outcome_core_shape_diagnostic(request: &AnalysisRequest<'_>) -> RuntimeFailure {
    runtime_type_diagnostic(
        request,
        fallback_span(request.hir.as_program()),
        "semantic-async-outcome-core-shape",
        "core.actor structured async outcome differs from its sealed declaration contract",
        "visibility, ownership, generic identity, variant order, and cause payload identity are compiler-authenticated",
        "restore the exact public Cancelled, DeadlineRejected, DeadlineExceeded, and AsyncExit declarations",
    )
}

fn exact_core_async_exit_source_shape(
    request: &AnalysisRequest<'_>,
    declarations: CoreAsyncExitDeclarations,
) -> bool {
    let program = request.hir.as_program();
    let exact_cause = |id: DeclarationId| {
        program.declaration(id).is_some_and(|record| {
            record.visibility == wrela_hir::Visibility::Public
                && matches!(&record.kind, DeclarationKind::Structure(aggregate)
                    if aggregate.generics.is_empty()
                        && aggregate.implements.is_empty()
                        && aggregate.fields.is_empty()
                        && aggregate.members.is_empty()
                        && !aggregate.linear
                        && !aggregate.copy
                        && aggregate.deriving.is_empty())
        })
    };
    if !exact_cause(declarations.cancelled)
        || !exact_cause(declarations.deadline_rejected)
        || !exact_cause(declarations.deadline_exceeded)
    {
        return false;
    }
    let Some(record) = program.declaration(declarations.outcome) else {
        return false;
    };
    let DeclarationKind::Enumeration(enumeration) = &record.kind else {
        return false;
    };
    let [generic] = enumeration.generics.as_slice() else {
        return false;
    };
    let exact_generic = program
        .generic_parameter(*generic)
        .is_some_and(|parameter| {
            parameter.owner == declarations.outcome
                && matches!(
                    parameter.kind,
                    wrela_hir::GenericParameterKind::Type { bound: None }
                )
        });
    let exact_payload =
        |variant: &wrela_hir::EnumVariant,
         name: &str,
         expected: Result<wrela_hir::GenericParameterId, DeclarationId>| {
            variant.name.as_str() == name
                && matches!(variant.fields.as_slice(), [field]
                if field.name.is_none()
                    && match (&field.ty.kind, expected) {
                        (TypeExpressionKind::Named {
                            definition: Definition::Generic(actual),
                            arguments,
                        }, Ok(expected)) => *actual == expected && arguments.is_empty(),
                        (TypeExpressionKind::Named {
                            definition: Definition::Declaration(actual),
                            arguments,
                        }, Err(expected)) => actual.package == request.standard_library_package
                            && actual.declaration == expected
                            && arguments.is_empty(),
                        _ => false,
                    })
        };
    record.visibility == wrela_hir::Visibility::Public
        && exact_generic
        && enumeration.members.is_empty()
        && enumeration.deriving.is_empty()
        && matches!(enumeration.variants.as_slice(), [operation, cancelled, rejected, exceeded]
            if exact_payload(operation, "Operation", Ok(*generic))
                && exact_payload(cancelled, "Cancelled", Err(declarations.cancelled))
                && exact_payload(rejected, "DeadlineRejected", Err(declarations.deadline_rejected))
                && exact_payload(exceeded, "DeadlineExceeded", Err(declarations.deadline_exceeded)))
}

fn is_exact_core_async_exit_declaration(
    request: &AnalysisRequest<'_>,
    resolved: &wrela_hir::ResolvedDeclaration,
    record: &wrela_hir::Declaration,
) -> bool {
    resolved.package == request.standard_library_package
        && record.visibility == wrela_hir::Visibility::Public
        && record.name.as_ref().map(wrela_hir::Name::as_str) == Some("AsyncExit")
        && request
            .hir
            .as_program()
            .modules
            .get(resolved.module.0 as usize)
            .is_some_and(|module| module.path.dotted() == "actor")
}

fn ensure_core_async_exit_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    error: SemanticTypeId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let declarations = core_async_exit_declarations(request, aggregate_work, is_cancelled)?;
    let mut causes = Vec::new();
    causes
        .try_reserve_exact(3)
        .map_err(|_| fact_resource(request, "structured async exit cause types"))?;
    for declaration in [
        declarations.cancelled,
        declarations.deadline_rejected,
        declarations.deadline_exceeded,
    ] {
        let mut existing = None;
        for ty in &partial.types {
            charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
            if matches!(&ty.kind, SemanticTypeKind::Structure { declaration: candidate, arguments, fields }
                if *candidate == declaration && arguments.is_empty() && fields.is_empty())
            {
                existing = Some(ty.id);
                break;
            }
        }
        if let Some(existing) = existing {
            causes.push(existing);
            continue;
        }
        if partial.types.len() >= request.limits.types as usize {
            return Err(fact_resource(request, "semantic types").into());
        }
        let id = SemanticTypeId(
            u32::try_from(partial.types.len())
                .map_err(|_| fact_resource(request, "semantic types"))?,
        );
        let source = request
            .hir
            .as_program()
            .declaration(declaration)
            .map(|record| record.source)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        partial
            .types
            .try_reserve(1)
            .map_err(|_| fact_resource(request, "semantic types"))?;
        partial.types.push(SemanticType {
            id,
            kind: SemanticTypeKind::Structure {
                declaration,
                arguments: Vec::new(),
                fields: Vec::new(),
            },
            linearity: Linearity::ExplicitCopy,
            size_upper_bound: Some(0),
            alignment_lower_bound: 1,
            source: Some(source),
        });
        causes.push(id);
    }
    let arguments = [SemanticArgument::Type(error)];
    for ty in &partial.types {
        charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
        if matches!(&ty.kind, SemanticTypeKind::Enumeration { declaration, arguments: candidate, .. }
            if *declaration == declarations.outcome && candidate.as_slice() == arguments)
        {
            return Ok(ty.id);
        }
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    let variants = [
        ("Operation", error),
        ("Cancelled", causes[0]),
        ("DeadlineRejected", causes[1]),
        ("DeadlineExceeded", causes[2]),
    ]
    .into_iter()
    .map(|(name, ty)| SemanticVariant {
        name: name.to_owned(),
        fields: vec![SemanticField {
            name: String::new(),
            ty,
            public: true,
        }],
    })
    .collect();
    let source = request
        .hir
        .as_program()
        .declaration(declarations.outcome)
        .map(|record| record.source)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Enumeration {
            declaration: declarations.outcome,
            arguments: arguments.to_vec(),
            variants,
        },
        linearity: Linearity::ExplicitCopy,
        size_upper_bound: Some(16),
        alignment_lower_bound: 8,
        source: Some(source),
    });
    Ok(id)
}

fn ensure_core_result_type_from_semantic_arguments(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    ok: SemanticTypeId,
    err: SemanticTypeId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let resolved = wrela_hir::ResolvedDeclaration {
        package: request.standard_library_package,
        module: record.module,
        declaration,
    };
    if !is_exact_core_result_declaration(request, &resolved, record) {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let arguments = [SemanticArgument::Type(ok), SemanticArgument::Type(err)];
    for ty in &partial.types {
        charge_runtime_aggregate_lookup(request, aggregate_work, is_cancelled)?;
        if matches!(&ty.kind, SemanticTypeKind::Enumeration { declaration: candidate, arguments: actual, .. }
            if *candidate == declaration && actual.as_slice() == arguments)
        {
            return Ok(ty.id);
        }
    }
    let ok_layout = partial
        .types
        .get(ok.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let err_layout = partial
        .types
        .get(err.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let alignment = ok_layout
        .alignment_lower_bound
        .max(err_layout.alignment_lower_bound)
        .max(1);
    let payload_size = ok_layout
        .size_upper_bound
        .zip(err_layout.size_upper_bound)
        .map(|(left, right)| left.max(right))
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mask = u64::from(alignment) - 1;
    let offset = 1_u64
        .checked_add(mask)
        .map(|value| value & !mask)
        .ok_or_else(|| fact_resource(request, "structured async Result layout"))?;
    let size = offset
        .checked_add(payload_size)
        .and_then(|value| value.checked_add(mask))
        .map(|value| value & !mask)
        .ok_or_else(|| fact_resource(request, "structured async Result layout"))?;
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Enumeration {
            declaration,
            arguments: arguments.to_vec(),
            variants: [("Ok", ok), ("Err", err)]
                .into_iter()
                .map(|(name, ty)| SemanticVariant {
                    name: name.to_owned(),
                    fields: vec![SemanticField {
                        name: String::new(),
                        ty,
                        public: true,
                    }],
                })
                .collect(),
        },
        linearity: Linearity::ExplicitCopy,
        size_upper_bound: Some(size),
        alignment_lower_bound: alignment,
        source: Some(record.source),
    });
    Ok(id)
}

fn ensure_core_admission_result_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let program = request.hir.as_program();
    let mut admission_error = None;
    let mut admission_result = None;
    for declaration in &program.declarations {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        let Some(module) = program.modules.get(declaration.module.0 as usize) else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if module.package != request.standard_library_package || module.path.dotted() != "actor" {
            continue;
        }
        match declaration.name.as_ref().map(wrela_hir::Name::as_str) {
            Some("AdmissionError") if admission_error.replace(declaration.id).is_some() => {
                return Err(AnalysisFailure::RequestMismatch.into());
            }
            Some("AdmissionResult") if admission_result.replace(declaration.id).is_some() => {
                return Err(AnalysisFailure::RequestMismatch.into());
            }
            _ => {}
        }
    }
    let error_id = admission_error.ok_or_else(|| {
        runtime_type_diagnostic(
            request,
            fallback_span(program),
            "semantic-admission-result-core-shape",
            "the authenticated core.actor AdmissionError declaration is missing",
            "try send has one standard-library-owned admission failure taxonomy",
            "restore the exact core.actor AdmissionError and AdmissionResult declarations",
        )
    })?;
    let result_id = admission_result.ok_or_else(|| {
        runtime_type_diagnostic(
            request,
            fallback_span(program),
            "semantic-admission-result-core-shape",
            "the authenticated core.actor AdmissionResult declaration is missing",
            "try send has one standard-library-owned admission outcome taxonomy",
            "restore the exact core.actor AdmissionError and AdmissionResult declarations",
        )
    })?;
    let error = program
        .declaration(error_id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let result = program
        .declaration(result_id)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let exact_unit_variant = |variant: &wrela_hir::EnumVariant, name: &str| {
        variant.name.as_str() == name && variant.fields.is_empty()
    };
    let exact_error = error.visibility == wrela_hir::Visibility::Public
        && matches!(&error.kind, DeclarationKind::Enumeration(enumeration)
            if enumeration.generics.is_empty()
                && enumeration.members.is_empty()
                && enumeration.deriving.is_empty()
                && matches!(enumeration.variants.as_slice(), [full, restarting, stale, cancelled, deadline]
                    if exact_unit_variant(full, "Full")
                        && exact_unit_variant(restarting, "Restarting")
                        && exact_unit_variant(stale, "StaleRequest")
                        && exact_unit_variant(cancelled, "Cancelled")
                        && exact_unit_variant(deadline, "DeadlineRejected")));
    let exact_result = result.visibility == wrela_hir::Visibility::Public
        && matches!(&result.kind, DeclarationKind::Enumeration(enumeration)
            if enumeration.generics.is_empty()
                && enumeration.members.is_empty()
                && enumeration.deriving.is_empty()
                && matches!(enumeration.variants.as_slice(), [admitted, rejected]
                    if exact_unit_variant(admitted, "Admitted")
                        && rejected.name.as_str() == "Rejected"
                        && matches!(rejected.fields.as_slice(), [field]
                            if field.name.is_none()
                                && matches!(&field.ty.kind, TypeExpressionKind::Named {
                                    definition: Definition::Declaration(resolved),
                                    arguments,
                                } if arguments.is_empty()
                                    && resolved.package == request.standard_library_package
                                    && resolved.module == error.module
                                    && resolved.declaration == error_id))));
    if !exact_error || !exact_result {
        return Err(runtime_type_diagnostic(
            request,
            result.source,
            "semantic-admission-result-core-shape",
            "core.actor admission taxonomy differs from its sealed declaration contract",
            "variant order, unit shapes, and the Rejected payload identity are compiler-authenticated",
            "restore the exact public AdmissionError and AdmissionResult declarations",
        ));
    }
    let error_ty = ensure_closed_scalar_enum_type(
        request,
        partial,
        error_id,
        &mut *aggregate_work,
        is_cancelled,
    )?;
    let result_ty = ensure_closed_scalar_enum_type(
        request,
        partial,
        result_id,
        &mut *aggregate_work,
        is_cancelled,
    )?;
    let exact_semantic = partial.types.get(result_ty.0 as usize).is_some_and(|ty| {
        matches!(&ty.kind, SemanticTypeKind::Enumeration {
                declaration,
                arguments,
                variants,
            } if *declaration == result_id
                && arguments.is_empty()
                && matches!(variants.as_slice(), [admitted, rejected]
                    if admitted.name == "Admitted"
                        && admitted.fields.is_empty()
                        && rejected.name == "Rejected"
                        && matches!(rejected.fields.as_slice(), [field]
                            if field.name.is_empty() && field.public && field.ty == error_ty)))
    });
    if !exact_semantic {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    Ok(result_ty)
}

fn ensure_closed_scalar_enum_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    ensure_closed_scalar_enum_type_specialized(
        request,
        partial,
        declaration,
        &[],
        aggregate_work,
        is_cancelled,
    )
}

fn ensure_closed_scalar_enum_type_from_source_arguments(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    source_arguments: &[wrela_hir::GenericArgument],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Enumeration(enumeration) = &record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if source_arguments.len() != enumeration.generics.len() {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-generic-enum-argument-count",
            "runtime generic enum specialization has the wrong number of arguments",
            "every declared type parameter must receive one exact type argument",
            "supply one supported copy-scalar type argument for every type parameter",
        ));
    }
    let mut arguments = Vec::new();
    arguments
        .try_reserve_exact(source_arguments.len())
        .map_err(|_| fact_resource(request, "runtime enum arguments"))?;
    for (generic_id, argument) in enumeration.generics.iter().zip(source_arguments) {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        let generic = request
            .hir
            .as_program()
            .generic_parameter(*generic_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if generic.owner != declaration
            || !matches!(
                generic.kind,
                wrela_hir::GenericParameterKind::Type { bound: None }
            )
        {
            return Err(runtime_type_diagnostic(
                request,
                generic.source,
                "semantic-runtime-generic-enum-parameter",
                "runtime generic enum parameter is outside the bounded type-only subset",
                "constant, region, and bounded type parameters require later specialization semantics",
                "use an unbounded type parameter specialized with a supported copy scalar",
            ));
        }
        arguments.push(SemanticArgument::Type(generic_enum_scalar_argument(
            request,
            partial,
            argument,
            aggregate_work,
            is_cancelled,
        )?));
    }
    ensure_closed_scalar_enum_type_specialized(
        request,
        partial,
        declaration,
        &arguments,
        aggregate_work,
        is_cancelled,
    )
}

fn generic_enum_scalar_argument(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    argument: &wrela_hir::GenericArgument,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let wrela_hir::GenericArgumentKind::Type(source) = &argument.kind else {
        return Err(runtime_type_diagnostic(
            request,
            argument.source,
            "semantic-runtime-generic-enum-argument-type",
            "runtime generic enum argument must be a type",
            "constant, region, capacity, and unresolved arguments are not runtime type specializations",
            "supply a primitive boolean, integer, or floating-point type",
        ));
    };
    if !matches!(&source.kind, TypeExpressionKind::Named {
        definition: Definition::Builtin(_),
        arguments,
    } if arguments.is_empty())
    {
        return Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-runtime-generic-enum-argument-type",
            "runtime generic enum argument is not a supported copy scalar",
            "nominal, nested generic, view, tuple, and function types require later specialization semantics",
            "use bool, an integer type, or f32/f64",
        ));
    }
    let ty = semantic_type_from_source(request, partial, source, aggregate_work, is_cancelled)?;
    let record = partial
        .types
        .get(ty.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if !is_stored_copy_scalar_type(record) {
        return Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-runtime-generic-enum-argument-type",
            "runtime generic enum argument is not a supported stored copy scalar",
            "unit and non-runtime builtins have no canonical payload representation",
            "use bool, an integer type, or f32/f64",
        ));
    }
    Ok(ty)
}

fn ensure_closed_scalar_enum_type_specialized(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    semantic_arguments: &[SemanticArgument],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    // Cycle guard (T0.1d): a payload enum whose id is already on the active
    // resolution stack recurses into itself (directly, or transitively through
    // another enum), so it has no finite machine layout. Fail closed here BEFORE
    // recursing again — never loop, overflow the native stack, or rely on the
    // aggregate-lookup budget to "eventually" stop. The offending enum is named
    // by its own declaration source span.
    if aggregate_work.resolving_enums.contains(&declaration) {
        let record = request
            .hir
            .as_program()
            .declaration(declaration)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-enum-recursive-payload",
            "runtime enum variant payload recurses into the enum being resolved",
            "a variant whose payload is its own enum (directly or transitively) has no finite machine layout",
            "break the payload cycle, or box the recursive payload in a later ownership slice",
        ));
    }
    // Push this enum onto the in-progress stack, resolve, then pop on EVERY
    // return path (the inner helper's `?` early-returns included) so the stack
    // stays balanced across sibling and later resolutions.
    aggregate_work
        .resolving_enums
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "runtime enum resolution stack"))?;
    aggregate_work.resolving_enums.push(declaration);
    let resolved = ensure_closed_scalar_enum_type_resolved(
        request,
        partial,
        declaration,
        semantic_arguments,
        &mut *aggregate_work,
        is_cancelled,
    );
    aggregate_work.resolving_enums.pop();
    resolved
}

fn ensure_closed_scalar_enum_type_resolved(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    semantic_arguments: &[SemanticArgument],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        if matches!(&existing.kind, SemanticTypeKind::Enumeration {
            declaration: candidate,
            arguments,
            ..
        } if *candidate == declaration && arguments.as_slice() == semantic_arguments)
        {
            return Ok(existing.id);
        }
    }
    let record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Enumeration(enumeration) = &record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if enumeration.generics.len() != semantic_arguments.len() {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-enum-generic-not-supported",
            "runtime enum specialization does not bind every generic parameter",
            "closed-world enum resolution requires an exact specialization key",
            "supply one supported copy-scalar argument for every type parameter",
        ));
    }
    if enumeration.variants.is_empty() || enumeration.variants.len() > 256 {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-enum-variant-count",
            "runtime enum must declare between one and 256 variants",
            "the canonical machine discriminant is one dense u8 tag in declaration order",
            "declare at least one and at most 256 variants",
        ));
    }
    let mut variants = Vec::new();
    variants
        .try_reserve_exact(enumeration.variants.len())
        .map_err(|_| fact_resource(request, "runtime enum variants"))?;
    // Tracks the widest payload slot across every payload-bearing variant as
    // `(max size, max alignment)`. Each variant keeps its OWN scalar payload
    // type (heterogeneous payloads are admitted); the machine layout is a
    // tagged union whose single payload slot is sized/aligned to the maxima.
    let mut payload_slot: Option<(u64, u32)> = None;
    for variant in &enumeration.variants {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        let field = match variant.fields.as_slice() {
            [] => {
                // Unit variant: no payload slot. Admitting the zero-field shape
                // lets mixed-arity enums such as the actor `AdmissionResult`
                // (`Admitted | Rejected(..)`) resolve at the runtime tier;
                // multiple-field and nominal payloads remain a later slice.
                variants.push(SemanticVariant {
                    name: copy_analysis_text(
                        variant.name.as_str(),
                        request.limits.fact_bytes,
                        is_cancelled,
                    )?,
                    fields: Vec::new(),
                });
                continue;
            }
            [field] => field,
            _ => {
                return Err(runtime_type_diagnostic(
                    request,
                    variant.source,
                    "semantic-runtime-enum-payload-shape",
                    "runtime enum variant admits at most one positional payload",
                    "multiple positional payload fields are outside this bounded revision slice",
                    "give the variant zero or one positional scalar payload",
                ));
            }
        };
        if field.name.is_some() {
            return Err(runtime_type_diagnostic(
                request,
                field.source,
                "semantic-runtime-enum-payload-shape",
                "runtime enum payload must be positional",
                "named variant fields are not part of the canonical R1 representation",
                "remove the payload field name",
            ));
        }
        let payload = match &field.ty.kind {
            TypeExpressionKind::Named {
                definition: Definition::Generic(generic),
                arguments,
            } if arguments.is_empty() => {
                let position = enumeration
                    .generics
                    .iter()
                    .position(|candidate| candidate == generic)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                match semantic_arguments.get(position) {
                    Some(SemanticArgument::Type(ty)) => *ty,
                    _ => return Err(AnalysisFailure::RequestMismatch.into()),
                }
            }
            TypeExpressionKind::Named {
                definition: Definition::Builtin(_),
                arguments,
            } if arguments.is_empty() => {
                let payload = semantic_type_from_source(
                    request,
                    partial,
                    &field.ty,
                    &mut *aggregate_work,
                    is_cancelled,
                )?;
                let payload_record = partial
                    .types
                    .get(payload.0 as usize)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if payload_record.linearity != Linearity::ScalarCopy
                    || !matches!(
                        payload_record.kind,
                        SemanticTypeKind::Bool
                            | SemanticTypeKind::Integer { .. }
                            | SemanticTypeKind::Float { bits: 32 | 64 }
                    )
                {
                    return Err(runtime_type_diagnostic(
                        request,
                        field.source,
                        "semantic-runtime-enum-payload-type",
                        "runtime enum payload is not a supported copy scalar",
                        "each variant payload must be a stored boolean, integer, or floating-point scalar",
                        "use one primitive boolean, integer, or floating-point payload type",
                    ));
                }
                payload
            }
            // A nominal payload is admitted as a variant's single field when it
            // is a flat struct (T0.1c) OR a nongeneric closed enum (T0.1d), each
            // resolved recursively by its own `ensure_*` routine, which folds its
            // size/alignment into the shared tagged-union slot below with no
            // layout-code change. `ensure_flat_structure_type` enforces the
            // flat-scalar subset; `ensure_closed_scalar_enum_type` enforces the
            // closed-enum subset AND detects payload recursion (a variant whose
            // payload is its own enum, directly or transitively) via the
            // resolution-in-progress stack, failing closed with
            // `semantic-runtime-enum-recursive-payload` instead of looping. A
            // flat struct stores only scalars, so it can never transitively
            // contain an enum. Argument-bearing nominal payloads, generic
            // payload declarations, views, tuples, and arrays stay rejected
            // here. A generic outer enum may use the exact nongeneric
            // flat-structure branch below.
            TypeExpressionKind::Named {
                definition: Definition::Declaration(resolved),
                arguments,
            } if arguments.is_empty() => {
                let payload_declaration = request
                    .hir
                    .resolved_declaration(resolved)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                match &payload_declaration.kind {
                    DeclarationKind::Structure(_) => ensure_flat_structure_type(
                        request,
                        partial,
                        payload_declaration.id,
                        &mut *aggregate_work,
                        is_cancelled,
                    )?,
                    DeclarationKind::Enumeration(payload_enum) => {
                        if !semantic_arguments.is_empty() {
                            return Err(runtime_type_diagnostic(
                                request,
                                field.source,
                                "semantic-runtime-generic-enum-payload-type",
                                "runtime generic enum has an unsupported fixed enum payload",
                                "this bounded increment authenticates fixed nongeneric flat-structure payloads but not nested enum payload layouts inside a generic specialization",
                                "use a primitive scalar, one unbounded type parameter, or one nongeneric flat structure payload",
                            ));
                        }
                        // Keep the existing generic rejection: a generic enum
                        // payload is not part of this bounded slice and stays
                        // rejected under the uniform payload-type diagnostic
                        // rather than reaching the nongeneric recursion path.
                        if !payload_enum.generics.is_empty() {
                            return Err(runtime_type_diagnostic(
                                request,
                                field.source,
                                "semantic-runtime-enum-payload-type",
                                "runtime enum payload is not a supported copy scalar, flat struct, or nongeneric enum",
                                "generic enum payloads require later ownership and monomorphization lowering",
                                "use one primitive scalar, one flat scalar-backed structure, or one nongeneric closed enum payload type",
                            ));
                        }
                        ensure_closed_scalar_enum_type(
                            request,
                            partial,
                            payload_declaration.id,
                            &mut *aggregate_work,
                            is_cancelled,
                        )?
                    }
                    _ => {
                        return Err(runtime_type_diagnostic(
                            request,
                            field.source,
                            "semantic-runtime-enum-payload-type",
                            "runtime enum payload is not a supported copy scalar, flat struct, or nongeneric enum",
                            "view and other non-structure, non-enum nominal payloads require later ownership lowering",
                            "use one primitive scalar, one flat scalar-backed structure, or one nongeneric closed enum payload type",
                        ));
                    }
                }
            }
            _ => {
                return Err(runtime_type_diagnostic(
                    request,
                    field.source,
                    "semantic-runtime-enum-payload-type",
                    "runtime enum payload is not a supported copy scalar or flat struct",
                    "nested, generic, view, tuple, and array payloads require later ownership lowering",
                    "use one primitive scalar or one flat scalar-backed structure payload type",
                ));
            }
        };
        // Fold this variant's payload (scalar OR flat struct) size and alignment
        // into the shared tagged-union slot maxima. Both the scalar path and
        // `ensure_flat_structure_type` populate `size_upper_bound`, so the union
        // layout generalizes to nominal payloads with no layout-code change.
        let payload_record = partial
            .types
            .get(payload.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let payload_size = payload_record
            .size_upper_bound
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let payload_alignment = payload_record.alignment_lower_bound.max(1);
        payload_slot = Some(match payload_slot {
            None => (payload_size, payload_alignment),
            Some((size, alignment)) => (size.max(payload_size), alignment.max(payload_alignment)),
        });
        variants.push(SemanticVariant {
            name: copy_analysis_text(
                variant.name.as_str(),
                request.limits.fact_bytes,
                is_cancelled,
            )?,
            fields: vec![SemanticField {
                name: String::new(),
                ty: payload,
                public: true,
            }],
        });
    }
    // All-unit enums carry only the one-byte discriminant; enums with any
    // scalar payload reserve one shared aligned payload slot after the tag,
    // sized and aligned to the maxima across every payload-bearing variant.
    let (size, alignment) = match payload_slot {
        None => (1_u64, 1_u32),
        Some((payload_size, alignment)) => {
            let offset = (1_u64 + u64::from(alignment) - 1) & !(u64::from(alignment) - 1);
            let size = offset
                .checked_add(payload_size)
                .and_then(|size| size.checked_add(u64::from(alignment) - 1))
                .map(|size| size & !(u64::from(alignment) - 1))
                .ok_or_else(|| fact_resource(request, "runtime enum layout"))?;
            (size, alignment)
        }
    };
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Enumeration {
            declaration,
            arguments: semantic_arguments.to_vec(),
            variants,
        },
        linearity: Linearity::ExplicitCopy,
        size_upper_bound: Some(size),
        alignment_lower_bound: alignment,
        source: Some(record.source),
    });
    Ok(id)
}

fn ensure_flat_structure_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    ensure_flat_structure_type_specialized(
        request,
        partial,
        declaration,
        &[],
        aggregate_work,
        is_cancelled,
    )
}

fn ensure_flat_structure_type_from_source_arguments(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    source_arguments: &[wrela_hir::GenericArgument],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(aggregate) = &record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if source_arguments.len() != aggregate.generics.len() {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-generic-structure-argument-count",
            "runtime generic structure specialization has the wrong number of arguments",
            "every declared type parameter must receive one exact type argument",
            "supply one supported copy-scalar type argument for every type parameter",
        ));
    }
    let mut arguments = Vec::new();
    arguments
        .try_reserve_exact(source_arguments.len())
        .map_err(|_| fact_resource(request, "runtime structure arguments"))?;
    for (generic_id, argument) in aggregate.generics.iter().zip(source_arguments) {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        let generic = request
            .hir
            .as_program()
            .generic_parameter(*generic_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if generic.owner != declaration
            || !matches!(
                generic.kind,
                wrela_hir::GenericParameterKind::Type { bound: None }
            )
        {
            return Err(runtime_type_diagnostic(
                request,
                generic.source,
                "semantic-runtime-generic-structure-parameter",
                "runtime generic structure parameter is outside the bounded type-only subset",
                "constant, region, and bounded type parameters require later specialization semantics",
                "use an unbounded type parameter specialized with a supported copy scalar",
            ));
        }
        arguments.push(SemanticArgument::Type(generic_structure_scalar_argument(
            request,
            partial,
            argument,
            aggregate_work,
            is_cancelled,
        )?));
    }
    ensure_flat_structure_type_specialized(
        request,
        partial,
        declaration,
        &arguments,
        aggregate_work,
        is_cancelled,
    )
}

fn generic_structure_scalar_argument(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    argument: &wrela_hir::GenericArgument,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    let wrela_hir::GenericArgumentKind::Type(source) = &argument.kind else {
        return Err(runtime_type_diagnostic(
            request,
            argument.source,
            "semantic-runtime-generic-structure-argument-type",
            "runtime generic structure argument must be a type",
            "constant, region, capacity, and unresolved arguments are not runtime type specializations",
            "supply a primitive boolean, integer, or floating-point type",
        ));
    };
    if !matches!(&source.kind, TypeExpressionKind::Named {
        definition: Definition::Builtin(_),
        arguments,
    } if arguments.is_empty())
    {
        return Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-runtime-generic-structure-argument-type",
            "runtime generic structure argument is not a supported copy scalar",
            "nested nominal, generic, view, tuple, and function arguments require later monomorphization semantics",
            "use bool, an integer type, or f32/f64",
        ));
    }
    let ty = semantic_type_from_source(request, partial, source, aggregate_work, is_cancelled)?;
    let record = partial
        .types
        .get(ty.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if !is_stored_copy_scalar_type(record) {
        return Err(runtime_type_diagnostic(
            request,
            source.source,
            "semantic-runtime-generic-structure-argument-type",
            "runtime generic structure argument is not a supported stored copy scalar",
            "unit and non-runtime builtins have no canonical stored field representation",
            "use bool, an integer type, or f32/f64",
        ));
    }
    Ok(ty)
}

fn ensure_flat_structure_type_specialized(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    declaration: DeclarationId,
    semantic_arguments: &[SemanticArgument],
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<SemanticTypeId> {
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        if matches!(
            &existing.kind,
            SemanticTypeKind::Structure {
                declaration: candidate,
                arguments,
                ..
            } if *candidate == declaration && arguments.as_slice() == semantic_arguments
        ) {
            return Ok(existing.id);
        }
    }
    let record = request
        .hir
        .as_program()
        .declaration(declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Structure(aggregate) = &record.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if aggregate.generics.len() != semantic_arguments.len() || !aggregate.implements.is_empty() {
        return Err(runtime_type_diagnostic(
            request,
            record.source,
            "semantic-runtime-aggregate-not-supported",
            "runtime structure is outside the flat scalar-backed subset",
            "every generic must be specialized exactly and interface specializations require later monomorphization support",
            "supply supported copy-scalar type arguments and remove interface specializations",
        ));
    }
    if u64::try_from(aggregate.fields.len()).map_or(true, |count| count > request.limits.fact_edges)
    {
        return Err(fact_resource(request, "runtime structure fields").into());
    }
    let mut fields = Vec::new();
    fields
        .try_reserve_exact(aggregate.fields.len())
        .map_err(|_| fact_resource(request, "runtime structure fields"))?;
    let mut size = 0_u64;
    let mut alignment = 1_u32;
    for field in &aggregate.fields {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        if field.default.is_some() || !field.attributes.is_empty() {
            return Err(runtime_type_diagnostic(
                request,
                field.source,
                "semantic-runtime-aggregate-not-supported",
                "runtime structure field is outside the flat scalar-backed subset",
                "field defaults and field attributes require aggregate initialization semantics not yet lowered",
                "use an unadorned scalar field with no default",
            ));
        }
        let field_ty = match &field.ty.kind {
            TypeExpressionKind::Named {
                definition: Definition::Builtin(_),
                arguments,
            } if arguments.is_empty() => semantic_type_from_source(
                request,
                partial,
                &field.ty,
                &mut *aggregate_work,
                is_cancelled,
            )?,
            TypeExpressionKind::Named {
                definition: Definition::Generic(generic),
                arguments,
            } if arguments.is_empty() => {
                let mut position = None;
                for (index, candidate) in aggregate.generics.iter().enumerate() {
                    charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
                    if candidate == generic {
                        position = Some(index);
                        break;
                    }
                }
                let Some(position) = position else {
                    return Err(AnalysisFailure::RequestMismatch.into());
                };
                match semantic_arguments.get(position) {
                    Some(SemanticArgument::Type(ty)) => *ty,
                    _ => {
                        return Err(AnalysisFailure::RequestMismatch.into());
                    }
                }
            }
            _ => {
                return Err(runtime_type_diagnostic(
                    request,
                    field.ty.source,
                    "semantic-runtime-aggregate-not-supported",
                    "runtime structure field is not a supported scalar",
                    "nested aggregates, views, and generic field types are intentionally outside this bounded vertical",
                    "store a primitive boolean, integer, or floating-point value directly",
                ));
            }
        };
        let field_record = partial
            .types
            .get(field_ty.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if !is_stored_copy_scalar_type(field_record) {
            return Err(runtime_type_diagnostic(
                request,
                field.ty.source,
                "semantic-runtime-aggregate-not-supported",
                "runtime structure field is not a supported scalar value",
                "unit and non-runtime builtins do not provide a flat stored field representation",
                "store a boolean, integer, or floating-point value",
            ));
        }
        let field_size = field_record
            .size_upper_bound
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let field_alignment = field_record.alignment_lower_bound;
        let mask = u64::from(field_alignment)
            .checked_sub(1)
            .ok_or_else(|| fact_resource(request, "runtime structure layout"))?;
        size = size
            .checked_add(mask)
            .map(|value| value & !mask)
            .and_then(|value| value.checked_add(field_size))
            .ok_or_else(|| fact_resource(request, "runtime structure layout"))?;
        alignment = alignment.max(field_alignment);
        fields.push(SemanticField {
            name: copy_analysis_text(field.name.as_str(), request.limits.fact_bytes, is_cancelled)?,
            ty: field_ty,
            public: field.visibility != wrela_hir::Visibility::Private,
        });
    }
    let mask = u64::from(alignment)
        .checked_sub(1)
        .ok_or_else(|| fact_resource(request, "runtime structure layout"))?;
    size = size
        .checked_add(mask)
        .map(|value| value & !mask)
        .ok_or_else(|| fact_resource(request, "runtime structure layout"))?;
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types").into());
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Structure {
            declaration,
            arguments: semantic_arguments.to_vec(),
            fields,
        },
        linearity: if aggregate.copy {
            Linearity::ScalarCopy
        } else {
            Linearity::ExplicitCopy
        },
        size_upper_bound: Some(size),
        alignment_lower_bound: alignment,
        source: Some(record.source),
    });
    Ok(id)
}

fn is_stored_copy_scalar_type(record: &SemanticType) -> bool {
    record.linearity == Linearity::ScalarCopy
        && matches!(
            record.kind,
            SemanticTypeKind::Bool
                | SemanticTypeKind::Integer { .. }
                | SemanticTypeKind::Float { bits: 32 | 64 }
        )
}

fn ensure_primitive_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    primitive: PrimitiveSemanticType,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<SemanticTypeId, AnalysisFailure> {
    let kind = match primitive {
        PrimitiveSemanticType::Bool => SemanticTypeKind::Bool,
        PrimitiveSemanticType::Character => SemanticTypeKind::Character,
        PrimitiveSemanticType::Integer {
            signed,
            bits,
            pointer_sized,
        } => SemanticTypeKind::Integer {
            signed,
            bits,
            pointer_sized,
        },
        PrimitiveSemanticType::Float { bits } => SemanticTypeKind::Float { bits },
    };
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        if existing.kind == kind {
            return Ok(existing.id);
        }
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types"));
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    let (size, alignment) = match primitive {
        PrimitiveSemanticType::Bool => (1, 1),
        PrimitiveSemanticType::Character => (4, 4),
        PrimitiveSemanticType::Integer { bits, .. } | PrimitiveSemanticType::Float { bits } => {
            let bytes = u64::from(bits.div_ceil(8));
            let alignment = u32::try_from(bytes)
                .map_err(|_| fact_resource(request, "semantic type alignment"))?;
            (bytes, alignment)
        }
    };
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind,
        linearity: Linearity::ScalarCopy,
        size_upper_bound: Some(size),
        alignment_lower_bound: alignment,
        source: None,
    });
    Ok(id)
}

fn primitive_from_builtin(
    request: &AnalysisRequest<'_>,
    builtin: Builtin,
) -> Option<PrimitiveSemanticType> {
    let integer = |signed, bits, pointer_sized| PrimitiveSemanticType::Integer {
        signed,
        bits,
        pointer_sized,
    };
    Some(match builtin {
        Builtin::Bool => PrimitiveSemanticType::Bool,
        Builtin::U8 => integer(false, 8, false),
        Builtin::U16 => integer(false, 16, false),
        Builtin::U32 => integer(false, 32, false),
        Builtin::U64 => integer(false, 64, false),
        Builtin::U128 => integer(false, 128, false),
        Builtin::Usize => integer(false, u16::from(request.target.pointer_width()), true),
        Builtin::I8 => integer(true, 8, false),
        Builtin::I16 => integer(true, 16, false),
        Builtin::I32 => integer(true, 32, false),
        Builtin::I64 => integer(true, 64, false),
        Builtin::I128 => integer(true, 128, false),
        Builtin::Isize => integer(true, u16::from(request.target.pointer_width()), true),
        Builtin::F32 => PrimitiveSemanticType::Float { bits: 32 },
        Builtin::F64 => PrimitiveSemanticType::Float { bits: 64 },
        Builtin::Never
        | Builtin::Unit
        | Builtin::Char
        | Builtin::Static
        | Builtin::Str
        | Builtin::Bytes
        | Builtin::String
        | Builtin::Option
        | Builtin::Result
        | Builtin::Actor
        | Builtin::Receipt
        | Builtin::Dma
        | Builtin::Mmio
        | Builtin::Validated => return None,
    })
}

fn ensure_function_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    color: FunctionColor,
    source_parameters: &[FunctionParameter],
    result: SemanticTypeId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<SemanticTypeId, AnalysisFailure> {
    let mut parameters = Vec::new();
    parameters
        .try_reserve_exact(source_parameters.len())
        .map_err(|_| fact_resource(request, "function type parameters"))?;
    for parameter in source_parameters {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        parameters.push(SemanticParameter {
            access: parameter.access,
            ty: parameter.ty,
        });
    }
    ensure_callable_type(
        request,
        partial,
        color,
        parameters,
        result,
        aggregate_work,
        is_cancelled,
    )
}

fn ensure_callable_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    color: FunctionColor,
    parameters: Vec<SemanticParameter>,
    result: SemanticTypeId,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<SemanticTypeId, AnalysisFailure> {
    let kind = SemanticTypeKind::Function {
        color,
        parameters,
        result,
    };
    for existing in &partial.types {
        charge_runtime_aggregate_lookup(request, &mut *aggregate_work, is_cancelled)?;
        if existing.kind == kind {
            return Ok(existing.id);
        }
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "semantic types"));
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len()).map_err(|_| fact_resource(request, "semantic types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "semantic types"))?;
    partial.types.push(SemanticType {
        id,
        kind,
        linearity: Linearity::ScalarCopy,
        size_upper_bound: Some(0),
        alignment_lower_bound: 1,
        source: None,
    });
    Ok(id)
}

fn lower_scalar_literal(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    ty: SemanticTypeId,
    literal: &Literal,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ConstantValue, AnalysisFailure> {
    let kind = partial
        .types
        .get(ty.0 as usize)
        .map(|record| &record.kind)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    match (literal, kind) {
        (Literal::Unit, SemanticTypeKind::Unit) => Ok(ConstantValue::Unit),
        (Literal::Boolean(value), SemanticTypeKind::Bool) => Ok(ConstantValue::Bool(*value)),
        (Literal::Character(value), SemanticTypeKind::Character) => {
            Ok(ConstantValue::Character(*value))
        }
        (Literal::Integer(spelling), SemanticTypeKind::Integer { signed, bits, .. }) => {
            let value = parse_integer_spelling(spelling).ok_or(AnalysisFailure::RequestMismatch)?;
            if *signed {
                let maximum = if *bits == 128 {
                    i128::MAX as u128
                } else {
                    (1_u128 << u32::from(*bits - 1)) - 1
                };
                if value > maximum {
                    return Err(AnalysisFailure::RequestMismatch);
                }
                let value = i128::try_from(value).map_err(|_| AnalysisFailure::RequestMismatch)?;
                Ok(ConstantValue::Signed { bits: *bits, value })
            } else {
                if *bits < 128 && value >= (1_u128 << u32::from(*bits)) {
                    return Err(AnalysisFailure::RequestMismatch);
                }
                Ok(ConstantValue::Unsigned { bits: *bits, value })
            }
        }
        (Literal::Float(spelling), SemanticTypeKind::Float { bits: 32 }) => {
            let value = parse_float_spelling(spelling, request.limits.fact_bytes, is_cancelled)?
                .and_then(|spelling| spelling.parse::<f32>().ok())
                .filter(|value| value.is_finite())
                .ok_or(AnalysisFailure::RequestMismatch)?;
            Ok(ConstantValue::Float32(value.to_bits()))
        }
        (Literal::Float(spelling), SemanticTypeKind::Float { bits: 64 }) => {
            let value = parse_float_spelling(spelling, request.limits.fact_bytes, is_cancelled)?
                .and_then(|spelling| spelling.parse::<f64>().ok())
                .filter(|value| value.is_finite())
                .ok_or(AnalysisFailure::RequestMismatch)?;
            Ok(ConstantValue::Float64(value.to_bits()))
        }
        _ => Err(AnalysisFailure::RequestMismatch),
    }
}

fn parse_float_spelling(
    value: &str,
    limit: u64,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Option<String>, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    if u64::try_from(value.len()).map_or(true, |bytes| bytes > limit) {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit,
        });
    }
    let mut spelling = String::new();
    spelling
        .try_reserve_exact(value.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit,
        })?;
    let mut start = 0;
    while start < value.len() {
        check_cancelled(is_cancelled)?;
        let mut end = start
            .checked_add(COMPTIME_SOURCE_COPY_CHUNK_BYTES)
            .unwrap_or(value.len())
            .min(value.len());
        while end > start && !value.is_char_boundary(end) {
            end -= 1;
        }
        if end == start {
            return Ok(None);
        }
        spelling.extend(
            value[start..end]
                .chars()
                .filter(|character| *character != '_'),
        );
        start = end;
    }
    Ok(Some(spelling))
}

fn parse_integer_spelling(value: &str) -> Option<u128> {
    let (digits, radix) = value.strip_prefix("0x").map_or_else(
        || {
            value.strip_prefix("0o").map_or_else(
                || {
                    value
                        .strip_prefix("0b")
                        .map_or((value, 10), |digits| (digits, 2))
                },
                |digits| (digits, 8),
            )
        },
        |digits| (digits, 16),
    );
    let mut result = 0u128;
    for byte in digits.bytes().filter(|byte| *byte != b'_') {
        let digit = match byte {
            b'0'..=b'9' => u128::from(byte - b'0'),
            b'a'..=b'f' => u128::from(byte - b'a' + 10),
            b'A'..=b'F' => u128::from(byte - b'A' + 10),
            _ => return None,
        };
        if digit >= radix {
            return None;
        }
        result = result.checked_mul(radix)?.checked_add(digit)?;
    }
    Some(result)
}

fn lower_access(access: wrela_hir::AccessMode) -> AccessMode {
    match access {
        wrela_hir::AccessMode::Value => AccessMode::Value,
        wrela_hir::AccessMode::Read => AccessMode::Read,
        wrela_hir::AccessMode::Mutate => AccessMode::Mutate,
        wrela_hir::AccessMode::Take => AccessMode::Take,
    }
}

fn optional_binding_map(
    count: usize,
    limit: u32,
) -> Result<Vec<Option<RuntimeBinding>>, AnalysisFailure> {
    if count > limit as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "runtime ownership maps",
            limit: u64::from(limit),
        });
    }
    let mut output = Vec::new();
    output
        .try_reserve_exact(count)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "runtime ownership maps",
            limit: u64::from(limit),
        })?;
    output.resize(count, None);
    Ok(output)
}

fn copy_binding_map(
    source: &[Option<RuntimeBinding>],
    limit: u32,
) -> Result<Vec<Option<RuntimeBinding>>, AnalysisFailure> {
    let mut output = optional_binding_map(source.len(), limit)?;
    output.copy_from_slice(source);
    Ok(output)
}

fn optional_call_map(
    count: usize,
    limit: u64,
) -> Result<Vec<Option<ResolvedCallArgument>>, AnalysisFailure> {
    if u64::try_from(count).map_or(true, |count| count > limit) {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "direct-call arguments",
            limit,
        });
    }
    let mut output = Vec::new();
    output
        .try_reserve_exact(count)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "direct-call arguments",
            limit,
        })?;
    output.resize(count, None);
    Ok(output)
}

fn fact_resource(request: &AnalysisRequest<'_>, resource: &'static str) -> AnalysisFailure {
    AnalysisFailure::ResourceLimit {
        resource,
        limit: request.limits.fact_edges,
    }
}

fn semantic_fact_bytes_resource(request: &AnalysisRequest<'_>) -> AnalysisFailure {
    AnalysisFailure::ResourceLimit {
        resource: "semantic fact bytes",
        limit: request.limits.fact_bytes,
    }
}

fn bounded_test_fact(
    request: &AnalysisRequest<'_>,
    prefix: &str,
    value: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<String, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let length = prefix
        .len()
        .checked_add(value.len())
        .ok_or(AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit: request.limits.fact_bytes,
        })?;
    if u64::try_from(length).unwrap_or(u64::MAX) > request.limits.fact_bytes {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit: request.limits.fact_bytes,
        });
    }
    let mut output = String::new();
    output
        .try_reserve_exact(length)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic fact bytes",
            limit: request.limits.fact_bytes,
        })?;
    append_polled_test_text(&mut output, prefix, is_cancelled)?;
    append_polled_test_text(&mut output, value, is_cancelled)?;
    Ok(output)
}

fn compile_generated_test_group(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    plan: &ValidatedTestPlan,
    group: ImageGroupId,
    diagnostics: &mut Vec<Diagnostic>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let record = plan.group(group).ok_or(AnalysisFailure::RequestMismatch)?;
    let ImageRoot::GeneratedHarness { harness_name } = &record.root else {
        return Err(AnalysisFailure::RequestMismatch);
    };
    let expected_events = u32::try_from(record.tests.len())
        .ok()
        .and_then(|count| count.checked_mul(2))
        .and_then(|count| count.checked_add(3))
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if record.name != GENERATED_GROUP_NAME
        || harness_name != GENERATED_HARNESS_NAME
        || record.deterministic_seed.is_some()
        || record.boot_timeout_ns != GENERATED_BOOT_TIMEOUT_NS
        || record.shutdown_timeout_ns != GENERATED_SHUTDOWN_TIMEOUT_NS
        || record.maximum_events != expected_events
        || record.maximum_output_bytes != GENERATED_MAXIMUM_OUTPUT_BYTES
        || record.tests.iter().any(|test| !test.assertions.is_empty()) && record.tests.len() != 1
    {
        return Err(AnalysisFailure::RequestMismatch);
    }
    populate_unit_type(request, partial)?;
    let program = request.hir.as_program();
    let mut candidates = std::collections::HashMap::new();
    candidates
        .try_reserve(program.test_candidates.len())
        .map_err(|_| test_resource_failure(request))?;
    for declaration in &program.test_candidates {
        check_cancelled(is_cancelled)?;
        if candidates
            .insert(source_test_key(request, *declaration), *declaration)
            .is_some()
        {
            return Err(AnalysisFailure::InternalInvariant(
                "semantic source test keys are not unique".to_owned(),
            ));
        }
    }
    let initial_diagnostic_count = diagnostics.len();
    let mut selected = Vec::new();
    let mut runtime_aggregate_work = RuntimeAggregateWork::default();
    selected
        .try_reserve_exact(record.tests.len())
        .map_err(|_| test_resource_failure(request))?;
    for planned in &record.tests {
        check_cancelled(is_cancelled)?;
        let ImageTestInvocation::GeneratedFunction { function_key } = planned.invocation else {
            return Err(AnalysisFailure::RequestMismatch);
        };
        let declaration = candidates
            .get(&function_key)
            .copied()
            .ok_or(AnalysisFailure::RequestMismatch)?;
        // This re-verifies an already-planned runtime/integration test
        // (checked below via `test.checked_comptime.is_some()` needing to
        // be false), not a fresh `--comptime` discovery request, so it must
        // not prefer a comptime-legality diagnostic over the runtime shape
        // checker's own.
        let test = match inspect_source_test(
            request,
            declaration,
            TestDiscoverySelection::Integration,
            is_cancelled,
        )? {
            Ok(test) => test,
            Err(diagnostic) => {
                push_diagnostic(diagnostics, diagnostic, request.limits)?;
                continue;
            }
        };
        if !matches!(test.color, FunctionColor::Sync | FunctionColor::Async)
            || test.checked_comptime.is_some()
            || planned.descriptor.kind != TestKind::IntegrationImage
            || planned.descriptor.name != test.name
            || planned.descriptor.source != Some(test.source)
            || planned.descriptor.timeout_ns != INTEGRATION_TEST_TIMEOUT_NS
            || planned.assertions != test.assertions
            || test.key != function_key
        {
            return Err(AnalysisFailure::RequestMismatch);
        }
        match append_source_test_function(
            request,
            partial,
            &test,
            &mut runtime_aggregate_work,
            is_cancelled,
        )? {
            Ok(_) => selected.push(test),
            Err(diagnostic) => {
                push_diagnostic(diagnostics, diagnostic, request.limits)?;
            }
        }
    }
    if diagnostics.len() != initial_diagnostic_count {
        return Ok(());
    }
    populate_generated_harness(
        request,
        partial,
        group,
        harness_name,
        &selected,
        is_cancelled,
    )?;
    Ok(())
}

fn populate_unit_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
) -> Result<(), AnalysisFailure> {
    if !partial.types.is_empty() || request.limits.types == 0 {
        return Err(AnalysisFailure::RequestMismatch);
    }
    partial
        .types
        .try_reserve_exact(1)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic types",
            limit: u64::from(request.limits.types),
        })?;
    partial.types.push(SemanticType {
        id: SemanticTypeId(0),
        kind: SemanticTypeKind::Unit,
        linearity: Linearity::ScalarCopy,
        size_upper_bound: Some(0),
        alignment_lower_bound: 1,
        source: None,
    });
    Ok(())
}

fn populate_generated_harness(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    group: ImageGroupId,
    harness_name: &str,
    tests: &[SupportedSourceTest],
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    if partial.functions.len() >= request.limits.monomorphizations as usize
        || partial
            .proofs
            .len()
            .checked_add(3)
            .is_none_or(|count| count > request.limits.proofs as usize)
    {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "generated test harness facts",
            limit: u64::from(request.limits.monomorphizations),
        });
    }
    partial
        .functions
        .try_reserve(1)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "monomorphizations",
            limit: u64::from(request.limits.monomorphizations),
        })?;
    partial
        .proofs
        .try_reserve(3)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        })?;
    let function_id = FunctionInstanceId(u32::try_from(partial.functions.len()).map_err(|_| {
        AnalysisFailure::ResourceLimit {
            resource: "monomorphizations",
            limit: u64::from(request.limits.monomorphizations),
        }
    })?);
    let type_proof = ProofId(u32::try_from(partial.proofs.len()).map_err(|_| {
        AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        }
    })?);
    let effect_proof = ProofId(type_proof.0.checked_add(1).ok_or(
        AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        },
    )?);
    let closed_proof = ProofId(effect_proof.0.checked_add(1).ok_or(
        AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        },
    )?);
    let mut sources = Vec::new();
    sources
        .try_reserve_exact(tests.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "proof edges",
            limit: request.limits.proof_edges,
        })?;
    sources.extend(tests.iter().map(|test| test.source));
    partial.proofs.push(Proof {
        id: type_proof,
        kind: ProofKind::TypeChecked,
        subject: "generated integration-test harness".to_owned(),
        sources: sources.clone(),
        depends_on: Vec::new(),
        bound: Some(u64::try_from(tests.len()).map_err(|_| test_resource_failure(request))?),
        explanation: vec![
            "every selected function has the sealed zero-argument unit test signature".to_owned(),
        ],
    });
    partial.proofs.push(Proof {
        id: effect_proof,
        kind: ProofKind::EffectsAllowed,
        subject: "generated integration-test harness effects".to_owned(),
        sources: sources.clone(),
        depends_on: vec![type_proof],
        bound: Some(
            u64::try_from(tests.len())
                .ok()
                .and_then(|count| count.checked_mul(2))
                .and_then(|count| count.checked_add(2))
                .ok_or_else(|| test_resource_failure(request))?,
        ),
        explanation: vec![
            "the harness invokes only selected test functions and the compiler-owned bounded event runtime"
                .to_owned(),
        ],
    });
    partial.proofs.push(Proof {
        id: closed_proof,
        kind: ProofKind::ImageClosed,
        subject: "closed generated integration-test image".to_owned(),
        sources,
        depends_on: vec![type_proof, effect_proof],
        bound: Some(u64::try_from(tests.len()).map_err(|_| test_resource_failure(request))?),
        explanation: vec![
            "the image contains the generated harness and exactly the selected test functions"
                .to_owned(),
        ],
    });
    let work_bound = tests.iter().try_fold(2u64, |total, test| {
        total.checked_add(3)?.checked_add(test.work_bound)
    });
    partial.functions.push(FunctionInstance {
        id: function_id,
        key: generated_harness_key(request, group),
        name: "__wrela_test_entry".to_owned(),
        origin: FunctionOrigin::GeneratedTestHarness { group },
        role: FunctionRole::ImageEntry,
        color: FunctionColor::Sync,
        generic_arguments: Vec::new(),
        parameters: Vec::new(),
        result: SemanticTypeId(0),
        effects: EffectSet(EffectSet::FIRMWARE),
        stack_bytes_bound: 0,
        frame_bytes_bound: 0,
        uninterrupted_work_bound: Some(work_bound.ok_or_else(|| test_resource_failure(request))?),
        recursive_depth_bound: Some(1),
        proofs: vec![type_proof, effect_proof, closed_proof],
        source: None,
    });
    partial.graph = Some(ImageGraph {
        name: copy_analysis_text(harness_name, request.limits.fact_bytes, is_cancelled)?,
        entry: function_id,
        actors: Vec::new(),
        tasks: Vec::new(),
        devices: Vec::new(),
        pools: Vec::new(),
        regions: Vec::new(),
        brands: Vec::new(),
        static_bytes: 0,
        peak_bytes: 0,
        startup_order: vec![ImageOwner::Runtime],
        shutdown_order: vec![ImageOwner::Runtime],
    });
    Ok(())
}

#[derive(Debug, PartialEq, Eq)]
struct EvaluatedImage {
    /// Image name followed by every actor name in one contiguous allocation.
    names: String,
    name_len: u32,
    name_source: Span,
    /// Actor records contain checked ranges into `names` and are `Copy`, so
    /// dropping an image is O(1) even when evaluation stops at cancellation.
    actors: Vec<EvaluatedActor>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EvaluatedActorKind {
    App,
    Service,
    Driver,
}

impl EvaluatedActorKind {
    fn from_install_method(name: &str) -> Option<Self> {
        match name {
            "app" => Some(Self::App),
            "service" => Some(Self::Service),
            "driver" => Some(Self::Driver),
            _ => None,
        }
    }

    const fn attribute(self) -> wrela_hir::BuiltinAttribute {
        match self {
            Self::App => wrela_hir::BuiltinAttribute::App,
            Self::Service => wrela_hir::BuiltinAttribute::Service,
            Self::Driver => wrela_hir::BuiltinAttribute::Driver,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct EvaluatedActor {
    class: DeclarationId,
    kind: EvaluatedActorKind,
    name_start: u64,
    name_len: u64,
    mailbox_capacity: u32,
    dependency: Option<u32>,
    wiring_source: Option<Span>,
    source: Span,
    mailbox_source: Span,
}

impl EvaluatedImage {
    fn name(&self) -> Option<&str> {
        self.names.get(..usize::try_from(self.name_len).ok()?)
    }

    fn actor_name(&self, actor: EvaluatedActor) -> Option<&str> {
        actor.name_in(&self.names)
    }
}

impl EvaluatedActor {
    fn name_in(self, actor_names: &str) -> Option<&str> {
        let start = usize::try_from(self.name_start).ok()?;
        let length = usize::try_from(self.name_len).ok()?;
        let end = start.checked_add(length)?;
        actor_names.get(start..end)
    }
}

#[derive(Debug, PartialEq, Eq)]
enum ComptimeValue {
    Text(String),
    Boolean(bool),
    Integer(ComptimeInteger),
    SelectedTarget,
    TargetType,
    ImageConstructor,
    ActorClass {
        declaration: DeclarationId,
        kind: EvaluatedActorKind,
    },
    InstalledActor {
        actor: u32,
        class: DeclarationId,
    },
    ActorHandle {
        actor: u32,
        class: DeclarationId,
    },
    /// Flat, nominal comptime-only structure value. Field values are stored in
    /// source declaration order and are restricted by the closure checker to
    /// target scalar values.
    Structure {
        declaration: DeclarationId,
        fields: Vec<ComptimeScalar>,
    },
    Image(EvaluatedImage),
    Unit,
}

/// Representation-enforced payload for the bounded flat-structure vertical.
///
/// Keeping structure elements `Copy` means dropping the backing vector is an
/// O(1) deallocation after the evaluator has explicitly polled its logical
/// field cleanup. No recursive `ComptimeValue` drop glue can hide unmetered
/// work in assignment replacement or successful frame teardown.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ComptimeScalar {
    Boolean(bool),
    Integer(ComptimeInteger),
    Unit,
}

impl ComptimeScalar {
    const fn into_value(self) -> ComptimeValue {
        match self {
            Self::Boolean(value) => ComptimeValue::Boolean(value),
            Self::Integer(value) => ComptimeValue::Integer(value),
            Self::Unit => ComptimeValue::Unit,
        }
    }

    fn from_value(value: ComptimeValue) -> Option<Self> {
        match value {
            ComptimeValue::Boolean(value) => Some(Self::Boolean(value)),
            ComptimeValue::Integer(value) => Some(Self::Integer(value)),
            ComptimeValue::Unit => Some(Self::Unit),
            _ => None,
        }
    }
}

impl ComptimeValue {
    const fn value_type(&self) -> Option<ComptimeType> {
        match self {
            Self::Boolean(_) => Some(ComptimeType::Bool),
            Self::Integer(value) => Some(value.scalar_type()),
            Self::Structure { declaration, .. } => Some(ComptimeType::Structure(*declaration)),
            Self::Unit => Some(ComptimeType::Unit),
            Self::Text(_)
            | Self::SelectedTarget
            | Self::TargetType
            | Self::ImageConstructor
            | Self::ActorClass { .. }
            | Self::InstalledActor { .. }
            | Self::ActorHandle { .. }
            | Self::Image(_) => None,
        }
    }
}

/// An integer value in the selected Wrela target's exact scalar domain.
///
/// `raw` is always masked to `bits`; signed values use target-width two's
/// complement rather than a host integer representation.  Keeping the source
/// signedness and resolved width on every value makes `usize`/`isize`
/// evaluation independent of the compiler host.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct ComptimeInteger {
    signed: bool,
    bits: u16,
    raw: u128,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ComptimeType {
    Unit,
    Bool,
    Integer { signed: bool, bits: u16 },
    Structure(DeclarationId),
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ComptimeExpressionAccess {
    /// Ordinary value production. A non-scalar local is moved; a non-scalar
    /// parameter cannot be moved because bare parameters are read borrows.
    Move,
    /// A source read. Scalars are copied and flat structures are represented
    /// by a bounded evaluator-private snapshot without changing ownership.
    Read,
    /// The explicit source `copy` operation.
    Copy,
}

impl ComptimeInteger {
    fn new(signed: bool, bits: u16, raw: u128) -> Option<Self> {
        if bits == 0 || bits > 128 || raw & !integer_mask(bits) != 0 {
            return None;
        }
        Some(Self { signed, bits, raw })
    }

    const fn scalar_type(self) -> ComptimeType {
        ComptimeType::Integer {
            signed: self.signed,
            bits: self.bits,
        }
    }

    fn signed_value(self) -> Option<i128> {
        if !self.signed {
            return None;
        }
        let sign_bit = 1_u128 << u32::from(self.bits - 1);
        let extended = if self.raw & sign_bit == 0 {
            self.raw
        } else {
            self.raw | !integer_mask(self.bits)
        };
        Some(extended as i128)
    }

    fn shift_count(self) -> Option<u32> {
        if self.signed && self.signed_value()? < 0 {
            return None;
        }
        u32::try_from(self.raw).ok()
    }
}

const fn integer_mask(bits: u16) -> u128 {
    if bits == 128 {
        u128::MAX
    } else {
        (1_u128 << bits) - 1
    }
}

fn integer_from_signed(bits: u16, value: i128) -> Option<ComptimeInteger> {
    if bits == 0 || bits > 128 {
        return None;
    }
    let (minimum, maximum) = if bits == 128 {
        (i128::MIN, i128::MAX)
    } else {
        let magnitude = 1_i128 << u32::from(bits - 1);
        (-magnitude, magnitude - 1)
    };
    (minimum..=maximum)
        .contains(&value)
        .then_some(ComptimeInteger {
            signed: true,
            bits,
            raw: value as u128 & integer_mask(bits),
        })
}

#[derive(Debug)]
struct ComptimeBinding<K> {
    id: K,
    /// `None` is a source-visible moved local. Parameters are immutable reads
    /// in the supported subset and therefore never transition to `None`.
    value: Option<ComptimeValue>,
}

#[derive(Debug)]
struct ComptimeFrame {
    declaration: DeclarationId,
    call_source: Option<Span>,
    parameters: Vec<ComptimeBinding<wrela_hir::ParameterId>>,
    locals: Vec<ComptimeBinding<LocalId>>,
    charged_bytes: u64,
    host_depth: u32,
}

#[derive(Debug)]
enum EvaluationFailure {
    Diagnostic(Box<Diagnostic>),
    Analysis(AnalysisFailure),
}

enum ComptimeCase {
    Result(TestCaseResult),
    Unsupported(Diagnostic),
}

fn evaluate_comptime_test(
    request: &AnalysisRequest<'_>,
    test: &SupportedSourceTest,
    descriptor: TestDescriptor,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ComptimeCase, AnalysisFailure> {
    let mut evaluator = match ImageEvaluator::new(request, is_cancelled) {
        Ok(evaluator) => evaluator,
        Err(AnalysisFailure::ResourceLimit { resource, limit })
            if resource.starts_with("comptime evaluator")
                || resource == "comptime local values" =>
        {
            return Ok(ComptimeCase::Result(TestCaseResult {
                descriptor,
                outcome: TestOutcome::Failed {
                    phase: FailurePhase::Comptime,
                    message: format!("comptime test exceeded {resource} limit {limit}"),
                },
                duration_ns: None,
            }));
        }
        Err(error) => return Err(error),
    };
    match evaluator.evaluate_test(test.declaration) {
        Ok(()) => Ok(ComptimeCase::Result(TestCaseResult {
            descriptor,
            outcome: TestOutcome::Passed,
            duration_ns: None,
        })),
        Err(EvaluationFailure::Diagnostic(diagnostic))
            if diagnostic.code.as_deref() == Some("semantic-comptime-assertion") =>
        {
            Ok(ComptimeCase::Result(TestCaseResult {
                descriptor,
                outcome: TestOutcome::Failed {
                    phase: FailurePhase::Comptime,
                    message: comptime_diagnostic_message(
                        *diagnostic,
                        false,
                        request.limits.test_bytes,
                        is_cancelled,
                    )?,
                },
                duration_ns: None,
            }))
        }
        Err(EvaluationFailure::Diagnostic(diagnostic))
            if diagnostic.code.as_deref() == Some("semantic-comptime-arithmetic")
                || diagnostic.code.as_deref() == Some("semantic-comptime-shift-count")
                || diagnostic.code.as_deref() == Some("semantic-comptime-shift-result-loss")
                || diagnostic.code.as_deref() == Some("semantic-comptime-resource-limit") =>
        {
            let include_code =
                diagnostic.code.as_deref() != Some("semantic-comptime-resource-limit");
            Ok(ComptimeCase::Result(TestCaseResult {
                descriptor,
                outcome: TestOutcome::Failed {
                    phase: FailurePhase::Comptime,
                    message: comptime_diagnostic_message(
                        *diagnostic,
                        include_code,
                        request.limits.test_bytes,
                        is_cancelled,
                    )?,
                },
                duration_ns: None,
            }))
        }
        Err(EvaluationFailure::Diagnostic(diagnostic)) => {
            Ok(ComptimeCase::Unsupported(*diagnostic))
        }
        Err(EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit { resource, limit }))
            if resource.starts_with("comptime evaluator")
                || resource == "comptime local values" =>
        {
            Ok(ComptimeCase::Result(TestCaseResult {
                descriptor,
                outcome: TestOutcome::Failed {
                    phase: FailurePhase::Comptime,
                    message: format!("comptime test exceeded {resource} limit {limit}"),
                },
                duration_ns: None,
            }))
        }
        Err(EvaluationFailure::Analysis(error)) => Err(error),
    }
}

fn comptime_diagnostic_message(
    diagnostic: Diagnostic,
    include_code: bool,
    limit: u64,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<String, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let prefix_bytes = if include_code {
        diagnostic
            .code
            .as_deref()
            .unwrap_or("semantic-comptime-evaluation")
            .len()
            .checked_add(2)
    } else {
        Some(0)
    }
    .ok_or(AnalysisFailure::ResourceLimit {
        resource: "test plan or results",
        limit,
    })?;
    // Three decimal source coordinates plus punctuation fit comfortably in
    // this canonical per-frame reserve on every supported source model.
    let stack_bytes = 64usize
        .checked_add(diagnostic.labels.len().checked_mul(72).ok_or(
            AnalysisFailure::ResourceLimit {
                resource: "test plan or results",
                limit,
            },
        )?)
        .ok_or(AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit,
        })?;
    let total = diagnostic
        .message
        .len()
        .checked_add(prefix_bytes)
        .and_then(|bytes| bytes.checked_add(stack_bytes))
        .ok_or(AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit,
        })?;
    if u64::try_from(total).map_or(true, |bytes| bytes > limit) {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "test plan or results",
            limit,
        });
    }
    let mut message = if include_code {
        let mut message = String::new();
        message
            .try_reserve_exact(total)
            .map_err(|_| AnalysisFailure::ResourceLimit {
                resource: "test plan or results",
                limit,
            })?;
        message.push_str(
            diagnostic
                .code
                .as_deref()
                .unwrap_or("semantic-comptime-evaluation"),
        );
        message.push_str(": ");
        message.push_str(&diagnostic.message);
        message
    } else {
        let mut message = diagnostic.message;
        message
            .try_reserve_exact(stack_bytes)
            .map_err(|_| AnalysisFailure::ResourceLimit {
                resource: "test plan or results",
                limit,
            })?;
        message
    };
    use std::fmt::Write as _;
    let primary = diagnostic.primary;
    write!(
        message,
        " [source {}:{}-{}",
        primary.file.0, primary.range.start, primary.range.end
    )
    .map_err(|_| AnalysisFailure::RequestMismatch)?;
    if !diagnostic.labels.is_empty() {
        message.push_str("; comptime calls");
        for label in &diagnostic.labels {
            check_cancelled(is_cancelled)?;
            write!(
                message,
                " <- {}:{}-{}",
                label.span.file.0, label.span.range.start, label.span.range.end
            )
            .map_err(|_| AnalysisFailure::RequestMismatch)?;
        }
    }
    message.push(']');
    check_cancelled(is_cancelled)?;
    Ok(message)
}

// Canonical evaluator-accounting units.  They deliberately describe the
// abstract evaluator state, not Rust allocation/layout details, so quota
// behavior is identical on every compiler host.
const COMPTIME_FRAME_BYTES: u64 = 64;
const COMPTIME_BINDING_BYTES: u64 = 32;
const COMPTIME_STRUCTURE_BYTES: usize = 32;
const COMPTIME_STRUCTURE_FIELD_BYTES: usize = 32;

fn comptime_structure_payload_bytes(field_count: usize) -> Option<u64> {
    field_count
        .checked_mul(COMPTIME_STRUCTURE_FIELD_BYTES)
        .and_then(|bytes| bytes.checked_add(COMPTIME_STRUCTURE_BYTES))
        .and_then(|bytes| u64::try_from(bytes).ok())
}
const COMPTIME_ACTOR_BYTES: usize = 64;
const COMPTIME_SOURCE_COPY_CHUNK_BYTES: usize = 64;
const COMPTIME_SYNTAX_DEPTH: u32 = 32;
// Each source invocation currently uses a small, fixed chain of Rust frames.
// Keep the language-visible active-call bound below the reviewed host-safe
// envelope until the evaluator moves to an explicit continuation stack.
const COMPTIME_HOST_CALL_DEPTH: u32 = 32;
// Bound the complete retained Rust recursion shape, not just active Wrela
// calls or one callee's local syntax depth in isolation. Flat aggregate values
// added more evaluator state to each host frame, so the reviewed cumulative
// envelope is conservatively capped at 48 for the 1 MiB small-stack proof.
// The independent language-visible active-call cap remains 32.
const COMPTIME_HOST_RECURSION_DEPTH: u32 = 48;

struct ImageEvaluator<'request, 'input> {
    request: &'request AnalysisRequest<'input>,
    program: &'request wrela_hir::Program,
    frames: Vec<ComptimeFrame>,
    steps: u64,
    step_limit: u64,
    retained_bytes: u64,
    peak_bytes: u64,
    byte_limit: u64,
    depth_limit: u32,
    current_source: Span,
    resource_source: Option<Span>,
    attempted_call: Option<(DeclarationId, Span)>,
    is_cancelled: &'request dyn Fn() -> bool,
}

impl<'request, 'input> ImageEvaluator<'request, 'input> {
    fn new(
        request: &'request AnalysisRequest<'input>,
        is_cancelled: &'request dyn Fn() -> bool,
    ) -> Result<Self, AnalysisFailure> {
        let program = request.hir.as_program();
        let byte_limit = request
            .limits
            .evaluator_bytes
            .min(request.build.profile.comptime.memory_bytes);
        Ok(Self {
            request,
            program,
            frames: Vec::new(),
            steps: 0,
            step_limit: request
                .limits
                .evaluator_steps
                .min(request.build.profile.comptime.steps),
            retained_bytes: 0,
            peak_bytes: 0,
            byte_limit,
            depth_limit: request
                .build
                .profile
                .comptime
                .call_depth
                .min(COMPTIME_HOST_CALL_DEPTH),
            current_source: fallback_span(program),
            resource_source: None,
            attempted_call: None,
            is_cancelled,
        })
    }

    fn evaluate(mut self, constructor: DeclarationId) -> Result<EvaluatedImage, EvaluationFailure> {
        let program = self.program;
        let declaration = program.declaration(constructor).ok_or_else(|| {
            self.diagnostic(
                fallback_span(program),
                "semantic-image-constructor-missing",
                "selected image constructor is absent from HIR",
            )
        })?;
        let wrela_hir::DeclarationKind::Function(function) = &declaration.kind else {
            return Err(self.diagnostic(
                declaration.source,
                "semantic-image-constructor-kind",
                "selected image entry is not a function",
            ));
        };
        if function.color != FunctionColor::Sync {
            return Err(self.diagnostic(
                declaration.source,
                "semantic-image-constructor-color",
                "an image constructor must be a plain, phase-neutral function",
            ));
        }
        if function.body.is_none() {
            return Err(self.diagnostic(
                declaration.source,
                "semantic-image-constructor-body",
                "an image constructor must have a body",
            ));
        }
        match self.invoke_function(constructor, Vec::new(), None, 0)? {
            ComptimeValue::Image(image) => Ok(image),
            _ => Err(self.diagnostic(
                declaration.source,
                "semantic-image-result",
                "image constructor did not return a closed Image value",
            )),
        }
    }

    fn evaluate_test(&mut self, test: DeclarationId) -> Result<(), EvaluationFailure> {
        let program = self.program;
        let declaration = program.declaration(test).ok_or_else(|| {
            self.diagnostic(
                fallback_span(program),
                "semantic-test-missing",
                "selected comptime test is absent from HIR",
            )
        })?;
        let wrela_hir::DeclarationKind::Function(function) = &declaration.kind else {
            return Err(self.diagnostic(
                declaration.source,
                "semantic-test-kind",
                "selected comptime test is not a function",
            ));
        };
        if function.color != FunctionColor::Sync {
            return Err(self.diagnostic(
                declaration.source,
                "semantic-test-color",
                "compiler-evaluated tests must be plain, phase-neutral functions",
            ));
        }
        if function.body.is_none() {
            return Err(self.diagnostic(
                declaration.source,
                "semantic-test-body-missing",
                "a comptime test must have a body",
            ));
        }
        let value = match self.invoke_function(test, Vec::new(), None, 0) {
            Ok(value) => value,
            Err(EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                resource,
                limit,
            })) if resource.starts_with("comptime evaluator") => {
                return Err(self.resource_diagnostic(resource, limit));
            }
            Err(error) => return Err(error),
        };
        match value {
            ComptimeValue::Unit => Ok(()),
            _ => Err(self.diagnostic(
                declaration.source,
                "semantic-test-result-not-supported",
                "a comptime test must complete with the unit value",
            )),
        }
    }

    fn execute_body(&mut self, body: BodyId, depth: u32) -> Result<Control, EvaluationFailure> {
        self.enter_syntax(depth)?;
        let program = self.program;
        let body = program.body(body).ok_or_else(|| {
            self.diagnostic(
                fallback_span(program),
                "semantic-comptime-body",
                "comptime body reference is invalid",
            )
        })?;
        for statement_id in &body.statements {
            self.current_source = body.source;
            self.work()?;
            let statement = program.statement(*statement_id).ok_or_else(|| {
                self.diagnostic(
                    body.source,
                    "semantic-comptime-statement",
                    "comptime statement reference is invalid",
                )
            })?;
            self.current_source = statement.source;
            match &statement.kind {
                StatementKind::Initialize { local, value } => {
                    let expected = self.local_value_type(*local);
                    let value = self.evaluate_owned_expression(*value, expected, depth)?;
                    self.store(*local, value, statement.source)?;
                }
                StatementKind::Assign {
                    targets,
                    operator: AssignmentOperator::Assign,
                    value,
                } if targets.len() == 1 && targets[0].projections.is_empty() => {
                    let Definition::Local(local) = targets[0].root else {
                        return Err(self.unsupported(statement.source));
                    };
                    let expected = self.local_value_type(local);
                    let value = self.evaluate_owned_expression(*value, expected, depth)?;
                    self.store(local, value, statement.source)?;
                }
                StatementKind::Assign {
                    targets,
                    operator,
                    value,
                } if targets.len() == 1 && targets[0].projections.is_empty() => {
                    let Definition::Local(local) = targets[0].root else {
                        return Err(self.unsupported(statement.source));
                    };
                    let current = self.load_local(local, statement.source)?;
                    let expected = current.value_type();
                    let right = self.evaluate_expression(*value, expected, depth)?;
                    let binary = compound_assignment_binary_operator(*operator)
                        .ok_or_else(|| self.unsupported(statement.source))?;
                    let value =
                        self.evaluate_binary_values(binary, current, right, statement.source)?;
                    self.store(local, value, statement.source)?;
                }
                StatementKind::Return(value) => {
                    let expected = self.current_result_value_type();
                    let value = match value {
                        Some(value) => self.evaluate_owned_expression(*value, expected, depth)?,
                        None => ComptimeValue::Unit,
                    };
                    return Ok(Control::Return(value));
                }
                StatementKind::Pass => {}
                StatementKind::Expression(expression) => {
                    let value = self.evaluate_expression(*expression, None, depth)?;
                    self.dispose_temporary_value(value, statement.source)?;
                }
                StatementKind::Assert {
                    condition, message, ..
                } => match self.evaluate_expression(*condition, Some(ComptimeType::Bool), depth)? {
                    ComptimeValue::Boolean(true) => {}
                    ComptimeValue::Boolean(false) => {
                        return Err(if let Some(message) = message.as_deref() {
                            let message = self.copy_source_diagnostic_text(message)?;
                            self.diagnostic_owned(
                                statement.source,
                                "semantic-comptime-assertion",
                                message,
                            )
                        } else {
                            self.diagnostic(
                                statement.source,
                                "semantic-comptime-assertion",
                                "comptime assertion failed",
                            )
                        });
                    }
                    _ => return Err(self.unsupported(statement.source)),
                },
                StatementKind::If {
                    branches,
                    else_body,
                } => {
                    let mut selected = None;
                    for (condition, branch) in branches {
                        match self.evaluate_expression(
                            *condition,
                            Some(ComptimeType::Bool),
                            depth,
                        )? {
                            ComptimeValue::Boolean(true) => {
                                selected = Some(*branch);
                                break;
                            }
                            ComptimeValue::Boolean(false) => {}
                            _ => return Err(self.unsupported(statement.source)),
                        }
                    }
                    if let Some(selected) = selected.or(*else_body) {
                        if let Control::Return(value) = self.execute_body(selected, depth + 1)? {
                            return Ok(Control::Return(value));
                        }
                    }
                }
                StatementKind::ComptimeIf {
                    condition,
                    then_body,
                    else_body,
                } => {
                    let selected = match self.evaluate_expression(
                        *condition,
                        Some(ComptimeType::Bool),
                        depth,
                    )? {
                        ComptimeValue::Boolean(true) => Some(*then_body),
                        ComptimeValue::Boolean(false) => *else_body,
                        _ => return Err(self.unsupported(statement.source)),
                    };
                    if let Some(selected) = selected {
                        if let Control::Return(value) = self.execute_body(selected, depth + 1)? {
                            return Ok(Control::Return(value));
                        }
                    }
                }
                StatementKind::Assign { .. }
                | StatementKind::Break
                | StatementKind::Continue
                | StatementKind::Send(_)
                | StatementKind::Yield(_)
                | StatementKind::Match { .. }
                | StatementKind::For { .. }
                | StatementKind::While { .. }
                | StatementKind::Loop { .. }
                | StatementKind::With { .. }
                | StatementKind::Error => return Err(self.unsupported(statement.source)),
            }
        }
        Ok(Control::Continue)
    }

    fn evaluate_expression(
        &mut self,
        id: ExpressionId,
        expected: Option<ComptimeType>,
        depth: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.evaluate_expression_with_access(id, expected, depth, ComptimeExpressionAccess::Read)
    }

    fn evaluate_owned_expression(
        &mut self,
        id: ExpressionId,
        expected: Option<ComptimeType>,
        depth: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.evaluate_expression_with_access(id, expected, depth, ComptimeExpressionAccess::Move)
    }

    fn evaluate_expression_with_access(
        &mut self,
        id: ExpressionId,
        expected: Option<ComptimeType>,
        depth: u32,
        access: ComptimeExpressionAccess,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.enter_syntax(depth)?;
        let program = self.program;
        let expression = program.expression(id).ok_or_else(|| {
            self.diagnostic(
                fallback_span(program),
                "semantic-comptime-expression",
                "comptime expression reference is invalid",
            )
        })?;
        self.current_source = expression.source;
        self.work()?;
        let value = match &expression.kind {
            ExpressionKind::Literal(Literal::String(value)) => {
                if expected.is_some() {
                    return Err(self.type_mismatch(expression.source));
                }
                Ok(ComptimeValue::Text(self.copy_source_text(value)?))
            }
            ExpressionKind::Literal(Literal::Boolean(value)) => Ok(ComptimeValue::Boolean(*value)),
            ExpressionKind::Literal(Literal::Integer(value)) => {
                self.evaluate_integer_literal(value, expected, expression.source)
            }
            ExpressionKind::Literal(Literal::Unit) => Ok(ComptimeValue::Unit),
            ExpressionKind::Reference(Definition::Local(local)) => {
                self.access_local(*local, expression.source, access)
            }
            ExpressionKind::Reference(Definition::Parameter(parameter)) => {
                self.access_parameter(*parameter, expression.source, access)
            }
            ExpressionKind::Reference(Definition::Declaration(declaration)) => {
                if let Some(name) = self.standard_declaration_name(declaration) {
                    return match name {
                        "Image" => Ok(ComptimeValue::ImageConstructor),
                        "Target" => Ok(ComptimeValue::TargetType),
                        _ => Err(self.unsupported(expression.source)),
                    };
                }
                if let Some(kind) = self.actor_class_kind(declaration.declaration) {
                    Ok(ComptimeValue::ActorClass {
                        declaration: declaration.declaration,
                        kind,
                    })
                } else {
                    Err(self.unsupported(expression.source))
                }
            }
            ExpressionKind::Reference(Definition::Variant(variant)) => {
                if self.is_selected_target_variant(variant) {
                    Ok(ComptimeValue::SelectedTarget)
                } else {
                    Err(self.unsupported(expression.source))
                }
            }
            // A resolved leading-dot variant (`.name`) is equivalent to the
            // qualified variant reference above once HIR lowering has
            // narrowed it to one same-spelling candidate: this evaluator has
            // no contextual-enum-type mechanism to disambiguate a genuinely
            // ambiguous candidate set, so only the unambiguous case resolves
            // here and everything else stays the stable unsupported
            // diagnostic.
            ExpressionKind::DotName { candidates, .. } => match candidates.as_slice() {
                [variant] if self.is_selected_target_variant(variant) => {
                    Ok(ComptimeValue::SelectedTarget)
                }
                _ => Err(self.unsupported(expression.source)),
            },
            ExpressionKind::Field { base, name } => {
                let base = self.evaluate_expression(*base, None, depth + 1)?;
                if base == ComptimeValue::TargetType && name.as_str() == "aarch64_qemu_virt_uefi" {
                    Ok(ComptimeValue::SelectedTarget)
                } else {
                    self.evaluate_structure_field(base, name, expression.source)
                }
            }
            ExpressionKind::Call { callee, arguments } => {
                if self.image_supervise_target(*callee).is_some() {
                    Err(self.diagnostic_category(
                        Category::ACTOR,
                        expression.source,
                        "semantic-supervision-policy-pending",
                        "explicit supervision policy requires restart, intensity, and failure-delivery semantics that are not implemented",
                    ))
                } else if let Some((image, install_kind)) = self.image_install_target(*callee) {
                    self.evaluate_image_install(
                        image,
                        install_kind,
                        arguments,
                        expression.source,
                        depth + 1,
                    )
                } else if let Some((actor, class)) =
                    self.actor_handle_target(*callee, expression.source)?
                {
                    if !arguments.is_empty() {
                        Err(self.diagnostic_category(
                            Category::ACTOR,
                            expression.source,
                            "semantic-actor-handle-shape",
                            "an image-wired actor handle takes no runtime arguments",
                        ))
                    } else {
                        Ok(ComptimeValue::ActorHandle { actor, class })
                    }
                } else if let Some(declaration) = self.direct_function_callee(*callee)? {
                    self.evaluate_user_call(declaration, arguments, expression.source, depth + 1)
                } else if let Some(declaration) = self.direct_structure_callee(*callee)? {
                    self.evaluate_structure_constructor(
                        declaration,
                        arguments,
                        expression.source,
                        depth + 1,
                    )
                } else if self.direct_initializer_struct_callee(*callee)?.is_some() {
                    Err(self.diagnostic(
                        expression.source,
                        "semantic-struct-construction-not-supported",
                        "initializer-based construction is not yet supported by semantic analysis",
                    ))
                } else {
                    let callee = self.evaluate_expression(*callee, None, depth + 1)?;
                    if callee != ComptimeValue::ImageConstructor {
                        return Err(self.unsupported(expression.source));
                    }
                    let mut image_name = None;
                    let mut target = None;
                    for argument in arguments {
                        let Some(argument_value) = argument.expression() else {
                            return Err(self.unsupported(argument.source));
                        };
                        let Some(name) = argument.name.as_ref().map(wrela_hir::Name::as_str) else {
                            return Err(self.unsupported(argument.source));
                        };
                        let value_source = self
                            .program
                            .expression(argument_value)
                            .map_or(argument.source, |expression| expression.source);
                        let argument_value =
                            self.evaluate_expression(argument_value, None, depth + 1)?;
                        match (name, argument_value) {
                            ("name", ComptimeValue::Text(value)) if image_name.is_none() => {
                                image_name = Some((value, value_source));
                            }
                            ("target", ComptimeValue::SelectedTarget) if target.is_none() => {
                                target = Some(());
                            }
                            _ => return Err(self.unsupported(argument.source)),
                        }
                    }
                    let (name, name_source) = image_name.ok_or_else(|| {
                        self.diagnostic(
                            expression.source,
                            "semantic-image-name",
                            "Image construction requires one string `name` argument",
                        )
                    })?;
                    if target.is_none() {
                        return Err(self.diagnostic(
                            expression.source,
                            "semantic-image-target",
                            "Image construction requires the selected target",
                        ));
                    }
                    if name.is_empty() || name.len() > 255 || name.chars().any(char::is_control) {
                        return Err(self.diagnostic(
                            expression.source,
                            "semantic-image-name",
                            "runtime image name must contain 1 to 255 non-control UTF-8 bytes",
                        ));
                    }
                    let name_len =
                        u32::try_from(name.len()).map_err(|_| self.evaluator_byte_failure())?;
                    Ok(ComptimeValue::Image(EvaluatedImage {
                        names: name,
                        name_len,
                        name_source,
                        actors: Vec::new(),
                    }))
                }
            }
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::Comptime,
                operand,
            } => self.evaluate_expression_with_access(*operand, expected, depth + 1, access),
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::Copy,
                operand,
            } => self.evaluate_expression_with_access(
                *operand,
                expected,
                depth + 1,
                ComptimeExpressionAccess::Copy,
            ),
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::BoolNot,
                operand,
            } => match self.evaluate_expression(*operand, Some(ComptimeType::Bool), depth + 1)? {
                ComptimeValue::Boolean(value) => Ok(ComptimeValue::Boolean(!value)),
                _ => Err(self.type_mismatch(expression.source)),
            },
            ExpressionKind::Unary {
                operator:
                    operator @ (wrela_hir::UnaryOperator::Negate | wrela_hir::UnaryOperator::BitNot),
                operand,
            } => {
                let operand_type = match expected {
                    Some(expected) => Some(expected),
                    None => self.expression_value_type(*operand, 0)?,
                };
                if *operator == wrela_hir::UnaryOperator::Negate {
                    if let Some(Literal::Integer(spelling)) = self
                        .program
                        .expression(*operand)
                        .and_then(|expression| match &expression.kind {
                            ExpressionKind::Literal(literal) => Some(literal),
                            _ => None,
                        })
                    {
                        let negative_bits = match expected {
                            Some(ComptimeType::Integer { signed: true, bits }) => Some(bits),
                            None => Some(64),
                            _ => None,
                        };
                        if let Some(bits) = negative_bits {
                            self.work()?;
                            return self.evaluate_negative_integer_literal(
                                spelling,
                                bits,
                                expression.source,
                            );
                        }
                    }
                }
                let operand = self.evaluate_expression(*operand, operand_type, depth + 1)?;
                self.evaluate_unary_value(*operator, operand, expression.source)
            }
            ExpressionKind::Binary {
                operator:
                    operator @ (wrela_hir::BinaryOperator::LogicalAnd
                    | wrela_hir::BinaryOperator::LogicalOr),
                left,
                right,
            } => {
                let left = self.evaluate_expression(*left, Some(ComptimeType::Bool), depth + 1)?;
                let ComptimeValue::Boolean(left) = left else {
                    return Err(self.type_mismatch(expression.source));
                };
                if (*operator == wrela_hir::BinaryOperator::LogicalAnd && !left)
                    || (*operator == wrela_hir::BinaryOperator::LogicalOr && left)
                {
                    Ok(ComptimeValue::Boolean(left))
                } else {
                    match self.evaluate_expression(*right, Some(ComptimeType::Bool), depth + 1)? {
                        ComptimeValue::Boolean(right) => Ok(ComptimeValue::Boolean(right)),
                        _ => Err(self.type_mismatch(expression.source)),
                    }
                }
            }
            ExpressionKind::Binary {
                operator,
                left,
                right,
            } => {
                let operand_type = match expected {
                    Some(expected) => Some(expected),
                    None => match self.expression_value_type(*left, 0)? {
                        Some(left) => Some(left),
                        None => self.expression_value_type(*right, 0)?,
                    },
                };
                let left = self.evaluate_expression(*left, operand_type, depth + 1)?;
                let right_type = left.value_type().or(operand_type);
                let right = self.evaluate_expression(*right, right_type, depth + 1)?;
                if let (Some(desugar), ComptimeValue::Structure { .. }) = (
                    crate::interfaces::DesugarOperator::from_binary(*operator),
                    &left,
                ) {
                    self.evaluate_operator_interface_binary(
                        desugar,
                        left,
                        right,
                        expression.source,
                        depth + 1,
                    )
                } else {
                    self.evaluate_binary_values(*operator, left, right, expression.source)
                }
            }
            ExpressionKind::Compare {
                left,
                operator,
                right,
            } if !matches!(
                operator,
                wrela_hir::ComparisonOperator::In | wrela_hir::ComparisonOperator::NotIn
            ) =>
            {
                let operand_type = match self.expression_value_type(*left, 0)? {
                    Some(left) => Some(left),
                    None => self.expression_value_type(*right, 0)?,
                };
                let left = self.evaluate_expression(*left, operand_type, depth + 1)?;
                let right_type = left.value_type().or(operand_type);
                let right = self.evaluate_expression(*right, right_type, depth + 1)?;
                if let (Some(desugar), ComptimeValue::Structure { .. }) = (
                    crate::interfaces::DesugarOperator::from_comparison(*operator),
                    &left,
                ) {
                    self.evaluate_operator_interface_binary(
                        desugar,
                        left,
                        right,
                        expression.source,
                        depth + 1,
                    )
                } else {
                    self.evaluate_comparison(*operator, left, right, expression.source)
                }
            }
            ExpressionKind::If {
                condition,
                then_branch,
                elif_branches,
                else_branch,
            } => {
                let condition =
                    self.evaluate_expression(*condition, Some(ComptimeType::Bool), depth + 1)?;
                let ComptimeValue::Boolean(condition) = condition else {
                    return Err(self.type_mismatch(expression.source));
                };
                if condition {
                    self.evaluate_expression(*then_branch, expected, depth + 1)
                } else {
                    for (elif_condition, elif_branch) in elif_branches {
                        let elif_condition = self.evaluate_expression(
                            *elif_condition,
                            Some(ComptimeType::Bool),
                            depth + 1,
                        )?;
                        let ComptimeValue::Boolean(elif_condition) = elif_condition else {
                            return Err(self.type_mismatch(expression.source));
                        };
                        if elif_condition {
                            return self.evaluate_expression(*elif_branch, expected, depth + 1);
                        }
                    }
                    self.evaluate_expression(*else_branch, expected, depth + 1)
                }
            }
            ExpressionKind::Literal(_)
            | ExpressionKind::Reference(_)
            | ExpressionKind::Closure { .. }
            | ExpressionKind::Unary { .. }
            | ExpressionKind::Compare { .. }
            | ExpressionKind::IsPattern { .. }
            | ExpressionKind::Range { .. }
            | ExpressionKind::Cast { .. }
            | ExpressionKind::Try(_)
            | ExpressionKind::Index { .. }
            | ExpressionKind::Tuple(_)
            | ExpressionKind::Array(_)
            | ExpressionKind::TrySend(_)
            | ExpressionKind::Interpolate(_)
            | ExpressionKind::Error => Err(self.unsupported(expression.source)),
        }?;
        self.require_expected(value, expected, expression.source)
    }

    fn direct_declaration_callee(
        &self,
        callee: ExpressionId,
    ) -> Result<Option<DeclarationId>, EvaluationFailure> {
        let Some(ExpressionKind::Reference(Definition::Declaration(resolved))) =
            self.program.expression(callee).map(|value| &value.kind)
        else {
            return Ok(None);
        };
        let declaration = self
            .program
            .declaration(resolved.declaration)
            .ok_or_else(|| {
                self.diagnostic(
                    fallback_span(self.program),
                    "semantic-comptime-call-target",
                    "comptime call target is missing from HIR",
                )
            })?;
        let module = self
            .program
            .modules
            .get(declaration.module.0 as usize)
            .filter(|module| {
                module.id == resolved.module
                    && module.package == resolved.package
                    && declaration.module == resolved.module
            })
            .ok_or_else(|| {
                self.diagnostic(
                    declaration.source,
                    "semantic-comptime-call-target",
                    "resolved comptime call target identity does not match its declaration",
                )
            })?;
        let _ = module;
        Ok(Some(resolved.declaration))
    }

    fn direct_function_callee(
        &self,
        callee: ExpressionId,
    ) -> Result<Option<DeclarationId>, EvaluationFailure> {
        let Some(declaration) = self.direct_declaration_callee(callee)? else {
            return Ok(None);
        };
        Ok(self
            .program
            .declaration(declaration)
            .is_some_and(|record| matches!(&record.kind, DeclarationKind::Function(_)))
            .then_some(declaration))
    }

    fn direct_structure_callee(
        &self,
        callee: ExpressionId,
    ) -> Result<Option<DeclarationId>, EvaluationFailure> {
        let Some(declaration) = self.direct_declaration_callee(callee)? else {
            return Ok(None);
        };
        let is_standard_image = self
            .program
            .declaration(declaration)
            .and_then(|record| {
                self.program
                    .modules
                    .get(record.module.0 as usize)
                    .map(|module| (record, module))
            })
            .is_some_and(|(record, module)| {
                module.package == self.request.standard_library_package
                    && record.name.as_ref().map(wrela_hir::Name::as_str) == Some("Image")
            });
        Ok(self
            .program
            .declaration(declaration)
            .is_some_and(|record| {
                !is_standard_image
                    && matches!(&record.kind, DeclarationKind::Structure(_))
                    && !self.aggregate_has_initializer(declaration)
            })
            .then_some(declaration))
    }

    fn aggregate_has_initializer(&self, declaration: DeclarationId) -> bool {
        aggregate_has_initializer(self.program, declaration)
    }

    fn direct_initializer_struct_callee(
        &self,
        callee: ExpressionId,
    ) -> Result<Option<DeclarationId>, EvaluationFailure> {
        let Some(declaration) = self.direct_declaration_callee(callee)? else {
            return Ok(None);
        };
        Ok(self
            .aggregate_has_initializer(declaration)
            .then_some(declaration))
    }

    fn evaluate_structure_constructor(
        &mut self,
        declaration: DeclarationId,
        arguments: &[wrela_hir::CallArgument],
        source: Span,
        depth: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.enter_syntax(depth)?;
        let program = self.program;
        let record = program
            .declaration(declaration)
            .ok_or_else(|| self.unsupported(source))?;
        if !self.check_flat_scalar_structure(declaration)? {
            return Err(self.aggregate_not_supported(record.source));
        }
        let DeclarationKind::Structure(aggregate) = &record.kind else {
            return Err(self.aggregate_not_supported(record.source));
        };
        if arguments.len() != aggregate.fields.len() {
            return Err(self.diagnostic(
                source,
                "semantic-comptime-constructor-argument",
                "comptime structure construction must supply every field exactly once",
            ));
        }
        let caller_module = self
            .frames
            .last()
            .and_then(|frame| program.declaration(frame.declaration))
            .map(|caller| caller.module)
            .ok_or_else(|| self.unsupported(source))?;
        let field_count = aggregate.fields.len();
        let payload = field_count
            .checked_mul(COMPTIME_STRUCTURE_FIELD_BYTES)
            .and_then(|bytes| bytes.checked_add(COMPTIME_STRUCTURE_BYTES))
            .ok_or_else(|| self.evaluator_byte_failure())?;
        self.retain(payload)?;
        let scratch_bytes = u64::try_from(field_count)
            .ok()
            .and_then(|count| count.checked_mul(COMPTIME_STRUCTURE_FIELD_BYTES as u64))
            .and_then(|bytes| bytes.checked_mul(2))
            .ok_or_else(|| self.evaluator_byte_failure())?;
        self.retain_u64(scratch_bytes)?;

        let mut resolved = Vec::new();
        resolved
            .try_reserve_exact(field_count)
            .map_err(|_| self.evaluator_byte_failure())?;
        for _ in 0..field_count {
            self.work()?;
            resolved.push(None);
        }
        for (source_index, argument) in arguments.iter().enumerate() {
            self.work()?;
            let Some(argument_value) = argument.expression() else {
                return Err(self.aggregate_not_supported(argument.source));
            };
            if field_count != 1 && argument.name.is_none() {
                return Err(self.diagnostic(
                    argument.source,
                    "semantic-comptime-constructor-argument",
                    "a comptime structure with more than one field requires every constructor argument to be named",
                ));
            }
            let field_index = if let Some(argument_name) = &argument.name {
                let mut selected = None;
                for (index, field) in aggregate.fields.iter().enumerate() {
                    self.work()?;
                    if self.comptime_names_equal(field.name.as_str(), argument_name.as_str())?
                        && selected.replace(index).is_some()
                    {
                        return Err(self.diagnostic(
                            argument.source,
                            "semantic-comptime-constructor-argument",
                            "comptime structure field name is ambiguous",
                        ));
                    }
                }
                selected.ok_or_else(|| {
                    self.diagnostic(
                        argument.source,
                        "semantic-comptime-constructor-argument",
                        "comptime constructor argument does not name a declared field",
                    )
                })?
            } else {
                source_index
            };
            let field = aggregate.fields.get(field_index).ok_or_else(|| {
                self.diagnostic(
                    argument.source,
                    "semantic-comptime-constructor-argument",
                    "comptime constructor supplies too many positional fields",
                )
            })?;
            self.require_structure_field_visible(
                field,
                caller_module == record.module,
                argument.source,
            )?;
            let expected = self
                .source_scalar_type_only(&field.ty)
                .ok_or_else(|| self.aggregate_not_supported(field.ty.source))?;
            let value = self.evaluate_expression(argument_value, Some(expected), depth + 1)?;
            let value = ComptimeScalar::from_value(value)
                .ok_or_else(|| self.type_mismatch(argument.source))?;
            let slot = resolved
                .get_mut(field_index)
                .ok_or_else(|| self.unsupported(argument.source))?;
            if slot.replace(value).is_some() {
                return Err(self.diagnostic(
                    argument.source,
                    "semantic-comptime-constructor-argument",
                    "comptime constructor supplies one field more than once",
                ));
            }
        }
        let mut fields = Vec::new();
        fields
            .try_reserve_exact(field_count)
            .map_err(|_| self.evaluator_byte_failure())?;
        for field in resolved {
            self.work()?;
            fields.push(field.ok_or_else(|| {
                self.diagnostic(
                    source,
                    "semantic-comptime-constructor-argument",
                    "comptime structure construction must supply every field exactly once",
                )
            })?);
        }
        self.release(scratch_bytes)?;
        Ok(ComptimeValue::Structure {
            declaration,
            fields,
        })
    }

    fn evaluate_structure_field(
        &mut self,
        base: ComptimeValue,
        name: &wrela_hir::Name,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let ComptimeValue::Structure {
            declaration,
            fields,
        } = base
        else {
            return Err(self.unsupported(source));
        };
        let program = self.program;
        let record = program
            .declaration(declaration)
            .ok_or_else(|| self.unsupported(source))?;
        if !self.check_flat_scalar_structure(declaration)? {
            return Err(self.aggregate_not_supported(record.source));
        }
        let DeclarationKind::Structure(aggregate) = &record.kind else {
            return Err(self.aggregate_not_supported(record.source));
        };
        if fields.len() != aggregate.fields.len() {
            return Err(self.aggregate_not_supported(source));
        }
        let caller_module = self
            .frames
            .last()
            .and_then(|frame| program.declaration(frame.declaration))
            .map(|caller| caller.module)
            .ok_or_else(|| self.unsupported(source))?;
        let mut selected = None;
        for (index, field) in aggregate.fields.iter().enumerate() {
            self.work()?;
            if self.comptime_names_equal(field.name.as_str(), name.as_str())?
                && selected.replace(index).is_some()
            {
                return Err(self.diagnostic(
                    source,
                    "semantic-comptime-field",
                    "comptime structure field name is ambiguous",
                ));
            }
        }
        let index = selected.ok_or_else(|| {
            self.diagnostic(
                source,
                "semantic-comptime-field",
                "comptime structure does not declare the selected field",
            )
        })?;
        let field = aggregate
            .fields
            .get(index)
            .ok_or_else(|| self.unsupported(source))?;
        self.require_structure_field_visible(field, caller_module == record.module, source)?;
        let expected = self
            .source_scalar_type_only(&field.ty)
            .ok_or_else(|| self.aggregate_not_supported(field.ty.source))?;
        let payload = u64::try_from(
            fields
                .len()
                .checked_mul(COMPTIME_STRUCTURE_FIELD_BYTES)
                .and_then(|bytes| bytes.checked_add(COMPTIME_STRUCTURE_BYTES))
                .ok_or_else(|| self.evaluator_byte_failure())?,
        )
        .map_err(|_| self.evaluator_byte_failure())?;
        let mut selected_value = None;
        for (field_index, value) in fields.iter().enumerate() {
            self.work()?;
            if field_index == index {
                selected_value = Some(*value);
            }
        }
        let value = selected_value.ok_or_else(|| self.aggregate_not_supported(source))?;
        drop(fields);
        self.release(payload)?;
        self.require_expected(value.into_value(), Some(expected), source)
    }

    fn evaluate_user_call(
        &mut self,
        declaration: DeclarationId,
        arguments: &[wrela_hir::CallArgument],
        source: Span,
        depth: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.enter_syntax(depth)?;
        let program = self.program;
        let declaration_record = program
            .declaration(declaration)
            .ok_or_else(|| self.unsupported(source))?;
        let DeclarationKind::Function(function) = &declaration_record.kind else {
            return Err(self.unsupported(source));
        };
        if function.color != FunctionColor::Sync
            || !function.generics.is_empty()
            || function.body.is_none()
            || arguments.len() != function.parameters.len()
        {
            return Err(self.unsupported(source));
        }
        if let Some(result) = function.result.as_ref() {
            if self
                .validated_source_value_type(result, result.source)?
                .is_none()
            {
                return Err(self.unsupported(source));
            }
        }

        let scratch_bytes = u64::try_from(function.parameters.len())
            .ok()
            .and_then(|count| count.checked_mul(COMPTIME_BINDING_BYTES))
            .and_then(|bytes| bytes.checked_mul(2))
            .ok_or_else(|| self.evaluator_byte_failure())?;
        self.retain_u64(scratch_bytes)?;

        let mut resolved = Vec::new();
        resolved
            .try_reserve_exact(function.parameters.len())
            .map_err(|_| self.evaluator_byte_failure())?;
        for _ in &function.parameters {
            self.work()?;
            resolved.push(None);
        }
        let mut non_receiver_count = 0usize;
        for parameter_id in &function.parameters {
            self.work()?;
            let parameter = self
                .program
                .parameters
                .get(parameter_id.0 as usize)
                .filter(|parameter| parameter.id == *parameter_id)
                .ok_or_else(|| self.unsupported(source))?;
            if !parameter.receiver {
                non_receiver_count = non_receiver_count
                    .checked_add(1)
                    .ok_or_else(|| self.evaluator_byte_failure())?;
            }
        }
        for argument in arguments.iter() {
            self.work()?;
            let parameter_index = if let Some(argument_name) = &argument.name {
                let mut selected = None;
                for (index, parameter_id) in function.parameters.iter().enumerate() {
                    self.work()?;
                    let parameter = self
                        .program
                        .parameters
                        .get(parameter_id.0 as usize)
                        .filter(|parameter| parameter.id == *parameter_id)
                        .ok_or_else(|| self.unsupported(argument.source))?;
                    if let Some(parameter_name) = &parameter.name {
                        if self
                            .comptime_names_equal(parameter_name.as_str(), argument_name.as_str())?
                            && selected.replace(index).is_some()
                        {
                            return Err(self.unsupported(argument.source));
                        }
                    }
                }
                let parameter_index = selected.ok_or_else(|| {
                    self.diagnostic(
                        argument.source,
                        "semantic-argument-unknown-label",
                        "call argument label does not name a declared parameter",
                    )
                })?;
                let parameter_id = function.parameters[parameter_index];
                let parameter = self
                    .program
                    .parameters
                    .get(parameter_id.0 as usize)
                    .ok_or_else(|| self.unsupported(argument.source))?;
                if parameter_is_effectively_positional(parameter, non_receiver_count) {
                    return Err(self.diagnostic(
                        argument.source,
                        "semantic-argument-label-forbidden",
                        "this parameter is positional-only and must not be labeled",
                    ));
                }
                parameter_index
            } else {
                let mut found = None;
                for (index, parameter_id) in function.parameters.iter().enumerate() {
                    self.work()?;
                    if resolved.get(index).is_some_and(Option::is_some) {
                        continue;
                    }
                    let parameter = self
                        .program
                        .parameters
                        .get(parameter_id.0 as usize)
                        .filter(|parameter| parameter.id == *parameter_id)
                        .ok_or_else(|| self.unsupported(argument.source))?;
                    if parameter.receiver
                        || !parameter_is_effectively_positional(parameter, non_receiver_count)
                    {
                        continue;
                    }
                    found = Some(index);
                    break;
                }
                found.ok_or_else(|| {
                    self.diagnostic(
                        argument.source,
                        "semantic-argument-label-required",
                        "this call needs a labeled argument for a remaining parameter",
                    )
                })?
            };
            let parameter_id = *function
                .parameters
                .get(parameter_index)
                .ok_or_else(|| self.unsupported(argument.source))?;
            let parameter = self
                .program
                .parameters
                .get(parameter_id.0 as usize)
                .filter(|parameter| {
                    parameter.id == parameter_id
                        && parameter.owner == wrela_hir::CallableOwner::Declaration(declaration)
                        && !parameter.receiver
                })
                .ok_or_else(|| self.unsupported(argument.source))?;
            if parameter.access != wrela_hir::AccessMode::Value
                || argument.access() != wrela_hir::AccessMode::Value
            {
                return Err(self.unsupported(argument.source));
            }
            let Some(argument_value) = argument.expression() else {
                return Err(self.unsupported(argument.source));
            };
            let parameter_type = match parameter.ty.as_ref() {
                Some(ty) => self.validated_source_value_type(ty, parameter.source)?,
                None => None,
            }
            .ok_or_else(|| self.unsupported(parameter.source))?;
            let value =
                self.evaluate_expression(argument_value, Some(parameter_type), depth + 1)?;
            let slot = resolved
                .get_mut(parameter_index)
                .ok_or_else(|| self.unsupported(argument.source))?;
            if slot.replace((parameter_id, value)).is_some() {
                return Err(self.diagnostic(
                    argument.source,
                    "semantic-comptime-call-argument",
                    "comptime call supplies one parameter more than once",
                ));
            }
        }
        let mut ordered = Vec::new();
        ordered
            .try_reserve_exact(resolved.len())
            .map_err(|_| self.evaluator_byte_failure())?;
        for argument in resolved {
            self.work()?;
            ordered.push(argument.ok_or_else(|| {
                self.diagnostic(
                    source,
                    "semantic-comptime-call-argument",
                    "comptime call does not supply every parameter",
                )
            })?);
        }
        self.release(scratch_bytes)?;
        self.invoke_function(declaration, ordered, Some(source), depth)
    }

    fn invoke_function(
        &mut self,
        declaration: DeclarationId,
        parameters: Vec<(wrela_hir::ParameterId, ComptimeValue)>,
        call_source: Option<Span>,
        syntax_contribution: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.attempted_call = call_source.map(|source| (declaration, source));
        self.current_source = call_source.unwrap_or_else(|| {
            self.program
                .declaration(declaration)
                .map_or_else(|| fallback_span(self.program), |value| value.source)
        });
        self.work()?;
        let active_depth = u32::try_from(self.frames.len())
            .ok()
            .and_then(|depth| depth.checked_add(1))
            .ok_or_else(|| self.call_depth_failure())?;
        if active_depth > self.depth_limit {
            self.resource_source = Some(self.current_source);
            self.attempted_call = call_source.map(|source| (declaration, source));
            return Err(self.call_depth_failure());
        }
        let parent_host_depth = self.frames.last().map_or(0, |frame| frame.host_depth);
        let host_increment = if self.frames.is_empty() {
            1
        } else {
            // Active calls already consume one independently bounded language
            // frame. Charge the additional retained syntax above that base so
            // 32 shallow calls remain admissible while deeply wrapped calls
            // share the conservative cumulative host envelope.
            syntax_contribution.saturating_sub(1).max(1)
        };
        let host_depth = parent_host_depth
            .checked_add(host_increment)
            .ok_or_else(|| self.host_recursion_failure())?;
        if host_depth > COMPTIME_HOST_RECURSION_DEPTH {
            self.resource_source = Some(self.current_source);
            self.attempted_call = call_source.map(|source| (declaration, source));
            return Err(self.host_recursion_failure());
        }
        let program = self.program;
        let declaration_record = program.declaration(declaration).ok_or_else(|| {
            self.unsupported(call_source.unwrap_or_else(|| fallback_span(program)))
        })?;
        let DeclarationKind::Function(function) = &declaration_record.kind else {
            return Err(self.unsupported(declaration_record.source));
        };
        if function.color != FunctionColor::Sync || !function.generics.is_empty() {
            return Err(self.unsupported(declaration_record.source));
        }
        let body = function
            .body
            .ok_or_else(|| self.unsupported(declaration_record.source))?;
        let mut parameter_mismatch = parameters.len() != function.parameters.len();
        if !parameter_mismatch {
            for (expected, (actual, _)) in function.parameters.iter().zip(&parameters) {
                self.work()?;
                if expected != actual {
                    parameter_mismatch = true;
                    break;
                }
            }
        }
        if parameter_mismatch {
            return Err(self.diagnostic(
                call_source.unwrap_or(declaration_record.source),
                "semantic-comptime-call-argument",
                "comptime invocation arguments do not match the function declaration",
            ));
        }
        let parameter_count =
            u64::try_from(parameters.len()).map_err(|_| self.evaluator_byte_failure())?;
        let charged_bytes = COMPTIME_FRAME_BYTES
            .checked_add(
                parameter_count
                    .checked_mul(COMPTIME_BINDING_BYTES)
                    .ok_or_else(|| self.evaluator_byte_failure())?,
            )
            .ok_or_else(|| self.evaluator_byte_failure())?;
        self.retain_u64(charged_bytes)?;
        let mut frame_parameters = Vec::new();
        frame_parameters
            .try_reserve_exact(parameters.len())
            .map_err(|_| self.evaluator_byte_failure())?;
        for (id, value) in parameters {
            self.work()?;
            frame_parameters.push(ComptimeBinding {
                id,
                value: Some(value),
            });
        }
        self.frames
            .try_reserve(1)
            .map_err(|_| self.evaluator_byte_failure())?;
        self.frames.push(ComptimeFrame {
            declaration,
            call_source,
            parameters: frame_parameters,
            locals: Vec::new(),
            charged_bytes,
            host_depth,
        });
        // The callee now has an ordinary frame, so stack construction must no
        // longer synthesize the pre-push attempted-call entry.
        self.attempted_call = None;

        let expected = match function.result.as_ref() {
            Some(result) => self.validated_source_value_type(result, result.source)?,
            None => Some(ComptimeType::Unit),
        };
        let execution = self.execute_body(body, 1);
        let result = match execution {
            Ok(Control::Return(value)) => self.require_expected(
                value,
                expected,
                call_source.unwrap_or(declaration_record.source),
            ),
            Ok(Control::Continue) if expected == Some(ComptimeType::Unit) => {
                Ok(ComptimeValue::Unit)
            }
            Ok(Control::Continue) => Err(self.diagnostic(
                declaration_record.source,
                "semantic-comptime-missing-return",
                "comptime function completed without returning its declared result",
            )),
            Err(error) => Err(error),
        };
        if result.is_ok() {
            let released_payload = self.poll_successful_frame_cleanup()?;
            let frame = self.frames.pop().expect("comptime frame was just pushed");
            let released_bytes = frame
                .charged_bytes
                .checked_add(released_payload)
                .ok_or_else(|| self.evaluator_byte_failure())?;
            self.release(released_bytes)?;
        }
        result
    }

    fn scan_integer_spelling(
        &mut self,
        spelling: &str,
        source: Span,
    ) -> Result<Option<u128>, EvaluationFailure> {
        let (radix, prefix_bytes) = if spelling.starts_with("0x") {
            (16_u128, 2)
        } else if spelling.starts_with("0o") {
            (8_u128, 2)
        } else if spelling.starts_with("0b") {
            (2_u128, 2)
        } else {
            (10_u128, 0)
        };
        let mut result = 0_u128;
        for (index, byte) in spelling.bytes().enumerate() {
            self.current_source = source;
            self.work()?;
            if index < prefix_bytes || byte == b'_' {
                continue;
            }
            let digit = match byte {
                b'0'..=b'9' => u128::from(byte - b'0'),
                b'a'..=b'f' => u128::from(byte - b'a' + 10),
                b'A'..=b'F' => u128::from(byte - b'A' + 10),
                _ => return Ok(None),
            };
            if digit >= radix {
                return Ok(None);
            }
            let Some(next) = result
                .checked_mul(radix)
                .and_then(|value| value.checked_add(digit))
            else {
                return Ok(None);
            };
            result = next;
        }
        Ok(Some(result))
    }

    fn comptime_names_equal(&mut self, left: &str, right: &str) -> Result<bool, EvaluationFailure> {
        self.work()?;
        if left.len() != right.len() {
            return Ok(false);
        }
        for (left, right) in left.bytes().zip(right.bytes()) {
            self.work()?;
            if left != right {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn copy_source_text(&mut self, value: &str) -> Result<String, EvaluationFailure> {
        self.retain(value.len())?;
        self.copy_precharged_text(value)
    }

    fn copy_precharged_text(&mut self, value: &str) -> Result<String, EvaluationFailure> {
        let mut output = String::new();
        output
            .try_reserve_exact(value.len())
            .map_err(|_| self.evaluator_byte_failure())?;
        let mut start = 0;
        while start < value.len() {
            self.work()?;
            let mut end = start
                .checked_add(COMPTIME_SOURCE_COPY_CHUNK_BYTES)
                .unwrap_or(value.len())
                .min(value.len());
            while end > start && !value.is_char_boundary(end) {
                end -= 1;
            }
            if end == start {
                return Err(self.type_mismatch(self.current_source));
            }
            output.push_str(&value[start..end]);
            start = end;
        }
        Ok(output)
    }

    fn copy_comptime_value(
        &mut self,
        value: &ComptimeValue,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let payload = match value {
            ComptimeValue::Text(value) => value.len(),
            ComptimeValue::Structure { fields, .. } => {
                for _field in fields {
                    self.work()?;
                }
                fields
                    .len()
                    .checked_mul(COMPTIME_STRUCTURE_FIELD_BYTES)
                    .and_then(|bytes| bytes.checked_add(COMPTIME_STRUCTURE_BYTES))
                    .ok_or_else(|| self.evaluator_byte_failure())?
            }
            ComptimeValue::Image(value) => {
                value.name().ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
                let mut bytes = value.names.len();
                for actor in &value.actors {
                    self.work()?;
                    value.actor_name(*actor).ok_or(EvaluationFailure::Analysis(
                        AnalysisFailure::RequestMismatch,
                    ))?;
                    bytes = bytes
                        .checked_add(COMPTIME_ACTOR_BYTES)
                        .ok_or_else(|| self.evaluator_byte_failure())?;
                }
                bytes
            }
            ComptimeValue::Boolean(_)
            | ComptimeValue::Integer(_)
            | ComptimeValue::SelectedTarget
            | ComptimeValue::TargetType
            | ComptimeValue::ImageConstructor
            | ComptimeValue::ActorClass { .. }
            | ComptimeValue::InstalledActor { .. }
            | ComptimeValue::ActorHandle { .. }
            | ComptimeValue::Unit => 0,
        };
        self.retain(payload)?;
        Ok(match value {
            ComptimeValue::Text(value) => ComptimeValue::Text(self.copy_precharged_text(value)?),
            ComptimeValue::Image(value) => {
                let mut actors = Vec::new();
                actors
                    .try_reserve_exact(value.actors.len())
                    .map_err(|_| self.evaluator_byte_failure())?;
                for actor in &value.actors {
                    self.work()?;
                    actors.push(*actor);
                }
                ComptimeValue::Image(EvaluatedImage {
                    names: self.copy_precharged_text(&value.names)?,
                    name_len: value.name_len,
                    name_source: value.name_source,
                    actors,
                })
            }
            ComptimeValue::Structure {
                declaration,
                fields,
            } => {
                let mut copied = Vec::new();
                copied
                    .try_reserve_exact(fields.len())
                    .map_err(|_| self.evaluator_byte_failure())?;
                for field in fields {
                    self.work()?;
                    copied.push(*field);
                }
                ComptimeValue::Structure {
                    declaration: *declaration,
                    fields: copied,
                }
            }
            ComptimeValue::Boolean(value) => ComptimeValue::Boolean(*value),
            ComptimeValue::Integer(value) => ComptimeValue::Integer(*value),
            ComptimeValue::SelectedTarget => ComptimeValue::SelectedTarget,
            ComptimeValue::TargetType => ComptimeValue::TargetType,
            ComptimeValue::ImageConstructor => ComptimeValue::ImageConstructor,
            ComptimeValue::ActorClass { declaration, kind } => ComptimeValue::ActorClass {
                declaration: *declaration,
                kind: *kind,
            },
            ComptimeValue::InstalledActor { actor, class } => ComptimeValue::InstalledActor {
                actor: *actor,
                class: *class,
            },
            ComptimeValue::ActorHandle { actor, class } => ComptimeValue::ActorHandle {
                actor: *actor,
                class: *class,
            },
            ComptimeValue::Unit => ComptimeValue::Unit,
        })
    }

    fn copy_source_diagnostic_text(&mut self, value: &str) -> Result<String, EvaluationFailure> {
        let bytes = u64::try_from(value.len()).map_err(|_| {
            EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                resource: "diagnostic bytes",
                limit: self.request.limits.diagnostic_bytes,
            })
        })?;
        if bytes > self.request.limits.diagnostic_bytes {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "diagnostic bytes",
                    limit: self.request.limits.diagnostic_bytes,
                },
            ));
        }
        if bytes > self.request.limits.test_bytes {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "test plan or results",
                    limit: self.request.limits.test_bytes,
                },
            ));
        }
        self.copy_source_text(value)
    }

    fn evaluate_integer_literal(
        &mut self,
        spelling: &str,
        expected: Option<ComptimeType>,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let raw = self
            .scan_integer_spelling(spelling, source)?
            .ok_or_else(|| self.type_mismatch(source))?;
        let (signed, bits) = match expected {
            Some(ComptimeType::Integer { signed, bits }) => (signed, bits),
            Some(ComptimeType::Bool | ComptimeType::Unit | ComptimeType::Structure(_)) => {
                return Err(self.type_mismatch(source));
            }
            None if raw <= i64::MAX as u128 => (true, 64),
            None if raw <= u64::MAX as u128 => (false, 64),
            None => {
                return Err(self.diagnostic(
                    source,
                    "semantic-comptime-integer-literal",
                    "unconstrained integer literal exceeds the u64 default domain",
                ));
            }
        };
        let fits = if signed {
            raw <= integer_mask(bits) >> 1
        } else {
            raw <= integer_mask(bits)
        };
        if !fits {
            return Err(self.diagnostic(
                source,
                "semantic-comptime-integer-literal",
                "integer literal does not fit its target scalar type",
            ));
        }
        Ok(ComptimeValue::Integer(
            ComptimeInteger::new(signed, bits, raw).ok_or_else(|| self.type_mismatch(source))?,
        ))
    }

    fn evaluate_negative_integer_literal(
        &mut self,
        spelling: &str,
        bits: u16,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let magnitude = self
            .scan_integer_spelling(spelling, source)?
            .ok_or_else(|| self.type_mismatch(source))?;
        let maximum_magnitude = 1_u128 << u32::from(bits - 1);
        if magnitude > maximum_magnitude {
            return Err(self.diagnostic(
                source,
                "semantic-comptime-integer-literal",
                "negative integer literal does not fit its target scalar type",
            ));
        }
        let value = if bits == 128 && magnitude == maximum_magnitude {
            i128::MIN
        } else {
            -i128::try_from(magnitude).map_err(|_| self.type_mismatch(source))?
        };
        Ok(ComptimeValue::Integer(
            integer_from_signed(bits, value).ok_or_else(|| self.type_mismatch(source))?,
        ))
    }

    fn evaluate_unary_value(
        &self,
        operator: wrela_hir::UnaryOperator,
        operand: ComptimeValue,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let ComptimeValue::Integer(value) = operand else {
            return Err(self.type_mismatch(source));
        };
        let result = match operator {
            wrela_hir::UnaryOperator::Negate if value.signed => {
                let signed = value
                    .signed_value()
                    .ok_or_else(|| self.type_mismatch(source))?;
                let negated = signed.checked_neg().ok_or_else(|| {
                    self.arithmetic_failure(source, "comptime integer negation overflow")
                })?;
                integer_from_signed(value.bits, negated).ok_or_else(|| {
                    self.arithmetic_failure(source, "comptime integer negation overflow")
                })?
            }
            wrela_hir::UnaryOperator::BitNot => ComptimeInteger {
                raw: !value.raw & integer_mask(value.bits),
                ..value
            },
            _ => return Err(self.unsupported(source)),
        };
        Ok(ComptimeValue::Integer(result))
    }

    fn evaluate_binary_values(
        &self,
        operator: wrela_hir::BinaryOperator,
        left: ComptimeValue,
        right: ComptimeValue,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let (ComptimeValue::Integer(left), ComptimeValue::Integer(right)) = (left, right) else {
            return Err(self.type_mismatch(source));
        };
        if left.scalar_type() != right.scalar_type() {
            return Err(self.type_mismatch(source));
        }
        let mask = integer_mask(left.bits);
        let overflow = || self.arithmetic_failure(source, "comptime integer arithmetic overflow");
        let divide_by_zero =
            || self.arithmetic_failure(source, "comptime integer division by zero");
        let invalid_shift = || self.shift_count_failure(source);
        let lost_shift_result = || self.shift_result_loss_failure(source);
        let value = match operator {
            wrela_hir::BinaryOperator::AddWrapping => ComptimeInteger {
                raw: left.raw.wrapping_add(right.raw) & mask,
                ..left
            },
            wrela_hir::BinaryOperator::SubtractWrapping => ComptimeInteger {
                raw: left.raw.wrapping_sub(right.raw) & mask,
                ..left
            },
            wrela_hir::BinaryOperator::MultiplyWrapping => ComptimeInteger {
                raw: left.raw.wrapping_mul(right.raw) & mask,
                ..left
            },
            wrela_hir::BinaryOperator::BitOr => ComptimeInteger {
                raw: left.raw | right.raw,
                ..left
            },
            wrela_hir::BinaryOperator::BitXor => ComptimeInteger {
                raw: left.raw ^ right.raw,
                ..left
            },
            wrela_hir::BinaryOperator::BitAnd => ComptimeInteger {
                raw: left.raw & right.raw,
                ..left
            },
            wrela_hir::BinaryOperator::ShiftLeft => {
                let shift = right
                    .shift_count()
                    .filter(|shift| *shift < u32::from(left.bits));
                let shift = shift.ok_or_else(invalid_shift)?;
                let shifted = ComptimeInteger {
                    // `shift < left.bits <= 128`, so the host shift is defined;
                    // the mask models the selected target width exactly.
                    raw: left.raw.checked_shl(shift).unwrap_or(0) & mask,
                    ..left
                };
                let preserves_mathematical_result = if left.signed {
                    shifted
                        .signed_value()
                        .zip(left.signed_value())
                        .is_some_and(|(shifted, original)| shifted >> shift == original)
                } else {
                    shifted.raw >> shift == left.raw
                };
                if !preserves_mathematical_result {
                    return Err(lost_shift_result());
                }
                shifted
            }
            wrela_hir::BinaryOperator::ShiftRight => {
                let shift = right
                    .shift_count()
                    .filter(|shift| *shift < u32::from(left.bits));
                let shift = shift.ok_or_else(invalid_shift)?;
                let raw = if left.signed {
                    (left
                        .signed_value()
                        .ok_or_else(|| self.type_mismatch(source))?
                        >> shift) as u128
                        & mask
                } else {
                    left.raw >> shift
                };
                ComptimeInteger { raw, ..left }
            }
            operator if left.signed => {
                let left_value = left
                    .signed_value()
                    .ok_or_else(|| self.type_mismatch(source))?;
                let right_value = right
                    .signed_value()
                    .ok_or_else(|| self.type_mismatch(source))?;
                let signed = match operator {
                    wrela_hir::BinaryOperator::Add => left_value.checked_add(right_value),
                    wrela_hir::BinaryOperator::Subtract => left_value.checked_sub(right_value),
                    wrela_hir::BinaryOperator::Multiply => left_value.checked_mul(right_value),
                    wrela_hir::BinaryOperator::Divide if right_value == 0 => {
                        return Err(divide_by_zero());
                    }
                    wrela_hir::BinaryOperator::Divide => left_value.checked_div(right_value),
                    wrela_hir::BinaryOperator::Remainder if right_value == 0 => {
                        return Err(divide_by_zero());
                    }
                    wrela_hir::BinaryOperator::Remainder
                        if left_value == i128::MIN && right_value == -1 =>
                    {
                        Some(0)
                    }
                    wrela_hir::BinaryOperator::Remainder => left_value.checked_rem(right_value),
                    _ => return Err(self.unsupported(source)),
                }
                .ok_or_else(overflow)?;
                integer_from_signed(left.bits, signed).ok_or_else(overflow)?
            }
            operator => {
                let raw = match operator {
                    wrela_hir::BinaryOperator::Add => left.raw.checked_add(right.raw),
                    wrela_hir::BinaryOperator::Subtract => left.raw.checked_sub(right.raw),
                    wrela_hir::BinaryOperator::Multiply => left.raw.checked_mul(right.raw),
                    wrela_hir::BinaryOperator::Divide if right.raw == 0 => {
                        return Err(divide_by_zero());
                    }
                    wrela_hir::BinaryOperator::Divide => left.raw.checked_div(right.raw),
                    wrela_hir::BinaryOperator::Remainder if right.raw == 0 => {
                        return Err(divide_by_zero());
                    }
                    wrela_hir::BinaryOperator::Remainder => left.raw.checked_rem(right.raw),
                    _ => return Err(self.unsupported(source)),
                }
                .filter(|raw| *raw <= mask)
                .ok_or_else(overflow)?;
                ComptimeInteger { raw, ..left }
            }
        };
        Ok(ComptimeValue::Integer(value))
    }

    fn evaluate_comparison(
        &self,
        operator: wrela_hir::ComparisonOperator,
        left: ComptimeValue,
        right: ComptimeValue,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        if matches!(&left, ComptimeValue::Structure { .. })
            || matches!(&right, ComptimeValue::Structure { .. })
        {
            return Err(self.unsupported(source));
        }
        if left.value_type() != right.value_type() {
            return Err(self.type_mismatch(source));
        }
        let ordering = match (&left, &right) {
            (ComptimeValue::Integer(left), ComptimeValue::Integer(right)) if left.signed => left
                .signed_value()
                .zip(right.signed_value())
                .map(|(left, right)| left.cmp(&right)),
            (ComptimeValue::Integer(left), ComptimeValue::Integer(right)) => {
                Some(left.raw.cmp(&right.raw))
            }
            _ => None,
        };
        let result = match operator {
            wrela_hir::ComparisonOperator::Equal => left == right,
            wrela_hir::ComparisonOperator::NotEqual => left != right,
            wrela_hir::ComparisonOperator::Less => ordering.is_some_and(|value| value.is_lt()),
            wrela_hir::ComparisonOperator::LessEqual => ordering.is_some_and(|value| value.is_le()),
            wrela_hir::ComparisonOperator::Greater => ordering.is_some_and(|value| value.is_gt()),
            wrela_hir::ComparisonOperator::GreaterEqual => {
                ordering.is_some_and(|value| value.is_ge())
            }
            wrela_hir::ComparisonOperator::In | wrela_hir::ComparisonOperator::NotIn => {
                return Err(self.unsupported(source));
            }
        };
        if ordering.is_none()
            && !matches!(
                operator,
                wrela_hir::ComparisonOperator::Equal | wrela_hir::ComparisonOperator::NotEqual
            )
        {
            return Err(self.type_mismatch(source));
        }
        Ok(ComptimeValue::Boolean(result))
    }

    /// Desugar `+ - < <= > >=` on a comptime struct value into a direct
    /// invocation of the unique visible `core.ops` impl method (chapter 10
    /// §12). `left`/`right` are already evaluated left-to-right as written;
    /// only the argument binding is swapped for `> <= >=`, and `<= >=` also
    /// negate the raw call result.
    fn evaluate_operator_interface_binary(
        &mut self,
        operator: crate::interfaces::DesugarOperator,
        left: ComptimeValue,
        right: ComptimeValue,
        source: Span,
        depth: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let ComptimeValue::Structure {
            declaration: left_declaration,
            ..
        } = &left
        else {
            return Err(self.unsupported(source));
        };
        let ComptimeValue::Structure {
            declaration: right_declaration,
            ..
        } = &right
        else {
            return Err(self.type_mismatch(source));
        };
        if left_declaration != right_declaration {
            return Err(self.type_mismatch(source));
        }
        let struct_declaration = *left_declaration;
        let (model, _) = crate::interfaces::collect_interface_model(
            self.program,
            self.request.standard_library_package,
            self.is_cancelled,
        )
        .map_err(EvaluationFailure::Analysis)?;
        let Some(resolution) = model.resolve_operator(self.program, operator, struct_declaration)
        else {
            return Err(self.unsupported(source));
        };
        let DeclarationKind::Function(function_decl) = &self
            .program
            .declaration(resolution.function)
            .ok_or_else(|| self.unsupported(source))?
            .kind
        else {
            return Err(self.unsupported(source));
        };
        if function_decl.parameters.len() != 2 {
            return Err(self.unsupported(source));
        }
        let self_parameter_id = function_decl.parameters[0];
        let other_parameter_id = function_decl.parameters[1];
        let (self_value, other_value) = if resolution.swap {
            (right, left)
        } else {
            (left, right)
        };
        let raw = self.invoke_function(
            resolution.function,
            vec![
                (self_parameter_id, self_value),
                (other_parameter_id, other_value),
            ],
            Some(source),
            depth,
        )?;
        if resolution.negate {
            match raw {
                ComptimeValue::Boolean(value) => Ok(ComptimeValue::Boolean(!value)),
                _ => Err(self.type_mismatch(source)),
            }
        } else {
            Ok(raw)
        }
    }

    fn expression_value_type(
        &mut self,
        expression: ExpressionId,
        depth: u32,
    ) -> Result<Option<ComptimeType>, EvaluationFailure> {
        if depth >= COMPTIME_SYNTAX_DEPTH {
            return Ok(None);
        }
        let program = self.program;
        let Some(expression) = program.expression(expression) else {
            return Ok(None);
        };
        Ok(match &expression.kind {
            ExpressionKind::Literal(Literal::Boolean(_)) => Some(ComptimeType::Bool),
            ExpressionKind::Literal(Literal::Integer(spelling)) => self
                .scan_integer_spelling(spelling, expression.source)?
                .and_then(|value| {
                    if value <= i64::MAX as u128 {
                        Some(ComptimeType::Integer {
                            signed: true,
                            bits: 64,
                        })
                    } else if value <= u64::MAX as u128 {
                        Some(ComptimeType::Integer {
                            signed: false,
                            bits: 64,
                        })
                    } else {
                        None
                    }
                }),
            ExpressionKind::Literal(Literal::Unit) => Some(ComptimeType::Unit),
            ExpressionKind::Reference(Definition::Local(local)) => {
                self.bound_local_value_type(*local)?
            }
            ExpressionKind::Reference(Definition::Parameter(parameter)) => {
                self.parameter_value_type(*parameter)
            }
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::BoolNot,
                ..
            }
            | ExpressionKind::Binary {
                operator:
                    wrela_hir::BinaryOperator::LogicalAnd | wrela_hir::BinaryOperator::LogicalOr,
                ..
            }
            | ExpressionKind::Compare { .. } => Some(ComptimeType::Bool),
            ExpressionKind::Unary {
                operator: wrela_hir::UnaryOperator::Negate,
                operand,
            } => {
                if let Some((spelling, source)) = program.expression(*operand).and_then(|operand| {
                    let ExpressionKind::Literal(Literal::Integer(spelling)) = &operand.kind else {
                        return None;
                    };
                    Some((spelling.as_str(), operand.source))
                }) {
                    self.scan_integer_spelling(spelling, source)?
                        .and_then(|magnitude| {
                            (magnitude <= (1_u128 << 63)).then_some(ComptimeType::Integer {
                                signed: true,
                                bits: 64,
                            })
                        })
                } else {
                    self.expression_value_type(*operand, depth + 1)?
                }
            }
            ExpressionKind::Unary { operand, .. } => {
                self.expression_value_type(*operand, depth + 1)?
            }
            ExpressionKind::Binary { left, right, .. } => {
                match self.expression_value_type(*left, depth + 1)? {
                    Some(left) => Some(left),
                    None => self.expression_value_type(*right, depth + 1)?,
                }
            }
            ExpressionKind::Field { base, name } => {
                let Some(ComptimeType::Structure(declaration)) =
                    self.expression_value_type(*base, depth + 1)?
                else {
                    return Ok(None);
                };
                if !self.check_flat_scalar_structure(declaration)? {
                    return Ok(None);
                }
                let Some(record) = program.declaration(declaration) else {
                    return Ok(None);
                };
                let DeclarationKind::Structure(aggregate) = &record.kind else {
                    return Ok(None);
                };
                let mut selected = None;
                for field in &aggregate.fields {
                    self.work()?;
                    if self.comptime_names_equal(field.name.as_str(), name.as_str())? {
                        if selected.is_some() {
                            return Ok(None);
                        }
                        selected = self.source_scalar_type_only(&field.ty);
                    }
                }
                selected
            }
            ExpressionKind::Call { callee, .. } => {
                let Some(callee) = program.expression(*callee) else {
                    return Ok(None);
                };
                let ExpressionKind::Reference(Definition::Declaration(resolved)) = &callee.kind
                else {
                    return Ok(None);
                };
                let Some(declaration) = program.declaration(resolved.declaration) else {
                    return Ok(None);
                };
                match &declaration.kind {
                    DeclarationKind::Function(function) => function
                        .result
                        .as_ref()
                        .and_then(|result| self.source_value_type(result))
                        .or_else(|| function.result.is_none().then_some(ComptimeType::Unit)),
                    DeclarationKind::Structure(_)
                        if self.check_flat_scalar_structure(declaration.id)? =>
                    {
                        Some(ComptimeType::Structure(declaration.id))
                    }
                    _ => None,
                }
            }
            _ => None,
        })
    }

    fn source_value_type(&self, source: &TypeExpression) -> Option<ComptimeType> {
        if let TypeExpressionKind::SelfType { owner } = &source.kind {
            let declaration =
                crate::interfaces::concrete_struct_for_self_owner(self.program, *owner)?;
            return (!self.is_standard_image_declaration(declaration))
                .then_some(ComptimeType::Structure(declaration));
        }
        let TypeExpressionKind::Named {
            definition,
            arguments,
        } = &source.kind
        else {
            return None;
        };
        if !arguments.is_empty() {
            return None;
        }
        match definition {
            Definition::Builtin(builtin) => self.scalar_builtin_type(*builtin),
            Definition::Declaration(resolved) => {
                let declaration = self.request.hir.resolved_declaration(resolved)?;
                (matches!(&declaration.kind, DeclarationKind::Structure(_))
                    && !self.is_standard_image_declaration(declaration.id))
                .then_some(ComptimeType::Structure(declaration.id))
            }
            _ => None,
        }
    }

    fn source_scalar_type_only(&self, source: &TypeExpression) -> Option<ComptimeType> {
        let TypeExpressionKind::Named {
            definition: Definition::Builtin(builtin),
            arguments,
        } = &source.kind
        else {
            return None;
        };
        if arguments.is_empty() {
            self.scalar_builtin_type(*builtin)
        } else {
            None
        }
    }

    fn scalar_builtin_type(&self, builtin: Builtin) -> Option<ComptimeType> {
        Some(match builtin {
            Builtin::Unit => ComptimeType::Unit,
            Builtin::Bool => ComptimeType::Bool,
            Builtin::U8 => ComptimeType::Integer {
                signed: false,
                bits: 8,
            },
            Builtin::U16 => ComptimeType::Integer {
                signed: false,
                bits: 16,
            },
            Builtin::U32 => ComptimeType::Integer {
                signed: false,
                bits: 32,
            },
            Builtin::U64 => ComptimeType::Integer {
                signed: false,
                bits: 64,
            },
            Builtin::U128 => ComptimeType::Integer {
                signed: false,
                bits: 128,
            },
            Builtin::Usize => ComptimeType::Integer {
                signed: false,
                bits: u16::from(self.request.target.pointer_width()),
            },
            Builtin::I8 => ComptimeType::Integer {
                signed: true,
                bits: 8,
            },
            Builtin::I16 => ComptimeType::Integer {
                signed: true,
                bits: 16,
            },
            Builtin::I32 => ComptimeType::Integer {
                signed: true,
                bits: 32,
            },
            Builtin::I64 => ComptimeType::Integer {
                signed: true,
                bits: 64,
            },
            Builtin::I128 => ComptimeType::Integer {
                signed: true,
                bits: 128,
            },
            Builtin::Isize => ComptimeType::Integer {
                signed: true,
                bits: u16::from(self.request.target.pointer_width()),
            },
            _ => return None,
        })
    }

    fn check_flat_scalar_structure(
        &mut self,
        declaration: DeclarationId,
    ) -> Result<bool, EvaluationFailure> {
        let program = self.program;
        let Some(declaration) = program.declaration(declaration) else {
            return Ok(false);
        };
        let DeclarationKind::Structure(aggregate) = &declaration.kind else {
            return Ok(false);
        };
        self.work()?;
        if !aggregate.generics.is_empty() || !aggregate.implements.is_empty() {
            return Ok(false);
        }
        for field in &aggregate.fields {
            self.work()?;
            if field.default.is_some()
                || !field.attributes.is_empty()
                || self.source_scalar_type_only(&field.ty).is_none()
            {
                return Ok(false);
            }
        }
        Ok(true)
    }

    fn validated_source_value_type(
        &mut self,
        source_type: &TypeExpression,
        diagnostic_source: Span,
    ) -> Result<Option<ComptimeType>, EvaluationFailure> {
        let ty = self.source_value_type(source_type);
        if let Some(ComptimeType::Structure(declaration)) = ty {
            if !self.check_flat_scalar_structure(declaration)? {
                return Err(self.aggregate_not_supported(diagnostic_source));
            }
        }
        Ok(ty)
    }

    fn is_standard_image_declaration(&self, declaration: DeclarationId) -> bool {
        self.program
            .declaration(declaration)
            .and_then(|record| {
                self.program
                    .modules
                    .get(record.module.0 as usize)
                    .map(|module| (record, module))
            })
            .is_some_and(|(record, module)| {
                module.package == self.request.standard_library_package
                    && record.name.as_ref().map(wrela_hir::Name::as_str) == Some("Image")
            })
    }

    fn require_structure_field_visible(
        &self,
        field: &wrela_hir::Field,
        same_module: bool,
        source: Span,
    ) -> Result<(), EvaluationFailure> {
        if same_module || field.visibility != wrela_hir::Visibility::Private {
            Ok(())
        } else {
            Err(self.diagnostic(
                source,
                "semantic-comptime-field-private",
                "comptime structure field is private to its declaring module",
            ))
        }
    }

    fn local_value_type(&self, local: LocalId) -> Option<ComptimeType> {
        self.program
            .locals
            .get(local.0 as usize)
            .filter(|record| record.id == local)
            .and_then(|record| record.ty.as_ref())
            .and_then(|ty| self.source_value_type(ty))
    }

    fn bound_local_value_type(
        &mut self,
        local: LocalId,
    ) -> Result<Option<ComptimeType>, EvaluationFailure> {
        if let Some(ty) = self.local_value_type(local) {
            return Ok(Some(ty));
        }
        let local_count = self.frames.last().map_or(0, |frame| frame.locals.len());
        for index in (0..local_count).rev() {
            self.work()?;
            if let Some(binding) = self
                .frames
                .last()
                .and_then(|frame| frame.locals.get(index))
                .filter(|binding| binding.id == local)
            {
                return Ok(binding.value.as_ref().and_then(ComptimeValue::value_type));
            }
        }
        Ok(None)
    }

    fn parameter_value_type(&self, parameter: wrela_hir::ParameterId) -> Option<ComptimeType> {
        self.program
            .parameters
            .get(parameter.0 as usize)
            .filter(|record| record.id == parameter)
            .and_then(|record| record.ty.as_ref())
            .and_then(|ty| self.source_value_type(ty))
    }

    fn current_result_value_type(&self) -> Option<ComptimeType> {
        let declaration = self.frames.last()?.declaration;
        let DeclarationKind::Function(function) = &self.program.declaration(declaration)?.kind
        else {
            return None;
        };
        function
            .result
            .as_ref()
            .and_then(|result| self.source_value_type(result))
            .or_else(|| function.result.is_none().then_some(ComptimeType::Unit))
    }

    fn require_expected(
        &self,
        value: ComptimeValue,
        expected: Option<ComptimeType>,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        if expected.is_some_and(|expected| value.value_type() != Some(expected)) {
            Err(self.type_mismatch(source))
        } else {
            Ok(value)
        }
    }

    fn type_mismatch(&self, source: Span) -> EvaluationFailure {
        self.diagnostic(
            source,
            "semantic-comptime-type-mismatch",
            "comptime value does not match its required target type",
        )
    }

    fn arithmetic_failure(&self, source: Span, message: &str) -> EvaluationFailure {
        self.diagnostic(source, "semantic-comptime-arithmetic", message)
    }

    fn shift_count_failure(&self, source: Span) -> EvaluationFailure {
        self.diagnostic(
            source,
            "semantic-comptime-shift-count",
            "comptime integer shift count is negative or not less than the target width",
        )
    }

    fn shift_result_loss_failure(&self, source: Span) -> EvaluationFailure {
        self.diagnostic(
            source,
            "semantic-comptime-shift-result-loss",
            "checked comptime left-shift result is not representable in the operand type",
        )
    }

    fn call_depth_failure(&self) -> EvaluationFailure {
        EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
            resource: "comptime evaluator depth",
            limit: u64::from(self.depth_limit),
        })
    }

    fn host_recursion_failure(&self) -> EvaluationFailure {
        EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
            resource: "comptime evaluator host recursion",
            limit: u64::from(COMPTIME_HOST_RECURSION_DEPTH),
        })
    }

    fn evaluator_byte_failure(&self) -> EvaluationFailure {
        EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
            resource: "comptime evaluator bytes",
            limit: self.byte_limit,
        })
    }

    fn resource_diagnostic(&self, resource: &'static str, limit: u64) -> EvaluationFailure {
        let source = self.resource_source.unwrap_or(self.current_source);
        let message = format!("comptime test exceeded {resource} limit {limit}");
        self.diagnostic(source, "semantic-comptime-resource-limit", &message)
    }

    fn image_install_target(&self, callee: ExpressionId) -> Option<(LocalId, EvaluatedActorKind)> {
        let ExpressionKind::Field { base, name } = &self.program.expression(callee)?.kind else {
            return None;
        };
        let ExpressionKind::Reference(Definition::Local(image)) = self
            .program
            .expression(*base)
            .map(|expression| &expression.kind)?
        else {
            return None;
        };
        EvaluatedActorKind::from_install_method(name.as_str()).map(|kind| (*image, kind))
    }

    fn image_supervise_target(&self, callee: ExpressionId) -> Option<LocalId> {
        let ExpressionKind::Field { base, name } = &self.program.expression(callee)?.kind else {
            return None;
        };
        if name.as_str() != "supervise" {
            return None;
        }
        let ExpressionKind::Reference(Definition::Local(image)) = self
            .program
            .expression(*base)
            .map(|expression| &expression.kind)?
        else {
            return None;
        };
        Some(*image)
    }

    fn actor_handle_target(
        &mut self,
        callee: ExpressionId,
        source: Span,
    ) -> Result<Option<(u32, DeclarationId)>, EvaluationFailure> {
        let Some(ExpressionKind::Field { base, name }) = self
            .program
            .expression(callee)
            .map(|expression| &expression.kind)
        else {
            return Ok(None);
        };
        if name.as_str() != "handle" {
            return Ok(None);
        }
        let Some(ExpressionKind::Reference(Definition::Local(local))) = self
            .program
            .expression(*base)
            .map(|expression| &expression.kind)
        else {
            return Ok(None);
        };
        match self.load_local(*local, source)? {
            ComptimeValue::InstalledActor { actor, class } => Ok(Some((actor, class))),
            value => {
                self.dispose_temporary_value(value, source)?;
                Ok(None)
            }
        }
    }

    fn actor_class_kind(&self, declaration: DeclarationId) -> Option<EvaluatedActorKind> {
        let declaration = self.program.declaration(declaration)?;
        if !matches!(declaration.kind, DeclarationKind::Structure(_)) {
            return None;
        }
        let mut selected = None;
        for attribute in &declaration.attributes {
            let wrela_hir::AttributeIdentity::Builtin(identity) = attribute.identity else {
                continue;
            };
            let kind = match identity {
                wrela_hir::BuiltinAttribute::App => EvaluatedActorKind::App,
                wrela_hir::BuiltinAttribute::Service => EvaluatedActorKind::Service,
                wrela_hir::BuiltinAttribute::Driver => EvaluatedActorKind::Driver,
                _ => continue,
            };
            if selected.replace(kind).is_some() {
                return None;
            }
        }
        selected
    }

    fn evaluate_image_install(
        &mut self,
        image: LocalId,
        install_kind: EvaluatedActorKind,
        arguments: &[wrela_hir::CallArgument],
        source: Span,
        depth: u32,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        if arguments.len() != 2
            && !(install_kind == EvaluatedActorKind::App && arguments.len() == 3)
        {
            return Err(self.diagnostic_category(
                Category::ACTOR,
                source,
                "semantic-actor-install-shape",
                "actor installation requires one actor struct, at most one image-wired service handle, and one `mailbox` capacity",
            ));
        }
        let class_argument = &arguments[0];
        let Some(class_argument_value) = class_argument.expression() else {
            return Err(self.unsupported(class_argument.source));
        };
        if class_argument.name.is_some() {
            return Err(self.unsupported(class_argument.source));
        }
        let class = self.evaluate_expression(class_argument_value, None, depth)?;
        let ComptimeValue::ActorClass {
            declaration: class,
            kind: class_kind,
        } = class
        else {
            return Err(self.diagnostic_category(
                Category::ACTOR,
                class_argument.source,
                "semantic-actor-install-class",
                "the first actor installation argument must name an actor struct",
            ));
        };
        if class_kind != install_kind {
            return Err(self.diagnostic_category(
                Category::ACTOR,
                class_argument.source,
                "semantic-actor-install-role",
                "the image installation method does not match the actor struct role",
            ));
        }
        if install_kind == EvaluatedActorKind::Driver {
            return Err(self.diagnostic_category(
                Category::HARDWARE,
                source,
                "semantic-hardware-actor-not-supported",
                "driver installation requires coherent target device and authority facts",
            ));
        }
        let mailbox_argument = arguments.last().ok_or_else(|| self.unsupported(source))?;
        if mailbox_argument.name.as_ref().map(wrela_hir::Name::as_str) != Some("mailbox")
            || mailbox_argument.access() != wrela_hir::AccessMode::Value
        {
            return Err(self.diagnostic_category(
                Category::CAPACITY,
                mailbox_argument.source,
                "semantic-actor-mailbox-shape",
                "actor installation requires a named `mailbox` capacity",
            ));
        }
        let mailbox_source = self
            .program
            .expression(
                mailbox_argument
                    .expression()
                    .ok_or_else(|| self.unsupported(mailbox_argument.source))?,
            )
            .map_or(mailbox_argument.source, |expression| expression.source);
        let mailbox = self.evaluate_expression(
            mailbox_argument
                .expression()
                .ok_or_else(|| self.unsupported(mailbox_argument.source))?,
            None,
            depth,
        )?;
        let ComptimeValue::Integer(mailbox) = mailbox else {
            return Err(self.diagnostic_category(
                Category::CAPACITY,
                mailbox_source,
                "semantic-actor-mailbox-constant",
                "actor mailbox capacity must be a compile-time unsigned integer",
            ));
        };
        let mailbox_capacity = (!mailbox.signed
            || mailbox.signed_value().is_some_and(|value| value >= 0))
        .then_some(mailbox.raw)
        .and_then(|value| u32::try_from(value).ok())
        .filter(|value| *value != 0)
        .ok_or_else(|| {
            self.diagnostic_category(
                Category::CAPACITY,
                mailbox_source,
                "semantic-actor-mailbox-capacity",
                "actor mailbox capacity must fit in u32 and be greater than zero",
            )
        })?;
        let program = self.program;
        let declaration = program.declaration(class).ok_or_else(|| {
            self.diagnostic_category(
                Category::ACTOR,
                class_argument.source,
                "semantic-actor-install-class",
                "the installed actor struct is missing from HIR",
            )
        })?;
        let dependency = if arguments.len() == 3 {
            let DeclarationKind::Structure(actor_class) = &declaration.kind else {
                return Err(self.unsupported(class_argument.source));
            };
            let [field] = actor_class.fields.as_slice() else {
                return Err(self.diagnostic_category(
                    Category::ACTOR,
                    class_argument.source,
                    "semantic-actor-wiring-field",
                    "the exact cross-actor subset requires one Actor[Service] field on the app",
                ));
            };
            let TypeExpressionKind::Named {
                definition: Definition::Builtin(Builtin::Actor),
                arguments: handle_arguments,
            } = &field.ty.kind
            else {
                return Err(self.diagnostic_category(
                    Category::ACTOR,
                    field.ty.source,
                    "semantic-actor-wiring-field",
                    "the app wiring field must have type Actor[Service]",
                ));
            };
            let [handle_argument] = handle_arguments.as_slice() else {
                return Err(self.unsupported(field.ty.source));
            };
            let wrela_hir::GenericArgumentKind::Type(TypeExpression {
                kind:
                    TypeExpressionKind::Named {
                        definition: Definition::Declaration(target),
                        arguments: target_arguments,
                    },
                ..
            }) = &handle_argument.kind
            else {
                return Err(self.unsupported(handle_argument.source));
            };
            if !target_arguments.is_empty() {
                return Err(self.unsupported(handle_argument.source));
            }
            let wiring_argument = &arguments[1];
            if wiring_argument.name.as_ref().map(wrela_hir::Name::as_str)
                != Some(field.name.as_str())
            {
                return Err(self.diagnostic_category(
                    Category::ACTOR,
                    wiring_argument.source,
                    "semantic-actor-wiring-name",
                    "the image-wired handle argument must name the app Actor field",
                ));
            }
            let wiring_expression = wiring_argument
                .expression()
                .ok_or_else(|| self.unsupported(wiring_argument.source))?;
            let wiring_value = self.evaluate_expression(wiring_expression, None, depth)?;
            let ComptimeValue::ActorHandle {
                actor: target_actor,
                class: target_class,
            } = wiring_value
            else {
                return Err(self.diagnostic_category(
                    Category::ACTOR,
                    wiring_argument.source,
                    "semantic-actor-wiring-handle",
                    "the app dependency must be the unique handle minted by a prior service installation",
                ));
            };
            if target_class != target.declaration {
                return Err(self.diagnostic_category(
                    Category::ACTOR,
                    wiring_argument.source,
                    "semantic-actor-wiring-target",
                    "the installed service handle does not match the app Actor field type",
                ));
            }
            Some((target_actor, wiring_argument.source))
        } else {
            let DeclarationKind::Structure(actor_class) = &declaration.kind else {
                return Err(self.unsupported(class_argument.source));
            };
            match actor_state_shape(program, actor_class) {
                ActorStateShape::Stateless | ActorStateShape::CanonicalZeroU64 { .. } => {}
                ActorStateShape::WiringField { source } => {
                    return Err(self.diagnostic_category(
                        Category::ACTOR,
                        source,
                        "semantic-actor-wiring-missing",
                        "an actor handle field requires one matching image installation argument",
                    ));
                }
                ActorStateShape::InitializerRequired { source } => {
                    return Err(self.diagnostic_category(
                        Category::ACTOR,
                        source,
                        "semantic-actor-state-initializer-required",
                        "the admitted actor state field requires an explicit initializer",
                    ));
                }
                ActorStateShape::InitializerPending { source } => {
                    return Err(self.diagnostic_category(
                        Category::ACTOR,
                        source,
                        "semantic-actor-state-initializer-pending",
                        "actor state initialization currently admits only canonical zero",
                    ));
                }
                ActorStateShape::ShapePending { source } => {
                    return Err(self.diagnostic_category(
                        Category::ACTOR,
                        source,
                        "semantic-actor-state-shape-pending",
                        "actor state storage currently admits exactly `value: u64 = 0`",
                    ));
                }
            }
            None
        };
        let actor_name = declaration
            .name
            .as_ref()
            .map(wrela_hir::Name::as_str)
            .ok_or_else(|| self.unsupported(class_argument.source))?;
        self.current_source = declaration.source;
        let actor_name = self.copy_source_text(actor_name)?;
        let current = self.load_local(image, source)?;
        let ComptimeValue::Image(current_image) = &current else {
            return Err(self.diagnostic_category(
                Category::IMAGE,
                source,
                "semantic-image-install-base",
                "actor installation must target an initialized local Image value",
            ));
        };
        if let Some((target, wiring_source)) = dependency {
            if install_kind != EvaluatedActorKind::App
                || current_image.actors.len() != 1
                || current_image
                    .actors
                    .get(target as usize)
                    .is_none_or(|actor| {
                        actor.kind != EvaluatedActorKind::Service || actor.dependency.is_some()
                    })
            {
                return Err(self.diagnostic_category(
                    Category::ACTOR,
                    wiring_source,
                    "semantic-actor-wiring-shape",
                    "the cross-actor subset requires exactly one prior stateless service and one dependent app",
                ));
            }
        }
        if let Some(previous) = current_image
            .actors
            .iter()
            .find(|actor| actor.class == class)
        {
            let mut diagnostic = match self.diagnostic_category(
                Category::ACTOR,
                source,
                "semantic-actor-instance-ambiguous",
                "revision 0.1 requires one concrete image instance per actor struct in this subset",
            ) {
                EvaluationFailure::Diagnostic(diagnostic) => diagnostic,
                EvaluationFailure::Analysis(_) => unreachable!(),
            };
            diagnostic.labels.try_reserve_exact(1).map_err(|_| {
                EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator bytes",
                    limit: self.byte_limit,
                })
            })?;
            diagnostic.labels.push(wrela_diagnostics::Label {
                span: previous.source,
                message: "the first concrete instance is installed here".to_owned(),
            });
            return Err(EvaluationFailure::Diagnostic(diagnostic));
        }
        if current_image.actors.len() >= self.request.limits.image_nodes as usize {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "image actor nodes",
                    limit: u64::from(self.request.limits.image_nodes),
                },
            ));
        }
        self.dispose_temporary_value(current, source)?;
        self.retain(COMPTIME_ACTOR_BYTES)?;
        let byte_limit = self.byte_limit;
        {
            let Some(ComptimeValue::Image(current)) = self.local_mut(image) else {
                return Err(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ));
            };
            current.actors.try_reserve(1).map_err(|_| {
                EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator bytes",
                    limit: byte_limit,
                })
            })?;
        }
        let (name_start, actor_name_len) =
            self.append_precharged_image_name(image, &actor_name, declaration.source)?;
        let image_node_limit = self.request.limits.image_nodes;
        let Some(ComptimeValue::Image(current)) = self.local_mut(image) else {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::RequestMismatch,
            ));
        };
        let actor = u32::try_from(current.actors.len()).map_err(|_| {
            EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                resource: "image actor nodes",
                limit: u64::from(image_node_limit),
            })
        })?;
        current.actors.push(EvaluatedActor {
            class,
            kind: install_kind,
            name_start,
            name_len: actor_name_len,
            mailbox_capacity,
            dependency: dependency.map(|(actor, _)| actor),
            wiring_source: dependency.map(|(_, source)| source),
            source,
            mailbox_source,
        });
        Ok(ComptimeValue::InstalledActor { actor, class })
    }

    fn standard_declaration_name(
        &self,
        declaration: &wrela_hir::ResolvedDeclaration,
    ) -> Option<&str> {
        if declaration.package != self.request.standard_library_package {
            return None;
        }
        self.program
            .declaration(declaration.declaration)?
            .name
            .as_ref()
            .map(wrela_hir::Name::as_str)
    }

    fn is_selected_target_variant(&self, variant: &wrela_hir::ResolvedVariant) -> bool {
        self.standard_declaration_name(&variant.enumeration) == Some("Target")
            && self
                .request
                .hir
                .resolved_variant(variant)
                .is_some_and(|value| value.name.as_str() == "aarch64_qemu_virt_uefi")
            && self.request.target.identity()
                == &wrela_build_model::TargetIdentity::aarch64_qemu_virt_uefi()
    }

    fn poll_structure_disposal(
        &mut self,
        field_count: usize,
        source: Span,
    ) -> Result<u64, EvaluationFailure> {
        self.current_source = source;
        // One unit for the aggregate allocation followed by one unit for every
        // logical field. The Copy-only payload representation makes the
        // subsequent host deallocation O(1), so no unmetered element drop glue
        // remains after this successful scan.
        self.work()?;
        for _ in 0..field_count {
            self.work()?;
        }
        comptime_structure_payload_bytes(field_count).ok_or_else(|| self.evaluator_byte_failure())
    }

    /// Explicitly disposes the evaluator-owned payload in `value` and returns
    /// its canonical retained-byte charge. Callers release that charge only
    /// after this method succeeds.
    ///
    /// Text is one allocation, a flat structure is one allocation plus one
    /// unit per scalar field, and an image polls every logical actor before
    /// releasing its one contiguous image-and-actor-name arena.
    /// Actor records are `Copy`, so cancellation leaves only O(1)-drop host
    /// allocations and cannot fall back to an implicit project-sized tail
    /// destructor. If polling fails, no unperformed cleanup is credited.
    fn dispose_owned_payload(
        &mut self,
        value: &mut ComptimeValue,
        source: Span,
    ) -> Result<u64, EvaluationFailure> {
        self.current_source = source;
        match value {
            ComptimeValue::Text(text) => {
                let payload =
                    u64::try_from(text.len()).map_err(|_| self.evaluator_byte_failure())?;
                self.work()?;
                drop(std::mem::take(text));
                Ok(payload)
            }
            ComptimeValue::Structure { fields, .. } => {
                let payload = self.poll_structure_disposal(fields.len(), source)?;
                drop(std::mem::take(fields));
                Ok(payload)
            }
            ComptimeValue::Image(image) => {
                image.name().ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
                let actor_bytes = image
                    .actors
                    .len()
                    .checked_mul(COMPTIME_ACTOR_BYTES)
                    .and_then(|bytes| u64::try_from(bytes).ok())
                    .ok_or_else(|| self.evaluator_byte_failure())?;
                let names_bytes =
                    u64::try_from(image.names.len()).map_err(|_| self.evaluator_byte_failure())?;
                let payload = actor_bytes
                    .checked_add(names_bytes)
                    .ok_or_else(|| self.evaluator_byte_failure())?;
                for actor in &image.actors {
                    self.work()?;
                    image.actor_name(*actor).ok_or(EvaluationFailure::Analysis(
                        AnalysisFailure::RequestMismatch,
                    ))?;
                }
                drop(std::mem::take(&mut image.actors));
                self.work()?;
                drop(std::mem::take(&mut image.names));
                Ok(payload)
            }
            ComptimeValue::Boolean(_)
            | ComptimeValue::Integer(_)
            | ComptimeValue::SelectedTarget
            | ComptimeValue::TargetType
            | ComptimeValue::ImageConstructor
            | ComptimeValue::ActorClass { .. }
            | ComptimeValue::InstalledActor { .. }
            | ComptimeValue::ActorHandle { .. }
            | ComptimeValue::Unit => Ok(0),
        }
    }

    fn poll_successful_frame_cleanup(&mut self) -> Result<u64, EvaluationFailure> {
        let mut released_payload = 0_u64;
        while self
            .frames
            .last()
            .is_some_and(|frame| !frame.locals.is_empty())
        {
            self.work()?;
            let mut value = self
                .frames
                .last_mut()
                .and_then(|frame| frame.locals.last_mut())
                .and_then(|binding| binding.value.take());
            let disposal = if let Some(payload) = value.as_mut() {
                self.dispose_owned_payload(payload, self.current_source)
            } else {
                Ok(0)
            };
            match disposal {
                Ok(payload) => {
                    released_payload = released_payload
                        .checked_add(payload)
                        .ok_or_else(|| self.evaluator_byte_failure())?;
                }
                Err(error) => {
                    let binding = self
                        .frames
                        .last_mut()
                        .and_then(|frame| frame.locals.last_mut())
                        .ok_or(EvaluationFailure::Analysis(
                            AnalysisFailure::RequestMismatch,
                        ))?;
                    binding.value = value;
                    return Err(error);
                }
            }
            let binding = self
                .frames
                .last_mut()
                .and_then(|frame| frame.locals.pop())
                .ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
            drop(binding);
        }
        while self
            .frames
            .last()
            .is_some_and(|frame| !frame.parameters.is_empty())
        {
            self.work()?;
            let mut value = self
                .frames
                .last_mut()
                .and_then(|frame| frame.parameters.last_mut())
                .and_then(|binding| binding.value.take());
            let disposal = if let Some(payload) = value.as_mut() {
                self.dispose_owned_payload(payload, self.current_source)
            } else {
                Ok(0)
            };
            match disposal {
                Ok(payload) => {
                    released_payload = released_payload
                        .checked_add(payload)
                        .ok_or_else(|| self.evaluator_byte_failure())?;
                }
                Err(error) => {
                    let binding = self
                        .frames
                        .last_mut()
                        .and_then(|frame| frame.parameters.last_mut())
                        .ok_or(EvaluationFailure::Analysis(
                            AnalysisFailure::RequestMismatch,
                        ))?;
                    binding.value = value;
                    return Err(error);
                }
            }
            let binding = self
                .frames
                .last_mut()
                .and_then(|frame| frame.parameters.pop())
                .ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
            drop(binding);
        }
        Ok(released_payload)
    }

    fn dispose_temporary_value(
        &mut self,
        mut value: ComptimeValue,
        source: Span,
    ) -> Result<(), EvaluationFailure> {
        let released_payload = self.dispose_owned_payload(&mut value, source)?;
        drop(value);
        self.release(released_payload)?;
        Ok(())
    }

    fn store(
        &mut self,
        local: LocalId,
        value: ComptimeValue,
        source: Span,
    ) -> Result<(), EvaluationFailure> {
        let declaration = self
            .frames
            .last()
            .map(|frame| frame.declaration)
            .ok_or_else(|| self.unsupported(source))?;
        let valid = self
            .program
            .locals
            .get(local.0 as usize)
            .filter(|record| record.id == local)
            .and_then(|record| self.program.body(record.body))
            .is_some_and(|body| body.owner == wrela_hir::BodyOwner::Declaration(declaration));
        if !valid {
            return Err(self.diagnostic(
                source,
                "semantic-comptime-local",
                "comptime local reference is invalid",
            ));
        }
        let local_count = self.frames.last().map_or(0, |frame| frame.locals.len());
        let mut existing = None;
        for index in 0..local_count {
            self.work()?;
            if self
                .frames
                .last()
                .and_then(|frame| frame.locals.get(index))
                .is_some_and(|binding| binding.id == local)
            {
                existing = Some(index);
                break;
            }
        }
        if let Some(index) = existing {
            let mut old_value = self
                .frames
                .last_mut()
                .and_then(|frame| frame.locals.get_mut(index))
                .and_then(|binding| binding.value.take());
            let disposal = if let Some(payload) = old_value.as_mut() {
                self.dispose_owned_payload(payload, source)
            } else {
                Ok(0)
            };
            let released_payload = match disposal {
                Ok(payload) => payload,
                Err(error) => {
                    let binding = self
                        .frames
                        .last_mut()
                        .and_then(|frame| frame.locals.get_mut(index))
                        .ok_or(EvaluationFailure::Analysis(
                            AnalysisFailure::RequestMismatch,
                        ))?;
                    binding.value = old_value;
                    return Err(error);
                }
            };
            let binding = self
                .frames
                .last_mut()
                .and_then(|frame| frame.locals.get_mut(index))
                .ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
            binding.value = Some(value);
            drop(old_value);
            self.release(released_payload)?;
            return Ok(());
        }
        self.retain_u64(COMPTIME_BINDING_BYTES)?;
        let byte_limit = self.byte_limit;
        let frame = self.frames.last_mut().ok_or(EvaluationFailure::Analysis(
            AnalysisFailure::RequestMismatch,
        ))?;
        frame.locals.try_reserve(1).map_err(|_| {
            EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                resource: "comptime evaluator bytes",
                limit: self.byte_limit,
            })
        })?;
        frame.locals.push(ComptimeBinding {
            id: local,
            value: Some(value),
        });
        frame.charged_bytes = frame
            .charged_bytes
            .checked_add(COMPTIME_BINDING_BYTES)
            .ok_or(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator bytes",
                    limit: byte_limit,
                },
            ))?;
        Ok(())
    }

    fn access_local(
        &mut self,
        local: LocalId,
        source: Span,
        access: ComptimeExpressionAccess,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let local_count = self.frames.last().map_or(0, |frame| frame.locals.len());
        let mut selected = None;
        for index in (0..local_count).rev() {
            self.work()?;
            if self
                .frames
                .last()
                .and_then(|frame| frame.locals.get(index))
                .is_some_and(|binding| binding.id == local)
            {
                selected = Some(index);
                break;
            }
        }
        let index = selected.ok_or_else(|| {
            self.diagnostic(
                source,
                "semantic-comptime-uninitialized",
                "comptime local is used before initialization",
            )
        })?;
        let original = self
            .frames
            .last_mut()
            .and_then(|frame| frame.locals.get_mut(index))
            .and_then(|binding| binding.value.take())
            .ok_or_else(|| {
                self.diagnostic(
                    source,
                    "semantic-comptime-use-after-move",
                    "comptime local is used after its aggregate value was moved",
                )
            })?;
        if access == ComptimeExpressionAccess::Move
            && matches!(&original, ComptimeValue::Structure { .. })
        {
            return Ok(original);
        }
        let value = self.copy_comptime_value(&original);
        let Some(binding) = self
            .frames
            .last_mut()
            .and_then(|frame| frame.locals.get_mut(index))
        else {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::RequestMismatch,
            ));
        };
        binding.value = Some(original);
        value
    }

    fn load_local(
        &mut self,
        local: LocalId,
        source: Span,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        self.access_local(local, source, ComptimeExpressionAccess::Read)
    }

    fn access_parameter(
        &mut self,
        parameter: wrela_hir::ParameterId,
        source: Span,
        access: ComptimeExpressionAccess,
    ) -> Result<ComptimeValue, EvaluationFailure> {
        let parameter_count = self.frames.last().map_or(0, |frame| frame.parameters.len());
        let mut selected = None;
        for index in 0..parameter_count {
            self.work()?;
            if self
                .frames
                .last()
                .and_then(|frame| frame.parameters.get(index))
                .is_some_and(|binding| binding.id == parameter)
            {
                selected = Some(index);
                break;
            }
        }
        let index = selected.ok_or_else(|| {
            self.diagnostic(
                source,
                "semantic-comptime-parameter",
                "comptime parameter reference is invalid in this invocation",
            )
        })?;
        let original = self
            .frames
            .last_mut()
            .and_then(|frame| frame.parameters.get_mut(index))
            .and_then(|binding| binding.value.take())
            .ok_or(EvaluationFailure::Analysis(
                AnalysisFailure::RequestMismatch,
            ))?;
        if access == ComptimeExpressionAccess::Move
            && matches!(&original, ComptimeValue::Structure { .. })
        {
            let Some(binding) = self
                .frames
                .last_mut()
                .and_then(|frame| frame.parameters.get_mut(index))
            else {
                return Err(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ));
            };
            binding.value = Some(original);
            return Err(self.diagnostic(
                source,
                "semantic-comptime-borrowed-value-move",
                "a bare comptime parameter is read-only; use `copy` to produce an owned aggregate result",
            ));
        }
        let value = self.copy_comptime_value(&original);
        let Some(binding) = self
            .frames
            .last_mut()
            .and_then(|frame| frame.parameters.get_mut(index))
        else {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::RequestMismatch,
            ));
        };
        binding.value = Some(original);
        value
    }

    fn local_mut(&mut self, local: LocalId) -> Option<&mut ComptimeValue> {
        self.frames
            .last_mut()?
            .locals
            .iter_mut()
            .rev()
            .find(|binding| binding.id == local)
            .and_then(|binding| binding.value.as_mut())
    }

    fn append_precharged_image_name(
        &mut self,
        image: LocalId,
        value: &str,
        source: Span,
    ) -> Result<(u64, u64), EvaluationFailure> {
        let byte_limit = self.byte_limit;
        let value_len = u64::try_from(value.len()).map_err(|_| self.evaluator_byte_failure())?;
        let name_start = {
            let Some(ComptimeValue::Image(current)) = self.local_mut(image) else {
                return Err(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ));
            };
            current
                .names
                .len()
                .checked_add(value.len())
                .ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
            current.names.try_reserve_exact(value.len()).map_err(|_| {
                EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator bytes",
                    limit: byte_limit,
                })
            })?;
            u64::try_from(current.names.len())
                .map_err(|_| EvaluationFailure::Analysis(AnalysisFailure::RequestMismatch))?
        };
        self.current_source = source;
        let mut copied = 0_usize;
        while copied < value.len() {
            self.work()?;
            let mut end = copied
                .checked_add(COMPTIME_SOURCE_COPY_CHUNK_BYTES)
                .unwrap_or(value.len())
                .min(value.len());
            while end > copied && !value.is_char_boundary(end) {
                end -= 1;
            }
            if end == copied {
                return Err(self.type_mismatch(source));
            }
            let Some(ComptimeValue::Image(current)) = self.local_mut(image) else {
                return Err(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ));
            };
            current.names.push_str(&value[copied..end]);
            copied = end;
        }
        Ok((name_start, value_len))
    }

    fn work(&mut self) -> Result<(), EvaluationFailure> {
        check_cancelled(self.is_cancelled).map_err(EvaluationFailure::Analysis)?;
        let Some(steps) = self.steps.checked_add(1) else {
            self.resource_source = Some(self.current_source);
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator steps",
                    limit: self.step_limit,
                },
            ));
        };
        self.steps = steps;
        if self.steps > self.step_limit {
            self.resource_source = Some(self.current_source);
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator steps",
                    limit: self.step_limit,
                },
            ));
        }
        Ok(())
    }

    fn enter_syntax(&mut self, depth: u32) -> Result<(), EvaluationFailure> {
        if depth > COMPTIME_SYNTAX_DEPTH {
            self.resource_source = Some(self.current_source);
            Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "comptime evaluator syntax depth",
                    limit: u64::from(COMPTIME_SYNTAX_DEPTH),
                },
            ))
        } else if self
            .frames
            .last()
            .map_or(0, |frame| frame.host_depth)
            .checked_add(depth)
            .is_none_or(|host_depth| host_depth > COMPTIME_HOST_RECURSION_DEPTH)
        {
            self.resource_source = Some(self.current_source);
            Err(self.host_recursion_failure())
        } else {
            Ok(())
        }
    }

    fn retain(&mut self, bytes: usize) -> Result<(), EvaluationFailure> {
        let bytes = u64::try_from(bytes).map_err(|_| self.evaluator_byte_failure())?;
        self.retain_u64(bytes)
    }

    fn retain_u64(&mut self, bytes: u64) -> Result<(), EvaluationFailure> {
        let Some(retained_bytes) = self.retained_bytes.checked_add(bytes) else {
            self.resource_source = Some(self.current_source);
            return Err(self.evaluator_byte_failure());
        };
        if retained_bytes > self.byte_limit {
            self.resource_source = Some(self.current_source);
            return Err(self.evaluator_byte_failure());
        }
        self.retained_bytes = retained_bytes;
        self.peak_bytes = self.peak_bytes.max(self.retained_bytes);
        Ok(())
    }

    fn release(&mut self, bytes: u64) -> Result<(), EvaluationFailure> {
        self.retained_bytes =
            self.retained_bytes
                .checked_sub(bytes)
                .ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ))?;
        Ok(())
    }

    fn unsupported(&self, source: Span) -> EvaluationFailure {
        self.diagnostic(
            source,
            "semantic-comptime-operation-not-implemented",
            "this comptime operation is not yet implemented by the production semantic analyzer",
        )
    }

    fn aggregate_not_supported(&self, source: Span) -> EvaluationFailure {
        self.diagnostic(
            source,
            "semantic-comptime-aggregate-not-supported",
            "comptime aggregate values currently support only nongeneric structures with scalar fields and no defaults or interface specializations",
        )
    }

    fn diagnostic(&self, source: Span, code: &str, message: &str) -> EvaluationFailure {
        self.diagnostic_category(Category::COMPTIME, source, code, message)
    }

    fn diagnostic_owned(&self, source: Span, code: &str, message: String) -> EvaluationFailure {
        let mut diagnostic = Diagnostic::error(Category::COMPTIME, source, message);
        diagnostic.code = Some(code.to_owned());
        self.finish_diagnostic(diagnostic)
    }

    fn stack_label(
        &self,
        declaration: DeclarationId,
        call_source: Span,
        label_bytes: usize,
    ) -> Result<wrela_diagnostics::Label, EvaluationFailure> {
        const PREFIX: &str = "comptime call to `";
        const SUFFIX: &str = "` entered here";
        let declaration = self
            .program
            .declaration(declaration)
            .ok_or_else(|| self.evaluator_byte_failure())?;
        let module = self
            .program
            .modules
            .get(declaration.module.0 as usize)
            .ok_or_else(|| self.evaluator_byte_failure())?;
        let name = declaration
            .name
            .as_ref()
            .map(wrela_hir::Name::as_str)
            .ok_or_else(|| self.evaluator_byte_failure())?;
        let mut message = String::new();
        message
            .try_reserve_exact(label_bytes)
            .map_err(|_| self.evaluator_byte_failure())?;
        message.push_str(PREFIX);
        for (index, segment) in module.path.segments().iter().enumerate() {
            check_cancelled(self.is_cancelled).map_err(EvaluationFailure::Analysis)?;
            if index != 0 {
                message.push('.');
            }
            self.append_polled_source_text(&mut message, segment)?;
        }
        message.push('.');
        self.append_polled_source_text(&mut message, name)?;
        message.push_str(SUFFIX);
        if message.len() != label_bytes {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::RequestMismatch,
            ));
        }
        Ok(wrela_diagnostics::Label {
            span: call_source,
            message,
        })
    }

    fn stack_label_bytes(&self, declaration: DeclarationId) -> Result<usize, EvaluationFailure> {
        const PREFIX: &str = "comptime call to `";
        const SUFFIX: &str = "` entered here";
        let declaration = self
            .program
            .declaration(declaration)
            .ok_or_else(|| self.evaluator_byte_failure())?;
        let module = self
            .program
            .modules
            .get(declaration.module.0 as usize)
            .ok_or_else(|| self.evaluator_byte_failure())?;
        let name = declaration
            .name
            .as_ref()
            .map(wrela_hir::Name::as_str)
            .ok_or_else(|| self.evaluator_byte_failure())?;
        let mut module_bytes = 0usize;
        for (index, segment) in module.path.segments().iter().enumerate() {
            check_cancelled(self.is_cancelled).map_err(EvaluationFailure::Analysis)?;
            module_bytes = module_bytes
                .checked_add(usize::from(index != 0))
                .and_then(|bytes| bytes.checked_add(segment.len()))
                .ok_or_else(|| self.evaluator_byte_failure())?;
        }
        PREFIX
            .len()
            .checked_add(module_bytes)
            .and_then(|bytes| bytes.checked_add(1))
            .and_then(|bytes| bytes.checked_add(name.len()))
            .and_then(|bytes| bytes.checked_add(SUFFIX.len()))
            .ok_or_else(|| self.evaluator_byte_failure())
    }

    fn append_polled_source_text(
        &self,
        output: &mut String,
        value: &str,
    ) -> Result<(), EvaluationFailure> {
        let mut start = 0;
        while start < value.len() {
            check_cancelled(self.is_cancelled).map_err(EvaluationFailure::Analysis)?;
            let mut end = start
                .checked_add(COMPTIME_SOURCE_COPY_CHUNK_BYTES)
                .unwrap_or(value.len())
                .min(value.len());
            while end > start && !value.is_char_boundary(end) {
                end -= 1;
            }
            if end == start {
                return Err(EvaluationFailure::Analysis(
                    AnalysisFailure::RequestMismatch,
                ));
            }
            output.push_str(&value[start..end]);
            start = end;
        }
        Ok(())
    }

    fn diagnostic_category(
        &self,
        category: Category,
        source: Span,
        code: &str,
        message: &str,
    ) -> EvaluationFailure {
        let mut diagnostic = Diagnostic::error(category, source, message);
        diagnostic.code = Some(code.to_owned());
        self.finish_diagnostic(diagnostic)
    }

    fn finish_diagnostic(&self, mut diagnostic: Diagnostic) -> EvaluationFailure {
        let diagnostic_limit = self.request.limits.diagnostic_bytes;
        let test_limit = self.request.limits.test_bytes;
        let mut diagnostic_bytes = diagnostic
            .message
            .len()
            .saturating_add(diagnostic.code.as_ref().map_or(0, String::len));
        for label in &diagnostic.labels {
            diagnostic_bytes = diagnostic_bytes.saturating_add(label.message.len());
        }
        let output_limit_failure = |resource, limit| {
            EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit { resource, limit })
        };
        if u64::try_from(diagnostic_bytes).map_or(true, |bytes| bytes > diagnostic_limit) {
            return output_limit_failure("diagnostic bytes", diagnostic_limit);
        }
        if u64::try_from(diagnostic_bytes).map_or(true, |bytes| bytes > test_limit) {
            return output_limit_failure("test plan or results", test_limit);
        }
        let stack_entries = usize::from(self.attempted_call.is_some()).saturating_add(
            self.frames
                .iter()
                .filter(|frame| frame.call_source.is_some())
                .count(),
        );
        if stack_entries != 0 {
            if diagnostic.labels.try_reserve_exact(stack_entries).is_err() {
                return self.evaluator_byte_failure();
            }
            if let Some((declaration, call_source)) = self.attempted_call {
                let label_bytes = match self.stack_label_bytes(declaration) {
                    Ok(bytes) => bytes,
                    Err(error) => return error,
                };
                if let Err(error) =
                    self.charge_stack_label_output(label_bytes, &mut diagnostic_bytes)
                {
                    return error;
                }
                match self.stack_label(declaration, call_source, label_bytes) {
                    Ok(label) => diagnostic.labels.push(label),
                    Err(error) => return error,
                }
            }
            for frame in self.frames.iter().rev() {
                if let Some(call_source) = frame.call_source {
                    let label_bytes = match self.stack_label_bytes(frame.declaration) {
                        Ok(bytes) => bytes,
                        Err(error) => return error,
                    };
                    if let Err(error) =
                        self.charge_stack_label_output(label_bytes, &mut diagnostic_bytes)
                    {
                        return error;
                    }
                    match self.stack_label(frame.declaration, call_source, label_bytes) {
                        Ok(label) => diagnostic.labels.push(label),
                        Err(error) => return error,
                    }
                }
            }
        }
        EvaluationFailure::Diagnostic(Box::new(diagnostic))
    }

    fn charge_stack_label_output(
        &self,
        label_bytes: usize,
        diagnostic_bytes: &mut usize,
    ) -> Result<(), EvaluationFailure> {
        *diagnostic_bytes =
            diagnostic_bytes
                .checked_add(label_bytes)
                .ok_or(EvaluationFailure::Analysis(
                    AnalysisFailure::ResourceLimit {
                        resource: "diagnostic bytes",
                        limit: self.request.limits.diagnostic_bytes,
                    },
                ))?;
        let output_bytes = u64::try_from(*diagnostic_bytes).map_err(|_| {
            EvaluationFailure::Analysis(AnalysisFailure::ResourceLimit {
                resource: "diagnostic bytes",
                limit: self.request.limits.diagnostic_bytes,
            })
        })?;
        if output_bytes > self.request.limits.diagnostic_bytes {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "diagnostic bytes",
                    limit: self.request.limits.diagnostic_bytes,
                },
            ));
        }
        if output_bytes > self.request.limits.test_bytes {
            return Err(EvaluationFailure::Analysis(
                AnalysisFailure::ResourceLimit {
                    resource: "test plan or results",
                    limit: self.request.limits.test_bytes,
                },
            ));
        }
        Ok(())
    }
}

enum Control {
    Continue,
    Return(ComptimeValue),
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ActorMethodRole {
    Turn,
    Task(TaskId),
}

#[derive(Debug)]
struct ActorMethodPlan {
    declaration: DeclarationId,
    body: BodyId,
    role: ActorMethodRole,
    color: FunctionColor,
    source: Span,
    runtime_statements: Vec<StatementId>,
    has_send: bool,
    await_sources: Vec<Span>,
    function: Option<FunctionInstanceId>,
}

#[derive(Debug)]
struct ActorPlan {
    id: ActorId,
    evaluated: EvaluatedActor,
    class_source: Span,
    state_source: Option<Span>,
    methods: Vec<ActorMethodPlan>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ActorStateShape {
    Stateless,
    CanonicalZeroU64 { source: Span },
    WiringField { source: Span },
    InitializerRequired { source: Span },
    InitializerPending { source: Span },
    ShapePending { source: Span },
}

fn actor_state_shape(
    program: &wrela_hir::Program,
    class: &wrela_hir::AggregateDeclaration,
) -> ActorStateShape {
    let [] = class.fields.as_slice() else {
        let [field] = class.fields.as_slice() else {
            return ActorStateShape::ShapePending {
                source: class.fields[1].source,
            };
        };
        if matches!(
            field.ty.kind,
            TypeExpressionKind::Named {
                definition: Definition::Builtin(Builtin::Actor),
                ..
            }
        ) {
            return ActorStateShape::WiringField {
                source: field.source,
            };
        }
        if field.name.as_str() != "value"
            || !matches!(
                field.ty.kind,
                TypeExpressionKind::Named {
                    definition: Definition::Builtin(Builtin::U64),
                    ref arguments,
                } if arguments.is_empty()
            )
        {
            return ActorStateShape::ShapePending {
                source: field.source,
            };
        }
        let Some(default) = field.default else {
            return ActorStateShape::InitializerRequired {
                source: field.source,
            };
        };
        let Some(expression) = program.expression(default) else {
            return ActorStateShape::InitializerPending {
                source: field.source,
            };
        };
        return if matches!(&expression.kind, ExpressionKind::Literal(wrela_hir::Literal::Integer(value)) if value == "0")
        {
            ActorStateShape::CanonicalZeroU64 {
                source: field.source,
            }
        } else {
            ActorStateShape::InitializerPending {
                source: expression.source,
            }
        };
    };
    ActorStateShape::Stateless
}

fn populate_evaluated_image(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    constructor: DeclarationId,
    mut image: EvaluatedImage,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Option<Diagnostic>, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let image_name = copy_analysis_text(
        image.name().ok_or(AnalysisFailure::RequestMismatch)?,
        request.limits.fact_bytes,
        is_cancelled,
    )?;
    let actors = std::mem::take(&mut image.actors);
    let names = std::mem::take(&mut image.names);
    let checkpoint = RuntimeCheckpoint::new(partial);
    populate_minimum_image(request, partial, constructor, image_name)?;
    if actors.is_empty() {
        return Ok(None);
    }
    match populate_actor_image(request, partial, actors, &names, is_cancelled) {
        Ok(()) => Ok(None),
        Err(RuntimeFailure::Diagnostic(diagnostic)) => {
            checkpoint.rollback(partial);
            partial.graph = None;
            Ok(Some(*diagnostic))
        }
        Err(RuntimeFailure::Analysis(error)) => {
            checkpoint.rollback(partial);
            partial.graph = None;
            Err(error)
        }
    }
}

fn inspect_actor_plans(
    request: &AnalysisRequest<'_>,
    actors: Vec<EvaluatedActor>,
    actor_names: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<Vec<ActorPlan>> {
    if actors.len() > request.limits.image_nodes as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "image actor nodes",
            limit: u64::from(request.limits.image_nodes),
        }
        .into());
    }
    let program = request.hir.as_program();
    if actors.iter().any(|actor| actor.dependency.is_some())
        && !matches!(
            actors.as_slice(),
            [service, client]
                if service.kind == EvaluatedActorKind::Service
                    && service.dependency.is_none()
                    && service.mailbox_capacity == 1
                    && client.kind == EvaluatedActorKind::App
                    && client.dependency == Some(0)
                    && client.mailbox_capacity == 1
        )
    {
        let source = actors
            .iter()
            .find_map(|actor| actor.wiring_source)
            .or_else(|| actors.last().map(|actor| actor.source))
            .ok_or(AnalysisFailure::RequestMismatch)?;
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            source,
            "semantic-actor-wiring-shape",
            "cross-actor wiring admits exactly one service and one dependent app with unit mailboxes",
            "install the service first, pass its unique handle to one app, and use mailbox=1 for both actors",
        ));
    }
    let mut plans = Vec::new();
    plans
        .try_reserve_exact(actors.len())
        .map_err(|_| fact_resource(request, "actor analysis plans"))?;
    let mut next_task = 0u32;
    for (actor_index, actor) in actors.into_iter().enumerate() {
        check_cancelled(is_cancelled)?;
        actor
            .name_in(actor_names)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let declaration = program
            .declaration(actor.class)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let DeclarationKind::Structure(class) = &declaration.kind else {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                actor.source,
                "semantic-actor-install-class",
                "installed actor declaration is not a struct",
                "install an @app or @service struct",
            ));
        };
        if declaration.visibility != wrela_hir::Visibility::Public
            || !class.generics.is_empty()
            || !class.implements.is_empty()
        {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                declaration.source,
                "semantic-actor-struct-shape",
                "actor struct must be public, concrete, and non-generic in this revision 0.1 slice",
                "remove generic and interface specialization from the installed actor struct",
            ));
        }
        let state_source = if actor.dependency.is_none() {
            match actor_state_shape(program, class) {
                ActorStateShape::Stateless => None,
                ActorStateShape::CanonicalZeroU64 { source } => Some(source),
                ActorStateShape::WiringField { source } => {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        source,
                        "semantic-actor-wiring-missing",
                        "an actor handle field requires one matching image installation argument",
                        "pass the unique installed service handle by the declared field name",
                    ));
                }
                ActorStateShape::InitializerRequired { source } => {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        source,
                        "semantic-actor-state-initializer-required",
                        "the admitted actor state field requires an explicit initializer",
                        "initialize the exact field as `value: u64 = 0`",
                    ));
                }
                ActorStateShape::InitializerPending { source } => {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        source,
                        "semantic-actor-state-initializer-pending",
                        "actor state initialization currently admits only canonical zero",
                        "initialize the exact field as `value: u64 = 0`",
                    ));
                }
                ActorStateShape::ShapePending { source } => {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        source,
                        "semantic-actor-state-shape-pending",
                        "actor state storage currently admits exactly `value: u64 = 0`",
                        "use one private u64 field named `value` with a zero initializer",
                    ));
                }
            }
        } else {
            None
        };
        let mut actor_attribute = None;
        let mut duplicate_actor_attribute = false;
        for attribute in &declaration.attributes {
            check_cancelled(is_cancelled)?;
            if matches!(
                attribute.identity,
                wrela_hir::AttributeIdentity::Builtin(
                    wrela_hir::BuiltinAttribute::App
                        | wrela_hir::BuiltinAttribute::Service
                        | wrela_hir::BuiltinAttribute::Driver
                )
            ) && actor_attribute.replace(attribute).is_some()
            {
                duplicate_actor_attribute = true;
            }
        }
        if duplicate_actor_attribute
            || actor_attribute.is_none_or(|attribute| {
                attribute.identity != wrela_hir::AttributeIdentity::Builtin(actor.kind.attribute())
                    || !attribute.arguments.is_empty()
            })
        {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                declaration.source,
                "semantic-actor-role",
                "installed actor struct has an ambiguous or mismatched actor role",
                "declare exactly one matching @app or @service attribute without arguments",
            ));
        }
        let mut methods = Vec::new();
        methods
            .try_reserve_exact(class.members.len())
            .map_err(|_| fact_resource(request, "actor method plans"))?;
        for member_id in &class.members {
            check_cancelled(is_cancelled)?;
            let member = program
                .declaration(*member_id)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let DeclarationKind::Function(function) = &member.kind else {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    member.source,
                    "semantic-actor-member-kind",
                    "actor structs in this slice may contain only runtime functions",
                    "move nested types and protocols outside the actor struct",
                ));
            };
            if function.color == FunctionColor::Isr {
                if let Some(interpolation) = function
                    .body
                    .and_then(|body| program.body(body))
                    .and_then(|body| {
                        body.statements.iter().find_map(|statement| {
                            let StatementKind::Initialize { value, .. } =
                                &program.statement(*statement)?.kind
                            else {
                                return None;
                            };
                            program.expression(*value).filter(|expression| {
                                matches!(expression.kind, ExpressionKind::Interpolate(_))
                            })
                        })
                    })
                {
                    return Err(actor_runtime_diagnostic(
                        Category::HARDWARE,
                        interpolation.source,
                        "semantic-bounded-interpolation-isr",
                        "bounded interpolation is forbidden in an interrupt handler",
                        "formatting work and destination storage are not admitted in ISR context",
                    ));
                }
                return Err(actor_runtime_diagnostic(
                    Category::HARDWARE,
                    member.source,
                    "semantic-isr-not-supported",
                    "ISR actor members require a concrete target device and interrupt binding",
                    "bind the ISR through a supported driver/device image installation",
                ));
            }
            if !function.generics.is_empty() {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    member.source,
                    "semantic-actor-method-shape",
                    "actor runtime methods must be concrete sync or async functions",
                    "remove generic parameters from the installed runtime method",
                ));
            }
            let mut task_attribute = None;
            let mut no_promote_attribute = None;
            let mut method_attribute_invalid = false;
            for attribute in &member.attributes {
                check_cancelled(is_cancelled)?;
                if attribute.identity
                    == wrela_hir::AttributeIdentity::Builtin(wrela_hir::BuiltinAttribute::Task)
                {
                    if task_attribute.replace(attribute).is_some() {
                        method_attribute_invalid = true;
                    }
                } else if attribute.identity
                    == wrela_hir::AttributeIdentity::Builtin(wrela_hir::BuiltinAttribute::NoPromote)
                {
                    if no_promote_attribute.replace(attribute).is_some() {
                        method_attribute_invalid = true;
                    }
                } else {
                    method_attribute_invalid = true;
                }
            }
            if method_attribute_invalid
                || task_attribute.is_some_and(|attribute| !attribute.arguments.is_empty())
                || no_promote_attribute.is_some_and(|attribute| !attribute.arguments.is_empty())
            {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    member.source,
                    "semantic-actor-method-attribute",
                    "actor method attributes are outside the supported static task subset",
                    "use at most one bare @task and one bare @no_promote attribute",
                ));
            }
            let role = if task_attribute.is_none() {
                if member.visibility != wrela_hir::Visibility::Public {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        member.source,
                        "semantic-actor-private-helper-not-supported",
                        "private actor helpers are not yet closed by this actor-body slice",
                        "move the helper to a module-level concrete function",
                    ));
                }
                ActorMethodRole::Turn
            } else {
                let task = TaskId(next_task);
                next_task = next_task
                    .checked_add(1)
                    .ok_or_else(|| fact_resource(request, "image task nodes"))?;
                ActorMethodRole::Task(task)
            };
            let Some(body) = function.body else {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    member.source,
                    "semantic-actor-method-body",
                    "installed actor method must have a body",
                    "provide a concrete bounded runtime body",
                ));
            };
            let unit_result = test_result_is_unit(function.result.as_ref());
            let bounded_reply_result = matches!(role, ActorMethodRole::Turn)
                && actor_reply_result_is_u64(function.result.as_ref());
            if (!unit_result && !bounded_reply_result) || function.parameters.is_empty() {
                return Err(actor_runtime_diagnostic(
                    Category::TYPE,
                    member.source,
                    "semantic-actor-method-signature",
                    "actor methods require a receiver and an admitted bounded result",
                    "use unit, or u64 on a public turn consumed by the exact single-flight reply path",
                ));
            }
            let receiver = program
                .parameter(function.parameters[0])
                .ok_or(AnalysisFailure::RequestMismatch)?;
            if !receiver.receiver || receiver.access != wrela_hir::AccessMode::Mutate {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    receiver.source,
                    "semantic-actor-receiver",
                    "actor turn and task methods require the actor-owned `mut self` receiver",
                    "declare `mut self` as the first parameter",
                ));
            }
            let mut runtime_statements = Vec::new();
            let mut runtime_callees = Vec::new();
            match inspect_runtime_body_shape(
                request,
                body,
                function.color,
                false,
                &mut runtime_statements,
                &mut runtime_callees,
                is_cancelled,
            ) {
                Ok(()) => {}
                Err(RuntimeShapeFailure::Unsupported(source)) => {
                    return Err(actor_runtime_diagnostic(
                        Category::ASYNC,
                        source,
                        "semantic-actor-body-not-supported",
                        "actor body is outside the bounded scalar async subset",
                        "use scalar locals, direct calls, await, return, and no-phi conditionals",
                    ));
                }
                Err(RuntimeShapeFailure::UnsupportedAssertion(source)) => {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        source,
                        "semantic-runtime-assertion-not-supported",
                        "runtime assertions are supported only in selected generated tests",
                        "actor abandonment and supervision are required before assertion failure can terminate a turn",
                    ));
                }
                Err(RuntimeShapeFailure::Failure(error)) => return Err(error.into()),
            }
            let closure = collect_source_body_closure(program, body, is_cancelled)?;
            let has_send = runtime_statements.iter().any(|statement| {
                program
                    .statement(*statement)
                    .is_some_and(|statement| matches!(statement.kind, StatementKind::Send(_)))
            });
            let mut await_sources = Vec::new();
            await_sources
                .try_reserve_exact(closure.expressions.len())
                .map_err(|_| fact_resource(request, "async suspension points"))?;
            for expression in closure.expressions {
                check_cancelled(is_cancelled)?;
                let expression = program
                    .expression(expression)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                if matches!(
                    expression.kind,
                    ExpressionKind::Unary {
                        operator: wrela_hir::UnaryOperator::Await,
                        ..
                    }
                ) {
                    await_sources.push(expression.source);
                }
            }
            cancellable_stable_sort_by(
                &mut await_sources,
                u64::from(request.limits.expression_facts),
                "async suspension-point sort scratch",
                is_cancelled,
                &|left, right| {
                    Ok((left.file, left.range.start, left.range.end).cmp(&(
                        right.file,
                        right.range.start,
                        right.range.end,
                    )))
                },
            )?;
            if let Some(await_source) = await_sources.first().copied() {
                for parameter_id in function.parameters.iter().skip(1) {
                    let parameter = program
                        .parameter(*parameter_id)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    if matches!(
                        parameter.access,
                        wrela_hir::AccessMode::Read | wrela_hir::AccessMode::Mutate
                    ) || parameter
                        .ty
                        .as_ref()
                        .is_some_and(|ty| matches!(ty.kind, TypeExpressionKind::View { .. }))
                    {
                        let mut diagnostic = Diagnostic::error(
                            Category::ASYNC,
                            await_source,
                            "borrowed access may not remain live across actor suspension",
                        );
                        diagnostic.code = Some("semantic-view-across-await".to_owned());
                        diagnostic
                            .labels
                            .try_reserve_exact(1)
                            .map_err(|_| fact_resource(request, "async diagnostic labels"))?;
                        diagnostic.labels.push(wrela_diagnostics::Label {
                            span: parameter.source,
                            message: "this external loan belongs to the caller".to_owned(),
                        });
                        diagnostic.notes.push(
                            "only the turn-rooted self access is stable while the non-reentrant actor is suspended"
                                .to_owned(),
                        );
                        diagnostic.help.push(
                            "copy or take the required value before await, then reacquire any view afterward"
                                .to_owned(),
                        );
                        return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
                    }
                }
            }
            methods.push(ActorMethodPlan {
                declaration: *member_id,
                body,
                role,
                color: function.color,
                source: member.source,
                runtime_statements,
                has_send,
                await_sources,
                function: None,
            });
        }
        if methods.is_empty() {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                declaration.source,
                "semantic-actor-empty",
                "installed actor has no public turn or static task entry",
                "add a public method or bare @task method",
            ));
        }
        plans.push(ActorPlan {
            id: ActorId(
                u32::try_from(actor_index)
                    .map_err(|_| fact_resource(request, "image actor nodes"))?,
            ),
            evaluated: actor,
            class_source: declaration.source,
            state_source,
            methods,
        });
    }
    let total_nodes = plans
        .len()
        .checked_add(
            usize::try_from(next_task).map_err(|_| fact_resource(request, "image task nodes"))?,
        )
        .ok_or_else(|| fact_resource(request, "image actor and task nodes"))?;
    if total_nodes > request.limits.image_nodes as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "image actor and task nodes",
            limit: u64::from(request.limits.image_nodes),
        }
        .into());
    }
    Ok(plans)
}

fn actor_runtime_diagnostic(
    category: Category,
    source: Span,
    code: &'static str,
    message: &'static str,
    help: &'static str,
) -> RuntimeFailure {
    let mut diagnostic = Diagnostic::error(category, source, message);
    diagnostic.code = Some(code.to_owned());
    diagnostic.help.push(help.to_owned());
    RuntimeFailure::Diagnostic(Box::new(diagnostic))
}

#[derive(Debug, Clone, Copy)]
struct ResolvedActorSend {
    actor: ActorId,
    receiver: ExpressionId,
    handle: Option<ExpressionId>,
    method: FunctionInstanceId,
    mailbox_proof: ProofId,
    source: Span,
}

fn resolve_self_actor_send(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    caller: FunctionInstanceId,
    expression: ExpressionId,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<ResolvedActorSend> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let call = program
        .expression(expression)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let ExpressionKind::Call { callee, arguments } = &call.kind else {
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            call.source,
            "semantic-actor-send-call",
            "one-way send requires an actor method call",
            "write `send self.method()` in the bounded startup-task subset",
        ));
    };
    if !arguments.is_empty() {
        return Err(actor_runtime_diagnostic(
            Category::TYPE,
            call.source,
            "semantic-actor-send-payload-not-supported",
            "one-way send payload is outside the implemented unit-message subset",
            "use a unit-returning actor method with no message parameters",
        ));
    }
    let callee_expression = program
        .expression(*callee)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let ExpressionKind::Field { base, name } = &callee_expression.kind else {
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            callee_expression.source,
            "semantic-actor-send-receiver",
            "the implemented one-way send subset requires the image-wired self actor",
            "send from a static @task with `send self.method()`",
        ));
    };
    let base_expression = program
        .expression(*base)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let (receiver_expression, receiver, dependency_name, handle) = match &base_expression.kind {
        ExpressionKind::Reference(Definition::Parameter(receiver)) => {
            (*base, *receiver, None, None)
        }
        ExpressionKind::Field {
            base: receiver_expression,
            name,
        } => {
            let receiver = program
                .expression(*receiver_expression)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let ExpressionKind::Reference(Definition::Parameter(receiver)) = receiver.kind else {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    base_expression.source,
                    "semantic-actor-send-receiver",
                    "one-way send cannot use an escaped or substituted actor handle",
                    "send only through the app's image-wired Actor[Service] field",
                ));
            };
            (*receiver_expression, receiver, Some(name), Some(*base))
        }
        _ => {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                base_expression.source,
                "semantic-actor-send-receiver",
                "one-way send cannot use an escaped or substituted actor handle",
                "send from a startup task through self or the app's image-wired Actor[Service] field",
            ));
        }
    };
    let caller_record = partial
        .functions
        .get(caller.0 as usize)
        .filter(|function| function.id == caller)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if caller_record
        .parameters
        .first()
        .is_none_or(|parameter| parameter.parameter != receiver)
    {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    let graph = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let source_actor = match caller_record.role {
        FunctionRole::TaskEntry(task_id) => graph
            .tasks
            .get(task_id.0 as usize)
            .filter(|task| task.id == task_id)
            .and_then(|task| task.supervisor)
            .ok_or(AnalysisFailure::RequestMismatch)?,
        FunctionRole::ActorTurn(actor) => actor,
        _ => {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                call.source,
                "semantic-actor-send-producer",
                "one-way send requires a bounded startup task or an admitted non-reentrant actor turn",
                "move the send into a bare @task, or publish one next turn from the current actor turn",
            ));
        }
    };
    let source_actor_record = graph
        .actors
        .get(source_actor.0 as usize)
        .filter(|record| record.id == source_actor)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let actor = if let Some(dependency_name) = dependency_name {
        if graph.actors.len() != 2 || source_actor != ActorId(1) {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                base_expression.source,
                "semantic-actor-send-receiver",
                "cross-actor send requires the unique image-wired app-to-service edge",
                "install exactly one service and one app, then send through the app Actor field",
            ));
        }
        let source_class = partial
            .types
            .get(source_actor_record.class.0 as usize)
            .and_then(|ty| match ty.kind {
                SemanticTypeKind::Class { declaration, .. } => Some(declaration),
                _ => None,
            })
            .and_then(|declaration| program.declaration(declaration))
            .and_then(|declaration| match &declaration.kind {
                DeclarationKind::Structure(class) => Some(class),
                _ => None,
            })
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let field = source_class
            .fields
            .iter()
            .find(|field| &field.name == dependency_name)
            .ok_or_else(|| {
                actor_runtime_diagnostic(
                    Category::ACTOR,
                    base_expression.source,
                    "semantic-actor-send-receiver",
                    "the selected actor handle is not the image-wired dependency field",
                    "send through the app's single Actor[Service] field",
                )
            })?;
        let TypeExpressionKind::Named {
            definition: Definition::Builtin(Builtin::Actor),
            arguments,
        } = &field.ty.kind
        else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        let [argument] = arguments.as_slice() else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        let wrela_hir::GenericArgumentKind::Type(TypeExpression {
            kind:
                TypeExpressionKind::Named {
                    definition: Definition::Declaration(target),
                    arguments,
                },
            ..
        }) = &argument.kind
        else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if !arguments.is_empty() {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        graph
            .actors
            .iter()
            .find(|candidate| {
                partial.types.get(candidate.class.0 as usize).is_some_and(|ty| {
                    matches!(ty.kind, SemanticTypeKind::Class { declaration, .. } if declaration == target.declaration)
                })
            })
            .map(|candidate| candidate.id)
            .filter(|target| *target == ActorId(0))
            .ok_or(AnalysisFailure::RequestMismatch)?
    } else {
        source_actor
    };
    let actor_record = graph
        .actors
        .get(actor.0 as usize)
        .filter(|record| record.id == actor)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if matches!(caller_record.role, FunctionRole::ActorTurn(_))
        && (dependency_name.is_some() || source_actor != actor)
    {
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            call.source,
            "semantic-actor-send-producer",
            "actor-turn sends may only publish to the same non-reentrant actor",
            "publish the next message through self after the current turn receives its mailbox entry",
        ));
    }
    let mut method = None;
    for candidate in &actor_record.turn_functions {
        check_cancelled(is_cancelled)?;
        let candidate_record = partial
            .functions
            .get(candidate.0 as usize)
            .filter(|function| function.id == *candidate)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let matches_name = match candidate_record.origin {
            FunctionOrigin::Source { declaration, .. } => program
                .declaration(declaration)
                .and_then(|declaration| declaration.name.as_ref())
                .is_some_and(|candidate_name| candidate_name == name),
            _ => false,
        };
        if matches_name && method.replace(*candidate).is_some() {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    let method = method.ok_or_else(|| {
        actor_runtime_diagnostic(
            Category::ACTOR,
            callee_expression.source,
            "semantic-actor-send-target",
            "one-way send target is not a public turn on the image-wired actor",
            "name one public unit-message actor method",
        )
    })?;
    if matches!(caller_record.role, FunctionRole::ActorTurn(_)) && method == caller {
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            call.source,
            "semantic-actor-send-producer",
            "an actor turn cannot republish itself in the bounded recurring subset",
            "publish one distinct terminal turn so the capacity-one drain is acyclic",
        ));
    }
    let method_record = partial
        .functions
        .get(method.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let result_is_unit_or_u64 = partial
        .types
        .get(method_record.result.0 as usize)
        .is_some_and(|ty| {
            ty.kind == SemanticTypeKind::Unit
                || matches!(
                    ty.kind,
                    SemanticTypeKind::Integer {
                        signed: false,
                        bits: 64,
                        ..
                    }
                )
        });
    if method_record.role != FunctionRole::ActorTurn(actor)
        || method_record.color != FunctionColor::Async
        || method_record.parameters.len() != 1
        || !result_is_unit_or_u64
    {
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            callee_expression.source,
            "semantic-actor-send-target",
            "actor request target must be one async unit-message actor turn with unit or u64 result",
            "declare `pub async fn method(mut self)` with a bounded body and an admitted result",
        ));
    }
    let mut mailbox_proof = None;
    for region in &graph.regions {
        check_cancelled(is_cancelled)?;
        if region.owner == ImageOwner::Actor(actor)
            && region.class == RegionClass::Image
            && mailbox_proof.replace(region.proof).is_some()
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    Ok(ResolvedActorSend {
        actor,
        receiver: receiver_expression,
        handle,
        method,
        mailbox_proof: mailbox_proof.ok_or(AnalysisFailure::RequestMismatch)?,
        source: call.source,
    })
}

fn ensure_actor_handle_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    class: SemanticTypeId,
) -> Result<SemanticTypeId, AnalysisFailure> {
    if let Some(existing) = partial
        .types
        .iter()
        .find(|ty| ty.kind == SemanticTypeKind::Actor { class })
    {
        return Ok(existing.id);
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "actor handle type"));
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len())
            .map_err(|_| fact_resource(request, "actor handle type"))?,
    );
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Actor { class },
        linearity: Linearity::ExplicitCopy,
        size_upper_bound: Some(8),
        alignment_lower_bound: 8,
        source: None,
    });
    Ok(id)
}

fn ensure_actor_reservation_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
) -> Result<SemanticTypeId, AnalysisFailure> {
    if let Some(existing) = partial
        .types
        .iter()
        .find(|ty| ty.kind == SemanticTypeKind::Reservation)
    {
        return Ok(existing.id);
    }
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "actor reservation type"));
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len())
            .map_err(|_| fact_resource(request, "actor reservation type"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "actor reservation type"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Reservation,
        linearity: Linearity::StrictLinear,
        size_upper_bound: Some(8),
        alignment_lower_bound: 8,
        source: None,
    });
    Ok(id)
}

fn prepare_actor_sends(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    plans: &[ActorPlan],
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    check_cancelled(is_cancelled)?;
    let actor_count = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?
        .actors
        .len();
    let mut direct_edges = Vec::new();
    direct_edges
        .try_reserve_exact(3)
        .map_err(|_| fact_resource(request, "actor send chain"))?;
    let mut attempted = Vec::new();
    attempted
        .try_reserve_exact(actor_count)
        .map_err(|_| fact_resource(request, "actor try-send attempt counts"))?;
    attempted.resize(actor_count, 0u32);
    let mut reply_requests = 0_u32;
    let mut reply_target = None;
    let mut needs_reservation = false;
    for plan in plans {
        for method in &plan.methods {
            check_cancelled(is_cancelled)?;
            let caller = method.function.ok_or(AnalysisFailure::RequestMismatch)?;
            for statement in &method.runtime_statements {
                check_cancelled(is_cancelled)?;
                let statement = request
                    .hir
                    .as_program()
                    .statement(*statement)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                let StatementKind::Send(expression) = statement.kind else {
                    continue;
                };
                needs_reservation = true;
                let resolved =
                    resolve_self_actor_send(request, partial, caller, expression, is_cancelled)?;
                if direct_edges.len() == 3 {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        statement.source,
                        "semantic-actor-send-chain",
                        "one-way sends exceed the implemented bounded recurring chain",
                        "use one startup send, or one startup-to-turn edge followed by one terminal turn",
                    ));
                }
                direct_edges.push((caller, resolved, statement.source));
            }

            let program = request.hir.as_program();
            for expression in &program.expressions {
                check_cancelled(is_cancelled)?;
                let wrela_hir::ExpressionOwner::Body(body) = expression.owner else {
                    continue;
                };
                let belongs_to_method = body == method.body
                    || method.runtime_statements.iter().any(|statement| {
                        program
                            .statement(*statement)
                            .is_some_and(|statement| statement.body == body)
                    });
                if let ExpressionKind::Unary {
                    operator: wrela_hir::UnaryOperator::Await,
                    operand,
                } = expression.kind
                    && belongs_to_method
                {
                    let actor_dependency_call = program
                        .expression(operand)
                        .and_then(|operand| match operand.kind {
                            ExpressionKind::Call { callee, .. } => program.expression(callee),
                            _ => None,
                        })
                        .and_then(|callee| match callee.kind {
                            ExpressionKind::Field { base, .. } => program.expression(base),
                            _ => None,
                        })
                        .is_some_and(|base| matches!(base.kind, ExpressionKind::Field { .. }));
                    if actor_dependency_call {
                        reply_requests = reply_requests
                            .checked_add(1)
                            .ok_or_else(|| fact_resource(request, "actor reply requests"))?;
                        if reply_requests != 1
                            || !matches!(
                                partial
                                    .functions
                                    .get(caller.0 as usize)
                                    .map(|record| record.role),
                                Some(FunctionRole::TaskEntry(_))
                            )
                        {
                            return Err(actor_runtime_diagnostic(
                                Category::ACTOR,
                                expression.source,
                                "semantic-actor-reply-single-flight",
                                "typed actor replies require one exact startup-task request",
                                "await one image-wired actor request from one bounded startup task",
                            ));
                        }
                        let exact_root_request = expression.owner
                            == wrela_hir::ExpressionOwner::Body(method.body)
                            && program.body(method.body).is_some_and(|body| {
                                let [statement] = body.statements.as_slice() else {
                                    return false;
                                };
                                program.statement(*statement).is_some_and(|statement| {
                                    matches!(
                                        statement.kind,
                                        StatementKind::Initialize { value, .. }
                                            if value == expression.id
                                    )
                                })
                            });
                        if !exact_root_request {
                            return Err(actor_runtime_diagnostic(
                                Category::ACTOR,
                                expression.source,
                                "semantic-actor-reply-single-flight",
                                "typed actor reply is not one exact top-level startup request",
                                "make the awaited request the startup task's sole direct binding; branches, loops, and additional effects are not admitted",
                            ));
                        }
                        let resolved = resolve_self_actor_send(
                            request,
                            partial,
                            caller,
                            operand,
                            is_cancelled,
                        )?;
                        let target = partial
                            .functions
                            .get(resolved.method.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        let source_returns_u64 = match target.origin {
                            FunctionOrigin::Source { declaration, .. } => program
                                .declaration(declaration)
                                .and_then(|record| match &record.kind {
                                    DeclarationKind::Function(function) => Some(function),
                                    _ => None,
                                })
                                .is_some_and(|function| {
                                    actor_reply_result_is_u64(function.result.as_ref())
                                }),
                            _ => false,
                        };
                        if !source_returns_u64 {
                            return Err(actor_runtime_diagnostic(
                                Category::TYPE,
                                expression.source,
                                "semantic-actor-reply-type-pending",
                                "typed actor reply is outside the exact u64 result subset",
                                "return u64 from the requested public async turn",
                            ));
                        }
                        let definitely_returns = match target.origin {
                            FunctionOrigin::Source { body, .. } => {
                                program.body(body).is_some_and(|body| {
                                    let [statement] = body.statements.as_slice() else {
                                        return false;
                                    };
                                    program.statement(*statement).is_some_and(|statement| {
                                        matches!(statement.kind, StatementKind::Return(Some(_)))
                                    })
                                })
                            }
                            _ => false,
                        };
                        if !definitely_returns {
                            return Err(actor_runtime_diagnostic(
                                Category::ACTOR,
                                target.source.unwrap_or(expression.source),
                                "semantic-actor-reply-definite-result",
                                "typed actor reply target does not return one definite result",
                                "use one direct `return <u64>` statement on the admitted reply turn",
                            ));
                        }
                        reply_target = Some(resolved.method);
                        let target_name = target.name.clone();
                        let target_type_proof = target
                            .proofs
                            .iter()
                            .copied()
                            .find(|proof| {
                                partial
                                    .proofs
                                    .get(proof.0 as usize)
                                    .is_some_and(|record| record.kind == ProofKind::TypeChecked)
                            })
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        let permit = append_actor_send_permit(
                            request,
                            partial,
                            caller,
                            resolved,
                            "reply admission: ",
                            "the startup-once producer owns one same-core capacity-one request and reply slot",
                            is_cancelled,
                        )?;
                        if partial.proofs.len() >= request.limits.proofs as usize {
                            return Err(fact_resource(request, "actor reply proof").into());
                        }
                        let reply = ProofId(
                            u32::try_from(partial.proofs.len())
                                .map_err(|_| fact_resource(request, "actor reply proof"))?,
                        );
                        partial
                            .proofs
                            .try_reserve(1)
                            .map_err(|_| fact_resource(request, "actor reply proof"))?;
                        let mut depends_on = Vec::new();
                        depends_on.try_reserve_exact(2).map_err(|_| {
                            AnalysisFailure::ResourceLimit {
                                resource: "actor reply proof dependencies",
                                limit: 2,
                            }
                        })?;
                        depends_on.extend([target_type_proof, permit]);
                        depends_on.sort_unstable();
                        depends_on.dedup();
                        partial.proofs.push(Proof {
                            id: reply,
                            kind: ProofKind::ActorReplyExactlyOnce,
                            subject: bounded_actor_text(
                                request,
                                "single-flight reply: ",
                                "",
                                target_name.as_str(),
                                is_cancelled,
                            )?,
                            sources: vec![resolved.source],
                            depends_on,
                            bound: Some(1),
                            explanation: vec![
                                "one static caller-owned reply slot transitions Empty→Pending→Writing→Resolved→Consumed exactly once"
                                    .to_owned(),
                            ],
                        });
                        let producer = partial
                            .functions
                            .get_mut(caller.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        producer
                            .proofs
                            .try_reserve(1)
                            .map_err(|_| fact_resource(request, "actor reply proof references"))?;
                        producer.proofs.push(reply);
                        producer.proofs.sort_unstable();
                        producer.proofs.dedup();
                        producer.effects.0 |= EffectSet::ACTOR;
                        continue;
                    }
                }
                let ExpressionKind::TrySend(call) = expression.kind else {
                    continue;
                };
                if !belongs_to_method {
                    continue;
                }
                needs_reservation = true;
                let resolved =
                    resolve_self_actor_send(request, partial, caller, call, is_cancelled)?;
                if !matches!(
                    partial
                        .functions
                        .get(caller.0 as usize)
                        .map(|record| record.role),
                    Some(FunctionRole::TaskEntry(_))
                ) {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        expression.source,
                        "semantic-actor-try-send-recurring-pending",
                        "nonblocking actor-turn admission is not implemented by the recurring drain",
                        "use direct `send self.next()` for the bounded recurring unit-message chain",
                    ));
                }
                let count = attempted
                    .get_mut(resolved.actor.0 as usize)
                    .ok_or(AnalysisFailure::RequestMismatch)?;
                *count = count
                    .checked_add(1)
                    .ok_or_else(|| fact_resource(request, "actor try-send attempt count"))?;
                if *count > 1 {
                    return Err(actor_runtime_diagnostic(
                        Category::ACTOR,
                        expression.source,
                        "semantic-actor-try-send-single-attempt-bound",
                        "the implemented admission-result subset permits one startup try-send attempt per actor",
                        "keep one direct try-send consumer until recurring admission scheduling is implemented",
                    ));
                }
                append_actor_send_permit(
                    request,
                    partial,
                    caller,
                    resolved,
                    "try-send admission attempt: ",
                    "the startup-once producer makes at most one nonblocking admission attempt against the actor's finite mailbox",
                    is_cancelled,
                )?;
            }
        }
    }
    for plan in plans {
        for method in &plan.methods {
            check_cancelled(is_cancelled)?;
            let declaration = request
                .hir
                .as_program()
                .declaration(method.declaration)
                .ok_or(AnalysisFailure::RequestMismatch)?;
            let returns_u64 = match &declaration.kind {
                DeclarationKind::Function(function) => {
                    actor_reply_result_is_u64(function.result.as_ref())
                }
                _ => false,
            };
            if matches!(method.role, ActorMethodRole::Turn)
                && returns_u64
                && method.function != reply_target
            {
                return Err(actor_runtime_diagnostic(
                    Category::ACTOR,
                    method.source,
                    "semantic-actor-reply-unconsumed",
                    "u64 actor turn has no exact single-flight reply consumer",
                    "await this turn as the sole direct startup-task request, or return unit",
                ));
            }
        }
    }
    if !direct_edges.is_empty() {
        validate_and_seal_direct_actor_send_chain(request, partial, &direct_edges, is_cancelled)?;
    }
    if needs_reservation {
        let _ = ensure_actor_reservation_type(request, partial)?;
    }
    Ok(())
}

fn validate_and_seal_direct_actor_send_chain(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    edges: &[(FunctionInstanceId, ResolvedActorSend, Span)],
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    check_cancelled(is_cancelled)?;
    let role = |function: FunctionInstanceId| {
        partial
            .functions
            .get(function.0 as usize)
            .map(|record| record.role)
    };
    let capacity = |actor: ActorId| {
        partial
            .graph
            .as_ref()
            .and_then(|graph| graph.actors.get(actor.0 as usize))
            .map(|record| record.mailbox_capacity)
    };
    let mut startup_edges: Vec<&(FunctionInstanceId, ResolvedActorSend, Span)> = Vec::new();
    startup_edges
        .try_reserve_exact(edges.len())
        .map_err(|_| fact_resource(request, "actor send startup edges"))?;
    startup_edges.extend(
        edges
            .iter()
            .filter(|(producer, _, _)| matches!(role(*producer), Some(FunctionRole::TaskEntry(_)))),
    );
    let single_startup = edges.len() == 1
        && startup_edges.len() == 1
        && capacity(edges[0].1.actor).is_some_and(|bound| bound >= 1);
    let recurring = if edges.len() == 2 && startup_edges.len() == 1 {
        let startup = startup_edges[0];
        let turn = edges
            .iter()
            .find(|edge| !matches!(role(edge.0), Some(FunctionRole::TaskEntry(_))));
        turn.is_some_and(|turn| {
            let actor = startup.1.actor;
            capacity(actor) == Some(1)
                && turn.1.actor == actor
                && matches!(role(turn.0), Some(FunctionRole::ActorTurn(owner)) if owner == actor)
                && startup.1.method == turn.0
                && turn.1.method != startup.1.method
                && partial.graph.as_ref().is_some_and(|graph| {
                    graph.actors.get(actor.0 as usize).is_some_and(|record| {
                        record.turn_functions.len() == 2
                            && record.turn_functions.contains(&startup.1.method)
                            && record.turn_functions.contains(&turn.1.method)
                    })
                })
        })
    } else {
        false
    };
    if !single_startup && !recurring {
        let source = edges
            .last()
            .map(|edge| edge.2)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if let Some(bound) = startup_edges
            .first()
            .and_then(|edge| capacity(edge.1.actor))
        {
            let startup_count = u32::try_from(startup_edges.len())
                .map_err(|_| fact_resource(request, "actor send admission count"))?;
            if startup_count > bound {
                return Err(actor_runtime_diagnostic(
                    Category::CAPACITY,
                    source,
                    "semantic-actor-send-mailbox-over-bound",
                    "startup one-way sends exceed the sealed mailbox capacity",
                    "increase the explicit mailbox bound or reduce the startup send burst",
                ));
            }
        }
        if startup_edges.len() > 1 {
            return Err(actor_runtime_diagnostic(
                Category::ACTOR,
                source,
                "semantic-actor-send-single-message-bound",
                "the implemented drain admits one startup message per actor",
                "keep one startup send; a recurring edge must be published by that first actor turn",
            ));
        }
        return Err(actor_runtime_diagnostic(
            Category::ACTOR,
            source,
            "semantic-actor-send-chain",
            "one-way sends do not form an admitted fixed actor mailbox profile",
            "use one startup send or an exact capacity-one startup-to-turn-to-terminal chain",
        ));
    }

    for (producer, resolved, _) in edges {
        check_cancelled(is_cancelled)?;
        let explanation = if recurring {
            "the startup publish and one turn-published successor form an acyclic capacity-one non-reentrant drain"
        } else {
            "the startup-once producer contributes one message to an initially empty bounded mailbox before FIFO dispatch"
        };
        append_actor_send_permit(
            request,
            partial,
            *producer,
            *resolved,
            "one-way admission: ",
            explanation,
            is_cancelled,
        )?;
    }
    Ok(())
}

#[allow(clippy::too_many_arguments)]
fn append_actor_send_permit(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    caller: FunctionInstanceId,
    resolved: ResolvedActorSend,
    subject_prefix: &str,
    explanation: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<ProofId> {
    if partial.proofs.len() >= request.limits.proofs as usize {
        return Err(fact_resource(request, "actor send admission proof").into());
    }
    let permit = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "actor send admission proof"))?,
    );
    let target_name = partial
        .functions
        .get(resolved.method.0 as usize)
        .map(|function| function.name.as_str())
        .ok_or(AnalysisFailure::RequestMismatch)?;
    partial
        .proofs
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "actor send admission proof"))?;
    partial.proofs.push(Proof {
        id: permit,
        kind: ProofKind::CapacityBound,
        subject: bounded_actor_text(request, subject_prefix, "", target_name, is_cancelled)?,
        sources: vec![resolved.source],
        depends_on: vec![resolved.mailbox_proof],
        bound: Some(1),
        explanation: vec![bounded_actor_text(
            request,
            explanation,
            "",
            "",
            is_cancelled,
        )?],
    });
    let caller_record = partial
        .functions
        .get_mut(caller.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    caller_record
        .proofs
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "actor send proof references"))?;
    caller_record.proofs.push(permit);
    caller_record.proofs.sort_unstable();
    caller_record.proofs.dedup();
    Ok(permit)
}

fn populate_actor_image(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    actors: Vec<EvaluatedActor>,
    actor_names: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<()> {
    check_cancelled(is_cancelled)?;
    let mut plans = inspect_actor_plans(request, actors, actor_names, is_cancelled)?;
    let Some(mut graph) = partial.graph.take() else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    if partial.proofs.last().map(|proof| (proof.id, &proof.kind))
        != Some((ProofId(2), &ProofKind::ImageClosed))
    {
        return Err(AnalysisFailure::RequestMismatch.into());
    }
    partial.proofs.pop();
    let entry = partial
        .functions
        .get_mut(graph.entry.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    if entry.proofs.pop() != Some(ProofId(2)) {
        return Err(AnalysisFailure::RequestMismatch.into());
    }

    let mut class_types = Vec::new();
    class_types
        .try_reserve_exact(plans.len())
        .map_err(|_| fact_resource(request, "actor class types"))?;
    let mut runtime_aggregate_work = RuntimeAggregateWork::default();
    for plan in &plans {
        check_cancelled(is_cancelled)?;
        class_types.push(append_actor_class_type(request, partial, plan)?);
    }

    let mut actor_nodes = Vec::new();
    let mut task_nodes = Vec::new();
    actor_nodes
        .try_reserve_exact(plans.len())
        .map_err(|_| fact_resource(request, "image actor nodes"))?;
    let task_count = plans
        .iter()
        .try_fold(0usize, |count, plan| {
            count.checked_add(
                plan.methods
                    .iter()
                    .filter(|method| matches!(method.role, ActorMethodRole::Task(_)))
                    .count(),
            )
        })
        .ok_or_else(|| fact_resource(request, "image task nodes"))?;
    task_nodes
        .try_reserve_exact(task_count)
        .map_err(|_| fact_resource(request, "image task nodes"))?;

    for (plan_index, plan) in plans.iter_mut().enumerate() {
        check_cancelled(is_cancelled)?;
        let plan_name = plan
            .evaluated
            .name_in(actor_names)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let class_ty = *class_types
            .get(plan_index)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let mut turn_functions = Vec::new();
        let mut message_types = Vec::new();
        turn_functions
            .try_reserve_exact(plan.methods.len())
            .map_err(|_| fact_resource(request, "actor turn functions"))?;
        message_types
            .try_reserve_exact(plan.methods.len())
            .map_err(|_| fact_resource(request, "actor message types"))?;
        for method in &mut plan.methods {
            check_cancelled(is_cancelled)?;
            let function = append_actor_method_function(
                request,
                partial,
                plan.id,
                class_ty,
                method,
                &mut runtime_aggregate_work,
                is_cancelled,
            )?;
            method.function = Some(function);
            match method.role {
                ActorMethodRole::Turn => {
                    turn_functions.push(function);
                    let (color, result, message_parameters) = {
                        let record = partial
                            .functions
                            .get(function.0 as usize)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        let source = record
                            .parameters
                            .get(1..)
                            .ok_or(AnalysisFailure::RequestMismatch)?;
                        let mut parameters = Vec::new();
                        parameters
                            .try_reserve_exact(source.len())
                            .map_err(|_| fact_resource(request, "actor message parameters"))?;
                        parameters.extend_from_slice(source);
                        (record.color, record.result, parameters)
                    };
                    let message_type = ensure_function_type(
                        request,
                        partial,
                        color,
                        &message_parameters,
                        result,
                        &mut runtime_aggregate_work,
                        is_cancelled,
                    )?;
                    message_types.push(message_type);
                }
                ActorMethodRole::Task(task) => {
                    task_nodes.push(TaskNode {
                        id: task,
                        name: bounded_actor_text(
                            request,
                            plan_name,
                            ".",
                            request
                                .hir
                                .as_program()
                                .declaration(method.declaration)
                                .and_then(|declaration| declaration.name.as_ref())
                                .map(wrela_hir::Name::as_str)
                                .ok_or(AnalysisFailure::RequestMismatch)?,
                            is_cancelled,
                        )?,
                        entry: function,
                        slots: 1,
                        priority: 1,
                        supervisor: Some(plan.id),
                        source: method.source,
                    });
                }
            }
        }
        cancellable_stable_sort_by(
            &mut turn_functions,
            u64::from(request.limits.monomorphizations),
            "actor turn-function sort scratch",
            is_cancelled,
            &|left, right| Ok(left.cmp(right)),
        )?;
        cancellable_stable_sort_by(
            &mut message_types,
            u64::from(request.limits.types),
            "actor message-type sort scratch",
            is_cancelled,
            &|left, right| Ok(left.cmp(right)),
        )?;
        cancellable_dedup(&mut message_types, is_cancelled)?;
        actor_nodes.push(ActorNode {
            id: plan.id,
            name: copy_analysis_text(plan_name, request.limits.fact_bytes, is_cancelled)?,
            class: class_ty,
            mailbox_capacity: plan.evaluated.mailbox_capacity,
            message_types,
            turn_functions,
            priority: 1,
            supervisor: None,
            source: plan.evaluated.source,
        });
    }
    cancellable_stable_sort_owned_by(
        &mut task_nodes,
        u64::from(request.limits.image_nodes),
        "image task-node sort scratch",
        is_cancelled,
        &|left, right| Ok(left.id.cmp(&right.id)),
    )?;
    for (index, task) in task_nodes.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        if task.id.0 as usize != index {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }

    graph.actors = actor_nodes;
    graph.tasks = task_nodes;
    append_actor_regions_and_capacity_proofs(request, partial, &plans, &mut graph, is_cancelled)?;
    partial.graph = Some(graph);
    if let [service, client] = plans.as_slice()
        && client.evaluated.dependency == Some(service.id.0)
    {
        let source = client
            .evaluated
            .wiring_source
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if partial.proofs.len() >= request.limits.proofs as usize {
            return Err(fact_resource(request, "actor dependency proof").into());
        }
        let id = ProofId(
            u32::try_from(partial.proofs.len())
                .map_err(|_| fact_resource(request, "actor dependency proof"))?,
        );
        partial.proofs.push(Proof {
            id,
            kind: ProofKind::ActorAsIf,
            subject: bounded_actor_text(
                request,
                "image-wired dependency: ",
                " -> ",
                "service",
                is_cancelled,
            )?,
            sources: vec![source],
            depends_on: Vec::new(),
            bound: Some(1),
            explanation: vec![
                "the image mints one immutable typed app-to-service handle; it cannot escape or be substituted"
                    .to_owned(),
            ],
        });
    }
    prepare_actor_sends(request, partial, &plans, is_cancelled)?;

    for plan in &plans {
        for method in &plan.methods {
            check_cancelled(is_cancelled)?;
            let function = method.function.ok_or(AnalysisFailure::RequestMismatch)?;
            populate_runtime_body(
                request,
                partial,
                RuntimeBodyTarget {
                    function,
                    declaration: method.declaration,
                    body: method.body,
                    allow_assertions: false,
                },
                &mut runtime_aggregate_work,
                is_cancelled,
            )?;
        }
    }

    infer_actor_state_promotions(request, partial, is_cancelled)?;

    let wait_proof = analyze_wait_graph(request, partial, is_cancelled)?;
    let supervision_proof = append_static_supervision_proof(request, partial, is_cancelled)?;
    let regions = &partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?
        .regions;
    let mut capacity_proofs = Vec::new();
    capacity_proofs
        .try_reserve_exact(regions.len())
        .map_err(|_| fact_resource(request, "capacity proof references"))?;
    capacity_proofs.extend(regions.iter().map(|region| region.proof));
    let closed_proof = append_actor_image_closed_proof(
        request,
        partial,
        &plans,
        wait_proof,
        supervision_proof,
        &capacity_proofs,
        is_cancelled,
    )?;
    let graph = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let entry = partial
        .functions
        .get_mut(graph.entry.0 as usize)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let additional_proofs = capacity_proofs
        .len()
        .checked_add(3)
        .ok_or_else(|| fact_resource(request, "image entry proof references"))?;
    entry
        .proofs
        .try_reserve(additional_proofs)
        .map_err(|_| fact_resource(request, "image entry proof references"))?;
    entry.effects = EffectSet(EffectSet::FIRMWARE | EffectSet::ACTOR | EffectSet::TASK);
    entry.uninterrupted_work_bound = Some(
        1u64.checked_add(
            u64::try_from(graph.actors.len())
                .map_err(|_| fact_resource(request, "image startup work"))?,
        )
        .and_then(|work| work.checked_add(u64::try_from(graph.tasks.len()).ok()?))
        .ok_or_else(|| fact_resource(request, "image startup work"))?,
    );
    entry.proofs.push(wait_proof);
    entry.proofs.push(supervision_proof);
    entry.proofs.extend(capacity_proofs);
    entry.proofs.push(closed_proof);
    cancellable_stable_sort_by(
        &mut entry.proofs,
        u64::from(request.limits.proofs),
        "image entry proof sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )?;
    cancellable_dedup(&mut entry.proofs, is_cancelled)?;
    Ok(())
}

fn append_actor_class_type(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    plan: &ActorPlan,
) -> Result<SemanticTypeId, AnalysisFailure> {
    if partial.types.len() >= request.limits.types as usize {
        return Err(fact_resource(request, "actor class types"));
    }
    let id = SemanticTypeId(
        u32::try_from(partial.types.len())
            .map_err(|_| fact_resource(request, "actor class types"))?,
    );
    partial
        .types
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "actor class types"))?;
    partial.types.push(SemanticType {
        id,
        kind: SemanticTypeKind::Class {
            declaration: plan.evaluated.class,
            arguments: Vec::new(),
            fields: Vec::new(),
        },
        linearity: Linearity::ReclaimableLinear,
        size_upper_bound: Some(0),
        alignment_lower_bound: 1,
        source: Some(plan.class_source),
    });
    Ok(id)
}

fn append_actor_method_function(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    actor: ActorId,
    class_ty: SemanticTypeId,
    plan: &ActorMethodPlan,
    aggregate_work: &mut RuntimeAggregateWork,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<FunctionInstanceId> {
    check_cancelled(is_cancelled)?;
    let program = request.hir.as_program();
    let declaration = program
        .declaration(plan.declaration)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let DeclarationKind::Function(source) = &declaration.kind else {
        return Err(AnalysisFailure::RequestMismatch.into());
    };
    let proof_count = if plan.color == FunctionColor::Async {
        5usize
    } else {
        3usize
    };
    if partial.functions.len() >= request.limits.monomorphizations as usize
        || partial
            .proofs
            .len()
            .checked_add(proof_count)
            .is_none_or(|count| count > request.limits.proofs as usize)
    {
        return Err(fact_resource(request, "actor functions and proofs").into());
    }
    let id = FunctionInstanceId(
        u32::try_from(partial.functions.len())
            .map_err(|_| fact_resource(request, "actor functions"))?,
    );
    let name = bounded_actor_text(
        request,
        program
            .declaration(actor_class_declaration(partial, class_ty)?)
            .and_then(|class| class.name.as_ref())
            .map(wrela_hir::Name::as_str)
            .ok_or(AnalysisFailure::RequestMismatch)?,
        ".",
        declaration
            .name
            .as_ref()
            .map(wrela_hir::Name::as_str)
            .ok_or(AnalysisFailure::RequestMismatch)?,
        is_cancelled,
    )?;
    let mut parameters = Vec::new();
    parameters
        .try_reserve_exact(source.parameters.len())
        .map_err(|_| fact_resource(request, "actor function parameters"))?;
    for (index, parameter_id) in source.parameters.iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let parameter = program
            .parameter(*parameter_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let ty = if index == 0 {
            class_ty
        } else {
            semantic_type_from_source(
                request,
                partial,
                parameter
                    .ty
                    .as_ref()
                    .ok_or(AnalysisFailure::RequestMismatch)?,
                &mut *aggregate_work,
                is_cancelled,
            )?
        };
        let value = append_semantic_value(
            request,
            partial,
            id,
            ty,
            (
                SemanticValueOrigin::Parameter(*parameter_id),
                Some(parameter.source),
                Some(if parameter.receiver {
                    "self"
                } else {
                    parameter
                        .name
                        .as_ref()
                        .map(wrela_hir::Name::as_str)
                        .ok_or(AnalysisFailure::RequestMismatch)?
                }),
            ),
            is_cancelled,
        )?;
        parameters.push(FunctionParameter {
            parameter: *parameter_id,
            value,
            access: lower_access(parameter.access),
            ty,
        });
    }
    let result = if let Some(result) = &source.result {
        semantic_type_from_source(request, partial, result, &mut *aggregate_work, is_cancelled)?
    } else {
        partial
            .types
            .iter()
            .find(|ty| ty.kind == SemanticTypeKind::Unit)
            .map(|ty| ty.id)
            .ok_or(AnalysisFailure::RequestMismatch)?
    };
    let first_proof = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "actor function proofs"))?,
    );
    let type_proof = first_proof;
    let effect_proof = ProofId(
        type_proof
            .0
            .checked_add(1)
            .ok_or_else(|| fact_resource(request, "actor function proofs"))?,
    );
    let ownership_proof = ProofId(
        effect_proof
            .0
            .checked_add(1)
            .ok_or_else(|| fact_resource(request, "actor function proofs"))?,
    );
    partial
        .proofs
        .try_reserve(proof_count)
        .map_err(|_| fact_resource(request, "actor function proofs"))?;
    partial.proofs.push(Proof {
        id: type_proof,
        kind: ProofKind::TypeChecked,
        subject: bounded_test_fact(request, "actor function type: ", &name, is_cancelled)?,
        sources: vec![plan.source],
        depends_on: Vec::new(),
        bound: None,
        explanation: vec![
            "the concrete actor receiver, scalar parameters, and admitted bounded result are well typed"
                .to_owned(),
        ],
    });
    let work_bound = u64::try_from(plan.runtime_statements.len())
        .ok()
        .and_then(|work| work.checked_add(1))
        .ok_or_else(|| fact_resource(request, "actor work bound"))?;
    partial.proofs.push(Proof {
        id: effect_proof,
        kind: ProofKind::EffectsAllowed,
        subject: bounded_test_fact(request, "actor function effects: ", &name, is_cancelled)?,
        sources: vec![plan.source],
        depends_on: vec![type_proof],
        bound: Some(work_bound),
        explanation: vec![if plan.color == FunctionColor::Async {
            "suspension is limited to statically resolved direct async activations".to_owned()
        } else {
            "the turn runs synchronously to completion under its finite statement bound".to_owned()
        }],
    });
    partial.proofs.push(Proof {
        id: ownership_proof,
        kind: ProofKind::Ownership,
        subject: bounded_test_fact(request, "actor turn ownership: ", &name, is_cancelled)?,
        sources: vec![plan.source],
        depends_on: vec![type_proof, effect_proof],
        bound: Some(1),
        explanation: vec![match plan.role {
            ActorMethodRole::Turn => "the actor owns exactly one non-reentrant external turn slot, retained across suspension".to_owned(),
            ActorMethodRole::Task(_) => "the static task owns its one generated activation slot and cannot alias an actor turn".to_owned(),
        }],
    });
    let mut proofs = vec![type_proof, effect_proof, ownership_proof];
    if plan.color == FunctionColor::Async {
        let view_proof = ProofId(
            ownership_proof
                .0
                .checked_add(1)
                .ok_or_else(|| fact_resource(request, "actor function proofs"))?,
        );
        let cleanup_proof = ProofId(
            view_proof
                .0
                .checked_add(1)
                .ok_or_else(|| fact_resource(request, "actor function proofs"))?,
        );
        let source_count = plan.await_sources.len().max(1);
        let mut sources = Vec::new();
        let mut cleanup_sources = Vec::new();
        sources
            .try_reserve_exact(source_count)
            .map_err(|_| fact_resource(request, "actor suspension proof sources"))?;
        cleanup_sources
            .try_reserve_exact(source_count)
            .map_err(|_| fact_resource(request, "actor cleanup proof sources"))?;
        if plan.await_sources.is_empty() {
            sources.push(plan.source);
            cleanup_sources.push(plan.source);
        } else {
            sources.extend_from_slice(&plan.await_sources);
            cleanup_sources.extend_from_slice(&plan.await_sources);
        }
        partial.proofs.push(Proof {
            id: view_proof,
            kind: ProofKind::ViewDoesNotEscape,
            subject: bounded_test_fact(
                request,
                "actor suspension safety: ",
                &name,
                is_cancelled,
            )?,
            sources,
            depends_on: vec![type_proof, ownership_proof],
            bound: Some(0),
            explanation: vec!["no external view or mutable loan is live at any suspension point; only turn-rooted self authority persists".to_owned()],
        });
        partial.proofs.push(Proof {
            id: cleanup_proof,
            kind: ProofKind::CleanupAcyclic,
            subject: bounded_test_fact(
                request,
                "actor cancellation cleanup: ",
                &name,
                is_cancelled,
            )?,
            sources: cleanup_sources,
            depends_on: vec![type_proof, ownership_proof, view_proof],
            bound: Some(
                u64::try_from(source.parameters.len())
                    .map_err(|_| fact_resource(request, "actor cleanup bound"))?,
            ),
            explanation: vec!["cancellation visits the fixed frame state once and destroys owned scalar values in reverse source order".to_owned()],
        });
        proofs.extend([view_proof, cleanup_proof]);
    }
    let frame_bytes_bound = if plan.color == FunctionColor::Async {
        let local_count = plan
            .runtime_statements
            .iter()
            .filter(|statement| {
                request
                    .hir
                    .as_program()
                    .statement(**statement)
                    .is_some_and(|statement| {
                        matches!(statement.kind, StatementKind::Initialize { .. })
                    })
            })
            .count();
        let live_values = source
            .parameters
            .len()
            .saturating_sub(1)
            .checked_add(local_count)
            .ok_or_else(|| fact_resource(request, "actor frame values"))?;
        16u64
            .checked_add(
                u64::try_from(live_values)
                    .ok()
                    .and_then(|values| values.checked_mul(16))
                    .ok_or_else(|| fact_resource(request, "actor frame bytes"))?,
            )
            .ok_or_else(|| fact_resource(request, "actor frame bytes"))?
    } else {
        0
    };
    partial
        .functions
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "actor functions"))?;
    partial.functions.push(FunctionInstance {
        id,
        key: actor_function_key(request, actor, plan.declaration, plan.role),
        name,
        origin: FunctionOrigin::Source {
            declaration: plan.declaration,
            body: plan.body,
        },
        role: match plan.role {
            ActorMethodRole::Turn => FunctionRole::ActorTurn(actor),
            ActorMethodRole::Task(task) => FunctionRole::TaskEntry(task),
        },
        color: plan.color,
        generic_arguments: Vec::new(),
        parameters,
        result,
        effects: EffectSet(
            match plan.role {
                ActorMethodRole::Turn => EffectSet::ACTOR,
                ActorMethodRole::Task(_) => EffectSet::TASK,
            } | if plan.has_send { EffectSet::ACTOR } else { 0 }
                | if plan.color == FunctionColor::Async {
                    EffectSet::SUSPEND
                } else {
                    0
                },
        ),
        stack_bytes_bound: 64,
        frame_bytes_bound,
        uninterrupted_work_bound: Some(work_bound),
        recursive_depth_bound: Some(1),
        proofs,
        source: Some(plan.source),
    });
    Ok(id)
}

fn actor_class_declaration(
    partial: &PartialAnalysis,
    class: SemanticTypeId,
) -> Result<DeclarationId, AnalysisFailure> {
    let Some(SemanticType {
        kind: SemanticTypeKind::Class { declaration, .. },
        ..
    }) = partial.types.get(class.0 as usize)
    else {
        return Err(AnalysisFailure::RequestMismatch);
    };
    Ok(*declaration)
}

fn actor_function_key(
    request: &AnalysisRequest<'_>,
    actor: ActorId,
    declaration: DeclarationId,
    role: ActorMethodRole,
) -> FunctionKey {
    let mut bytes = *request.build.identity.request.as_bytes();
    bytes[0] ^= 0x41;
    bytes[1] ^= match role {
        ActorMethodRole::Turn => 0x54,
        ActorMethodRole::Task(_) => 0x4b,
    };
    for (destination, source) in bytes[20..24].iter_mut().zip(actor.0.to_be_bytes()) {
        *destination ^= source;
    }
    for (destination, source) in bytes[24..28].iter_mut().zip(declaration.0.to_be_bytes()) {
        *destination ^= source;
    }
    if let ActorMethodRole::Task(task) = role {
        for (destination, source) in bytes[28..32].iter_mut().zip(task.0.to_be_bytes()) {
            *destination ^= source;
        }
    }
    if bytes.iter().all(|byte| *byte == 0) {
        bytes[0] = 0x41;
    }
    FunctionKey(wrela_build_model::Sha256Digest::from_bytes(bytes))
}

fn bounded_actor_text(
    request: &AnalysisRequest<'_>,
    left: &str,
    separator: &str,
    right: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<String, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let resource_failure = || AnalysisFailure::ResourceLimit {
        resource: "semantic fact bytes",
        limit: request.limits.fact_bytes,
    };
    let length = left
        .len()
        .checked_add(separator.len())
        .and_then(|length| length.checked_add(right.len()))
        .ok_or_else(&resource_failure)?;
    if u64::try_from(length).map_or(true, |length| length > request.limits.fact_bytes) {
        return Err(resource_failure());
    }
    let mut output = String::new();
    output
        .try_reserve_exact(length)
        .map_err(|_| resource_failure())?;
    append_polled_test_text(&mut output, left, is_cancelled)?;
    append_polled_test_text(&mut output, separator, is_cancelled)?;
    append_polled_test_text(&mut output, right, is_cancelled)?;
    if output.len() != length {
        return Err(AnalysisFailure::RequestMismatch);
    }
    Ok(output)
}

fn append_actor_regions_and_capacity_proofs(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    plans: &[ActorPlan],
    graph: &mut ImageGraph,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    let region_count = graph
        .actors
        .len()
        .checked_add(
            plans
                .iter()
                .filter(|plan| plan.state_source.is_some())
                .count(),
        )
        .and_then(|count| {
            count.checked_add(
                graph
                    .actors
                    .iter()
                    .filter(|actor| !actor.turn_functions.is_empty())
                    .count(),
            )
        })
        .and_then(|count| count.checked_add(graph.tasks.len()))
        .ok_or_else(|| fact_resource(request, "image capacity regions"))?;
    if region_count > request.limits.image_nodes as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "image capacity regions",
            limit: u64::from(request.limits.image_nodes),
        });
    }
    graph
        .regions
        .try_reserve_exact(region_count)
        .map_err(|_| fact_resource(request, "image capacity regions"))?;
    let mut static_bytes = 0u64;
    for actor in &graph.actors {
        check_cancelled(is_cancelled)?;
        let plan = plans
            .get(actor.id.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let mailbox_bytes = u64::from(actor.mailbox_capacity)
            .checked_mul(16)
            .ok_or_else(|| fact_resource(request, "actor mailbox bytes"))?;
        let proof = append_capacity_proof(
            request,
            partial,
            bounded_actor_text(request, "actor mailbox: ", "", &actor.name, is_cancelled)?,
            vec![plan.evaluated.mailbox_source],
            u64::from(actor.mailbox_capacity),
            "the explicit logical mailbox slot count is finite; each supported scalar message reserves a fixed 16-byte upper-bound slot",
        )?;
        graph.regions.push(Region {
            id: RegionId(
                u32::try_from(graph.regions.len())
                    .map_err(|_| fact_resource(request, "image capacity regions"))?,
            ),
            name: bounded_actor_text(request, &actor.name, ".", "mailbox", is_cancelled)?,
            class: RegionClass::Image,
            capacity_bytes: mailbox_bytes,
            alignment: 8,
            owner: ImageOwner::Actor(actor.id),
            proof,
            source: plan.evaluated.source,
        });
        static_bytes = static_bytes
            .checked_add(mailbox_bytes)
            .ok_or_else(|| fact_resource(request, "image static bytes"))?;
        if let Some(state_source) = plan.state_source {
            let state_proof = append_capacity_proof(
                request,
                partial,
                bounded_actor_text(request, "actor state: ", "", &actor.name, is_cancelled)?,
                vec![state_source],
                1,
                "the exact `value: u64 = 0` declaration reserves one actor-owned eight-byte state cell with a canonical zero initializer",
            )?;
            graph.regions.push(Region {
                id: RegionId(
                    u32::try_from(graph.regions.len())
                        .map_err(|_| fact_resource(request, "image capacity regions"))?,
                ),
                name: bounded_actor_text(request, &actor.name, ".", "state", is_cancelled)?,
                class: RegionClass::Image,
                capacity_bytes: 8,
                alignment: 8,
                owner: ImageOwner::Actor(actor.id),
                proof: state_proof,
                source: state_source,
            });
            static_bytes = static_bytes
                .checked_add(8)
                .ok_or_else(|| fact_resource(request, "image static bytes"))?;
        }
        if !actor.turn_functions.is_empty() {
            let turn_frame_bytes = actor
                .turn_functions
                .iter()
                .filter_map(|function| partial.functions.get(function.0 as usize))
                .map(|function| function.frame_bytes_bound.max(1))
                .max()
                .unwrap_or(1);
            let turn_proof = append_capacity_proof(
                request,
                partial,
                bounded_actor_text(request, "actor turn slot: ", "", &actor.name, is_cancelled)?,
                vec![plan.evaluated.source],
                1,
                "non-reentrant actor scheduling admits exactly one active external turn and retains that fixed frame across suspension",
            )?;
            graph.regions.push(Region {
                id: RegionId(
                    u32::try_from(graph.regions.len())
                        .map_err(|_| fact_resource(request, "image capacity regions"))?,
                ),
                name: bounded_actor_text(request, &actor.name, ".", "turn-frame", is_cancelled)?,
                class: RegionClass::TaskFrame,
                capacity_bytes: turn_frame_bytes,
                alignment: 8,
                owner: ImageOwner::Actor(actor.id),
                proof: turn_proof,
                source: plan.evaluated.source,
            });
            static_bytes = static_bytes
                .checked_add(turn_frame_bytes)
                .ok_or_else(|| fact_resource(request, "image static bytes"))?;
        }
    }
    for task in &graph.tasks {
        check_cancelled(is_cancelled)?;
        let function = partial
            .functions
            .get(task.entry.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let frame_bytes = function.frame_bytes_bound.max(1);
        let capacity_bytes = frame_bytes
            .checked_mul(u64::from(task.slots))
            .ok_or_else(|| fact_resource(request, "task frame bytes"))?;
        let proof = append_capacity_proof(
            request,
            partial,
            bounded_actor_text(request, "task slots: ", "", &task.name, is_cancelled)?,
            vec![task.source],
            u64::from(task.slots),
            "the image installs one static activation slot and reserves its complete state-machine frame before boot",
        )?;
        graph.regions.push(Region {
            id: RegionId(
                u32::try_from(graph.regions.len())
                    .map_err(|_| fact_resource(request, "image capacity regions"))?,
            ),
            name: bounded_actor_text(request, &task.name, ".", "frame", is_cancelled)?,
            class: RegionClass::TaskFrame,
            capacity_bytes,
            alignment: 8,
            owner: ImageOwner::Task(task.id),
            proof,
            source: task.source,
        });
        static_bytes = static_bytes
            .checked_add(capacity_bytes)
            .ok_or_else(|| fact_resource(request, "image static bytes"))?;
    }
    graph.static_bytes = static_bytes;
    graph.peak_bytes = static_bytes;
    let owner_count = 1usize
        .checked_add(graph.actors.len())
        .and_then(|count| count.checked_add(graph.tasks.len()))
        .ok_or_else(|| fact_resource(request, "image owner order"))?;
    graph
        .startup_order
        .try_reserve(owner_count.saturating_sub(graph.startup_order.len()))
        .map_err(|_| fact_resource(request, "image startup order"))?;
    graph.startup_order.clear();
    graph.startup_order.push(ImageOwner::Runtime);
    graph
        .startup_order
        .extend(graph.actors.iter().map(|actor| ImageOwner::Actor(actor.id)));
    graph
        .startup_order
        .extend(graph.tasks.iter().map(|task| ImageOwner::Task(task.id)));
    graph
        .shutdown_order
        .try_reserve(owner_count.saturating_sub(graph.shutdown_order.len()))
        .map_err(|_| fact_resource(request, "image shutdown order"))?;
    graph.shutdown_order.clear();
    graph.shutdown_order.extend(
        graph
            .tasks
            .iter()
            .rev()
            .map(|task| ImageOwner::Task(task.id)),
    );
    graph.shutdown_order.extend(
        graph
            .actors
            .iter()
            .rev()
            .map(|actor| ImageOwner::Actor(actor.id)),
    );
    graph.shutdown_order.push(ImageOwner::Runtime);
    Ok(())
}

fn append_capacity_proof(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    subject: String,
    sources: Vec<Span>,
    bound: u64,
    explanation: &'static str,
) -> Result<ProofId, AnalysisFailure> {
    if partial.proofs.len() >= request.limits.proofs as usize {
        return Err(fact_resource(request, "capacity proofs"));
    }
    let id = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "capacity proofs"))?,
    );
    partial
        .proofs
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "capacity proofs"))?;
    partial.proofs.push(Proof {
        id,
        kind: ProofKind::CapacityBound,
        subject,
        sources,
        depends_on: Vec::new(),
        bound: Some(bound),
        explanation: vec![explanation.to_owned()],
    });
    Ok(id)
}

#[derive(Debug, Clone, Copy)]
struct WaitEdge {
    from: FunctionInstanceId,
    to: FunctionInstanceId,
    source: Span,
}

fn analyze_wait_graph(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    is_cancelled: &dyn Fn() -> bool,
) -> RuntimeResult<ProofId> {
    check_cancelled(is_cancelled)?;
    if partial.functions.len() > request.limits.fixed_point_iterations as usize {
        return Err(AnalysisFailure::ResourceLimit {
            resource: "semantic wait graph iterations",
            limit: u64::from(request.limits.fixed_point_iterations),
        }
        .into());
    }
    let program = request.hir.as_program();
    let mut edges = Vec::new();
    let mut awaited_operands = std::collections::HashSet::new();
    awaited_operands
        .try_reserve(partial.expressions.len())
        .map_err(|_| fact_resource(request, "wait graph awaited operands"))?;
    for fact in &partial.expressions {
        check_cancelled(is_cancelled)?;
        if fact.resolution != ExpressionResolution::Builtin(IntrinsicOperation::Await) {
            continue;
        }
        let expression = program
            .expression(fact.expression)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let ExpressionKind::Unary {
            operator: wrela_hir::UnaryOperator::Await,
            operand,
        } = expression.kind
        else {
            return Err(AnalysisFailure::RequestMismatch.into());
        };
        if !awaited_operands.insert((fact.function, operand)) {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
        let operand_fact = partial
            .expressions
            .iter()
            .find(|operand_fact| {
                operand_fact.function == fact.function && operand_fact.expression == operand
            })
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let target = match operand_fact.resolution {
            ExpressionResolution::DirectCall {
                function: target, ..
            }
            | ExpressionResolution::ActorRequest {
                method: target,
                reply: Some(_),
                ..
            } => target,
            _ => return Err(AnalysisFailure::RequestMismatch.into()),
        };
        if u64::try_from(edges.len()).map_or(true, |count| count >= request.limits.fact_edges) {
            return Err(fact_resource(request, "semantic wait graph edges").into());
        }
        edges
            .try_reserve(1)
            .map_err(|_| fact_resource(request, "semantic wait graph edges"))?;
        edges.push(WaitEdge {
            from: fact.function,
            to: target,
            source: expression.source,
        });
    }
    for fact in &partial.expressions {
        check_cancelled(is_cancelled)?;
        let target = match fact.resolution {
            ExpressionResolution::DirectCall {
                function: target, ..
            } => target,
            _ => continue,
        };
        if partial
            .functions
            .get(target.0 as usize)
            .is_some_and(|target| target.color == FunctionColor::Async)
            && !awaited_operands.contains(&(fact.function, fact.expression))
        {
            let source = program
                .expression(fact.expression)
                .map_or_else(|| fallback_span(program), |expression| expression.source);
            let mut diagnostic = Diagnostic::error(
                Category::ASYNC,
                source,
                "async activation is created without an immediate await boundary",
            );
            diagnostic.code = Some("semantic-async-result-not-awaited".to_owned());
            diagnostic.notes.push(
                "revision 0.1 does not allocate implicit futures or detached dynamic task frames"
                    .to_owned(),
            );
            diagnostic.help.push(
                "await the call immediately or install a statically bounded @task entry".to_owned(),
            );
            return Err(RuntimeFailure::Diagnostic(Box::new(diagnostic)));
        }
    }
    cancellable_stable_sort_by(
        &mut edges,
        request.limits.fact_edges,
        "wait-graph edge sort scratch",
        is_cancelled,
        &|left, right| {
            Ok((
                left.from,
                left.to,
                left.source.file,
                left.source.range.start,
                left.source.range.end,
            )
                .cmp(&(
                    right.from,
                    right.to,
                    right.source.file,
                    right.source.range.start,
                    right.source.range.end,
                )))
        },
    )?;
    for pair in edges.windows(2) {
        check_cancelled(is_cancelled)?;
        if pair[0].from == pair[1].from
            && pair[0].to == pair[1].to
            && pair[0].source == pair[1].source
        {
            return Err(AnalysisFailure::RequestMismatch.into());
        }
    }
    if let Some(cycle) = find_wait_cycle(partial.functions.len(), &edges, is_cancelled)? {
        return Err(wait_cycle_diagnostic(
            request,
            partial,
            &cycle,
            is_cancelled,
        )?);
    }
    if partial.proofs.len() >= request.limits.proofs as usize {
        return Err(fact_resource(request, "wait graph proof").into());
    }
    let mut sources = Vec::new();
    sources
        .try_reserve_exact(edges.len())
        .map_err(|_| fact_resource(request, "wait graph proof sources"))?;
    sources.extend(edges.iter().map(|edge| edge.source));
    cancellable_stable_sort_by(
        &mut sources,
        request.limits.fact_edges,
        "wait-graph source sort scratch",
        is_cancelled,
        &|left, right| {
            Ok((left.file, left.range.start, left.range.end).cmp(&(
                right.file,
                right.range.start,
                right.range.end,
            )))
        },
    )?;
    cancellable_dedup(&mut sources, is_cancelled)?;
    let mut dependencies = Vec::new();
    dependencies
        .try_reserve_exact(partial.functions.len())
        .map_err(|_| fact_resource(request, "wait graph proof dependencies"))?;
    for function in &partial.functions {
        check_cancelled(is_cancelled)?;
        if function.color == FunctionColor::Async {
            if let Some(proof) = function.proofs.get(1).copied() {
                dependencies.push(proof);
            }
        }
    }
    cancellable_stable_sort_by(
        &mut dependencies,
        u64::from(request.limits.monomorphizations),
        "wait-graph dependency sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )?;
    cancellable_dedup(&mut dependencies, is_cancelled)?;
    let id = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "wait graph proof"))?,
    );
    partial
        .proofs
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "wait graph proof"))?;
    partial.proofs.push(Proof {
        id,
        kind: ProofKind::WaitGraphAcyclic,
        subject: copy_analysis_text(
            "closed actor/task wait-for graph",
            request.limits.fact_bytes,
            is_cancelled,
        )?,
        sources,
        depends_on: dependencies,
        bound: Some(
            u64::try_from(edges.len())
                .map_err(|_| fact_resource(request, "wait graph proof bound"))?,
        ),
        explanation: vec![
            "every await edge names a concrete monomorphized activation; bounded traversal found no hold-and-wait cycle"
                .to_owned(),
        ],
    });
    Ok(id)
}

fn find_wait_cycle(
    node_count: usize,
    edges: &[WaitEdge],
    is_cancelled: &dyn Fn() -> bool,
) -> Result<Option<Vec<WaitEdge>>, AnalysisFailure> {
    let limit = u64::try_from(edges.len()).unwrap_or(u64::MAX);
    let mut colors = Vec::new();
    let mut parents = Vec::new();
    let mut stack = Vec::new();
    colors
        .try_reserve_exact(node_count)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic wait graph scratch",
            limit,
        })?;
    parents
        .try_reserve_exact(node_count)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic wait graph scratch",
            limit,
        })?;
    stack
        .try_reserve_exact(node_count)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic wait graph scratch",
            limit,
        })?;
    colors.resize(node_count, 0u8);
    parents.resize(node_count, None::<WaitEdge>);
    for root in 0..node_count {
        check_cancelled(is_cancelled)?;
        if colors[root] != 0 {
            continue;
        }
        colors[root] = 1;
        let start = edges.partition_point(|edge| (edge.from.0 as usize) < root);
        stack.push((root, start));
        while let Some((node, next)) = stack.last_mut() {
            check_cancelled(is_cancelled)?;
            let end = edges.partition_point(|edge| edge.from.0 as usize <= *node);
            if *next >= end {
                colors[*node] = 2;
                stack.pop();
                continue;
            }
            let edge = edges[*next];
            *next += 1;
            let target = edge.to.0 as usize;
            let Some(color) = colors.get(target).copied() else {
                return Err(AnalysisFailure::RequestMismatch);
            };
            if color == 0 {
                colors[target] = 1;
                parents[target] = Some(edge);
                let target_start =
                    edges.partition_point(|candidate| (candidate.from.0 as usize) < target);
                stack.push((target, target_start));
            } else if color == 1 {
                let mut cycle = Vec::new();
                cycle
                    .try_reserve_exact(node_count.saturating_add(1))
                    .map_err(|_| AnalysisFailure::ResourceLimit {
                        resource: "semantic wait cycle",
                        limit,
                    })?;
                cycle.push(edge);
                let mut current = *node;
                while current != target {
                    let parent = parents
                        .get(current)
                        .and_then(|edge| *edge)
                        .ok_or(AnalysisFailure::RequestMismatch)?;
                    cycle.push(parent);
                    current = parent.from.0 as usize;
                    if cycle.len() > node_count {
                        return Err(AnalysisFailure::RequestMismatch);
                    }
                }
                cycle.reverse();
                return Ok(Some(cycle));
            }
        }
    }
    Ok(None)
}

fn wait_cycle_diagnostic(
    request: &AnalysisRequest<'_>,
    partial: &PartialAnalysis,
    cycle: &[WaitEdge],
    is_cancelled: &dyn Fn() -> bool,
) -> Result<RuntimeFailure, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let primary = cycle
        .last()
        .map(|edge| edge.source)
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let mut diagnostic = Diagnostic::error(
        Category::ASYNC,
        primary,
        "blocking actor/task wait-for cycle",
    );
    diagnostic.code = Some("semantic-wait-cycle".to_owned());
    diagnostic
        .labels
        .try_reserve_exact(cycle.len())
        .map_err(|_| fact_resource(request, "wait-cycle diagnostic labels"))?;
    diagnostic
        .notes
        .try_reserve_exact(cycle.len())
        .map_err(|_| fact_resource(request, "wait-cycle diagnostic notes"))?;
    for edge in cycle {
        let from = partial
            .functions
            .get(edge.from.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let to = partial
            .functions
            .get(edge.to.0 as usize)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        diagnostic.labels.push(wrela_diagnostics::Label {
            span: edge.source,
            message: bounded_actor_text(
                request,
                &from.name,
                " waits for ",
                &to.name,
                is_cancelled,
            )?,
        });
        diagnostic.notes.push(bounded_actor_text(
            request,
            &from.name,
            " retains its activation while awaiting ",
            &to.name,
            is_cancelled,
        )?);
    }
    diagnostic.help.push(
        "break the cycle with a one-way notification, move work behind an external completion, or merge the mutually waiting state"
            .to_owned(),
    );
    Ok(RuntimeFailure::Diagnostic(Box::new(diagnostic)))
}

fn append_static_supervision_proof(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ProofId, AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    if partial.proofs.len() >= request.limits.proofs as usize {
        return Err(fact_resource(request, "static supervision proof"));
    }
    let graph = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let node_count = graph
        .actors
        .len()
        .checked_add(graph.tasks.len())
        .ok_or_else(|| fact_resource(request, "static supervision nodes"))?;
    let mut sources = Vec::new();
    sources
        .try_reserve_exact(node_count)
        .map_err(|_| fact_resource(request, "static supervision proof sources"))?;
    for actor in &graph.actors {
        check_cancelled(is_cancelled)?;
        if actor.supervisor.is_some() {
            return Err(AnalysisFailure::RequestMismatch);
        }
        sources.push(actor.source);
    }
    for task in &graph.tasks {
        check_cancelled(is_cancelled)?;
        let supervisor_id = task.supervisor.ok_or(AnalysisFailure::RequestMismatch)?;
        let supervisor = graph
            .actors
            .get(supervisor_id.0 as usize)
            .filter(|actor| actor.id == supervisor_id)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        let function = partial
            .functions
            .get(task.entry.0 as usize)
            .filter(|function| function.role == FunctionRole::TaskEntry(task.id))
            .ok_or(AnalysisFailure::RequestMismatch)?;
        if supervisor.id != supervisor_id || function.source != Some(task.source) {
            return Err(AnalysisFailure::RequestMismatch);
        }
        sources.push(task.source);
    }
    let id = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "static supervision proof"))?,
    );
    partial
        .proofs
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "static supervision proof"))?;
    partial.proofs.push(Proof {
        id,
        kind: ProofKind::SupervisionComplete,
        subject: copy_analysis_text(
            "complete static actor/task parent topology",
            request.limits.fact_bytes,
            is_cancelled,
        )?,
        sources,
        depends_on: vec![ProofId(0)],
        bound: Some(
            u64::try_from(node_count)
                .map_err(|_| fact_resource(request, "static supervision nodes"))?,
        ),
        explanation: vec![
            "the static actor parent graph is acyclic and every static @task is owned by exactly its declaring actor; restart policy and failure delivery are not claimed"
                .to_owned(),
        ],
    });
    Ok(id)
}

fn append_actor_image_closed_proof(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    plans: &[ActorPlan],
    wait_proof: ProofId,
    supervision_proof: ProofId,
    capacity_proofs: &[ProofId],
    is_cancelled: &dyn Fn() -> bool,
) -> Result<ProofId, AnalysisFailure> {
    if partial.proofs.len() >= request.limits.proofs as usize {
        return Err(fact_resource(request, "closed actor image proof"));
    }
    let mut dependencies = Vec::new();
    dependencies
        .try_reserve_exact(capacity_proofs.len().saturating_add(4))
        .map_err(|_| fact_resource(request, "closed actor image proof dependencies"))?;
    dependencies.extend([ProofId(0), ProofId(1), wait_proof, supervision_proof]);
    dependencies.extend_from_slice(capacity_proofs);
    cancellable_stable_sort_by(
        &mut dependencies,
        u64::from(request.limits.proofs),
        "closed-image dependency sort scratch",
        is_cancelled,
        &|left, right| Ok(left.cmp(right)),
    )?;
    cancellable_dedup(&mut dependencies, is_cancelled)?;
    let mut sources = Vec::new();
    sources
        .try_reserve_exact(plans.len().saturating_add(1))
        .map_err(|_| fact_resource(request, "closed actor image proof sources"))?;
    sources.push(
        partial
            .proofs
            .first()
            .and_then(|proof| proof.sources.first())
            .copied()
            .ok_or(AnalysisFailure::RequestMismatch)?,
    );
    sources.extend(plans.iter().map(|plan| plan.evaluated.source));
    let graph = partial
        .graph
        .as_ref()
        .ok_or(AnalysisFailure::RequestMismatch)?;
    let id = ProofId(
        u32::try_from(partial.proofs.len())
            .map_err(|_| fact_resource(request, "closed actor image proof"))?,
    );
    partial
        .proofs
        .try_reserve(1)
        .map_err(|_| fact_resource(request, "closed actor image proof"))?;
    partial.proofs.push(Proof {
        id,
        kind: ProofKind::ImageClosed,
        subject: copy_analysis_text(
            "closed bounded actor image",
            request.limits.fact_bytes,
            is_cancelled,
        )?,
        sources,
        depends_on: dependencies,
        bound: Some(graph.static_bytes),
        explanation: vec![
            "the concrete actor, task, mailbox, frame, startup, shutdown, cancellation, and wait-for sets are finite and image-owned"
                .to_owned(),
        ],
    });
    if let Some(effect) = partial.proofs.get_mut(1) {
        effect.bound = Some(
            u64::try_from(graph.actors.len())
                .ok()
                .and_then(|actors| actors.checked_add(u64::try_from(graph.tasks.len()).ok()?))
                .ok_or_else(|| fact_resource(request, "image effect bound"))?,
        );
        effect.explanation = vec![
            "the generated entry initializes only the closed actor/task graph and then transfers control to the bounded executor"
                .to_owned(),
        ];
    }
    Ok(id)
}

fn populate_minimum_image(
    request: &AnalysisRequest<'_>,
    partial: &mut PartialAnalysis,
    constructor: DeclarationId,
    image_name: String,
) -> Result<(), AnalysisFailure> {
    let source = request
        .hir
        .as_program()
        .declaration(constructor)
        .ok_or(AnalysisFailure::RequestMismatch)?
        .source;
    partial
        .types
        .try_reserve_exact(1)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic types",
            limit: u64::from(request.limits.types),
        })?;
    partial.types.push(SemanticType {
        id: SemanticTypeId(0),
        kind: SemanticTypeKind::Unit,
        linearity: Linearity::ScalarCopy,
        size_upper_bound: Some(0),
        alignment_lower_bound: 1,
        source: None,
    });

    partial
        .proofs
        .try_reserve_exact(3)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic proofs",
            limit: u64::from(request.limits.proofs),
        })?;
    partial.proofs.extend([
        Proof {
            id: ProofId(0),
            kind: ProofKind::TypeChecked,
            subject: "minimum image constructor".to_owned(),
            sources: vec![source],
            depends_on: Vec::new(),
            bound: None,
            explanation: vec![
                "the constructor and generated runtime entry are well typed".to_owned(),
            ],
        },
        Proof {
            id: ProofId(1),
            kind: ProofKind::EffectsAllowed,
            subject: "minimum image effects".to_owned(),
            sources: vec![source],
            depends_on: vec![ProofId(0)],
            bound: Some(1),
            explanation: vec!["the empty runtime graph has no source runtime effects".to_owned()],
        },
        Proof {
            id: ProofId(2),
            kind: ProofKind::ImageClosed,
            subject: "minimum closed image".to_owned(),
            sources: vec![source],
            depends_on: vec![ProofId(0), ProofId(1)],
            bound: Some(0),
            explanation: vec!["the image contains only the compiler-owned runtime root".to_owned()],
        },
    ]);

    partial
        .functions
        .try_reserve_exact(1)
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource: "semantic functions",
            limit: u64::from(request.limits.monomorphizations),
        })?;
    partial.functions.push(FunctionInstance {
        id: FunctionInstanceId(0),
        key: FunctionKey(request.build.identity.request),
        name: "__wrela_image_entry".to_owned(),
        origin: FunctionOrigin::GeneratedImageEntry { constructor },
        role: FunctionRole::ImageEntry,
        color: FunctionColor::Sync,
        generic_arguments: Vec::new(),
        parameters: Vec::new(),
        result: SemanticTypeId(0),
        effects: EffectSet(EffectSet::FIRMWARE),
        stack_bytes_bound: 0,
        frame_bytes_bound: 0,
        uninterrupted_work_bound: Some(1),
        recursive_depth_bound: Some(1),
        proofs: vec![ProofId(0), ProofId(1), ProofId(2)],
        source: None,
    });

    partial.graph = Some(ImageGraph {
        name: image_name,
        entry: FunctionInstanceId(0),
        actors: Vec::new(),
        tasks: Vec::new(),
        devices: Vec::new(),
        pools: Vec::new(),
        regions: Vec::new(),
        brands: Vec::new(),
        static_bytes: 0,
        peak_bytes: 0,
        startup_order: vec![ImageOwner::Runtime],
        shutdown_order: vec![ImageOwner::Runtime],
    });
    Ok(())
}

fn fallback_span(program: &wrela_hir::Program) -> Span {
    program.modules.first().map_or(
        Span {
            file: wrela_source::FileId(0),
            range: wrela_source::TextRange { start: 0, end: 0 },
        },
        |module| module.source,
    )
}

fn check_cancelled(is_cancelled: &dyn Fn() -> bool) -> Result<(), AnalysisFailure> {
    if is_cancelled() {
        Err(AnalysisFailure::Cancelled)
    } else {
        Ok(())
    }
}

/// Stable bottom-up merge sort with explicit scratch bounds and one
/// cancellation poll before every scratch fill, merge output, and copy-back.
fn cancellable_stable_sort_by<T: Copy>(
    values: &mut [T],
    maximum_entries: u64,
    resource: &'static str,
    is_cancelled: &dyn Fn() -> bool,
    compare: &impl Fn(&T, &T) -> Result<std::cmp::Ordering, AnalysisFailure>,
) -> Result<(), AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let length = u64::try_from(values.len()).map_err(|_| AnalysisFailure::ResourceLimit {
        resource,
        limit: maximum_entries,
    })?;
    if length > maximum_entries {
        return Err(AnalysisFailure::ResourceLimit {
            resource,
            limit: maximum_entries,
        });
    }
    let Some(first) = values.first().copied() else {
        return Ok(());
    };
    let mut scratch = Vec::new();
    scratch
        .try_reserve_exact(values.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource,
            limit: maximum_entries,
        })?;
    for _ in 0..values.len() {
        check_cancelled(is_cancelled)?;
        scratch.push(first);
    }
    let mut width = 1_usize;
    let mut source_is_values = true;
    while width < values.len() {
        if source_is_values {
            cancellable_merge_pass(values, &mut scratch, width, is_cancelled, compare)?;
        } else {
            cancellable_merge_pass(&scratch, values, width, is_cancelled, compare)?;
        }
        source_is_values = !source_is_values;
        width = width.checked_mul(2).unwrap_or(values.len());
    }
    if !source_is_values {
        for (destination, source) in values.iter_mut().zip(scratch) {
            check_cancelled(is_cancelled)?;
            *destination = source;
        }
    }
    check_cancelled(is_cancelled)
}

fn cancellable_merge_pass<T: Copy>(
    source: &[T],
    destination: &mut [T],
    width: usize,
    is_cancelled: &dyn Fn() -> bool,
    compare: &impl Fn(&T, &T) -> Result<std::cmp::Ordering, AnalysisFailure>,
) -> Result<(), AnalysisFailure> {
    let mut start = 0_usize;
    while start < source.len() {
        let middle = start
            .checked_add(width)
            .unwrap_or(source.len())
            .min(source.len());
        let end = middle
            .checked_add(width)
            .unwrap_or(source.len())
            .min(source.len());
        let (mut left, mut right) = (start, middle);
        for output in &mut destination[start..end] {
            check_cancelled(is_cancelled)?;
            let take_left = right >= end
                || left < middle
                    && compare(&source[left], &source[right])? != std::cmp::Ordering::Greater;
            if take_left {
                *output = source[left];
                left += 1;
            } else {
                *output = source[right];
                right += 1;
            }
        }
        start = end;
    }
    Ok(())
}

fn cancellable_stable_sort_owned_by<T>(
    values: &mut [T],
    maximum_entries: u64,
    resource: &'static str,
    is_cancelled: &dyn Fn() -> bool,
    compare: &impl Fn(&T, &T) -> Result<std::cmp::Ordering, AnalysisFailure>,
) -> Result<(), AnalysisFailure> {
    check_cancelled(is_cancelled)?;
    let length = u64::try_from(values.len()).map_err(|_| AnalysisFailure::ResourceLimit {
        resource,
        limit: maximum_entries,
    })?;
    if length > maximum_entries {
        return Err(AnalysisFailure::ResourceLimit {
            resource,
            limit: maximum_entries,
        });
    }
    let mut order = Vec::new();
    order
        .try_reserve_exact(values.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource,
            limit: maximum_entries,
        })?;
    for index in 0..values.len() {
        check_cancelled(is_cancelled)?;
        order.push(index);
    }
    cancellable_stable_sort_by(
        &mut order,
        maximum_entries,
        resource,
        is_cancelled,
        &|left, right| compare(&values[*left], &values[*right]),
    )?;
    let mut destinations = Vec::new();
    destinations
        .try_reserve_exact(values.len())
        .map_err(|_| AnalysisFailure::ResourceLimit {
            resource,
            limit: maximum_entries,
        })?;
    for _ in 0..values.len() {
        check_cancelled(is_cancelled)?;
        destinations.push(0_usize);
    }
    for (destination, source) in order.into_iter().enumerate() {
        check_cancelled(is_cancelled)?;
        let slot = destinations
            .get_mut(source)
            .ok_or(AnalysisFailure::RequestMismatch)?;
        *slot = destination;
    }
    for index in 0..values.len() {
        while destinations[index] != index {
            check_cancelled(is_cancelled)?;
            let destination = destinations[index];
            values.swap(index, destination);
            destinations.swap(index, destination);
        }
    }
    check_cancelled(is_cancelled)
}

fn cancellable_dedup<T: Copy + Eq>(
    values: &mut Vec<T>,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<(), AnalysisFailure> {
    let mut write = 0_usize;
    for read in 0..values.len() {
        check_cancelled(is_cancelled)?;
        if write == 0 || values[read] != values[write - 1] {
            values[write] = values[read];
            write += 1;
        }
    }
    values.truncate(write);
    Ok(())
}

fn cancellable_str_cmp(
    left: &str,
    right: &str,
    is_cancelled: &dyn Fn() -> bool,
) -> Result<std::cmp::Ordering, AnalysisFailure> {
    for (left, right) in left.bytes().zip(right.bytes()) {
        check_cancelled(is_cancelled)?;
        match left.cmp(&right) {
            std::cmp::Ordering::Equal => {}
            ordering => return Ok(ordering),
        }
    }
    check_cancelled(is_cancelled)?;
    Ok(left.len().cmp(&right.len()))
}

