    fn static_literal_actor_source(helper_body: &str) -> String {
        format!(
            r#"module app

from core.image import Image, Target

fn retain_literals():
{helper_body}

async fn checkpoint():
    pass

@service
pub struct Worker:
    @task
    async fn pulse(mut self):
        retain_literals()
        await checkpoint()

@image
pub fn boot() -> Image:
    img = Image(name="actor-image", target=Target.aarch64_qemu_virt_uefi)
    installed = img.service(Worker, mailbox=1)
    return img
"#
        )
    }

    #[test]
    fn inferred_static_text_and_bytes_literals_have_exact_deduplicated_types() {
        let source = static_literal_actor_source(
            "    first = \"hé\"\n    second = \"ok\"\n    same = \"yo\"\n    payload = b\"A\\x42\\0\"",
        );
        let fixture = parsed_actor_fixture(&source);
        let changes = no_changes();
        let output = CanonicalSemanticAnalyzer::new()
            .analyze(
                parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                &|| false,
            )
            .expect("static literal analysis");
        assert!(
            output.diagnostics().is_empty(),
            "inferred static literals must analyze: {:?}",
            output.diagnostics()
        );
        let image = output.successful().expect("sealed static literal image");
        let facts = image.facts();
        let string_types: Vec<_> = facts
            .types
            .iter()
            .filter(|ty| matches!(ty.kind, SemanticTypeKind::StaticString { .. }))
            .collect();
        assert_eq!(
            string_types.len(),
            2,
            "equal UTF-8 byte lengths intern once"
        );
        assert!(
            string_types
                .iter()
                .any(|ty| { matches!(ty.kind, SemanticTypeKind::StaticString { bytes: 3 }) })
        );
        assert!(
            string_types
                .iter()
                .any(|ty| { matches!(ty.kind, SemanticTypeKind::StaticString { bytes: 2 }) })
        );
        assert!(
            facts
                .types
                .iter()
                .any(|ty| { matches!(ty.kind, SemanticTypeKind::StaticBytes { bytes: 3 }) })
        );
        assert!(facts.expressions.iter().any(|fact| {
            matches!(&fact.resolution, ExpressionResolution::Constant(ConstantValue::String(value)) if value == "hé")
        }));
        assert!(facts.expressions.iter().any(|fact| {
            matches!(&fact.resolution, ExpressionResolution::Constant(ConstantValue::Bytes(value)) if value == &[b'A', b'B', 0])
        }));
    }

    #[test]
    fn bounded_bool_interpolation_analyzes_in_an_unconsumed_sync_local() {
        let source = static_literal_actor_source(
            "    rendered = f\"ready={true}\"\n    second = f\"{false}/{true}\"",
        );
        let fixture = parsed_actor_fixture(&source);
        let changes = no_changes();
        let output = CanonicalSemanticAnalyzer::new()
            .analyze(
                parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                &|| false,
            )
            .expect("bounded bool interpolation analysis");
        assert!(
            output.diagnostics().is_empty(),
            "bounded bool interpolation must analyze: {:?}",
            output.diagnostics()
        );
        let image = output
            .successful()
            .expect("sealed bounded interpolation image");
        let facts = image.facts();
        assert_eq!(
            facts
                .types
                .iter()
                .filter(|ty| matches!(ty.kind, SemanticTypeKind::BoundedString { capacity: 11 }))
                .count(),
            1,
            "equal checked capacities intern one compiler-minted type"
        );
        let interpolations: Vec<_> = facts
            .expressions
            .iter()
            .filter_map(|fact| match &fact.resolution {
                ExpressionResolution::BoundedInterpolation { capacity, parts } => {
                    Some((*capacity, parts))
                }
                _ => None,
            })
            .collect();
        assert_eq!(interpolations.len(), 2);
        assert!(interpolations.iter().all(|(capacity, _)| *capacity == 11));
        assert!(matches!(
            interpolations[0].1.as_slice(),
            [
                BoundedInterpolationPart::Text { value, .. },
                BoundedInterpolationPart::Bool { .. }
            ] if value == "ready="
        ));
        assert!(matches!(
            interpolations[1].1.as_slice(),
            [
                BoundedInterpolationPart::Bool { .. },
                BoundedInterpolationPart::Text { value, .. },
                BoundedInterpolationPart::Bool { .. }
            ] if value == "/"
        ));
    }

