    #[test]
    fn static_literal_consumers_and_interpolation_fail_closed_by_name() {
        let diagnostic = |source: String| {
            let fixture = parsed_actor_fixture(&source);
            let changes = no_changes();
            let output = CanonicalSemanticAnalyzer::new()
                .analyze(
                    parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                    &|| false,
                )
                .expect("static literal rejection is recoverable");
            assert!(output.successful().is_none());
            output
                .diagnostics()
                .first()
                .and_then(|diagnostic| diagnostic.code.clone())
                .expect("named static literal diagnostic")
        };

        assert_eq!(
            diagnostic(static_literal_actor_source("    text: String[..8] = \"x\"")),
            "semantic-static-data-context-pending"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source("    text = \"x\"\n    text")),
            "semantic-static-data-consumer-pending"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source("    return \"x\"")),
            "semantic-static-data-context-pending"
        );

        let call_source = static_literal_actor_source("    sink(\"x\")").replace(
            "fn retain_literals():",
            "fn sink(value: u64):\n    pass\n\nfn retain_literals():",
        );
        assert_eq!(
            diagnostic(call_source),
            "semantic-static-data-context-pending"
        );

        let storage_source =
            STATE_ACCESS_ACTOR_SOURCE.replace("self.value = 7", "self.value = \"x\"");
        assert_eq!(
            diagnostic(storage_source),
            "semantic-static-data-context-pending"
        );

        let persistent_source = static_literal_actor_source("    pass").replace(
            "        retain_literals()",
            "        retained = \"x\"\n        retain_literals()",
        );
        assert_eq!(
            diagnostic(persistent_source),
            "semantic-static-data-persistence-pending"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    rendered = f\"value={1.0}\""
            )),
            "semantic-bounded-interpolation-value-type"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    payload = b\"AB\"\n    rendered = f\"{payload}\""
            )),
            "semantic-bounded-interpolation-value-type"
        );
    }

    #[test]
    fn bounded_primitive_interpolation_tails_fail_closed_by_name() {
        let diagnostic = |source: String| {
            let fixture = parsed_actor_fixture(&source);
            let changes = no_changes();
            let output = CanonicalSemanticAnalyzer::new()
                .analyze(
                    parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                    &|| false,
                )
                .expect("bounded interpolation rejection is recoverable");
            assert!(output.successful().is_none());
            output
                .diagnostics()
                .first()
                .and_then(|diagnostic| diagnostic.code.as_deref())
                .expect("named bounded interpolation rejection")
                .to_owned()
        };

        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    rendered = f\"value={1.0}\""
            )),
            "semantic-bounded-interpolation-value-type"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    rendered = f\"value={1 + 2}\""
            )),
            "semantic-bounded-interpolation-expression-pending"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    glyph: char = 'x'\n    rendered = f\"{glyph}\""
            )),
            "semantic-runtime-function-body-not-supported"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    rendered = f\"value={true:x}\""
            )),
            "semantic-bounded-interpolation-format-pending"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    rendered = f\"ready={true}\"\n    rendered"
            )),
            "semantic-bounded-string-consumer-pending"
        );
        assert_eq!(
            diagnostic(static_literal_actor_source(
                "    rendered: String[..16] = f\"ready={true}\""
            )),
            "semantic-bounded-interpolation-context-pending"
        );
        let persistent_source = static_literal_actor_source("    pass").replace(
            "        retain_literals()",
            "        rendered = f\"ready={true}\"",
        );
        assert_eq!(
            diagnostic(persistent_source),
            "semantic-bounded-interpolation-persistence-pending"
        );
        let isr_source = BOUNDED_ACTOR_SOURCE.replace(
            "    pub async fn ping(mut self):\n        await checkpoint()",
            "    isr fn irq(mut self):\n        rendered = f\"ready={true}\"",
        );
        assert_eq!(diagnostic(isr_source), "semantic-bounded-interpolation-isr");
    }

    fn admission_actor_source(task_body: &str) -> String {
        let task_tail = if task_body.contains("return ") {
            ""
        } else {
            "        await checkpoint()\n"
        };
        format!(
            r#"module app

from core.actor import AdmissionError, AdmissionResult
from core.image import Image, Target

async fn checkpoint():
    pass

@service
pub struct Worker:
    pub async fn ping(mut self):
        await checkpoint()

    pub async fn pong(mut self):
        await checkpoint()

    @task
    async fn publish(mut self):
{task_body}
{task_tail}

@image
pub fn boot() -> Image:
    img = Image(name="actor-image", target=Target.aarch64_qemu_virt_uefi)
    installed = img.service(Worker, mailbox=1)
    return img
"#
        )
    }

    fn fallible_async_actor_source(task_body: &str) -> String {
        format!(
            r#"module app

from core.actor import AsyncExit
from core.image import Image, Target
from core.result import Result

async fn checkpoint() -> Result[u64, u64]:
    return Result.Ok(7)

@service
pub struct Worker:
    @task
    async fn consume(mut self):
{task_body}

@image
pub fn boot() -> Image:
    img = Image(name="actor-image", target=Target.aarch64_qemu_virt_uefi)
    installed = img.service(Worker, mailbox=1)
    return img
"#
        )
    }

    const FALLIBLE_ASYNC_NESTED_MATCH: &str = r#"        match await checkpoint():
            case Result.Ok(value):
                pass
            case Result.Err(outcome):
                match outcome:
                    case AsyncExit.Operation(error):
                        pass
                    case AsyncExit.Cancelled(_):
                        pass
                    case AsyncExit.DeadlineRejected(_):
                        pass
                    case AsyncExit.DeadlineExceeded(_):
                        pass
"#;

    const ACTOR_REPLY_SOURCE: &str = r#"module app

from core.image import Image, Target

@service
pub struct Worker:
    pub async fn ping(mut self) -> u64:
        return 7

@app
pub struct Client:
    worker: Actor[Worker]

    @task
    async fn request(mut self):
        answer: u64 = await self.worker.ping()

@image
pub fn boot() -> Image:
    img = Image(name="actor-image", target=Target.aarch64_qemu_virt_uefi)
    worker = img.service(Worker, mailbox=1)
    client = img.app(Client, worker=worker.handle(), mailbox=1)
    return img
"#;

    #[test]
    fn startup_task_awaits_one_exact_u64_actor_reply() {
        let fixture = parsed_actor_fixture(ACTOR_REPLY_SOURCE);
        let changes = no_changes();
        let output = CanonicalSemanticAnalyzer::new()
            .analyze(
                parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                &|| false,
            )
            .expect("actor reply analysis is recoverable");
        assert!(
            output.diagnostics().is_empty(),
            "exact actor reply must analyze: {:?}",
            output.diagnostics()
        );
        let image = output.successful().expect("actor reply image seals");
        let facts = image.facts();
        let request = facts
            .expressions
            .iter()
            .find(|fact| matches!(fact.resolution, ExpressionResolution::ActorRequest { .. }))
            .expect("awaited actor request fact");
        assert!(matches!(
            facts.types.get(request.ty.0 as usize).map(|ty| &ty.kind),
            Some(SemanticTypeKind::Integer {
                signed: false,
                bits: 64,
                ..
            })
        ));
        assert!(facts.expressions.iter().any(|fact| {
            fact.resolution == ExpressionResolution::Builtin(IntrinsicOperation::Await)
                && fact.ty == request.ty
                && fact.effects == EffectSet(EffectSet::ACTOR | EffectSet::SUSPEND)
        }));
        let request_index = facts
            .expressions
            .iter()
            .position(|fact| fact.expression == request.expression)
            .expect("request index");
        let await_index = facts
            .expressions
            .iter()
            .position(|fact| {
                fact.resolution == ExpressionResolution::Builtin(IntrinsicOperation::Await)
            })
            .expect("await index");
        let ExpressionResolution::ActorRequest {
            permit,
            reply: Some(reply),
            ..
        } = request.resolution
        else {
            panic!("typed request authority");
        };

        let mut forged_request_proofs = facts.clone();
        forged_request_proofs.expressions[request_index]
            .proofs
            .retain(|proof| *proof != permit);
        forged_request_proofs
            .validate_partial_structure()
            .expect("proof omission remains prefix-valid");
        assert!(
            forged_request_proofs
                .validate_for_seal(image.hir(), &|| false)
                .is_err(),
            "the exact request must carry its permit proof"
        );

        let mut forged_await_effects = facts.clone();
        forged_await_effects.expressions[await_index].effects = EffectSet(EffectSet::SUSPEND);
        forged_await_effects
            .validate_partial_structure()
            .expect("effect substitution remains prefix-valid");
        assert!(
            forged_await_effects
                .validate_for_seal(image.hir(), &|| false)
                .is_err(),
            "await must preserve actor effects"
        );

        let producer = request.function;
        let mut forged_function_effects = facts.clone();
        forged_function_effects.functions[producer.0 as usize].effects =
            EffectSet(EffectSet::TASK | EffectSet::SUSPEND);
        forged_function_effects
            .validate_partial_structure()
            .expect("function effect substitution remains prefix-valid");
        assert!(
            forged_function_effects
                .validate_for_seal(image.hir(), &|| false)
                .is_err(),
            "reply producer must retain the actor effect"
        );

        let mut forged_reply_dependencies = facts.clone();
        forged_reply_dependencies.proofs[reply.0 as usize].depends_on = vec![permit];
        forged_reply_dependencies
            .validate_partial_structure()
            .expect("dependency omission remains prefix-valid");
        assert!(
            forged_reply_dependencies
                .validate_for_seal(image.hir(), &|| false)
                .is_err(),
            "reply proof must depend on the target result witness"
        );
    }

    #[test]
    fn typed_actor_reply_rejects_nonexact_or_unconsumed_paths_by_name() {
        let cases = [
            (
                ACTOR_REPLY_SOURCE.replace(
                    "        answer: u64 = await self.worker.ping()",
                    "        pass\n        answer: u64 = await self.worker.ping()",
                ),
                "semantic-actor-reply-single-flight",
            ),
            (
                ACTOR_REPLY_SOURCE.replace("        return 7", "        pass"),
                "semantic-actor-reply-definite-result",
            ),
            (
                ACTOR_REPLY_SOURCE.replace(
                    "    pub async fn ping(mut self) -> u64:\n        return 7",
                    "    pub async fn ping(mut self) -> u64:\n        return 7\n\n    pub async fn unused(mut self) -> u64:\n        return 9",
                ),
                "semantic-actor-reply-unconsumed",
            ),
        ];
        for (source, expected) in cases {
            let fixture = parsed_actor_fixture(&source);
            let changes = no_changes();
            let output = CanonicalSemanticAnalyzer::new()
                .analyze(
                    parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                    &|| false,
                )
                .expect("actor reply rejection is recoverable");
            assert_eq!(
                output
                    .diagnostics()
                    .first()
                    .and_then(|diagnostic| diagnostic.code.as_deref()),
                Some(expected),
                "unexpected diagnostics: {:?}",
                output.diagnostics()
            );
        }
    }

    #[test]
    fn admission_result_try_send_matches_exhaustively_with_exact_ephemeral_facts() {
        let source = admission_actor_source(
            "        match try send self.ping():\n            case AdmissionResult.Admitted:\n                pass\n            case AdmissionResult.Rejected(reason):\n                pass\n",
        );
        let fixture = parsed_actor_admission_fixture(&source);
        let changes = no_changes();
        let output = CanonicalSemanticAnalyzer::new()
            .analyze(
                parsed_actor_request(&fixture, &changes, AnalysisLimits::standard()),
                &|| false,
            )
            .expect("try-send analysis");
        assert!(
            output.diagnostics().is_empty(),
            "canonical AdmissionResult match must analyze: {:?}",
            output.diagnostics()
        );
        let image = output.successful().expect("sealed admission-result image");
        let facts = image.facts();
        let try_send = facts
            .expressions
            .iter()
            .find(|fact| {
                matches!(
                    fact.resolution,
                    ExpressionResolution::Builtin(IntrinsicOperation::ActorTrySend {
                        actor: ActorId(0)
                    })
                )
            })
            .expect("outer try-send fact");
        assert_eq!(try_send.effects, EffectSet(EffectSet::ACTOR));
        assert_eq!(try_send.ownership_before, OwnershipState::Owned);
        assert_eq!(try_send.ownership_after, OwnershipState::Owned);
        let result = try_send.result.expect("try-send outcome value");
        let outcome = facts
            .values
            .get(result.0 as usize)
            .expect("try-send outcome record");
        assert_eq!(
            outcome.class,
            SemanticValueClass::Ephemeral(EphemeralKind::AdmissionResult)
        );
        assert!(matches!(
            facts.types.get(outcome.ty.0 as usize).map(|ty| &ty.kind),
            Some(SemanticTypeKind::Enumeration { variants, .. })
                if matches!(variants.as_slice(), [admitted, rejected]
                    if admitted.name == "Admitted"
                        && admitted.fields.is_empty()
                        && rejected.name == "Rejected"
                        && rejected.fields.len() == 1)
        ));
        let request = facts
            .expressions
            .iter()
            .find(|fact| matches!(fact.resolution, ExpressionResolution::ActorRequest { .. }))
            .expect("inner actor request fact");
        assert_ne!(request.expression, try_send.expression);
        assert_eq!(request.proofs, try_send.proofs);
        let ExpressionResolution::ActorRequest { permit, .. } = request.resolution else {
            unreachable!();
        };
        assert!(try_send.proofs.contains(&permit));

        let try_index = facts
            .expressions
            .iter()
            .position(|fact| fact.expression == try_send.expression)
            .expect("try-send fact index");
        let request_index = facts
            .expressions
            .iter()
            .position(|fact| fact.expression == request.expression)
            .expect("request fact index");

        let mut forged_class = facts.clone();
        forged_class.values[result.0 as usize].class = SemanticValueClass::FirstClass;
        forged_class
            .validate_partial_structure()
            .expect("first-class substitution remains prefix-valid");
        assert!(
            forged_class
                .validate_for_seal(image.hir(), &|| false)
                .is_err()
        );

        let error_ty = facts
            .types
            .iter()
            .find(|ty| {
                matches!(&ty.kind, SemanticTypeKind::Enumeration { variants, .. }
                    if variants.iter().any(|variant| variant.name == "DeadlineRejected"))
            })
            .map(|ty| ty.id)
            .expect("AdmissionError type");
        let mut forged_type = facts.clone();
        forged_type.expressions[try_index].ty = error_ty;
        forged_type.values[result.0 as usize].ty = error_ty;
        forged_type
            .validate_partial_structure()
            .expect("nominal type substitution remains prefix-valid");
        assert!(
            forged_type
                .validate_for_seal(image.hir(), &|| false)
                .is_err()
        );

        let replacement_proof = facts
            .proofs
            .iter()
            .map(|proof| proof.id)
            .find(|candidate| *candidate != permit)
            .expect("another valid proof");
        let mut forged_proof = facts.clone();
        forged_proof.expressions[try_index]
            .proofs
            .retain(|proof| *proof != permit);
        forged_proof.expressions[try_index]
            .proofs
            .push(replacement_proof);
        forged_proof.expressions[try_index].proofs.sort_unstable();
        forged_proof
            .validate_partial_structure()
            .expect("valid proof substitution remains prefix-valid");
        assert!(
            forged_proof
                .validate_for_seal(image.hir(), &|| false)
                .is_err()
        );

        let pong = facts
            .functions
            .iter()
            .find(|function| {
                function.role == FunctionRole::ActorTurn(ActorId(0))
                    && matches!(function.origin, FunctionOrigin::Source { declaration, .. }
                        if image.hir().as_program().declaration(declaration)
                            .and_then(|record| record.name.as_ref())
                            .is_some_and(|name| name.as_str() == "pong"))
            })
            .map(|function| function.id)
            .expect("alternate actor turn");
        let mut forged_method = facts.clone();
        let ExpressionResolution::ActorRequest { method, .. } =
            &mut forged_method.expressions[request_index].resolution
        else {
            unreachable!();
        };
        *method = pong;
        forged_method
            .validate_partial_structure()
            .expect("valid method substitution remains prefix-valid");
        assert!(
            forged_method
                .validate_for_seal(image.hir(), &|| false)
                .is_err()
        );
    }

